import type { StateCreator } from "zustand";
import { computeNewAchievementIds } from "../../lib/achievementEngine";
import { ACHIEVEMENTS, isAchievementId } from "../../data/achievementSchema";
import type { AppState } from "../useAppStore";

export type AchievementProgressMap = {
  resolvedTickets: number;
  helpdeskClears: number;
  bestArenaScoreMax: number;
  streakDays: number;
};

export interface AchievementSlice {
  unlockedAchievementIds: string[];
  achievementProgressMap: AchievementProgressMap;
  checkAchievements: () => void;
  tryUnlockAchievements: () => void;
  unlockAchievement: (achievementId: string) => boolean;
}

function buildProgressMap(state: AppState): AchievementProgressMap {
  const best = Math.max(0, ...Object.values(state.arenaBestScores));
  return {
    resolvedTickets: state.resolvedTickets.length,
    helpdeskClears: state.helpdeskClears,
    bestArenaScoreMax: best,
    streakDays: state.dailyGrind.streakDays,
  };
}

export const createAchievementSlice: StateCreator<AppState, [], [], AchievementSlice> = (set, get) => ({
  unlockedAchievementIds: [],
  achievementProgressMap: {
    resolvedTickets: 0,
    helpdeskClears: 0,
    bestArenaScoreMax: 0,
    streakDays: 0,
  },
  checkAchievements: () => {
    const s = get();
    const progressMap = buildProgressMap(s);
    const newIds = computeNewAchievementIds({
      unlocked: new Set(s.unlockedAchievementIds),
      resolvedTickets: progressMap.resolvedTickets,
      helpdeskClears: progressMap.helpdeskClears,
      bestArenaScoreMax: progressMap.bestArenaScoreMax,
      streakDays: progressMap.streakDays,
    });
    if (newIds.length === 0) {
      set({ achievementProgressMap: progressMap });
      return;
    }
    const merged = [...new Set([...s.unlockedAchievementIds, ...newIds])];
    set({
      unlockedAchievementIds: merged,
      achievementProgressMap: progressMap,
    });
    for (const achievementId of newIds) {
      if (!isAchievementId(achievementId)) continue;
      const def = ACHIEVEMENTS[achievementId];
      get().enqueueNotification({
        id: `ach-${achievementId}-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
        kind: "achievement",
        achievementId,
        title: def.title,
        requirement: def.requirement,
      });
    }
  },
  tryUnlockAchievements: () => {
    get().checkAchievements();
  },
  unlockAchievement: (achievementId) => {
    if (!isAchievementId(achievementId)) return false;
    const s = get();
    if (s.unlockedAchievementIds.includes(achievementId)) return false;
    const def = ACHIEVEMENTS[achievementId];
    set({
      unlockedAchievementIds: [...s.unlockedAchievementIds, achievementId],
      achievementProgressMap: buildProgressMap(s),
    });
    get().enqueueNotification({
      id: `ach-${achievementId}-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      kind: "achievement",
      achievementId,
      title: def.title,
      requirement: def.requirement,
    });
    return true;
  },
});
