import { useAppStore } from "../../store/useAppStore";

/** Phase 62 — Shell-Gate wenn adminCmd ohne isAdmin */
export function AdminGateLockout() {
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  return (
    <section className="border border-red-900/60 bg-red-950/25 px-4 py-8 font-mono sm:px-6">
      <p className="text-[10px] font-bold uppercase tracking-[0.28em] text-red-300">CRITICAL · Zugang verweigert</p>
      <p className="mt-2 max-w-md text-[11px] leading-relaxed text-red-200/90">
        Admin-Kernel nicht gebunden — keine Telemetrie ohne gültige Signatur
      </p>
      <button
        type="button"
        onClick={() => setActiveSection("command")}
        className="mt-5 border border-red-600/50 bg-red-950/40 px-3 py-1.5 text-[9px] font-bold uppercase tracking-[0.2em] text-red-200 hover:bg-red-900/35"
      >
        Zurück zum Command Deck
      </button>
    </section>
  );
}
