import { buildSqlAcademyChapters } from "../data/factories/sqlContentFactory";
import type { SqlUniverseId } from "../data/universes";
import type { ChapterProgress, VaultSqlDeepLinkFocus } from "../store/academyStore";
import { normalizeChapterProgress } from "../store/academyStore";

export type KnowledgeExamBand = "AP1" | "AP2" | "WISO" | "PRAXIS";
export type KnowledgeTopic = "SQL" | "NETZ" | "KARTE";
export type KnowledgeLane = "briefing" | "snippet" | "task";

export type KnowledgeVaultJump =
  | { kind: "sql_academy"; universeId: SqlUniverseId; chapterId: string; focus: VaultSqlDeepLinkFocus }
  | { kind: "helpdesk" }
  | { kind: "flashcards" };

export type KnowledgeCard = {
  id: string;
  lane: KnowledgeLane;
  examBand: KnowledgeExamBand;
  topic: KnowledgeTopic;
  title: string;
  subtitle: string;
  meta: string;
  jump: KnowledgeVaultJump;
};

function examBandFromChapterOrder(order: number): KnowledgeExamBand {
  if (order >= 1 && order <= 6) return "AP1";
  if (order >= 7 && order <= 11) return "AP2";
  return "PRAXIS";
}

type UniverseChapterMap = Record<string, ChapterProgress | undefined>;

export function deriveKnowledgeHubCards(input: {
  universeId: SqlUniverseId;
  universeProgress: UniverseChapterMap;
  helpdeskClears: number;
  resolvedTicketCount: number;
  flashcardActiveCount: number;
}): KnowledgeCard[] {
  const { universeId, universeProgress, helpdeskClears, resolvedTicketCount, flashcardActiveCount } = input;
  const chapters = buildSqlAcademyChapters(universeId);
  const out: KnowledgeCard[] = [];

  for (const chapter of chapters) {
    const row = normalizeChapterProgress(universeProgress[chapter.id]);
    const band = examBandFromChapterOrder(chapter.order);

    if (row.learningFlowLessonComplete) {
      out.push({
        id: `hub-${universeId}-${chapter.id}-briefing`,
        lane: "briefing",
        examBand: band,
        topic: "SQL",
        title: chapter.title,
        subtitle: "Theoriepfad abgeschlossen",
        meta: `Kapitel ${String(chapter.order).padStart(2, "0")}`,
        jump: { kind: "sql_academy", universeId, chapterId: chapter.id, focus: { kind: "chapter_hub" } },
      });
    }

    if (row.materialPhaseComplete) {
      out.push({
        id: `hub-${universeId}-${chapter.id}-material`,
        lane: "snippet",
        examBand: band,
        topic: "SQL",
        title: chapter.title,
        subtitle: "Snippets und Vertiefung frei",
        meta: `Kapitel ${String(chapter.order).padStart(2, "0")}`,
        jump: { kind: "sql_academy", universeId, chapterId: chapter.id, focus: { kind: "chapter_hub" } },
      });
    }

    for (const quiz of chapter.quizBlocks ?? []) {
      if (row.masteredQuizIds.includes(quiz.id)) {
        const q = quiz.question.length > 56 ? `${quiz.question.slice(0, 53)}…` : quiz.question;
        out.push({
          id: `hub-${universeId}-${chapter.id}-quiz-${quiz.id}`,
          lane: "snippet",
          examBand: band,
          topic: "SQL",
          title: q,
          subtitle: "Theorie Check gesichert",
          meta: `Kapitel ${String(chapter.order).padStart(2, "0")}`,
          jump: { kind: "sql_academy", universeId, chapterId: chapter.id, focus: { kind: "chapter_hub" } },
        });
      }
    }

    for (const task of chapter.tasks) {
      if (row.solvedTaskIds.includes(task.id)) {
        const promptShort = task.prompt.length > 72 ? `${task.prompt.slice(0, 69)}…` : task.prompt;
        out.push({
          id: `hub-${universeId}-${chapter.id}-task-${task.id}`,
          lane: "task",
          examBand: band,
          topic: "SQL",
          title: `Aufgabe ${task.letter}`,
          subtitle: promptShort,
          meta: `Kapitel ${String(chapter.order).padStart(2, "0")}`,
          jump: { kind: "sql_academy", universeId, chapterId: chapter.id, focus: { kind: "guided_task", taskId: task.id } },
        });
      }
    }
  }

  if (helpdeskClears > 0) {
    out.push({
      id: `hub-${universeId}-helpdesk-clears`,
      lane: "snippet",
      examBand: "AP1",
      topic: "NETZ",
      title: "Helpdesk Episoden",
      subtitle: "Supportpfad mit Clear Signal",
      meta: `${helpdeskClears} Clears`,
      jump: { kind: "helpdesk" },
    });
  }

  if (resolvedTicketCount > 0) {
    out.push({
      id: `hub-${universeId}-tickets`,
      lane: "task",
      examBand: "AP1",
      topic: "NETZ",
      title: "Ticket Ledger",
      subtitle: "Erledigte Inbox Eintraege",
      meta: `${resolvedTicketCount} Tickets`,
      jump: { kind: "helpdesk" },
    });
  }

  if (flashcardActiveCount > 0) {
    out.push({
      id: `hub-${universeId}-flashcards`,
      lane: "briefing",
      examBand: "WISO",
      topic: "KARTE",
      title: "Karteikarten Stack",
      subtitle: "SM2 Fortschritt aktiv",
      meta: `${flashcardActiveCount} Karten`,
      jump: { kind: "flashcards" },
    });
  }

  return out;
}

export function filterKnowledgeCards(
  cards: readonly KnowledgeCard[],
  exam: "all" | KnowledgeExamBand,
  topic: "all" | KnowledgeTopic,
): KnowledgeCard[] {
  return cards.filter((card) => {
    if (exam !== "all" && card.examBand !== exam) return false;
    if (topic !== "all" && card.topic !== topic) return false;
    return true;
  });
}
