import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import { useAppStore } from "../../store/useAppStore";

export function AudioVisualizerBars({ compact = false }: { compact?: boolean }) {
  const tick = useAppStore((s) => s.audioActivityTick);
  const prefersReduced = useReducedMotion();
  const maxH = compact ? 20 : 34;
  const [bars, setBars] = useState(() =>
    Array.from({ length: 8 }, () => 0.12 + Math.random() * 0.06),
  );

  useEffect(() => {
    if (tick === 0) return;
    setBars(Array.from({ length: 8 }, () => 0.18 + Math.random() * 0.82));
    const tm = window.setTimeout(() => {
      setBars(Array.from({ length: 8 }, () => 0.08 + Math.random() * 0.06));
    }, prefersReduced ? 60 : 400);
    return () => window.clearTimeout(tm);
  }, [tick, prefersReduced]);

  return (
    <div className="flex items-end justify-start gap-[3px]" aria-hidden>
      {bars.map((h, i) => (
        <motion.div
          key={i}
          className="w-[3px] origin-bottom rounded-full border border-white/10 bg-gradient-to-t from-cyber-cyan/25 via-cyber-cyan to-magenta/70"
          initial={false}
          animate={{ height: Math.max(4, h * maxH) }}
          transition={
            prefersReduced
              ? { duration: 0.02 }
              : { type: "spring", stiffness: 460, damping: 28 }
          }
        />
      ))}
    </div>
  );
}
