import { motion, useReducedMotion } from "framer-motion";
import { IconCloud } from "../icons/ThinLineIcons";
import { cn } from "../../lib/cn";
import { getSupabase } from "../../lib/supabase";
import type { CloudSyncStatus } from "../../store/useAppStore";

export function CloudSyncLed({
  syncStatus,
  busy,
}: {
  syncStatus: CloudSyncStatus;
  busy: boolean;
}) {
  const prefersReduced = useReducedMotion();
  const configured = getSupabase() !== null;
  const offline = !configured || syncStatus === "offline";
  const syncedIdle = configured && syncStatus === "cloud-synced" && !busy;

  const color = offline
    ? "text-foreground-muted"
    : syncedIdle
      ? "text-signal"
      : "text-foreground";

  return (
    <div
      className="flex items-center gap-1.5 rounded-full border border-white/10 bg-white/[0.04] px-2 py-1 ring-1 ring-white/[0.08]"
      title={
        !configured
          ? "Cloud-Uplink nicht konfiguriert"
          : syncStatus === "offline"
            ? "Offline"
            : busy
              ? "Übertragung"
              : syncStatus === "cloud-synced"
                ? "Synchronisiert"
                : "Ausstehend"
      }
    >
      <motion.span
        animate={
          busy && !prefersReduced
            ? { scale: [1, 1.06, 1], opacity: [0.75, 1, 0.75] }
            : { scale: 1, opacity: offline ? 0.45 : 1 }
        }
        transition={
          busy && !prefersReduced
            ? { duration: 0.85, repeat: Infinity, ease: "easeInOut" }
            : { duration: 0.25 }
        }
        className={cn(
          "relative flex size-7 items-center justify-center rounded-full bg-surface-muted/70 ring-1 ring-white/[0.1]",
          color,
        )}
      >
        <IconCloud className="size-3.5" />
      </motion.span>
      <span className="hidden font-mono text-[9px] font-semibold uppercase tracking-wider text-foreground-muted sm:inline">
        {!configured ? "NO UPLINK" : syncStatus === "offline" ? "OFFLINE" : busy ? "UPLINK" : syncStatus === "cloud-synced" ? "SYNCED" : "QUEUE"}
      </span>
    </div>
  );
}
