import { useMemo } from "react";
import { buildTelemetrySnapshot, type TelemetrySnapshot } from "../lib/telemetryMatrix";
import { useAppStore } from "../store/useAppStore";

export function useTelemetrySnapshot(): TelemetrySnapshot {
  const mockExamHistory = useAppStore((s) => s.mockExamHistory);
  const arenaBestScores = useAppStore((s) => s.arenaBestScores);
  const flashcardProgress = useAppStore((s) => s.flashcardProgress);
  const flashcardTotalReviews = useAppStore((s) => s.flashcardTotalReviews);
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const globalXpToNext = useAppStore((s) => s.globalXpToNext);
  const gems = useAppStore((s) => s.gems);
  const dailyGrind = useAppStore((s) => s.dailyGrind);

  return useMemo(
    () =>
      buildTelemetrySnapshot({
        mockExamHistory,
        arenaBestScores,
        flashcardProgress,
        flashcardTotalReviews,
        userLevel,
        globalXP,
        globalXpToNext,
        gems,
        dailyGrind,
      }),
    [
      mockExamHistory,
      arenaBestScores,
      flashcardProgress,
      flashcardTotalReviews,
      userLevel,
      globalXP,
      globalXpToNext,
      gems,
      dailyGrind,
    ],
  );
}
