import { computeLifetimeXp } from "../lib/xpCurve";
import { normalizeTerminalThemeId } from "../data/terminalThemes";
import type { ArtifactCraftAttempt } from "./slices/createProgressSlice";
import type {
  AppState,
  EventsPersistSnapshot,
  GlobalLoreState,
  MockExamHistoryEntry,
  MockExamState,
  RaidArtifact,
  SeasonLegacyArtifact,
} from "./useAppStore";

export function partializeAppState(s: AppState): Partial<AppState> {
  return {
    selectedPerkIds: s.selectedPerkIds,
    selectedExamId: s.selectedExamId,
    operatorHandle: s.operatorHandle,
    onboardingCompleted: s.onboardingCompleted,
    onboardingHandleDraft: s.onboardingHandleDraft,
    careerPath: s.careerPath,
    operatorWelcomePulseEmitted: s.operatorWelcomePulseEmitted,
    welcomeProtocolSeen: s.welcomeProtocolSeen,
    arenaBestScores: s.arenaBestScores,
    unlockedNodes: s.unlockedNodes,
    selectedFaction: s.selectedFaction,
    realmGold: s.realmGold,
    realmDiamonds: s.realmDiamonds,
    realmKnowledge: s.realmKnowledge,
    realmTiles: s.realmTiles,
    realmTutorialComplete: s.realmTutorialComplete,
    sqlUnlockedLevels: s.sqlUnlockedLevels,
    pseudoUnlockedLevels: s.pseudoUnlockedLevels,
    supportInboxIds: s.supportInboxIds,
    resolvedTickets: s.resolvedTickets,
    userLevel: s.userLevel,
    globalXP: s.globalXP,
    globalXpToNext: s.globalXpToNext,
    gems: s.gems,
    totalXp: s.totalXp,
    currentLevel: s.currentLevel,
    prestige: s.prestige,
    skillPoints: s.skillPoints,
    inventory: s.inventory,
    synthesisHistory: s.synthesisHistory,
    activeCraftResult: s.activeCraftResult,
    flashcardProgress: s.flashcardProgress,
    flashcardTotalReviews: s.flashcardTotalReviews,
    feedbackEnabled: s.feedbackEnabled,
    dailyGrind: s.dailyGrind,
    unlockedAchievementIds: s.unlockedAchievementIds,
    achievementProgressMap: s.achievementProgressMap,
    seasonLegacyArtifacts: s.seasonLegacyArtifacts,
    raidDropRateScale: s.raidDropRateScale,
    raidArtifacts: s.raidArtifacts,
    globalLore: s.globalLore,
    globalFrictionAvg: s.globalFrictionAvg,
    claimedOutbreakRewardIds: s.claimedOutbreakRewardIds,
    events: {
      raidDropRateScale: s.raidDropRateScale,
      globalLore: s.globalLore,
      globalFrictionAvg: s.globalFrictionAvg,
      claimedOutbreakRewardIds: s.claimedOutbreakRewardIds,
    },
    legacyPoints: s.legacyPoints,
    legacyTranscendCount: s.legacyTranscendCount,
    legacyXpBoostMultiplier: s.legacyXpBoostMultiplier,
    helpdeskClears: s.helpdeskClears,
    mockExam: s.mockExam,
    mockExamHistory: s.mockExamHistory,
    rigTerminalThemeId: s.rigTerminalThemeId,
    rigScanlineDial: s.rigScanlineDial,
    ghostModeEnabled: s.ghostModeEnabled,
    bossGhostArmed: s.bossGhostArmed,
  };
}

export function mergeAppState(persisted: unknown, current: AppState): AppState {
  const p = (persisted ?? {}) as Partial<AppState>;
  const persistedMock = p.mockExam;
  const mockExam =
    persistedMock &&
    typeof persistedMock === "object" &&
    Array.isArray((persistedMock as MockExamState).questionSet) &&
    Array.isArray((persistedMock as MockExamState).answers)
      ? (() => {
          const raw = persistedMock as MockExamState;
          const n = raw.answers.length;
          const flagged =
            Array.isArray(raw.flagged) && raw.flagged.length === n
              ? raw.flagged.map((x) => Boolean(x))
              : Array.from({ length: n }, () => false);
          return {
            ...raw,
            flagged,
            challengeMeta:
              raw.challengeMeta && typeof raw.challengeMeta === "object" ? raw.challengeMeta : null,
            challengeAccepted: typeof raw.challengeAccepted === "boolean" ? raw.challengeAccepted : true,
          } as MockExamState;
        })()
      : current.mockExam;
  const mergedUserLevel = typeof p.userLevel === "number" && p.userLevel >= 0 ? p.userLevel : current.userLevel;
  const mergedGlobalXp = typeof p.globalXP === "number" && p.globalXP >= 0 ? p.globalXP : current.globalXP;
  const mergedLifetimeXp = computeLifetimeXp(mergedUserLevel, mergedGlobalXp);
  const normalizedRigTheme = normalizeTerminalThemeId(
    typeof p.rigTerminalThemeId === "string" ? p.rigTerminalThemeId : current.rigTerminalThemeId,
    mergedLifetimeXp,
  );
  const mergedScanlineDial =
    typeof p.rigScanlineDial === "number" && Number.isFinite(p.rigScanlineDial)
      ? Math.max(0, Math.min(100, Math.round(p.rigScanlineDial)))
      : current.rigScanlineDial;

  const persistedHistory = p.mockExamHistory;
  const mockExamHistory = Array.isArray(persistedHistory)
    ? persistedHistory
        .map((row): MockExamHistoryEntry | null => {
          if (!row || typeof row !== "object") return null;
          const r = row as MockExamHistoryEntry;
          if (
            typeof r.completedAtMs !== "number" ||
            typeof r.totalQuestions !== "number" ||
            typeof r.correctAnswers !== "number" ||
            typeof r.percent !== "number" ||
            typeof r.grade !== "number" ||
            typeof r.gradeLabel !== "string" ||
            !r.correctTagHits ||
            typeof r.correctTagHits !== "object" ||
            !r.wrongTagHits ||
            typeof r.wrongTagHits !== "object"
          ) {
            return null;
          }
          return {
            ...r,
            challengeMeta: r.challengeMeta && typeof r.challengeMeta === "object" ? r.challengeMeta : null,
          };
        })
        .filter((row): row is MockExamHistoryEntry => !!row)
        .slice(0, 32)
    : current.mockExamHistory;
  return {
    ...current,
    ...p,
    rigTerminalThemeId: normalizedRigTheme,
    rigScanlineDial: mergedScanlineDial,
    unlockedAchievementIds: Array.isArray(p.unlockedAchievementIds) ? p.unlockedAchievementIds : current.unlockedAchievementIds,
    seasonLegacyArtifacts: Array.isArray(p.seasonLegacyArtifacts)
      ? p.seasonLegacyArtifacts
          .map((row): SeasonLegacyArtifact | null => {
            if (!row || typeof row !== "object") return null;
            const r = row as SeasonLegacyArtifact;
            if (
              typeof r.seasonKey !== "string" ||
              (r.rank !== 1 && r.rank !== 2 && r.rank !== 3) ||
              (r.winnerFaction !== "FISI" && r.winnerFaction !== "FIAE" && r.winnerFaction !== "TIE") ||
              typeof r.label !== "string" ||
              typeof r.closedAt !== "string"
            ) {
              return null;
            }
            return {
              seasonKey: r.seasonKey,
              rank: r.rank,
              winnerFaction: r.winnerFaction,
              label: r.label,
              closedAt: r.closedAt,
            };
          })
          .filter((row): row is SeasonLegacyArtifact => !!row)
          .slice(-24)
      : current.seasonLegacyArtifacts,
    raidArtifacts: Array.isArray(p.raidArtifacts)
      ? p.raidArtifacts
          .map((row): RaidArtifact | null => {
            if (!row || typeof row !== "object") return null;
            const r = row as RaidArtifact;
            if (
              typeof r.id !== "string" ||
              typeof r.label !== "string" ||
              (r.rarity !== "rare" && r.rarity !== "legendary" && r.rarity !== "mythic") ||
              typeof r.receivedAt !== "string" ||
              typeof r.eventId !== "string"
            ) {
              return null;
            }
            if (
              r.module !== "networking" &&
              r.module !== "security" &&
              r.module !== "operating_systems" &&
              r.module !== "hardware" &&
              r.module !== "programming" &&
              r.module !== "databases" &&
              r.module !== "testing" &&
              r.module !== "architecture" &&
              r.module !== "process" &&
              r.module !== "wiso"
            ) {
              return null;
            }
            return {
              id: r.id,
              label: r.label,
              rarity: r.rarity,
              module: r.module,
              eventId: r.eventId,
              receivedAt: r.receivedAt,
            };
          })
          .filter((row): row is RaidArtifact => !!row)
          .slice(0, 24)
      : current.raidArtifacts,
    globalLore:
      p.globalLore &&
      typeof p.globalLore === "object" &&
      typeof (p.globalLore as GlobalLoreState).totalGlobalXp === "number" &&
      Array.isArray((p.globalLore as GlobalLoreState).unlockedLoreIds)
        ? {
            totalGlobalXp: Math.max(0, Math.floor((p.globalLore as GlobalLoreState).totalGlobalXp)),
            unlockedLoreIds: Array.from(
              new Set((p.globalLore as GlobalLoreState).unlockedLoreIds.filter((row): row is string => typeof row === "string")),
            ),
          }
        : current.globalLore,
    globalFrictionAvg:
      typeof p.globalFrictionAvg === "number" && Number.isFinite(p.globalFrictionAvg)
        ? Math.max(0, Math.min(1, p.globalFrictionAvg))
        : current.globalFrictionAvg,
    claimedOutbreakRewardIds: Array.isArray(p.claimedOutbreakRewardIds)
      ? p.claimedOutbreakRewardIds.filter((x): x is string => typeof x === "string").slice(-24)
      : current.claimedOutbreakRewardIds,
    legacyPoints:
      typeof p.legacyPoints === "number" && Number.isFinite(p.legacyPoints)
        ? Math.max(0, Math.floor(p.legacyPoints))
        : current.legacyPoints,
    legacyTranscendCount:
      typeof p.legacyTranscendCount === "number" && Number.isFinite(p.legacyTranscendCount)
        ? Math.max(0, Math.floor(p.legacyTranscendCount))
        : current.legacyTranscendCount,
    legacyXpBoostMultiplier:
      typeof p.legacyXpBoostMultiplier === "number" && Number.isFinite(p.legacyXpBoostMultiplier)
        ? Math.max(1, Math.min(1.6, p.legacyXpBoostMultiplier))
        : current.legacyXpBoostMultiplier,
    totalXp: typeof p.totalXp === "string" && /^\d+$/.test(p.totalXp) ? p.totalXp : current.totalXp,
    currentLevel:
      typeof p.currentLevel === "number" && Number.isFinite(p.currentLevel)
        ? Math.max(0, Math.floor(p.currentLevel))
        : current.currentLevel,
    prestige:
      typeof p.prestige === "number" && Number.isFinite(p.prestige) ? Math.max(0, Math.floor(p.prestige)) : current.prestige,
    skillPoints:
      typeof p.skillPoints === "number" && Number.isFinite(p.skillPoints)
        ? Math.max(0, Math.floor(p.skillPoints))
        : current.skillPoints,
    inventory: Array.isArray(p.inventory) ? p.inventory.filter((x): x is string => typeof x === "string") : current.inventory,
    synthesisHistory: Array.isArray(p.synthesisHistory)
      ? p.synthesisHistory
          .map((entry): ArtifactCraftAttempt | null => {
            if (!entry || typeof entry !== "object") return null;
            const item = entry as ArtifactCraftAttempt;
            if (
              typeof item.id !== "string" ||
              typeof item.recipeId !== "string" ||
              typeof item.recipeName !== "string" ||
              typeof item.success !== "boolean" ||
              !Array.isArray(item.consumedMaterials) ||
              typeof item.outputAmount !== "number" ||
              typeof item.roll !== "number" ||
              typeof item.successRate !== "number" ||
              typeof item.createdAt !== "string"
            ) {
              return null;
            }
            return {
              id: item.id,
              recipeId: item.recipeId,
              recipeName: item.recipeName,
              success: item.success,
              consumedMaterials: item.consumedMaterials
                .map((material) => {
                  if (
                    !material ||
                    typeof material !== "object" ||
                    typeof material.itemId !== "string" ||
                    typeof material.amount !== "number"
                  ) {
                    return null;
                  }
                  return {
                    itemId: material.itemId,
                    amount: Math.max(1, Math.floor(material.amount)),
                  };
                })
                .filter(
                  (material): material is { itemId: string; amount: number } =>
                    !!material && material.itemId.length > 0,
                ),
              outputItemId: typeof item.outputItemId === "string" ? item.outputItemId : null,
              outputAmount: Math.max(0, Math.floor(item.outputAmount)),
              roll: Math.max(0, Math.min(0.999999, item.roll)),
              successRate: Math.max(0, Math.min(1, item.successRate)),
              createdAt: item.createdAt,
            };
          })
          .filter((entry): entry is ArtifactCraftAttempt => !!entry)
          .slice(0, 40)
      : current.synthesisHistory,
    activeCraftResult:
      p.activeCraftResult &&
      typeof p.activeCraftResult === "object" &&
      typeof (p.activeCraftResult as ArtifactCraftAttempt).id === "string" &&
      typeof (p.activeCraftResult as ArtifactCraftAttempt).recipeId === "string" &&
      typeof (p.activeCraftResult as ArtifactCraftAttempt).recipeName === "string"
        ? (p.activeCraftResult as ArtifactCraftAttempt)
        : current.activeCraftResult,
    helpdeskClears: typeof p.helpdeskClears === "number" && p.helpdeskClears >= 0 ? p.helpdeskClears : current.helpdeskClears,
    achievementProgressMap:
      p.achievementProgressMap &&
      typeof p.achievementProgressMap === "object" &&
      typeof (p.achievementProgressMap as { resolvedTickets?: unknown }).resolvedTickets === "number" &&
      typeof (p.achievementProgressMap as { helpdeskClears?: unknown }).helpdeskClears === "number" &&
      typeof (p.achievementProgressMap as { bestArenaScoreMax?: unknown }).bestArenaScoreMax === "number" &&
      typeof (p.achievementProgressMap as { streakDays?: unknown }).streakDays === "number"
        ? {
            resolvedTickets: Math.max(0, Math.floor((p.achievementProgressMap as { resolvedTickets: number }).resolvedTickets)),
            helpdeskClears: Math.max(0, Math.floor((p.achievementProgressMap as { helpdeskClears: number }).helpdeskClears)),
            bestArenaScoreMax: Math.max(
              0,
              Math.floor((p.achievementProgressMap as { bestArenaScoreMax: number }).bestArenaScoreMax),
            ),
            streakDays: Math.max(0, Math.floor((p.achievementProgressMap as { streakDays: number }).streakDays)),
          }
        : current.achievementProgressMap,
    operatorWelcomePulseEmitted:
      typeof p.operatorWelcomePulseEmitted === "boolean" ? p.operatorWelcomePulseEmitted : current.operatorWelcomePulseEmitted,
    welcomeProtocolSeen: typeof p.welcomeProtocolSeen === "boolean" ? p.welcomeProtocolSeen : current.welcomeProtocolSeen,
    linkPulseStatus: current.linkPulseStatus,
    serverTimeOffsetMs: current.serverTimeOffsetMs,
    globalLiveEvent: current.globalLiveEvent,
    activeEventModifier: current.activeEventModifier,
    raidDropRateScale:
      typeof p.raidDropRateScale === "number" && Number.isFinite(p.raidDropRateScale)
        ? Math.max(0, Math.min(3, p.raidDropRateScale))
        : current.raidDropRateScale,
    events:
      p.events &&
      typeof p.events === "object" &&
      typeof (p.events as EventsPersistSnapshot).raidDropRateScale === "number" &&
      typeof (p.events as EventsPersistSnapshot).globalFrictionAvg === "number" &&
      Array.isArray((p.events as EventsPersistSnapshot).claimedOutbreakRewardIds) &&
      (p.events as EventsPersistSnapshot).globalLore &&
      typeof (p.events as EventsPersistSnapshot).globalLore === "object"
        ? {
            raidDropRateScale: Math.max(0, Math.min(3, (p.events as EventsPersistSnapshot).raidDropRateScale)),
            globalLore: {
              totalGlobalXp: Math.max(
                0,
                Math.floor(((p.events as EventsPersistSnapshot).globalLore as GlobalLoreState).totalGlobalXp ?? 0),
              ),
              unlockedLoreIds: Array.from(
                new Set(
                  (((p.events as EventsPersistSnapshot).globalLore as GlobalLoreState).unlockedLoreIds ?? []).filter(
                    (row): row is string => typeof row === "string",
                  ),
                ),
              ),
            },
            globalFrictionAvg: Math.max(0, Math.min(1, (p.events as EventsPersistSnapshot).globalFrictionAvg)),
            claimedOutbreakRewardIds: (p.events as EventsPersistSnapshot).claimedOutbreakRewardIds
              .filter((x): x is string => typeof x === "string")
              .slice(-24),
          }
        : {
            raidDropRateScale: current.raidDropRateScale,
            globalLore: current.globalLore,
            globalFrictionAvg: current.globalFrictionAvg,
            claimedOutbreakRewardIds: current.claimedOutbreakRewardIds,
          },
    swNeedRefresh: current.swNeedRefresh,
    nexusActivity: current.nexusActivity,
    ghostModeEnabled: typeof p.ghostModeEnabled === "boolean" ? p.ghostModeEnabled : current.ghostModeEnabled,
    bossGhostArmed: typeof p.bossGhostArmed === "boolean" ? p.bossGhostArmed : current.bossGhostArmed,
    mockExam,
    mockExamHistory,
  };
}
