import type { StateCreator } from "zustand";
import { dossierMemoryHit } from "../../lib/utils/dossierHelpers";
import { startSyndicateRealtimeBridge, stopSyndicateRealtimeBridge } from "../../lib/services/syndicateService";
import type { AppState } from "../useAppStore";

export interface SyndicateSlice {
  selectedPublicOperatorId: AppState["selectedPublicOperatorId"];
  selectedPublicOperatorHandle: AppState["selectedPublicOperatorHandle"];
  publicDossierReturnSection: AppState["publicDossierReturnSection"];
  publicDossierBusy: AppState["publicDossierBusy"];
  publicDossierOnline: AppState["publicDossierOnline"];
  publicDossierData: AppState["publicDossierData"];
  publicDossierLastFetchedAt: AppState["publicDossierLastFetchedAt"];
  publicDossierCachedUserId: AppState["publicDossierCachedUserId"];
  publicDossierCachedPayload: AppState["publicDossierCachedPayload"];
  openPublicDossier: AppState["openPublicDossier"];
  closePublicDossier: AppState["closePublicDossier"];
  setPublicDossierBusy: AppState["setPublicDossierBusy"];
  setPublicDossierData: AppState["setPublicDossierData"];
  nexusActivity: AppState["nexusActivity"];
  pushNexusActivity: AppState["pushNexusActivity"];
  clearNexusActivity: AppState["clearNexusActivity"];
  factionFisiXp: AppState["factionFisiXp"];
  factionFiaeXp: AppState["factionFiaeXp"];
  factionWarPulseKey: AppState["factionWarPulseKey"];
  startSyndicateRealtime: () => void;
  stopSyndicateRealtime: () => void;
}

export const createSyndicateSlice: StateCreator<AppState, [], [], SyndicateSlice> = (set, get) => ({
  selectedPublicOperatorId: null,
  selectedPublicOperatorHandle: null,
  publicDossierReturnSection: "arena",
  publicDossierBusy: false,
  publicDossierOnline: false,
  publicDossierData: null,
  publicDossierLastFetchedAt: null,
  publicDossierCachedUserId: null,
  publicDossierCachedPayload: null,
  openPublicDossier: (userId, handle) =>
    set((state) => {
      if (dossierMemoryHit(state, userId)) {
        const snap = state.publicDossierCachedPayload;
        if (snap) {
          return {
            activeSection: "publicDossier",
            selectedPublicOperatorId: userId,
            selectedPublicOperatorHandle: handle?.trim() || snap.handle,
            publicDossierReturnSection:
              state.activeSection === "publicDossier" ? state.publicDossierReturnSection : state.activeSection,
            publicDossierBusy: false,
            publicDossierOnline: snap.online,
            publicDossierData: snap,
            moreMenuOpen: false,
          };
        }
      }
      return {
        activeSection: "publicDossier",
        selectedPublicOperatorId: userId,
        selectedPublicOperatorHandle: handle?.trim() || null,
        publicDossierReturnSection:
          state.activeSection === "publicDossier" ? state.publicDossierReturnSection : state.activeSection,
        publicDossierBusy: true,
        publicDossierOnline: false,
        publicDossierData: null,
        moreMenuOpen: false,
      };
    }),
  closePublicDossier: () =>
    set((state) => ({
      activeSection: state.publicDossierReturnSection,
      selectedPublicOperatorId: null,
      selectedPublicOperatorHandle: null,
      publicDossierBusy: false,
      publicDossierOnline: false,
      publicDossierData: null,
      moreMenuOpen: false,
    })),
  setPublicDossierBusy: (busy) => set({ publicDossierBusy: busy }),
  setPublicDossierData: (data) =>
    set(
      data
        ? {
            publicDossierData: data,
            publicDossierBusy: false,
            publicDossierOnline: data.online,
            publicDossierLastFetchedAt: Date.now(),
            publicDossierCachedUserId: data.userId,
            publicDossierCachedPayload: data,
          }
        : {
            publicDossierData: null,
            publicDossierBusy: false,
            publicDossierOnline: false,
            publicDossierLastFetchedAt: null,
            publicDossierCachedUserId: null,
            publicDossierCachedPayload: null,
          },
    ),
  nexusActivity: [],
  pushNexusActivity: (event) =>
    set((s) => {
      const id = `nx-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
      const full = { ...event, id, ts: Date.now() };
      return { nexusActivity: [full, ...s.nexusActivity].slice(0, 40) };
    }),
  clearNexusActivity: () => set({ nexusActivity: [] }),
  factionFisiXp: 0,
  factionFiaeXp: 0,
  factionWarPulseKey: null,
  startSyndicateRealtime: () => {
    startSyndicateRealtimeBridge({
      onActivity: (payload) => get().pushNexusActivity(payload),
      onFactionTotals: (snapshot) => {
        const prevFisi = get().factionFisiXp;
        const prevFiae = get().factionFiaeXp;
        const pulseKey =
          snapshot.fisiXp !== prevFisi || snapshot.fiaeXp !== prevFiae ? `war-${Date.now()}-${Math.random()}` : null;
        set({
          factionFisiXp: snapshot.fisiXp,
          factionFiaeXp: snapshot.fiaeXp,
          ...(pulseKey ? { factionWarPulseKey: pulseKey } : {}),
        });
      },
    });
  },
  stopSyndicateRealtime: () => {
    stopSyndicateRealtimeBridge();
  },
});
