import { type CSSProperties, useEffect, useState } from "react";
import type { SqlUniverseId } from "../../../../data/universes";
import { useTranslation } from "../../../../i18n/useTranslation";
import { useAcademyStore } from "../../../../store/academyStore";
import { UNIVERSE_THEME_FALLBACK } from "../../../../styles/themes/universeThemes";
import { FloatingGains } from "../effects/FloatingGains";
import { LivePreview } from "./LivePreview";

type TaskAccordionProps = {
  chapterId: string;
  taskId: string;
  universeId: SqlUniverseId;
  letter: string;
  prompt: string;
  sql: string;
  explanation: string;
  columns: string[];
  rows: Array<Record<string, string | number | null>>;
  querySuccessful?: boolean;
  radarMetrics?: Array<{ label: string; value: number }>;
  successfulTasksCount?: number;
  completed: boolean;
  onToggleComplete: () => void;
};

function decodeFrame(text: string, progress: number): string {
  const chars = "01ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  const fixed = Math.floor(text.length * progress);
  return text
    .split("")
    .map((char, idx) => {
      if (idx < fixed || char === " " || char === "\n") return char;
      return chars[(idx + fixed) % chars.length] ?? char;
    })
    .join("");
}

export function TaskAccordion({
  chapterId,
  taskId,
  universeId,
  letter,
  prompt,
  sql,
  explanation,
  columns,
  rows,
  querySuccessful = true,
  radarMetrics = [],
  successfulTasksCount = 0,
  completed,
  onToggleComplete,
}: TaskAccordionProps) {
  const [open, setOpen] = useState(false);
  const [phase, setPhase] = useState(0);
  const [showGain, setShowGain] = useState(false);
  const lastXpGain = useAcademyStore((s) => s.lastXpGain);
  const t = useTranslation();

  useEffect(() => {
    if (!open) return;
    if (phase >= 10) return;
    const timer = window.setTimeout(() => setPhase((value) => value + 1), 24);
    return () => window.clearTimeout(timer);
  }, [open, phase]);

  const decodedExplanation = open ? decodeFrame(explanation, phase / 10) : "";

  const primary = `var(--universe-primary, ${UNIVERSE_THEME_FALLBACK.primary})`;
  const accent = `var(--universe-accent, ${UNIVERSE_THEME_FALLBACK.accent})`;

  const articleFrame: CSSProperties = completed
    ? {
        borderColor: `color-mix(in srgb, ${accent} 42%, transparent)`,
        boxShadow: `0 0 0 1px color-mix(in srgb, ${accent} 14%, transparent), 0 14px 40px color-mix(in srgb, ${accent} 10%, transparent)`,
      }
    : {
        borderColor: `color-mix(in srgb, ${primary} 34%, transparent)`,
        boxShadow: `0 0 0 1px color-mix(in srgb, ${primary} 12%, transparent), 0 14px 44px color-mix(in srgb, ${primary} 9%, transparent)`,
      };

  useEffect(() => {
    if (!lastXpGain) return;
    if (lastXpGain.entityType !== "task") return;
    if (lastXpGain.universeId !== universeId) return;
    if (lastXpGain.chapterId !== chapterId) return;
    if (lastXpGain.entityId !== taskId) return;
    setShowGain(true);
  }, [lastXpGain, universeId, chapterId, taskId]);

  return (
    <article className="rounded-xl border border-solid bg-slate-950/60 p-4" style={articleFrame}>
      <div className="flex flex-wrap items-start gap-3">
        <span
          className="rounded-md border border-solid px-2 py-1 text-xs font-bold"
          style={{
            fontFamily: '"JetBrains Mono", monospace',
            borderColor: `color-mix(in srgb, ${primary} 48%, transparent)`,
            backgroundColor: `color-mix(in srgb, ${primary} 14%, rgb(15 23 42))`,
            color: `color-mix(in srgb, ${primary} 82%, white)`,
            boxShadow: `0 0 12px color-mix(in srgb, ${primary} 18%, transparent)`,
          }}
        >
          {letter}
        </span>
        <p className="flex-1 text-sm leading-6 text-slate-100">{prompt}</p>
      </div>

      <div className="relative mt-3 flex flex-wrap gap-2">
        <FloatingGains open={showGain} amount={18} universeId={universeId} onDone={() => setShowGain(false)} />
        <button
          type="button"
          className="rounded-md border border-solid px-3 py-2 text-xs uppercase tracking-[0.15em]"
          style={{
            fontFamily: '"JetBrains Mono", monospace',
            borderColor: `color-mix(in srgb, ${primary} 42%, transparent)`,
            backgroundColor: `color-mix(in srgb, ${primary} 12%, rgb(15 23 42))`,
            color: `color-mix(in srgb, ${primary} 78%, white)`,
            boxShadow: `0 0 14px color-mix(in srgb, ${primary} 12%, transparent)`,
          }}
          onClick={() => {
            setOpen((value) => !value);
            setPhase(0);
          }}
        >
          {open ? t.ui.solutionClose : t.ui.solutionOpen}
        </button>
        <button
          type="button"
          className="rounded-md border border-solid px-3 py-2 text-xs uppercase tracking-[0.15em]"
          style={{
            fontFamily: '"JetBrains Mono", monospace',
            borderColor: `color-mix(in srgb, ${accent} 44%, transparent)`,
            backgroundColor: `color-mix(in srgb, ${accent} 12%, rgb(15 23 42))`,
            color: `color-mix(in srgb, ${accent} 76%, white)`,
            boxShadow: `0 0 14px color-mix(in srgb, ${accent} 12%, transparent)`,
          }}
          onClick={onToggleComplete}
        >
          {completed ? t.ui.markOpen : t.ui.markDone}
        </button>
      </div>

      <div
        className="grid overflow-hidden transition-[grid-template-rows] duration-300 ease-out"
        style={{ gridTemplateRows: open ? "1fr" : "0fr" }}
      >
        <div className="min-h-0">
          <div
            className="mt-4 space-y-3 border-t border-solid pt-4"
            style={{ borderTopColor: `color-mix(in srgb, ${primary} 22%, transparent)` }}
          >
            <LivePreview
              title={`Task ${letter} ${t.ui.taskPreview}`}
              sql={sql}
              columns={columns}
              rows={rows}
              querySuccessful={querySuccessful}
              universeId={universeId}
              radarMetrics={radarMetrics}
              successfulTasksCount={successfulTasksCount}
            />
            <div
              className="rounded-lg border border-solid bg-slate-900/70 p-3"
              style={{
                borderColor: `color-mix(in srgb, ${primary} 26%, transparent)`,
                boxShadow: `inset 0 0 20px color-mix(in srgb, ${primary} 6%, transparent)`,
              }}
            >
              <p
                className="mb-2 text-[10px] uppercase tracking-[0.18em]"
                style={{
                  fontFamily: '"JetBrains Mono", monospace',
                  color: `color-mix(in srgb, ${primary} 72%, white)`,
                }}
              >
                {t.ui.decodedExplanation}
              </p>
              <p
                className="text-sm leading-6 text-slate-200"
                style={{ fontFamily: '"JetBrains Mono", monospace' }}
              >
                {decodedExplanation}
              </p>
            </div>
          </div>
        </div>
      </div>
    </article>
  );
}
