export interface SkillTreeNode {
  id: string;
  label: string;
  /** Position in SVG viewBox 0–100 (x) und 0–56 (y) */
  x: number;
  y: number;
  /** Alle Parents müssen freigeschaltet sein */
  parents: readonly string[];
}

export const SKILL_TREE_NODES: readonly SkillTreeNode[] = [
  { id: "nexus-root", label: "Base Camp", x: 50, y: 10, parents: [] },
  { id: "nexus-html", label: "HTML/CSS", x: 26, y: 28, parents: ["nexus-root"] },
  { id: "nexus-ts", label: "TypeScript", x: 50, y: 28, parents: ["nexus-root"] },
  { id: "nexus-db", label: "SQL Core", x: 74, y: 28, parents: ["nexus-root"] },
  { id: "nexus-api", label: "API Design", x: 34, y: 42, parents: ["nexus-html", "nexus-ts"] },
  { id: "nexus-react", label: "React", x: 66, y: 42, parents: ["nexus-ts", "nexus-db"] },
  { id: "nexus-cap", label: "Capstone", x: 50, y: 49, parents: ["nexus-api", "nexus-react"] },
] as const;

export interface SkillTreeEdge {
  from: string;
  to: string;
}

export const SKILL_TREE_EDGES: readonly SkillTreeEdge[] = [
  { from: "nexus-root", to: "nexus-html" },
  { from: "nexus-root", to: "nexus-ts" },
  { from: "nexus-root", to: "nexus-db" },
  { from: "nexus-html", to: "nexus-api" },
  { from: "nexus-ts", to: "nexus-api" },
  { from: "nexus-ts", to: "nexus-react" },
  { from: "nexus-db", to: "nexus-react" },
  { from: "nexus-api", to: "nexus-cap" },
  { from: "nexus-react", to: "nexus-cap" },
] as const;

export function getNode(id: string): SkillTreeNode | undefined {
  return SKILL_TREE_NODES.find((n) => n.id === id);
}

export function canUnlockNode(nodeId: string, unlocked: readonly string[]): boolean {
  const node = getNode(nodeId);
  if (!node || unlocked.includes(nodeId)) return false;
  return node.parents.every((p) => unlocked.includes(p));
}
