import { AnimatePresence, motion } from "framer-motion";
import { SYNTHESIS_RECIPES } from "../../../data/synthesisRecipes";
import { useAppStore } from "../../../store/useAppStore";

function formatPercent(value: number): string {
  return `${Math.round(value * 100)}%`;
}

export function ArtifactCraftingPanel() {
  const inventory = useAppStore((s) => s.inventory);
  const getCraftableRecipes = useAppStore((s) => s.getCraftableRecipes);
  const craftArtifact = useAppStore((s) => s.craftArtifact);
  const activeCraftResult = useAppStore((s) => s.activeCraftResult);
  const dismissCraftResult = useAppStore((s) => s.dismissCraftResult);
  const craftableSet = new Set(getCraftableRecipes());

  return (
    <section className="rounded-2xl border border-cyan/30 bg-background-secondary/85 p-4 shadow-[0_0_32px_rgba(0,255,255,0.08)] sm:p-5">
      <div className="mb-4 flex items-center justify-between gap-3">
        <div>
          <p className="font-sans text-[11px] font-semibold uppercase tracking-[0.3em] text-cyan">Synthesis Workbench</p>
          <h3 className="font-display text-lg uppercase tracking-wide text-foreground sm:text-xl">Artifact Forge</h3>
        </div>
        <span className="rounded-md border border-magenta/40 bg-magenta/10 px-2 py-1 font-mono text-[11px] uppercase tracking-wide text-magenta">
          Inventory {inventory.length}
        </span>
      </div>

      <div className="space-y-3">
        {SYNTHESIS_RECIPES.map((recipe) => {
          const canCraft = craftableSet.has(recipe.id);
          return (
            <motion.div
              key={recipe.id}
              layout
              className="rounded-xl border border-foreground/15 bg-background/70 p-3"
              whileHover={{ scale: 1.01 }}
            >
              <div className="flex flex-wrap items-start justify-between gap-3">
                <div className="space-y-1">
                  <p className="font-display text-sm uppercase tracking-wide text-foreground">{recipe.name}</p>
                  <p className="font-mono text-[11px] uppercase tracking-wide text-foreground-muted">
                    {recipe.type} recipe {formatPercent(recipe.successRate)} success
                  </p>
                  <p className="font-sans text-xs text-foreground-muted">
                    Input {recipe.input.map((input) => `${input.amount}x ${input.itemId}`).join(" + ")}
                  </p>
                  <p className="font-sans text-xs text-cyan">
                    Output {recipe.output.amount}x {recipe.output.itemId}
                  </p>
                </div>
                <motion.button
                  type="button"
                  onClick={() => {
                    if (!canCraft) return;
                    craftArtifact(recipe.id);
                  }}
                  disabled={!canCraft}
                  className="rounded-md border border-cyan/40 bg-cyan/15 px-3 py-1.5 font-mono text-xs uppercase tracking-wide text-cyan transition hover:bg-cyan/25 disabled:cursor-not-allowed disabled:border-foreground/20 disabled:bg-foreground/10 disabled:text-foreground-muted"
                  whileTap={{ scale: 0.96 }}
                >
                  {canCraft ? "Synthesize" : "Missing materials"}
                </motion.button>
              </div>
            </motion.div>
          );
        })}
      </div>

      <AnimatePresence>
        {activeCraftResult ? (
          <motion.div
            key={activeCraftResult.id}
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 12 }}
            className={`mt-4 rounded-xl border p-3 ${
              activeCraftResult.success
                ? "border-cyan/40 bg-cyan/10 text-cyan"
                : "border-magenta/40 bg-magenta/10 text-magenta"
            }`}
          >
            <div className="flex items-start justify-between gap-3">
              <div className="space-y-1">
                <p className="font-display text-sm uppercase tracking-wide">
                  {activeCraftResult.success ? "Synthesis success" : "Synthesis failed"}
                </p>
                <p className="font-sans text-xs">
                  {activeCraftResult.success
                    ? `Output ${activeCraftResult.outputAmount}x ${activeCraftResult.outputItemId ?? "Unknown"}`
                    : "Materials consumed output lost in instability"}
                </p>
                <p className="font-mono text-[11px] uppercase tracking-wide opacity-85">
                  Roll {Math.round(activeCraftResult.roll * 1000) / 1000} threshold {formatPercent(activeCraftResult.successRate)}
                </p>
              </div>
              <button
                type="button"
                onClick={dismissCraftResult}
                className="rounded-md border border-current/40 px-2 py-1 font-mono text-[11px] uppercase tracking-wide"
              >
                Dismiss
              </button>
            </div>
          </motion.div>
        ) : null}
      </AnimatePresence>
    </section>
  );
}
