import { memo } from "react";

type PortfolioShowcaseProps = {
  universeLabel: string;
  universeIcon: string;
  primaryColor: string;
  accentColor: string;
  masteryPercent: number;
  solvedUnits: number;
  totalUnits: number;
  level: number;
  title: string;
  totalXp: number;
  streak: number;
  careerCompleted: number;
  radarMetrics?: Array<{ label: string; value: number }>;
};

function PortfolioShowcaseBase({
  universeLabel,
  universeIcon,
  primaryColor,
  accentColor,
  masteryPercent,
  solvedUnits,
  totalUnits,
  level,
  title,
  totalXp,
  streak,
  careerCompleted,
  radarMetrics = [],
}: PortfolioShowcaseProps) {
  return (
    <section
      className="relative overflow-hidden rounded-2xl border p-6 shadow-[0_0_45px_rgb(12_255_238_/_0.2)]"
      aria-readonly="true"
      data-showcase-mode="read-only"
      style={{
        borderColor: `${primaryColor}66`,
        background:
          `radial-gradient(circle at 15% 10%, ${accentColor}22, transparent 34%),` +
          `radial-gradient(circle at 85% 90%, ${primaryColor}20, transparent 38%),` +
          "#030712",
      }}
    >
      <div className="pointer-events-none absolute inset-0 bg-[linear-gradient(to_bottom,transparent_0%,rgba(255,255,255,0.03)_50%,transparent_100%)] bg-[length:100%_5px] opacity-60" />
      <div className="relative">
        <p className="text-[10px] uppercase tracking-[0.18em]" style={{ color: primaryColor }}>
          Public Portfolio Link
        </p>
        <h3 className="mt-2 text-2xl font-semibold text-cyan-50">
          {universeIcon} {universeLabel} Portfolio Showcase
        </h3>
        <p className="mt-2 text-sm text-slate-200">Read only achievements view for recruiters and collaborators</p>

        <div className="mt-5 grid grid-cols-2 gap-3 text-[11px] sm:grid-cols-4">
          <div className="rounded-lg border bg-slate-900/60 px-3 py-2" style={{ borderColor: `${primaryColor}44` }}>
            <p className="uppercase tracking-[0.12em]" style={{ color: primaryColor }}>
              Mastery
            </p>
            <p className="mt-1 text-base font-semibold text-cyan-100">{masteryPercent}%</p>
          </div>
          <div className="rounded-lg border bg-slate-900/60 px-3 py-2" style={{ borderColor: `${primaryColor}44` }}>
            <p className="uppercase tracking-[0.12em]" style={{ color: primaryColor }}>
              Solved Units
            </p>
            <p className="mt-1 text-base font-semibold text-cyan-100">
              {solvedUnits}/{totalUnits}
            </p>
          </div>
          <div className="rounded-lg border bg-slate-900/60 px-3 py-2" style={{ borderColor: `${primaryColor}44` }}>
            <p className="uppercase tracking-[0.12em]" style={{ color: primaryColor }}>
              Level
            </p>
            <p className="mt-1 text-base font-semibold text-cyan-100">{level}</p>
          </div>
          <div className="rounded-lg border bg-slate-900/60 px-3 py-2" style={{ borderColor: `${primaryColor}44` }}>
            <p className="uppercase tracking-[0.12em]" style={{ color: primaryColor }}>
              Career Tickets
            </p>
            <p className="mt-1 text-base font-semibold text-cyan-100">{careerCompleted}</p>
          </div>
        </div>

        <div className="mt-4 rounded-lg border bg-slate-900/65 p-3" style={{ borderColor: `${accentColor}66` }}>
          <p className="text-[10px] uppercase tracking-[0.14em]" style={{ color: accentColor }}>
            Professional Signal
          </p>
          <p className="mt-1 text-xs text-slate-100">Title {title}</p>
          <p className="mt-1 text-xs text-slate-200">Total XP {totalXp} | Daily Streak {streak}</p>
        </div>

        {radarMetrics.length > 0 ? (
          <div className="mt-4 rounded-lg border bg-slate-900/65 p-3" style={{ borderColor: `${primaryColor}66` }}>
            <p className="text-[10px] uppercase tracking-[0.14em]" style={{ color: primaryColor }}>
              Read Only Radar Hover
            </p>
            <div className="mt-2 grid grid-cols-2 gap-2 sm:grid-cols-4">
              {radarMetrics.map((metric) => (
                <div
                  key={metric.label}
                  title={`${metric.label} ${Math.round(metric.value)} percent`}
                  className="group rounded-md border px-2 py-2"
                  style={{ borderColor: `${primaryColor}44` }}
                >
                  <p className="text-[10px] uppercase tracking-[0.12em] text-slate-300">{metric.label}</p>
                  <div className="mt-1 h-1.5 w-full overflow-hidden rounded-full bg-slate-800">
                    <div
                      className="h-full transition-[width,filter] duration-300 group-hover:brightness-125"
                      style={{ width: `${Math.max(0, Math.min(100, metric.value))}%`, background: `linear-gradient(90deg, ${primaryColor}, ${accentColor})` }}
                    />
                  </div>
                  <p className="mt-1 text-[10px] text-cyan-100">{Math.round(metric.value)}%</p>
                </div>
              ))}
            </div>
          </div>
        ) : null}
      </div>
    </section>
  );
}

export const PortfolioShowcase = memo(PortfolioShowcaseBase);
