/**
 * Canonical site origin for auth email links and redirects.
 * Set `VITE_SITE_URL` on Netlify to `https://itcodesnap.netlify.app` (no trailing slash).
 * Falls back to `window.location.origin` when unset (local dev).
 */
export function getSiteUrl(): string {
  const fromEnv = (import.meta.env.VITE_SITE_URL as string | undefined)?.trim();
  if (fromEnv) return fromEnv.replace(/\/+$/, "");
  if (typeof window !== "undefined") return window.location.origin;
  return "";
}

export function getAuthEmailRedirectUrl(): string {
  const base = getSiteUrl();
  return base ? `${base}/` : "/";
}
