import type { ArenaQuestion } from "./questionContent";
import {
  aggregateExamDomains,
  inferRepairTargetFromBucket,
  mapQuestionToRadarBucket,
  type ExamRadarBucket,
  type ExamRepairTarget,
} from "./mockExamAnalysis";

const BUCKET_ORDER: ExamRadarBucket[] = ["sql", "netz", "wiso", "it_core"];

const DOMAIN_LABEL_DE: Record<ExamRadarBucket, string> = {
  sql: "SQL",
  netz: "Netzwerk",
  wiso: "WISO",
  it_core: "IT Kern",
};

const DOMAIN_GAP_TITLE_DE: Record<ExamRadarBucket, string> = {
  sql: "SQL Performance heben",
  netz: "Netzwerk Themen schärfen",
  wiso: "WISO Grundlagen vertiefen",
  it_core: "IT Kernkompetenz ausbauen",
};

export type MockExamSnapshotForPlan = {
  questionSet: readonly ArenaQuestion[];
  answers: readonly (number | null)[];
  flagged: readonly boolean[] | undefined;
  finishedAtMs: number;
};

export type TrainingPlanTaskSource = "domain_gap" | "flagged_wrong";

export type TrainingPlanTaskV1 = {
  rank: number;
  title: string;
  subtitle: string;
  repairTarget: ExamRepairTarget;
  source: TrainingPlanTaskSource;
  domainBucket?: ExamRadarBucket;
  questionId?: string;
};

export type TrainingPlanV1 = {
  v: 1;
  generatedAtMs: number;
  basedOnExamFinishedAtMs: number;
  tasks: TrainingPlanTaskV1[];
};

function domainPercent(stats: ReturnType<typeof aggregateExamDomains>, bucket: ExamRadarBucket): number {
  const s = stats[bucket];
  if (s.total <= 0) return 100;
  return (s.correct / s.total) * 100;
}

function isRepairTarget(x: string): x is ExamRepairTarget {
  return x === "sql_academy" || x === "helpdesk" || x === "flashcards" || x === "vault";
}

function isRadarBucket(x: string): x is ExamRadarBucket {
  return x === "sql" || x === "netz" || x === "wiso" || x === "it_core";
}

function isTaskSource(x: string): x is TrainingPlanTaskSource {
  return x === "domain_gap" || x === "flagged_wrong";
}

export function normalizeTrainingPlan(raw: unknown): TrainingPlanV1 | null {
  if (raw === null || raw === undefined) return null;
  if (typeof raw !== "object") return null;
  const o = raw as Record<string, unknown>;
  if (o.v !== 1) return null;
  if (typeof o.generatedAtMs !== "number" || typeof o.basedOnExamFinishedAtMs !== "number") return null;
  if (!Array.isArray(o.tasks)) return null;
  const tasks: TrainingPlanTaskV1[] = [];
  for (const row of o.tasks) {
    if (typeof row !== "object" || row === null) return null;
    const t = row as Record<string, unknown>;
    if (typeof t.rank !== "number" || typeof t.title !== "string" || typeof t.subtitle !== "string") return null;
    if (typeof t.repairTarget !== "string" || !isRepairTarget(t.repairTarget)) return null;
    if (typeof t.source !== "string" || !isTaskSource(t.source)) return null;
    let domainBucket: ExamRadarBucket | undefined;
    if (t.domainBucket !== undefined) {
      if (typeof t.domainBucket !== "string" || !isRadarBucket(t.domainBucket)) return null;
      domainBucket = t.domainBucket;
    }
    const questionId = t.questionId === undefined ? undefined : typeof t.questionId === "string" ? t.questionId : undefined;
    tasks.push({
      rank: t.rank,
      title: t.title,
      subtitle: t.subtitle,
      repairTarget: t.repairTarget,
      source: t.source,
      domainBucket,
      questionId,
    });
  }
  return {
    v: 1,
    generatedAtMs: o.generatedAtMs,
    basedOnExamFinishedAtMs: o.basedOnExamFinishedAtMs,
    tasks,
  };
}

type PlanTaskDraft = Omit<TrainingPlanTaskV1, "rank">;

export function buildTrainingPlanFromMockExam(snapshot: MockExamSnapshotForPlan): TrainingPlanV1 | null {
  const stats = aggregateExamDomains(snapshot.questionSet, snapshot.answers);

  const weakBuckets = BUCKET_ORDER.filter((b) => {
    const s = stats[b];
    if (s.total <= 0) return false;
    return domainPercent(stats, b) < 50;
  }).sort((a, b) => domainPercent(stats, a) - domainPercent(stats, b));

  const weakTasks: PlanTaskDraft[] = weakBuckets.map((bucket) => ({
    title: DOMAIN_GAP_TITLE_DE[bucket],
    subtitle: `Trefferquote unter 50% in ${DOMAIN_LABEL_DE[bucket]}`,
    repairTarget: inferRepairTargetFromBucket(bucket),
    source: "domain_gap",
    domainBucket: bucket,
  }));

  const flagged = snapshot.flagged ?? [];
  const flaggedWrongIndices: number[] = [];
  for (let i = 0; i < snapshot.questionSet.length; i++) {
    if (!flagged[i]) continue;
    const ans = snapshot.answers[i];
    const q = snapshot.questionSet[i];
    if (ans === null || ans === undefined) continue;
    if (ans === q.correctIndex) continue;
    flaggedWrongIndices.push(i);
  }

  flaggedWrongIndices.sort((i, j) => {
    const bi = mapQuestionToRadarBucket(snapshot.questionSet[i]);
    const bj = mapQuestionToRadarBucket(snapshot.questionSet[j]);
    return domainPercent(stats, bi) - domainPercent(stats, bj);
  });

  const flaggedTasks: PlanTaskDraft[] = flaggedWrongIndices.map((i) => {
    const q = snapshot.questionSet[i];
    const bucket = mapQuestionToRadarBucket(q);
    const raw = q.prompt.replace(/\s+/g, " ").trim();
    const subtitle = raw.length > 80 ? `${raw.slice(0, 80)}…` : raw;
    return {
      title: "Markierte Frage nacharbeiten",
      subtitle,
      repairTarget: inferRepairTargetFromBucket(bucket),
      source: "flagged_wrong",
      domainBucket: bucket,
      questionId: q.id,
    };
  });

  const merged: PlanTaskDraft[] = [...weakTasks, ...flaggedTasks];
  const seenQuestion = new Set<string>();
  const deduped: PlanTaskDraft[] = [];
  for (const t of merged) {
    if (t.source === "flagged_wrong" && t.questionId) {
      if (seenQuestion.has(t.questionId)) continue;
      seenQuestion.add(t.questionId);
    }
    deduped.push(t);
  }

  const top = deduped.slice(0, 3);
  if (top.length === 0) return null;

  const tasks: TrainingPlanTaskV1[] = top.map((t, idx) => ({ ...t, rank: idx + 1 }));

  return {
    v: 1,
    generatedAtMs: Date.now(),
    basedOnExamFinishedAtMs: snapshot.finishedAtMs,
    tasks,
  };
}
