import { motion, useReducedMotion } from "framer-motion";
import { cn } from "../../lib/cn";
import type { SeasonLegacyArtifact } from "../../store/useAppStore";

type SeasonLegacyBadgeProps = {
  artifact: SeasonLegacyArtifact;
};

const RANK_META: Record<1 | 2 | 3, { title: string; frame: string; orb: string; txt: string }> = {
  1: {
    title: "Apex Gold",
    frame:
      "border-amber-300/45 bg-[linear-gradient(160deg,rgba(251,191,36,0.3),rgba(255,215,128,0.12),rgba(120,80,10,0.25))] shadow-[inset_0_0_26px_rgba(251,191,36,0.28),0_0_24px_rgba(251,191,36,0.18)]",
    orb: "from-amber-200/45 via-amber-300/5 to-transparent",
    txt: "text-amber-100",
  },
  2: {
    title: "Vault Silver",
    frame:
      "border-slate-300/35 bg-[linear-gradient(160deg,rgba(203,213,225,0.28),rgba(248,250,252,0.06),rgba(71,85,105,0.24))] shadow-[inset_0_0_22px_rgba(203,213,225,0.2),0_0_18px_rgba(203,213,225,0.12)]",
    orb: "from-slate-200/30 via-slate-200/5 to-transparent",
    txt: "text-slate-100",
  },
  3: {
    title: "Iron Bronze",
    frame:
      "border-orange-300/30 bg-[linear-gradient(160deg,rgba(251,146,60,0.24),rgba(255,237,213,0.05),rgba(124,45,18,0.22))] shadow-[inset_0_0_18px_rgba(251,146,60,0.18),0_0_14px_rgba(251,146,60,0.1)]",
    orb: "from-orange-200/28 via-orange-200/5 to-transparent",
    txt: "text-orange-100",
  },
};

export function SeasonLegacyBadge({ artifact }: SeasonLegacyBadgeProps) {
  const prefersReduced = useReducedMotion();
  const meta = RANK_META[artifact.rank];
  const factionTone =
    artifact.winnerFaction === "FISI"
      ? "text-signal"
      : artifact.winnerFaction === "FIAE"
        ? "text-fuchsia-300"
        : "text-foreground-muted";

  return (
    <motion.article
      layout
      whileHover={prefersReduced ? undefined : { y: -2 }}
      transition={{ type: "spring", stiffness: 340, damping: 28 }}
      className={cn("group relative aspect-square overflow-hidden border p-3", meta.frame)}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
      <div className="pointer-events-none absolute inset-0 scanlines opacity-[0.14]" />

      {!prefersReduced && artifact.rank === 1 ? (
        <motion.div
          aria-hidden
          className="pointer-events-none absolute inset-[-22%] rounded-full border border-amber-200/28"
          animate={{ rotate: 360 }}
          transition={{ duration: 9.5, ease: "linear", repeat: Infinity }}
        />
      ) : null}

      <div className="relative z-10 flex h-full flex-col justify-between">
        <div className="space-y-1">
          <p className={cn("font-mono text-[9px] font-bold uppercase tracking-[0.2em]", meta.txt)}>
            Legacy {artifact.rank}
          </p>
          <p className="font-mono text-[9px] uppercase tracking-[0.15em] text-foreground-muted">{meta.title}</p>
        </div>

        <div className="space-y-1">
          <p className="truncate font-sans text-sm font-semibold text-foreground">{artifact.label}</p>
          <p className={cn("font-mono text-[10px] uppercase tracking-[0.18em]", factionTone)}>
            Sieger {artifact.winnerFaction}
          </p>
        </div>
      </div>

      <div className="pointer-events-none absolute inset-0 z-20 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
        <div className={cn("absolute inset-0 bg-gradient-to-br", meta.orb)} />
        <div className="absolute inset-x-2 bottom-2 border border-white/[0.16] bg-black/78 px-2 py-1">
          <p className="truncate font-mono text-[9px] uppercase tracking-[0.14em] text-foreground">
            {artifact.label}
          </p>
          <p className={cn("mt-0.5 font-mono text-[9px] uppercase tracking-[0.16em]", factionTone)}>
            Fraktion {artifact.winnerFaction}
          </p>
        </div>
      </div>
    </motion.article>
  );
}
