import { useEffect } from "react";
import type { SqlUniverseId } from "../../../../data/universes";

type AchievementToastProps = {
  open: boolean;
  label: string;
  universeId: SqlUniverseId;
  onDone: () => void;
};

const ICON_BY_UNIVERSE: Record<SqlUniverseId, string> = {
  bodybuilding: "🏋",
  star_wars: "⚔",
  anime: "✦",
  nutrition: "🥗",
  cs_tactical: "🎯",
  warzone: "🛡",
  wow: "⚚",
};

export function AchievementToast({ open, label, universeId, onDone }: AchievementToastProps) {
  useEffect(() => {
    if (!open) return;
    const timer = window.setTimeout(onDone, 2600);
    return () => window.clearTimeout(timer);
  }, [open, onDone]);

  if (!open) return null;
  const legendary = /legendary/i.test(label);

  return (
    <div
      className={`pointer-events-none fixed bottom-6 right-6 z-[575] max-w-sm rounded-lg px-4 py-3 ${
        legendary
          ? "border border-amber-300/70 bg-slate-950/94 shadow-[0_0_26px_rgb(255_196_87_/_0.35)]"
          : "border border-cyan-300/55 bg-slate-950/92 shadow-[0_0_22px_rgb(0_229_255_/_0.22)]"
      }`}
    >
      <p className={`text-[10px] uppercase tracking-[0.14em] ${legendary ? "text-amber-200" : "text-cyan-300"}`}>Achievement</p>
      <p className={`mt-1 text-sm font-semibold ${legendary ? "text-amber-100" : "text-cyan-100"}`}>
        {ICON_BY_UNIVERSE[universeId]} {label}
      </p>
    </div>
  );
}
