import { useEffect, useMemo, useState } from "react";
import { useTranslation } from "../../../../i18n/useTranslation";

type MentorTourProps = {
  open: boolean;
  onDone: () => void;
};

export function MentorTour({ open, onDone }: MentorTourProps) {
  const [stepIndex, setStepIndex] = useState(0);
  const t = useTranslation();
  const steps = [
    { id: "mentor-step-1", targetId: "academy-diagram-engine", ...t.ui.mentorSteps[0] },
    { id: "mentor-step-2", targetId: "academy-sql-editor", ...t.ui.mentorSteps[1] },
    { id: "mentor-step-3", targetId: "academy-xp-dashboard", ...t.ui.mentorSteps[2] },
  ];

  useEffect(() => {
    if (!open) return;
    setStepIndex(0);
  }, [open]);

  const step = useMemo(() => steps[stepIndex] ?? steps[0], [stepIndex, steps]);

  useEffect(() => {
    if (!open) return;
    const el = document.getElementById(step.targetId);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  }, [open, step.targetId]);

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-[600] bg-black/70 p-4">
      <div className="mx-auto mt-24 w-full max-w-md rounded-xl border border-cyan-300/50 bg-slate-950/95 p-5">
        <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-300">{t.ui.mentorTour}</p>
        <h4 className="mt-2 text-lg font-semibold text-cyan-100">{step.title}</h4>
        <p className="mt-2 text-sm text-slate-200">{step.body}</p>
        <p className="mt-2 text-[10px] uppercase tracking-[0.16em] text-cyan-300">
          {t.ui.mentorStep} {stepIndex + 1} {t.ui.mentorOf} {steps.length}
        </p>
        <div className="mt-4 flex flex-wrap gap-2">
          <button
            type="button"
            className="rounded-md border border-slate-500/60 bg-slate-900/70 px-3 py-1.5 text-xs font-semibold uppercase tracking-[0.14em] text-slate-200"
            onClick={() => setStepIndex((v) => Math.max(0, v - 1))}
            disabled={stepIndex === 0}
          >
            {t.ui.mentorBack}
          </button>
          {stepIndex < steps.length - 1 ? (
            <button
              type="button"
              className="rounded-md border border-cyan-300/60 bg-cyan-950/35 px-3 py-1.5 text-xs font-semibold uppercase tracking-[0.14em] text-cyan-100"
              onClick={() => setStepIndex((v) => Math.min(steps.length - 1, v + 1))}
            >
              {t.ui.mentorNext}
            </button>
          ) : (
            <button
              type="button"
              className="rounded-md border border-emerald-300/60 bg-emerald-950/35 px-3 py-1.5 text-xs font-semibold uppercase tracking-[0.14em] text-emerald-100"
              onClick={onDone}
            >
              {t.ui.mentorStartTraining}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
