import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import type { SyndicateTechNodeId } from "../../data/techTreeNodes";
import type { SyndicateOverview } from "../../lib/syncController";
import { TechGridMap } from "./TechGridMap";

export function SyndicatePanel() {
  const prefersReduced = !!useReducedMotion();
  const [busy, setBusy] = useState(false);
  const [createBusy, setCreateBusy] = useState(false);
  const [joinBusy, setJoinBusy] = useState(false);
  const [unlockBusyId, setUnlockBusyId] = useState<SyndicateTechNodeId | null>(null);
  const [nameDraft, setNameDraft] = useState("");
  const [inviteDraft, setInviteDraft] = useState("");
  const [errorLine, setErrorLine] = useState<string | null>(null);
  const [row, setRow] = useState<SyndicateOverview | null>(null);

  const progressPct = useMemo(() => {
    if (!row) return 0;
    return Math.max(0, Math.min(100, Math.round((row.vaultXp / Math.max(1, row.nextThresholdXp)) * 100)));
  }, [row]);

  const refresh = () => {
    setBusy(true);
    setErrorLine(null);
    void import("../../lib/syncController")
      .then((m) => m.fetchMySyndicateOverview())
      .then((next) => setRow(next))
      .catch(() => setErrorLine("Syndicate uplink nicht erreichbar"))
      .finally(() => setBusy(false));
  };

  useEffect(() => {
    refresh();
  }, []);

  return (
    <section className="relative overflow-hidden rounded-3xl border border-lime-300/35 bg-gradient-to-br from-lime-500/[0.1] via-black/45 to-cyan-500/[0.08] p-5 ring-1 ring-lime-200/20">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.16]" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex items-end justify-between gap-3">
          <div>
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-lime-100/92">
              Syndicate Nodes
            </p>
            <h3 className="font-display text-xl font-bold uppercase tracking-wide text-lime-50">
              Encrypted Cell Grid
            </h3>
          </div>
          <button
            type="button"
            onClick={refresh}
            className="border border-lime-200/35 bg-lime-500/[0.16] px-2.5 py-1 font-mono text-[9px] uppercase tracking-[0.16em] text-lime-100 hover:bg-lime-500/[0.24]"
          >
            Refresh
          </button>
        </div>

        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-lime-100/88">Syndicate uplink synchronisiert</p>
        ) : row ? (
          <div className="space-y-3">
            <div className="border border-lime-200/25 bg-black/35 p-3">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.18em] text-lime-50">{row.name}</p>
                <span className="border border-cyan-300/35 bg-cyan-500/[0.16] px-2 py-0.5 font-mono text-[9px] uppercase tracking-[0.14em] text-cyan-100">
                  Invite {row.inviteCode}
                </span>
              </div>
              <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.14em] text-lime-100/85">
                Tier {row.ascensionTier} Vault {row.vaultXp}/{row.nextThresholdXp} Role {row.myRole}
              </p>
              <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.14em] text-cyan-100/85">{row.activeBuff}</p>
              <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.14em] text-fuchsia-100/85">{row.missionLine}</p>
              <div className="mt-2 h-2 overflow-hidden border border-lime-300/30 bg-black/60">
                <motion.div
                  className="h-full bg-gradient-to-r from-lime-300 via-cyan-300 to-lime-200"
                  animate={{ width: `${progressPct}%` }}
                  transition={{ duration: prefersReduced ? 0 : 0.3, ease: "easeOut" }}
                />
              </div>
            </div>
            <TechGridMap
              unlockedNodeIds={row.unlockedNodeIds}
              vaultXp={row.vaultXp}
              myRole={row.myRole}
              unlockBusyId={unlockBusyId}
              onUnlock={(nodeId) => {
                if (unlockBusyId) return;
                setUnlockBusyId(nodeId);
                setErrorLine(null);
                void import("../../lib/syncController")
                  .then((m) => m.unlockSyndicateTechNode(nodeId))
                  .then((res) => {
                    if (!res.ok) {
                      setErrorLine(res.error ?? "Tech Link blockiert");
                      return;
                    }
                    refresh();
                  })
                  .finally(() => setUnlockBusyId(null));
              }}
            />

            <div className="space-y-1">
              {row.members.map((member, idx) => (
                <div
                  key={`${member.userId}-${idx}`}
                  className="grid grid-cols-[1fr_auto] items-center gap-2 border border-white/[0.1] bg-black/30 px-3 py-2"
                >
                  <p className="truncate font-mono text-[9px] uppercase tracking-[0.13em] text-lime-100">
                    {member.handle} {member.role} XP {member.contributionXp}
                  </p>
                  <span className="font-mono text-[8px] uppercase tracking-[0.12em] text-cyan-100/85">
                    {new Date(member.joinedAt).toLocaleDateString("de-DE")}
                  </span>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-lime-100/88">
              Kein aktives Syndicate verbunden
            </p>
            <div className="grid gap-2 md:grid-cols-2">
              <div className="space-y-2 border border-lime-200/20 bg-black/30 p-3">
                <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-lime-100/90">Cell gründen</p>
                <input
                  value={nameDraft}
                  onChange={(event) => setNameDraft(event.target.value)}
                  placeholder="Tech Name optional"
                  className="w-full border border-lime-200/30 bg-black/45 px-2 py-1.5 font-mono text-[10px] uppercase tracking-[0.12em] text-lime-50 outline-none placeholder:text-lime-200/40"
                />
                <button
                  type="button"
                  disabled={createBusy}
                  onClick={() => {
                    setCreateBusy(true);
                    setErrorLine(null);
                    void import("../../lib/syncController")
                      .then((m) => m.createSyndicate(nameDraft))
                      .then((res) => {
                        if (!res.ok) {
                          setErrorLine(res.error ?? "Syndicate konnte nicht erstellt werden");
                          return;
                        }
                        setNameDraft("");
                        refresh();
                      })
                      .finally(() => setCreateBusy(false));
                  }}
                  className="border border-lime-300/40 bg-lime-500/[0.18] px-3 py-1.5 font-mono text-[9px] font-bold uppercase tracking-[0.14em] text-lime-100 hover:bg-lime-500/[0.28]"
                >
                  {createBusy ? "Linking" : "Create Syndicate"}
                </button>
              </div>

              <div className="space-y-2 border border-cyan-200/20 bg-black/30 p-3">
                <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-cyan-100/90">Cell joinen</p>
                <input
                  value={inviteDraft}
                  onChange={(event) => setInviteDraft(event.target.value.toUpperCase())}
                  placeholder="Invite Code"
                  className="w-full border border-cyan-200/30 bg-black/45 px-2 py-1.5 font-mono text-[10px] uppercase tracking-[0.14em] text-cyan-50 outline-none placeholder:text-cyan-200/40"
                />
                <button
                  type="button"
                  disabled={joinBusy}
                  onClick={() => {
                    setJoinBusy(true);
                    setErrorLine(null);
                    void import("../../lib/syncController")
                      .then((m) => m.joinSyndicateByInviteCode(inviteDraft))
                      .then((res) => {
                        if (!res.ok) {
                          setErrorLine(res.error ?? "Invite Link blockiert");
                          return;
                        }
                        setInviteDraft("");
                        refresh();
                      })
                      .finally(() => setJoinBusy(false));
                  }}
                  className="border border-cyan-300/40 bg-cyan-500/[0.18] px-3 py-1.5 font-mono text-[9px] font-bold uppercase tracking-[0.14em] text-cyan-100 hover:bg-cyan-500/[0.28]"
                >
                  {joinBusy ? "Linking" : "Join Syndicate"}
                </button>
              </div>
            </div>
          </div>
        )}

        {errorLine ? (
          <p className="font-mono text-[9px] uppercase tracking-[0.14em] text-red-200">{errorLine}</p>
        ) : null}
      </div>
    </section>
  );
}
