import { useMemo, useState } from "react";
import type { SqlChapter } from "../../../../data/sqlAcademyContent";
import type { SqlUniverseBlueprintSeed, SqlUniverseId } from "../../../../data/universes";
import { UNIVERSE_THEMES } from "../../../../styles/themes/universeThemes";
import { DBSFlow } from "../diagrams/DBSFlow";
import { FilterLogic } from "../diagrams/FilterLogic";
import { TableAnatomy } from "../diagrams/TableAnatomy";

type DiagramEngineProps = {
  chapter: SqlChapter;
  universeSeed: SqlUniverseBlueprintSeed;
  universeId: SqlUniverseId;
};

type Link = { from: string; to: string; by: string };

function inferLinks(universeSeed: SqlUniverseBlueprintSeed): Link[] {
  const tableNames = universeSeed.tables.map((t) => t.tableName);
  const links: Link[] = [];
  for (const table of universeSeed.tables) {
    for (const col of table.columns) {
      if (!col.name.endsWith("_id")) continue;
      const base = col.name.replace(/_id$/, "");
      const candidates = [base, `${base}e`, `${base}en`, `${base}s`];
      const to = tableNames.find((name) => candidates.includes(name));
      if (!to) continue;
      links.push({ from: table.tableName, to, by: col.name });
    }
  }
  return links;
}

export function DiagramEngine({ chapter, universeSeed, universeId }: DiagramEngineProps) {
  const [mode, setMode] = useState<"single" | "map">("single");
  const theme = UNIVERSE_THEMES[universeId];
  const links = useMemo(() => inferLinks(universeSeed), [universeSeed]);

  const mapWidth = 760;
  const mapHeight = 220;
  const step = Math.max(1, universeSeed.tables.length);

  return (
    <div className="mt-4 rounded-xl border border-cyan-500/30 bg-slate-950/65 p-3">
      <div className="mb-3 inline-flex items-center gap-2 rounded-md border border-cyan-400/30 bg-slate-900/70 p-1">
        <button
          type="button"
          className={`rounded px-2 py-1 text-[10px] uppercase tracking-[0.14em] ${mode === "single" ? "bg-cyan-300 text-slate-950" : "text-cyan-200"}`}
          onClick={() => setMode("single")}
        >
          Table View
        </button>
        <button
          type="button"
          className={`rounded px-2 py-1 text-[10px] uppercase tracking-[0.14em] ${mode === "map" ? "bg-cyan-300 text-slate-950" : "text-cyan-200"}`}
          onClick={() => setMode("map")}
        >
          Universe Map
        </button>
      </div>

      {mode === "single" ? (
        <div className="grid gap-4 md:grid-cols-3">
          {chapter.conceptCards.some((card) => card.diagram === "dbs-flow") ? <DBSFlow /> : null}
          {chapter.conceptCards.some((card) => card.diagram === "table-anatomy") ? <TableAnatomy /> : null}
          {chapter.conceptCards.some((card) => card.diagram === "filter-logic") ? <FilterLogic /> : null}
        </div>
      ) : (
        <svg viewBox={`0 0 ${mapWidth} ${mapHeight}`} className="academy-diagram" role="img" aria-label="Universe map mit Tabellenbeziehungen">
          <rect x="8" y="8" width={mapWidth - 16} height={mapHeight - 16} rx="12" fill="#070f18" stroke={theme.primary} strokeOpacity="0.45" />
          {universeSeed.tables.map((table, index) => {
            const x = 30 + (index * (mapWidth - 60)) / step;
            const y = 110 + (index % 2 === 0 ? -32 : 20);
            return (
              <g key={table.tableName}>
                <rect x={x} y={y} width="148" height="54" rx="8" fill="#0b1522" stroke={theme.accent} strokeOpacity="0.7" />
                <text x={x + 10} y={y + 20} fill={theme.primary} fontSize="11" fontFamily="JetBrains Mono, monospace">
                  {table.tableName}
                </text>
                <text x={x + 10} y={y + 38} fill="#b6e7ff" fontSize="9" fontFamily="JetBrains Mono, monospace">
                  {table.columns.length} cols
                </text>
              </g>
            );
          })}
          {links.map((link, idx) => {
            const fromIndex = universeSeed.tables.findIndex((t) => t.tableName === link.from);
            const toIndex = universeSeed.tables.findIndex((t) => t.tableName === link.to);
            if (fromIndex < 0 || toIndex < 0) return null;
            const x1 = 30 + (fromIndex * (mapWidth - 60)) / step + 148;
            const y1 = 110 + (fromIndex % 2 === 0 ? -5 : 47);
            const x2 = 30 + (toIndex * (mapWidth - 60)) / step;
            const y2 = 110 + (toIndex % 2 === 0 ? -5 : 47);
            return (
              <g key={`${link.from}-${link.to}-${idx}`}>
                <line x1={x1} y1={y1} x2={x2} y2={y2} stroke={theme.primary} strokeWidth="2" strokeOpacity="0.75" />
                <text x={(x1 + x2) / 2} y={(y1 + y2) / 2 - 4} fill={theme.accent} fontSize="8" fontFamily="JetBrains Mono, monospace">
                  {link.by}
                </text>
              </g>
            );
          })}
        </svg>
      )}
    </div>
  );
}
