import { motion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { getRealtimeIntegritySnapshot } from "../../lib/syncController";
import { getAudioRuntimeHealth } from "../../lib/webAudioUi";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

type LedState = "ok" | "warn" | "error";

function ledClass(state: LedState): string {
  if (state === "ok") return "bg-cyan-300 shadow-[0_0_10px_rgba(34,211,238,0.6)]";
  if (state === "warn") return "bg-amber-300 shadow-[0_0_10px_rgba(252,211,77,0.55)]";
  return "bg-rose-400 shadow-[0_0_10px_rgba(251,113,133,0.55)]";
}

function textClass(state: LedState): string {
  if (state === "ok") return "text-cyan-200";
  if (state === "warn") return "text-amber-200";
  return "text-rose-300";
}

export function SystemReadinessChip() {
  const syncStatus = useAppStore((s) => s.syncStatus);
  const swNeedRefresh = useAppStore((s) => s.swNeedRefresh);
  const feedbackEnabled = useAppStore((s) => s.feedbackEnabled);
  const [tick, setTick] = useState(0);
  const [hovered, setHovered] = useState(false);

  useEffect(() => {
    const id = window.setInterval(() => setTick((n) => n + 1), 2200);
    return () => window.clearInterval(id);
  }, []);

  const checks = useMemo(() => {
    void tick;
    const rt = getRealtimeIntegritySnapshot();
    const audio = getAudioRuntimeHealth();

    const sync: LedState =
      syncStatus === "cloud-synced" ? "ok" : syncStatus === "cloud-outdated" ? "warn" : "error";

    const realtime: LedState =
      rt.pulse === "subscribed" && rt.faction === "subscribed"
        ? "ok"
        : rt.pulse === "error" || rt.faction === "error" || rt.arena === "error"
          ? "error"
          : "warn";

    const audioState: LedState =
      !feedbackEnabled
        ? "warn"
        : audio.contextState === "running" && audio.masterReady
          ? "ok"
          : audio.contextState === "suspended" && audio.masterReady
            ? "warn"
            : "error";

    const sw: LedState = swNeedRefresh ? "warn" : "ok";

    const values = [sync, realtime, audioState, sw];
    const overall: LedState = values.includes("error")
      ? "error"
      : values.includes("warn")
        ? "warn"
        : "ok";

    return { sync, realtime, audio: audioState, sw, overall };
  }, [feedbackEnabled, swNeedRefresh, syncStatus, tick]);

  return (
    <div className="relative" onPointerEnter={() => setHovered(true)} onPointerLeave={() => setHovered(false)}>
      <div className="inline-flex items-center gap-2 border border-white/[0.1] bg-white/[0.02] px-2.5 py-1.5">
        <span className="font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
          Readiness
        </span>
        <motion.span
          aria-hidden
          className={cn("size-1.5 rounded-full", ledClass(checks.overall))}
          animate={{ opacity: [0.55, 1, 0.55] }}
          transition={{ duration: 1.9, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>
      {hovered ? (
        <motion.div
          initial={{ opacity: 0, y: 3 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.16, ease: [0.16, 1, 0.3, 1] }}
          className="absolute right-0 top-full z-20 mt-1.5 min-w-[11rem] border border-white/[0.12] bg-black/88 px-2.5 py-2 font-mono text-[9px] uppercase tracking-[0.14em] text-foreground-muted"
        >
          <p className="mb-1 text-foreground">System Checks</p>
          <div className="space-y-1">
            <p className="flex items-center justify-between gap-3"><span>Sync</span><span className={textClass(checks.sync)}>{checks.sync}</span></p>
            <p className="flex items-center justify-between gap-3"><span>Realtime</span><span className={textClass(checks.realtime)}>{checks.realtime}</span></p>
            <p className="flex items-center justify-between gap-3"><span>Audio</span><span className={textClass(checks.audio)}>{checks.audio}</span></p>
            <p className="flex items-center justify-between gap-3"><span>Patch</span><span className={textClass(checks.sw)}>{checks.sw}</span></p>
          </div>
        </motion.div>
      ) : null}
    </div>
  );
}
