import { getSupabase } from "../supabase";
import {
  applyVaultStorageToLocalStorage,
  buildWrappedVaultPayloadForCloud,
  validateVaultImportPayload,
} from "../vaultBackup";

type VaultStateGetter = Parameters<typeof buildWrappedVaultPayloadForCloud>[0];

export async function hydrateQuestionBankOnly(): Promise<void> {
  const m = await import("../syncController");
  await m.hydrateQuestionBank();
}

export async function hydrateCloudSessionState(): Promise<void> {
  const m = await import("../syncController");
  await m.syncCloudToLocal();
  await m.hydrateOperatorHandleFromCloud();
  await m.hydrateOperatorGhostModeFromCloud();
  await m.hydrateOnboardingStateFromCloud();
  await m.hydrateProfileAdminFlagFromCloud();
}

export async function pushVaultToCloud(
  userId: string,
  getState: VaultStateGetter,
): Promise<{ ok: boolean; error?: string }> {
  const sb = getSupabase();
  if (!sb) return { ok: false, error: "Uplink nicht konfiguriert" };
  const wrapped = buildWrappedVaultPayloadForCloud(getState);
  if (!wrapped.ok) return { ok: false, error: wrapped.error };
  const payload = JSON.parse(wrapped.storageJson) as unknown;
  const { error } = await sb.from("profiles").upsert(
    {
      id: userId,
      save_data: payload,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "id" },
  );
  if (error) return { ok: false, error: error.message };
  return { ok: true };
}

export async function fetchVaultFromCloud(userId: string): Promise<{
  ok: boolean;
  didImport: boolean;
  error?: string;
}> {
  const sb = getSupabase();
  if (!sb) return { ok: false, didImport: false, error: "Uplink nicht konfiguriert" };
  const { data, error } = await sb.from("profiles").select("save_data").eq("id", userId).maybeSingle();
  if (error) return { ok: false, didImport: false, error: error.message };
  const raw = data?.save_data;
  if (
    raw === null ||
    raw === undefined ||
    (typeof raw === "object" && raw !== null && Object.keys(raw as object).length === 0)
  ) {
    return { ok: true, didImport: false };
  }
  const validated = validateVaultImportPayload(JSON.stringify(raw));
  if (!validated.ok) return { ok: false, didImport: false, error: validated.error };
  applyVaultStorageToLocalStorage(validated.storageJson);
  return { ok: true, didImport: true };
}
