import { AnimatePresence, motion } from "framer-motion";
import { useAppStore } from "../../store/useAppStore";

const STEPS = [
  {
    title: "Willkommen im Grid",
    body: "Oben siehst du Gold, Diamanten, Wissen und Felder — alles live per sanfter Animation",
  },
  {
    title: "Bauen am Rand",
    body: "Tippe ein leeres Nachbarfeld deiner Basis an — unten öffnet sich das Glas-Menü für Mine oder Kaserne",
  },
  {
    title: "Diamanten sparen",
    body: "Kasernen droppen beim Bau einen Diamanten — später für Boosts und Skins gedacht",
  },
] as const;

export function TutorialOverlay() {
  const realmTutorialStep = useAppStore((s) => s.realmTutorialStep);
  const advanceRealmTutorial = useAppStore((s) => s.advanceRealmTutorial);
  const skipRealmTutorial = useAppStore((s) => s.skipRealmTutorial);

  const open = realmTutorialStep !== null;
  const step = realmTutorialStep ?? 0;
  const content = STEPS[step];

  return (
    <AnimatePresence>
      {open && content ? (
        <motion.div
          key="tutorial"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="pointer-events-auto fixed inset-0 z-[70] flex items-end justify-center bg-black/55 p-4 pb-28 backdrop-blur-sm sm:items-center sm:pb-8"
        >
          <motion.div
            initial={{ scale: 0.94, y: 12 }}
            animate={{ scale: 1, y: 0 }}
            exit={{ scale: 0.96, y: 8 }}
            transition={{ type: "spring", stiffness: 260, damping: 24 }}
            className="relative w-full max-w-md rounded-2xl border-2 border-purple-400/45 bg-surface/95 p-6 ring-1 ring-white/10"
          >
            <div className="pointer-events-none absolute inset-0 rounded-2xl ring-2 ring-purple-300/70" />
            <div className="relative space-y-4">
              <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.35em] text-purple-300">
                Schritt {step + 1} / {STEPS.length}
              </p>
              <h3 className="font-display text-2xl font-bold uppercase tracking-wide text-foreground">
                {content.title}
              </h3>
              <p className="font-sans text-sm leading-relaxed text-foreground-muted">{content.body}</p>
              <div className="flex flex-wrap gap-2 pt-2">
                <button
                  type="button"
                  onClick={() => skipRealmTutorial()}
                  className="rounded-full border border-border-glass px-4 py-2 font-sans text-xs font-semibold uppercase tracking-wide text-foreground-muted transition hover:text-foreground"
                >
                  Überspringen
                </button>
                <button
                  type="button"
                  onClick={() => advanceRealmTutorial()}
                  className="rounded-full border border-purple-400/50 bg-purple-500/20 px-5 py-2 font-display text-xs font-bold uppercase tracking-wide text-purple-200 ring-1 ring-white/10 transition hover:bg-purple-500/30"
                >
                  {step >= STEPS.length - 1 ? "Los geht's" : "Weiter"}
                </button>
              </div>
            </div>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
