import { sanitizeAchievementIds } from "../data/achievementSchema";
import { EXAMS, type ExamId } from "../data/exams";
import { PERKS, type PerkId } from "../data/perks";
import type { RealmFactionId } from "../types/faction";
import type { RealmTileState, RealmTileStructure } from "../types/realmQuest";

/** Persist-Key identisch mit zustand `persist.name` in useAppStore */
export const VAULT_LOCAL_STORAGE_KEY = "codesnap-arena";

const MAX_IMPORT_BYTES = 2_000_000;

const EXAM_IDS = new Set(EXAMS.map((e) => e.id));
const PERK_IDS = new Set(PERKS.map((p) => p.id));
const FACTION_IDS = new Set<RealmFactionId>(["humans", "orcs", "dwarves"]);
const REALM_STRUCTURES = new Set<RealmTileStructure>(["empty", "main", "goldmine", "barracks"]);

/** Nur Felder die `partialize` in den LocalStorage schreibt */
export interface CodesnapVaultState {
  selectedPerkIds: PerkId[];
  selectedExamId: ExamId;
  unlockedNodes: string[];
  selectedFaction: RealmFactionId | null;
  realmGold: number;
  realmDiamonds: number;
  realmKnowledge: number;
  realmTiles: Record<string, RealmTileState>;
  realmTutorialComplete: boolean;
  sqlUnlockedLevels: string[];
  pseudoUnlockedLevels: string[];
  supportInboxIds: string[];
  resolvedTickets: string[];
  unlockedAchievementIds: string[];
  helpdeskClears: number;
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  flashcardProgress: Record<
    string,
    { ef: number; interval: number; repetitions: number; nextReviewDate: number }
  >;
  flashcardTotalReviews: number;
  feedbackEnabled: boolean;
}

export type VaultImportResult =
  | { ok: true; storageJson: string }
  | { ok: false; error: string };

export type VaultExportResult =
  | { ok: true; code: string }
  | { ok: false; error: string };

function isPlainObject(v: unknown): v is Record<string, unknown> {
  return typeof v === "object" && v !== null && !Array.isArray(v);
}

function isFiniteInt(n: unknown): n is number {
  return typeof n === "number" && Number.isFinite(n) && Math.floor(n) === n;
}

function isFiniteNum(n: unknown): n is number {
  return typeof n === "number" && Number.isFinite(n);
}

function isStringArray(v: unknown, maxLen: number): v is string[] {
  if (!Array.isArray(v) || v.length > maxLen) return false;
  return v.every((x) => typeof x === "string" && x.length < 512);
}

function sanitizeRealmTiles(raw: unknown): Record<string, RealmTileState> | null {
  if (!isPlainObject(raw)) return null;
  const keys = Object.keys(raw);
  if (keys.length > 800) return null;
  const out: Record<string, RealmTileState> = {};
  for (const k of keys) {
    if (k.length > 32 || !/^-?\d+,-?\d+$/.test(k)) continue;
    const cell = raw[k];
    if (!isPlainObject(cell)) return null;
    const structure = cell.structure;
    if (typeof structure !== "string" || !REALM_STRUCTURES.has(structure as RealmTileStructure)) {
      return null;
    }
    out[k] = { structure: structure as RealmTileStructure };
  }
  return out;
}

function sanitizeFlashcardProgress(
  raw: unknown,
): CodesnapVaultState["flashcardProgress"] | null {
  if (!isPlainObject(raw)) return null;
  const keys = Object.keys(raw);
  if (keys.length > 500) return null;
  const out: CodesnapVaultState["flashcardProgress"] = {};
  for (const id of keys) {
    if (typeof id !== "string" || id.length > 128) return null;
    const e = raw[id];
    if (!isPlainObject(e)) return null;
    const { ef, interval, repetitions, nextReviewDate } = e;
    if (!isFiniteNum(ef) || ef < 1.3 || ef > 10) return null;
    if (!isFiniteInt(interval) || interval < 0 || interval > 36500) return null;
    if (!isFiniteInt(repetitions) || repetitions < 0 || repetitions > 100000) return null;
    if (!isFiniteNum(nextReviewDate) || Math.abs(nextReviewDate) > 1e14) return null;
    out[id] = {
      ef,
      interval,
      repetitions,
      nextReviewDate,
    };
  }
  return out;
}

/**
 * Baut den persistierten Zustand aus einem beliebigen Store-Snapshot (nur erlaubte Keys)
 */
export function pickVaultStateFromStore(s: {
  selectedPerkIds: PerkId[];
  selectedExamId: ExamId;
  unlockedNodes: string[];
  selectedFaction: RealmFactionId | null;
  realmGold: number;
  realmDiamonds: number;
  realmKnowledge: number;
  realmTiles: Record<string, RealmTileState>;
  realmTutorialComplete: boolean;
  sqlUnlockedLevels: string[];
  pseudoUnlockedLevels: string[];
  supportInboxIds: string[];
  resolvedTickets: string[];
  unlockedAchievementIds: string[];
  helpdeskClears: number;
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  flashcardProgress: CodesnapVaultState["flashcardProgress"];
  flashcardTotalReviews: number;
  feedbackEnabled: boolean;
}): CodesnapVaultState {
  return {
    selectedPerkIds: [...s.selectedPerkIds],
    selectedExamId: s.selectedExamId,
    unlockedNodes: [...s.unlockedNodes],
    selectedFaction: s.selectedFaction,
    realmGold: s.realmGold,
    realmDiamonds: s.realmDiamonds,
    realmKnowledge: s.realmKnowledge,
    realmTiles: { ...s.realmTiles },
    realmTutorialComplete: s.realmTutorialComplete,
    sqlUnlockedLevels: [...s.sqlUnlockedLevels],
    pseudoUnlockedLevels: [...s.pseudoUnlockedLevels],
    supportInboxIds: [...s.supportInboxIds],
    resolvedTickets: [...s.resolvedTickets],
    unlockedAchievementIds: [...s.unlockedAchievementIds],
    helpdeskClears: s.helpdeskClears,
    userLevel: s.userLevel,
    globalXP: s.globalXP,
    globalXpToNext: s.globalXpToNext,
    gems: s.gems,
    flashcardProgress: { ...s.flashcardProgress },
    flashcardTotalReviews: s.flashcardTotalReviews,
    feedbackEnabled: s.feedbackEnabled,
  };
}

/** Snapshot-Typ für Vault- und Cloud-Speicher */
export type VaultSourceSlice = Parameters<typeof pickVaultStateFromStore>[0];

/** Validiert `{ state, version }` wie Vault-Export für Supabase `jsonb` */
export function buildWrappedVaultPayloadForCloud(get: () => VaultSourceSlice): VaultImportResult {
  const state = pickVaultStateFromStore(get());
  return validateVaultImportPayload(JSON.stringify({ state, version: 0 }));
}

export function vaultEncodeUtf8(plain: string): string {
  const bytes = new TextEncoder().encode(plain);
  let bin = "";
  const chunk = 0x8000;
  for (let i = 0; i < bytes.length; i += chunk) {
    bin += String.fromCharCode(...bytes.subarray(i, i + chunk));
  }
  return btoa(bin);
}

export type VaultDecodeResult =
  | { ok: true; utf8Payload: string }
  | { ok: false; error: string };

export function vaultDecodeUtf8(b64: string): VaultDecodeResult {
  const trimmed = b64.replace(/\s+/g, "");
  if (!trimmed) return { ok: false, error: "Leerer Uplink-Code" };
  try {
    const bin = atob(trimmed);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    const plain = new TextDecoder("utf-8", { fatal: true }).decode(bytes);
    return { ok: true, utf8Payload: plain };
  } catch {
    return { ok: false, error: "Base64-Segment beschädigt" };
  }
}

function parseJsonSafe(text: string): unknown | null {
  try {
    return JSON.parse(text) as unknown;
  } catch {
    return null;
  }
}

/**
 * Prüft und normalisiert den Inhalt für `localStorage.setItem(VAULT_LOCAL_STORAGE_KEY, …)`
 */
export function validateVaultImportPayload(plainJson: string): VaultImportResult {
  if (plainJson.length > MAX_IMPORT_BYTES) {
    return { ok: false, error: "Payload überschreitet das Sicherheitslimit" };
  }
  const root = parseJsonSafe(plainJson);
  if (!isPlainObject(root)) return { ok: false, error: "Kein gültiges JSON-Objekt" };
  const stateRaw = root["state"];
  const version = root["version"];
  if (!isPlainObject(stateRaw)) return { ok: false, error: "Fehlendes State-Segment" };
  if (version !== undefined && (!isFiniteInt(version as number) || (version as number) < 0)) {
    return { ok: false, error: "Versionsfeld ungültig" };
  }

  const perkIds = stateRaw.selectedPerkIds;
  if (!Array.isArray(perkIds) || perkIds.length > 8) return { ok: false, error: "Perk-Liste beschädigt" };
  for (const p of perkIds) {
    if (typeof p !== "string" || !PERK_IDS.has(p as PerkId)) {
      return { ok: false, error: "Unbekannte Perk-ID" };
    }
  }

  const examId = stateRaw.selectedExamId;
  if (typeof examId !== "string" || !EXAM_IDS.has(examId as ExamId)) {
    return { ok: false, error: "Prüfungs-ID nicht erkannt" };
  }

  const unlocked = stateRaw.unlockedNodes;
  if (!isStringArray(unlocked, 400)) return { ok: false, error: "Skill-Knotenliste beschädigt" };

  const faction = stateRaw.selectedFaction;
  if (faction !== null && (typeof faction !== "string" || !FACTION_IDS.has(faction as RealmFactionId))) {
    return { ok: false, error: "Fraktionsfeld ungültig" };
  }

  const intFields = ["realmGold", "realmDiamonds", "realmKnowledge", "userLevel", "gems", "flashcardTotalReviews"] as const;
  for (const key of intFields) {
    const n = stateRaw[key];
    if (!isFiniteInt(n) || n < 0 || n > 1_000_000_000) {
      return { ok: false, error: "Numerisches Feld außerhalb des Rahmens" };
    }
  }
  for (const key of ["globalXP", "globalXpToNext"] as const) {
    const n = stateRaw[key];
    if (!isFiniteNum(n) || n < 0 || n > 1_000_000_000_000) {
      return { ok: false, error: "XP-Felder außerhalb des Rahmens" };
    }
  }

  if (typeof stateRaw.realmTutorialComplete !== "boolean") {
    return { ok: false, error: "Tutorial-Flag fehlt" };
  }
  if (typeof stateRaw.feedbackEnabled !== "boolean") {
    return { ok: false, error: "Feedback-Flag fehlt" };
  }

  const realmTiles = sanitizeRealmTiles(stateRaw.realmTiles);
  if (!realmTiles) return { ok: false, error: "Realm-Raster beschädigt" };

  const sqlLv = stateRaw.sqlUnlockedLevels;
  const pseudoLv = stateRaw.pseudoUnlockedLevels;
  if (!isStringArray(sqlLv, 200) || !isStringArray(pseudoLv, 200)) {
    return { ok: false, error: "Level-Listen beschädigt" };
  }

  const inbox = stateRaw.supportInboxIds;
  const resolved = stateRaw.resolvedTickets;
  if (!isStringArray(inbox, 200) || !isStringArray(resolved, 400)) {
    return { ok: false, error: "Ticket-Listen beschädigt" };
  }

  const rawAch = stateRaw.unlockedAchievementIds;
  let unlockedAchievementIds: string[] = [];
  if (rawAch !== undefined) {
    if (!Array.isArray(rawAch) || rawAch.length > 64) {
      return { ok: false, error: "Achievement-Liste beschädigt" };
    }
    unlockedAchievementIds = sanitizeAchievementIds(rawAch, 64);
  }

  const rawHd = stateRaw.helpdeskClears;
  let helpdeskClears = 0;
  if (rawHd !== undefined) {
    if (!isFiniteInt(rawHd) || rawHd < 0 || rawHd > 50000) {
      return { ok: false, error: "Helpdesk-Zähler beschädigt" };
    }
    helpdeskClears = rawHd;
  }

  const fc = sanitizeFlashcardProgress(stateRaw.flashcardProgress);
  if (!fc) return { ok: false, error: "Karten-Fortschritt beschädigt" };

  const clean: CodesnapVaultState = {
    selectedPerkIds: perkIds as PerkId[],
    selectedExamId: examId as ExamId,
    unlockedNodes: unlocked,
    selectedFaction: faction as RealmFactionId | null,
    realmGold: stateRaw.realmGold as number,
    realmDiamonds: stateRaw.realmDiamonds as number,
    realmKnowledge: stateRaw.realmKnowledge as number,
    realmTiles,
    realmTutorialComplete: stateRaw.realmTutorialComplete,
    sqlUnlockedLevels: sqlLv,
    pseudoUnlockedLevels: pseudoLv,
    supportInboxIds: inbox,
    resolvedTickets: resolved,
    unlockedAchievementIds,
    helpdeskClears,
    userLevel: stateRaw.userLevel as number,
    globalXP: stateRaw.globalXP as number,
    globalXpToNext: stateRaw.globalXpToNext as number,
    gems: stateRaw.gems as number,
    flashcardProgress: fc,
    flashcardTotalReviews: stateRaw.flashcardTotalReviews as number,
    feedbackEnabled: stateRaw.feedbackEnabled,
  };

  const wrapped = { state: clean, version: typeof version === "number" ? version : 0 };
  return { ok: true, storageJson: JSON.stringify(wrapped) };
}

/**
 * Validiert vorhandenen LocalStorage-Eintrag (gleiches Format wie Import)
 */
export function validateExistingStorageRaw(raw: string): VaultImportResult {
  return validateVaultImportPayload(raw);
}

/** Export-Code: Base64 über validiertes Persist-JSON */
export function buildVaultExportCode(getState: () => CodesnapVaultState): VaultExportResult {
  const fromLs = typeof localStorage !== "undefined" ? localStorage.getItem(VAULT_LOCAL_STORAGE_KEY) : null;
  if (fromLs && fromLs.trim()) {
    const checked = validateExistingStorageRaw(fromLs);
    if (checked.ok) return { ok: true, code: vaultEncodeUtf8(checked.storageJson) };
  }
  const live = getState();
  const wrapped = { state: live, version: 0 };
  const preChecked = validateVaultImportPayload(JSON.stringify(wrapped));
  if (!preChecked.ok) return { ok: false, error: preChecked.error };
  return { ok: true, code: vaultEncodeUtf8(preChecked.storageJson) };
}

export function decodeAndValidateVaultCode(b64: string): VaultImportResult {
  const dec = vaultDecodeUtf8(b64);
  if (!dec.ok) return dec;
  return validateVaultImportPayload(dec.utf8Payload);
}

export function applyVaultStorageToLocalStorage(storageJson: string): void {
  localStorage.setItem(VAULT_LOCAL_STORAGE_KEY, storageJson);
}
