import { motion } from "framer-motion";
import { useCallback, useId, useRef, useState } from "react";
import { IconPlay, IconTrash } from "../icons/ThinLineIcons";
import { cn } from "../../lib/cn";
import { itemReveal, staggerContainer } from "../../motion/variants";

export function SqlSandboxTerminal() {
  const id = useId();
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const [buffer, setBuffer] = useState("");
  const [log, setLog] = useState<string[]>([
    "[root@sql-core ~]# session init — offline sandbox aktiv",
    "[hint] Tippe SQL und ENTER — kein Netzwerk, nur Vibes",
  ]);

  const run = useCallback(() => {
    const q = buffer.trim();
    if (!q) return;
    setLog((prev) => [...prev, `> ${q}`, "[sandbox] OK — Ausführung simuliert (kein Backend)"]);
    setBuffer("");
    inputRef.current?.focus();
  }, [buffer]);

  const clear = useCallback(() => {
    setLog(["[root@sql-core ~]# buffer cleared"]);
  }, []);

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className="space-y-4"
    >
      <motion.div variants={itemReveal} className="space-y-1">
        <p className="font-mono text-[10px] uppercase tracking-[0.35em] text-emerald-400/80">
          Sandbox / Freie Konsole
        </p>
        <h2 className="font-display text-2xl font-bold uppercase tracking-wide text-emerald-100 sm:text-3xl">
          SQL-Core Terminal
        </h2>
      </motion.div>

      <motion.div
        variants={itemReveal}
        className={cn(
          "overflow-hidden rounded-2xl border border-emerald-500/25 bg-[#020203] ring-1 ring-white/10",
        )}
      >
        <div className="flex items-center justify-between border-b border-emerald-500/20 bg-black/60 px-3 py-2">
          <span className="font-mono text-[10px] uppercase tracking-widest text-emerald-500/90">
            session://sql-adventure/sandbox
          </span>
          <span className="font-mono text-[10px] text-emerald-600">SECURE</span>
        </div>
        <div
          className="max-h-[min(38vh,320px)] overflow-y-auto overscroll-y-contain p-4 font-mono text-xs leading-relaxed text-emerald-100/90 sm:text-sm"
          style={{ contain: "layout paint" }}
        >
          {log.map((line, i) => (
            <div key={`${id}-${i}`} className="whitespace-pre-wrap break-words">
              {line}
            </div>
          ))}
        </div>
        <div className="border-t border-emerald-500/15 bg-black/70 p-3">
          <label htmlFor={`${id}-sql`} className="sr-only">
            SQL-Eingabe
          </label>
          <textarea
            id={`${id}-sql`}
            ref={inputRef}
            rows={3}
            spellCheck={false}
            autoCapitalize="none"
            autoCorrect="off"
            value={buffer}
            onChange={(e) => setBuffer(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                run();
              }
            }}
            placeholder="SELECT * FROM reality WHERE vibe = 'max'"
            className={cn(
              "w-full resize-none rounded-lg border border-emerald-500/20 bg-black/80 px-3 py-2 font-mono text-sm text-emerald-100",
              "placeholder:text-emerald-700/50 focus:border-emerald-400/50 focus:outline-none focus:ring-1 focus:ring-emerald-400/40",
            )}
          />
          <div className="mt-2 flex flex-wrap gap-2">
            <motion.button
              type="button"
              whileTap={{ scale: 0.97 }}
              onClick={() => run()}
              className="inline-flex items-center gap-2 rounded-lg border border-emerald-400/40 bg-emerald-500/15 px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-emerald-200 ring-1 ring-white/10"
            >
              <IconPlay className="size-3.5 shrink-0" aria-hidden />
              Ausführen
            </motion.button>
            <motion.button
              type="button"
              whileTap={{ scale: 0.97 }}
              onClick={() => clear()}
              className="inline-flex items-center gap-2 rounded-lg border border-zinc-600/60 bg-zinc-900/80 px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-zinc-400"
            >
              <IconTrash className="size-3.5 shrink-0 opacity-80" aria-hidden />
              Log leeren
            </motion.button>
          </div>
        </div>
      </motion.div>
    </motion.div>
  );
}
