export function getRankArtifact(level: number): RankArtifact {
  const safeLevel = Math.max(0, Math.floor(level));
  return (
    ARTIFACTS.find((a) => safeLevel >= a.levelMin && safeLevel <= a.levelMax) ??
    ARTIFACTS[ARTIFACTS.length - 1]
  );
}

/** Phase 40 — Prestige-Titel an Lifetime-XP (Palette über paletteLevel an rankEngine gekoppelt) */
export type PrestigeRankDef = {
  title: string;
  minLifetimeXp: number;
  /** Level-Anchor für getRankArtifact — Farb-Hierarchie */
  paletteLevel: number;
};

export const PRESTIGE_RANKS: readonly PrestigeRankDef[] = [
  { title: "System Trainee", minLifetimeXp: 0, paletteLevel: 2 },
  { title: "Network Operator", minLifetimeXp: 2800, paletteLevel: 12 },
  { title: "Cyber Sentinel", minLifetimeXp: 9500, paletteLevel: 24 },
  { title: "Root Archon", minLifetimeXp: 24000, paletteLevel: 42 },
  { title: "Apex Nexus", minLifetimeXp: 52000, paletteLevel: 72 },
] as const;

export function getPrestigeRankIndex(lifetimeXp: number): number {
  const x = Math.max(0, Math.floor(lifetimeXp));
  let idx = 0;
  for (let i = 0; i < PRESTIGE_RANKS.length; i += 1) {
    if (x >= PRESTIGE_RANKS[i].minLifetimeXp) idx = i;
  }
  return idx;
}

export function getPrestigeRankByLifetimeXp(lifetimeXp: number): PrestigeRankDef {
  return PRESTIGE_RANKS[getPrestigeRankIndex(lifetimeXp)] ?? PRESTIGE_RANKS[0];
}

export function getPrestigePaletteArtifact(lifetimeXp: number): RankArtifact {
  return getRankArtifact(getPrestigeRankByLifetimeXp(lifetimeXp).paletteLevel);
}

export function getNextRankMilestone(level: number): { nextTier: RankTier; nextLevel: number } | null {
  const safeLevel = Math.max(0, Math.floor(level));
  const current = getRankArtifact(safeLevel);
  const idx = ARTIFACTS.findIndex((a) => a.tier === current.tier);
  const next = ARTIFACTS[idx + 1];
  if (!next) return null;
  return { nextTier: next.tier, nextLevel: next.levelMin };
}

/** Daily-Grind-Streak-Bänder — gleiche Schwellen wie Arena Leaderboard */
export type StreakFlexBand = "none" | "short" | "mid" | "long";

export function getStreakFlexBand(streakDays: number): StreakFlexBand {
  const s = Math.max(0, Math.floor(Number(streakDays) || 0));
  if (s >= 14) return "long";
  if (s >= 7) return "mid";
  if (s >= 3) return "short";
  return "none";
}

/** Inset-Glow aus Rank-Palette (auraColor) — Intensität über Band (3+ / 7+ / 14+) */
export type StreakInsetGlowMotion = {
  boxShadow: string;
  pulseOpacity: [number, number, number];
  duration: number;
};

export function getStreakInsetGlowMotion(artifact: RankArtifact, band: StreakFlexBand): StreakInsetGlowMotion | null {
  if (band === "none") return null;
  const blur = band === "long" ? 48 : band === "mid" ? 32 : 22;
  const innerBlur = Math.max(10, Math.floor(blur * 0.42));
  const boxShadow = `inset 0 0 ${blur}px ${artifact.auraColor}, inset 0 0 ${innerBlur}px ${artifact.auraSecondaryColor}`;
  const pulseOpacity: [number, number, number] =
    band === "long" ? [0.1, 0.26, 0.1] : band === "mid" ? [0.08, 0.2, 0.08] : [0.06, 0.16, 0.06];
  const duration = band === "long" ? 2.8 : 2.35;
  return { boxShadow, pulseOpacity, duration };
}
