import type { StateCreator } from "zustand";
import { PRESTIGE_RANKS, getPrestigeRankIndex } from "../../lib/rankEngine";
import { computeLifetimeXp, globalXpToNextForLevel } from "../../lib/xpCurve";
import type { QuestionModule } from "../../data/questionSchema";
import { SYNTHESIS_RECIPES_BY_ID, type SynthesisMaterialRequirement } from "../../data/synthesisRecipes";
import { getCraftableRecipeIds, runSynthesisAttempt } from "../../lib/services/synthesisService";
import type { AppState } from "../useAppStore";

export type NotificationNotice =
  | {
      id: string;
      kind: "level_up";
      level: number;
      fromLevel: number;
      gemsGained: number;
      skillPointsGained: number;
    }
  | {
      id: string;
      kind: "achievement";
      achievementId: string;
      title: string;
      requirement: string;
    }
  | {
      id: string;
      kind: "syndicate_event";
      title: string;
      message: string;
    };

export interface ProgressSlice {
  synthesisHistory: ArtifactCraftAttempt[];
  activeCraftResult: ArtifactCraftAttempt | null;
  pendingLevelUps: Array<{
    id: string;
    level: number;
    fromLevel: number;
    gemsGained: number;
    skillPointsGained: number;
  }>;
  lastLevelUp: null | {
    id: string;
    level: number;
    fromLevel: number;
    gemsGained: number;
    skillPointsGained: number;
  };
  notificationQueue: NotificationNotice[];
  activeNotification: NotificationNotice | null;
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  totalXp: string;
  currentLevel: number;
  prestige: number;
  skillPoints: number;
  inventory: string[];
  awardGlobalXp: (
    amount: number,
    opts?: {
      module?: QuestionModule;
      bossGhostVictory?: boolean;
      bossLabel?: string;
      modifierIntensity?: number;
    },
  ) => void;
  addXp: (
    amount: number,
    opts?: {
      module?: QuestionModule;
      bossGhostVictory?: boolean;
      bossLabel?: string;
      modifierIntensity?: number;
    },
  ) => void;
  levelUp: () => void;
  enqueueLevelUpNotice: (input: {
    level: number;
    fromLevel: number;
    gemsGained?: number;
    skillPointsGained?: number;
  }) => void;
  enqueueNotification: (notice: NotificationNotice) => void;
  dismissActiveNotification: () => void;
  spendSkillPoints: (amount?: number) => boolean;
  addInventoryItem: (itemId: string) => void;
  addInventoryItems: (itemIds: string[]) => number;
  consumeMaterials: (materials: SynthesisMaterialRequirement[]) => boolean;
  addSynthesizedItem: (itemId: string, amount?: number) => void;
  craftArtifact: (recipeId: string) => ArtifactCraftAttempt;
  getCraftableRecipes: () => string[];
  dismissCraftResult: () => void;
  clearCraftingInventory: () => void;
  consumeArenaNeuralHintCost: () => { spentGems: number } | null;
  levelUpCelebration: null | {
    level: number;
    fromLevel: number;
    gemsGained: number;
  };
  dismissLevelUp: () => void;
  dismissLevelUpCelebration: () => void;
  promotionCelebration: null | {
    fromTitle: string;
    toTitle: string;
    fromIndex: number;
    toIndex: number;
  };
  dismissPromotionCelebration: () => void;
}

export interface ArtifactCraftAttempt {
  id: string;
  recipeId: string;
  recipeName: string;
  success: boolean;
  consumedMaterials: SynthesisMaterialRequirement[];
  outputItemId: string | null;
  outputAmount: number;
  roll: number;
  successRate: number;
  createdAt: string;
}

function toTotalXpString(level: number, xpInLevel: number): string {
  const total = BigInt(Math.max(0, computeLifetimeXp(level, xpInLevel)));
  return total.toString();
}

export const createProgressSlice: StateCreator<AppState, [], [], ProgressSlice> = (set, get) => ({
  pendingLevelUps: [],
  lastLevelUp: null,
  notificationQueue: [],
  activeNotification: null,
  userLevel: 12,
  globalXP: 1840,
  globalXpToNext: globalXpToNextForLevel(12),
  gems: 14,
  totalXp: toTotalXpString(12, 1840),
  currentLevel: 12,
  prestige: getPrestigeRankIndex(computeLifetimeXp(12, 1840)),
  skillPoints: 0,
  inventory: [],
  synthesisHistory: [],
  activeCraftResult: null,
  levelUpCelebration: null,
  promotionCelebration: null,
  awardGlobalXp: (amount, opts) => {
    if (amount <= 0) return;
    const before = get();
    const off = before.serverTimeOffsetMs;
    let live = before.globalLiveEvent;
    let raid = before.activeEventModifier;
    if (live != null && Date.now() + off >= live.endsAtMs) {
      set({ globalLiveEvent: null });
      live = null;
    }
    if (raid != null && Date.now() + off >= raid.endsAtMs) {
      set({ activeEventModifier: null });
      raid = null;
    }
    const liveMult = live != null ? Math.max(1, live.xpMultiplier * live.factionPointsMultiplier) : 1;
    const raidEligible = !!raid && !!opts?.module && raid.targetModule === opts.module;
    const raidMult = raidEligible && raid ? Math.max(1, Math.min(4, raid.xpMultiplier)) : 1;
    const bossMult = opts?.bossGhostVictory ? 1.35 : 1;
    const modifierDepth = Math.max(0, Math.floor(opts?.modifierIntensity ?? 0));
    const modExp = Math.pow(1.26, modifierDepth);
    const syndicateMult = Math.max(1, before.syndicateRuntimeBuffs.xpMultiplier);
    const councilEligible =
      !!before.councilRuntime.active &&
      !!opts?.module &&
      before.councilRuntime.targetModule === opts.module;
    const councilMult = councilEligible ? Math.max(1, before.councilRuntime.xpBoostMultiplier) : 1;
    const nowMs = Date.now() + off;
    if (before.launchPulse.active && nowMs >= before.launchPulse.endsAtMs) {
      set({
        launchPulse: {
          ...before.launchPulse,
          active: false,
        },
      });
    }
    const launchMult =
      before.launchPulse.active && nowMs < before.launchPulse.endsAtMs
        ? Math.max(1, Math.min(2, before.launchPulse.xpMultiplier))
        : 1;
    const legacyMult = Math.max(1, before.legacyXpBoostMultiplier);
    const mult = Math.max(1, liveMult * raidMult * bossMult * modExp * syndicateMult * councilMult * launchMult * legacyMult);
    const awarded = Math.max(1, Math.floor(amount * mult + Number.EPSILON));
    const preLife = computeLifetimeXp(before.userLevel, before.globalXP);
    const prePrestigeIdx = getPrestigeRankIndex(preLife);
    let xp = before.globalXP + awarded;
    let lvl = before.userLevel;
    let gemsTotal = before.gems;
    let xpNext = before.globalXpToNext;
    const startLevel = lvl;
    let gemsBatch = 0;
    let didLevel = false;
    let gainedSkillPoints = 0;
    while (xp >= xpNext) {
      xp -= xpNext;
      lvl += 1;
      const g = 3 + Math.floor(lvl / 2);
      gemsTotal += g;
      gemsBatch += g;
      gainedSkillPoints += 1;
      xpNext = globalXpToNextForLevel(lvl);
      didLevel = true;
    }
    const totalXp = toTotalXpString(lvl, xp);
    const p = before.progress;
    const patch: Partial<AppState> = {
      globalXP: xp,
      userLevel: lvl,
      gems: gemsTotal,
      globalXpToNext: xpNext,
      totalXp,
      currentLevel: lvl,
      prestige: getPrestigeRankIndex(computeLifetimeXp(lvl, xp)),
      skillPoints: Math.max(0, before.skillPoints + gainedSkillPoints),
      progress: {
        ...p,
        level: lvl,
        xpCurrent: xp,
        xpToNext: xpNext,
      },
    };
    if (didLevel && lvl > startLevel) {
      const levelUpEntry = {
        id: `lvl-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        level: lvl,
        fromLevel: startLevel,
        gemsGained: gemsBatch,
        skillPointsGained: gainedSkillPoints,
      };
      patch.levelUpCelebration = {
        level: lvl,
        fromLevel: startLevel,
        gemsGained: gemsBatch,
      };
      patch.lastLevelUp = levelUpEntry;
      patch.pendingLevelUps = [...before.pendingLevelUps, levelUpEntry].slice(-5);
      const levelUpNotice: NotificationNotice = {
        id: levelUpEntry.id,
        kind: "level_up",
        level: levelUpEntry.level,
        fromLevel: levelUpEntry.fromLevel,
        gemsGained: levelUpEntry.gemsGained,
        skillPointsGained: levelUpEntry.skillPointsGained,
      };
      const queuedNotices = [...before.notificationQueue, levelUpNotice].slice(-24);
      if (before.activeNotification) {
        patch.notificationQueue = queuedNotices;
      } else {
        const [nextActive, ...restQueue] = queuedNotices;
        patch.activeNotification = nextActive ?? null;
        patch.notificationQueue = restQueue;
      }
      const handle = (before.operatorHandle ?? before.progress.displayName ?? "Unknown_Operator")
        .trim()
        .replace(/\s+/g, "_");
      void import("../../lib/syncController").then((m) =>
        m.emitNexusActivityEvent({
          kind: "NEW_RANK",
          userId: before.authUser?.id,
          handle,
          routeHint: "public_dossier",
          label: `${handle} level ${lvl}`,
        }),
      );
    }
    const postLife = computeLifetimeXp(lvl, xp);
    const postPrestigeIdx = getPrestigeRankIndex(postLife);
    if (postPrestigeIdx > prePrestigeIdx) {
      patch.promotionCelebration = {
        fromTitle: PRESTIGE_RANKS[prePrestigeIdx].title,
        toTitle: PRESTIGE_RANKS[postPrestigeIdx].title,
        fromIndex: prePrestigeIdx,
        toIndex: postPrestigeIdx,
      };
    }
    if (opts?.bossGhostVictory && opts.module) {
      const bossTag = (opts.bossLabel ?? "GLOBAL_BOSS").trim().replace(/\s+/g, "_");
      const eliteArtifact = {
        id: `boss-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        label: `Boss Sigil ${bossTag} ${opts.module.toUpperCase()}`,
        rarity: "mythic" as const,
        module: opts.module,
        eventId: "global-boss",
        receivedAt: new Date().toISOString(),
      };
      patch.raidArtifacts = [eliteArtifact, ...before.raidArtifacts].slice(0, 24);
      get().pushSystemPulseEvent({
        kind: "SYSTEM_ANNOUNCEMENT",
        message: `DIAG BOSS GHOST DOWN ${bossTag} ELITE ARTIFACT SYNCED`,
      });
    }
    set(patch);
    void import("../../lib/syncController").then((m) => m.scheduleBackgroundProgressSync());
    void import("../../lib/services/progressService").then((svc) =>
      svc.queueOptimisticProgressSync({
        userLevel: lvl,
        globalXP: xp,
        globalXpToNext: xpNext,
        gems: gemsTotal,
        totalXp,
      }),
    );
  },
  addXp: (amount, opts) => {
    get().awardGlobalXp(amount, opts);
  },
  levelUp: () => {
    const xpNeeded = Math.max(1, get().globalXpToNext - get().globalXP);
    get().awardGlobalXp(xpNeeded);
  },
  enqueueLevelUpNotice: (input) => {
    const level = Math.max(0, Math.floor(input.level));
    const fromLevel = Math.max(0, Math.floor(input.fromLevel));
    if (level <= fromLevel) return;
    const gemsGained = Math.max(0, Math.floor(input.gemsGained ?? 0));
    const skillPointsGained = Math.max(0, Math.floor(input.skillPointsGained ?? 0));
    const next = {
      id: `lvl-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      level,
      fromLevel,
      gemsGained,
      skillPointsGained,
    };
    const notice: NotificationNotice = {
      id: next.id,
      kind: "level_up",
      level: next.level,
      fromLevel: next.fromLevel,
      gemsGained: next.gemsGained,
      skillPointsGained: next.skillPointsGained,
    };
    get().enqueueNotification(notice);
    set((s) => ({
      pendingLevelUps: [...s.pendingLevelUps, next].slice(-5),
      lastLevelUp: next,
      levelUpCelebration: { level: next.level, fromLevel: next.fromLevel, gemsGained: next.gemsGained },
    }));
  },
  enqueueNotification: (notice) =>
    set((s) => {
      const queued = [...s.notificationQueue, notice].slice(-24);
      if (s.activeNotification) {
        return { notificationQueue: queued };
      }
      const [nextActive, ...rest] = queued;
      return {
        activeNotification: nextActive ?? null,
        notificationQueue: rest,
      };
    }),
  dismissActiveNotification: () =>
    set((s) => {
      if (s.notificationQueue.length === 0) {
        return { activeNotification: null };
      }
      const [nextActive, ...rest] = s.notificationQueue;
      return {
        activeNotification: nextActive ?? null,
        notificationQueue: rest,
      };
    }),
  spendSkillPoints: (amount = 1) => {
    const cost = Math.max(1, Math.floor(amount));
    const current = get().skillPoints;
    if (current < cost) return false;
    set({ skillPoints: current - cost });
    return true;
  },
  addInventoryItem: (itemId) => {
    get().addInventoryItems([itemId]);
  },
  addInventoryItems: (itemIds) => {
    const normalized = itemIds.map((item) => item.trim()).filter((item) => item.length > 0);
    if (normalized.length === 0) return 0;
    set((s) => ({ inventory: [...s.inventory, ...normalized] }));
    return normalized.length;
  },
  consumeMaterials: (materials) => {
    if (materials.length === 0) return true;
    const snapshot = [...get().inventory];
    const nextInventory = [...snapshot];
    for (const material of materials) {
      if (!material.itemId || material.amount <= 0) continue;
      for (let count = 0; count < material.amount; count += 1) {
        const index = nextInventory.findIndex((item) => item === material.itemId);
        if (index < 0) {
          return false;
        }
        nextInventory.splice(index, 1);
      }
    }
    set({ inventory: nextInventory });
    return true;
  },
  addSynthesizedItem: (itemId, amount = 1) => {
    const trimmed = itemId.trim();
    if (!trimmed) return;
    const count = Math.max(1, Math.floor(amount));
    get().addInventoryItems(Array.from({ length: count }, () => trimmed));
  },
  craftArtifact: (recipeId) => {
    const recipe = SYNTHESIS_RECIPES_BY_ID[recipeId];
    if (!recipe) {
      throw new Error(`Unknown synthesis recipe ${recipeId}`);
    }
    const before = get();
    const inventorySnapshot = [...before.inventory];
    const result = runSynthesisAttempt(recipeId, { inventory: inventorySnapshot });
    const consumed = get().consumeMaterials(result.consumedMaterials);
    if (!consumed) {
      throw new Error(`Synthesis consume failed for ${recipeId}`);
    }
    if (result.success && result.producedItemId) {
      get().addSynthesizedItem(result.producedItemId, result.producedAmount);
    }
    const attempt: ArtifactCraftAttempt = {
      id: `craft-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      recipeId,
      recipeName: recipe.name,
      success: result.success,
      consumedMaterials: result.consumedMaterials,
      outputItemId: result.producedItemId,
      outputAmount: result.producedAmount,
      roll: result.roll,
      successRate: result.successRate,
      createdAt: new Date().toISOString(),
    };
    set((s) => ({
      synthesisHistory: [attempt, ...s.synthesisHistory].slice(0, 40),
      activeCraftResult: attempt,
    }));
    return attempt;
  },
  getCraftableRecipes: () => {
    const inventorySnapshot = [...get().inventory];
    return getCraftableRecipeIds({ inventory: inventorySnapshot });
  },
  dismissCraftResult: () => {
    set({ activeCraftResult: null });
  },
  clearCraftingInventory: () => {
    set({
      inventory: [],
      raidArtifacts: [],
      synthesisHistory: [],
      activeCraftResult: null,
    });
  },
  consumeArenaNeuralHintCost: () => {
    const GEM_COST = 2;
    const before = get();
    if (before.gems < GEM_COST) return null;
    set({ gems: before.gems - GEM_COST });
    void import("../../lib/syncController").then((m) => m.scheduleBackgroundProgressSync());
    return { spentGems: GEM_COST };
  },
  dismissLevelUp: () =>
    set((s) => {
      const hasLevelUpActive = s.activeNotification?.kind === "level_up";
      const [nextActive, ...restQueue] = s.notificationQueue;
      if (s.pendingLevelUps.length === 0) {
        return {
          levelUpCelebration: null,
          lastLevelUp: null,
          activeNotification: hasLevelUpActive ? nextActive ?? null : s.activeNotification,
          notificationQueue: hasLevelUpActive ? restQueue : s.notificationQueue,
        };
      }
      const [, ...rest] = s.pendingLevelUps;
      const nextHead = rest[0] ?? null;
      return {
        pendingLevelUps: rest,
        lastLevelUp: nextHead,
        levelUpCelebration: nextHead
          ? {
              level: nextHead.level,
              fromLevel: nextHead.fromLevel,
              gemsGained: nextHead.gemsGained,
            }
          : null,
        activeNotification: hasLevelUpActive ? nextActive ?? null : s.activeNotification,
        notificationQueue: hasLevelUpActive ? restQueue : s.notificationQueue,
      };
    }),
  dismissLevelUpCelebration: () => get().dismissLevelUp(),
  dismissPromotionCelebration: () => set({ promotionCelebration: null }),
});
