import type { CSSProperties } from "react";

export type MockExamRadarMetric = {
  id: string;
  label: string;
  value: number;
};

function clamp(value: number): number {
  return Math.max(0, Math.min(100, value));
}

type MockExamResultRadarProps = {
  metrics: MockExamRadarMetric[];
  style?: CSSProperties;
};

/** Kompaktes Radar für Prüfungs-Domänen nutzt --universe-primary und --universe-accent */
export function MockExamResultRadar({ metrics, style }: MockExamResultRadarProps) {
  if (metrics.length < 3) return null;
  const center = 140;
  const radius = 88;
  const levels = [0.25, 0.5, 0.75, 1];
  const points = metrics.map((metric, index) => {
    const angle = -Math.PI / 2 + (index * Math.PI * 2) / metrics.length;
    const r = radius * (clamp(metric.value) / 100);
    return {
      x: center + Math.cos(angle) * r,
      y: center + Math.sin(angle) * r,
      angle,
    };
  });
  const polygonPoints = points.map((p) => `${p.x},${p.y}`).join(" ");

  return (
    <div
      className="rounded-2xl border border-white/[0.08] bg-black/35 p-4 ring-1 ring-white/[0.04]"
      style={style}
    >
      <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.22em] text-zinc-500">Domänen Radar</p>
      <div className="mt-3 w-full max-w-md">
        <svg viewBox="0 0 280 280" className="mx-auto h-auto w-full" role="img" aria-label="Leistung nach Themenbereichen">
          {levels.map((level) => {
            const ring = metrics
              .map((_, index) => {
                const angle = -Math.PI / 2 + (index * Math.PI * 2) / metrics.length;
                const ringRadius = radius * level;
                const x = center + Math.cos(angle) * ringRadius;
                const y = center + Math.sin(angle) * ringRadius;
                return `${x},${y}`;
              })
              .join(" ");
            return (
              <polygon
                key={`ring-${level}`}
                points={ring}
                fill="none"
                stroke="var(--universe-primary)"
                strokeOpacity={0.14 + level * 0.08}
                strokeWidth={1}
              />
            );
          })}
          {metrics.map((metric, index) => {
            const angle = -Math.PI / 2 + (index * Math.PI * 2) / metrics.length;
            const x = center + Math.cos(angle) * radius;
            const y = center + Math.sin(angle) * radius;
            const labelX = center + Math.cos(angle) * (radius + 24);
            const labelY = center + Math.sin(angle) * (radius + 24);
            return (
              <g key={metric.id}>
                <line
                  x1={center}
                  y1={center}
                  x2={x}
                  y2={y}
                  stroke="var(--universe-primary)"
                  strokeOpacity={0.28}
                  strokeWidth={1}
                />
                <text
                  x={labelX}
                  y={labelY}
                  fill="var(--universe-primary)"
                  fontSize="10"
                  textAnchor="middle"
                  dominantBaseline="middle"
                  className="font-mono uppercase tracking-wide"
                  style={{ opacity: 0.92 }}
                >
                  {metric.label}
                </text>
              </g>
            );
          })}
          <polygon
            points={polygonPoints}
            fill="var(--universe-accent)"
            fillOpacity={0.18}
            stroke="var(--universe-accent)"
            strokeWidth={2}
            strokeOpacity={0.85}
          />
          {points.map((point, index) => (
            <circle key={`dot-${metrics[index]?.id ?? index}`} cx={point.x} cy={point.y} r={3.5} fill="var(--universe-accent)" />
          ))}
        </svg>
      </div>
      <div className="mt-3 grid grid-cols-2 gap-2 sm:grid-cols-4">
        {metrics.map((m) => (
          <div
            key={m.id}
            className="rounded-lg border px-2 py-2 font-mono text-[10px] uppercase tracking-wide"
            style={{
              borderColor: "color-mix(in srgb, var(--universe-primary) 32%, transparent)",
              backgroundColor: "color-mix(in srgb, var(--universe-primary) 8%, rgb(9 9 11))",
              color: "color-mix(in srgb, var(--universe-primary) 88%, rgb(228 228 231))",
            }}
          >
            <p className="truncate">{m.label}</p>
            <p className="mt-1 text-xs font-bold tabular-nums">{Math.round(clamp(m.value))}%</p>
          </div>
        ))}
      </div>
    </div>
  );
}
