import { ACHIEVEMENTS, achievementTierClasses, type AchievementId } from "../../data/achievementSchema";
import { cn } from "../../lib/cn";

function MedalGlyph({ className }: { className?: string }) {
  return (
    <svg viewBox="0 0 32 32" className={cn("size-7", className)} aria-hidden>
      <path
        fill="currentColor"
        d="M16 2 20.5 11h9.2L23 17.2l3.5 9.1L16 20.8 5.5 26.3 9 17.2 2.3 11h9.2L16 2Z"
        opacity="0.92"
      />
      <path
        fill="none"
        stroke="currentColor"
        strokeWidth="1"
        d="M16 6.5 18.8 12h6.4L20.2 15.8l2.2 6L16 18.2 9.6 21.8l2.2-6L6.8 12h6.4L16 6.5Z"
        opacity="0.55"
      />
    </svg>
  );
}

type AchievementMedalTileProps = {
  id: AchievementId;
  className?: string;
};

export function AchievementMedalTile({ id, className }: AchievementMedalTileProps) {
  const def = ACHIEVEMENTS[id];
  const tier = achievementTierClasses(def.tier);
  return (
    <div
      title={def.requirement}
      role="img"
      aria-label={def.requirement}
      className={cn(
        "group relative flex flex-col items-center justify-center gap-1 border px-2 py-2.5",
        "transition-[box-shadow,transform] duration-300 hover:-translate-y-px",
        tier.frame,
        tier.glow,
        className,
      )}
    >
      <MedalGlyph className={cn(tier.icon, "drop-shadow-[0_0_8px_currentColor]")} />
      <span className="max-w-[5.5rem] text-center font-mono text-[8px] font-semibold uppercase leading-tight tracking-[0.12em] text-foreground/88">
        {def.title}
      </span>
      <span className="pointer-events-none absolute inset-0 opacity-0 transition-opacity duration-300 group-hover:opacity-[0.14] hud-grid" aria-hidden />
    </div>
  );
}
