import type { StateCreator } from "zustand";
import type { ArenaQuestion } from "../../data/mockQuestions";
import { ihkGradeFromPercent, ihkGradeLabel } from "../../lib/mockExamGrading";
import {
  getChallengeQuestionSet,
  getMockExamQuestions,
  submitMockExamResult,
} from "../../lib/services/examService";
import type { AppState, MockExamHistoryEntry, MockExamState } from "../useAppStore";
import { useAcademyStore } from "../academyStore";

function pushTrainingPlanFromRun(run: MockExamState): void {
  useAcademyStore.getState().applyTrainingPlanFromMockExam({
    questionSet: run.questionSet,
    answers: run.answers,
    flagged: run.flagged,
    finishedAtMs: run.finishedAtMs ?? Date.now(),
  });
}

function buildMockExamHistoryEntry(run: MockExamState): MockExamHistoryEntry {
  const totalQuestions = run.questionSet.length;
  let correctAnswers = 0;
  const correctTagHits: Record<string, number> = {};
  const wrongTagHits: Record<string, number> = {};
  run.questionSet.forEach((q, idx) => {
    const answer = run.answers[idx];
    const correct = answer === q.correctIndex;
    if (correct) correctAnswers += 1;
    for (const tag of q.tags) {
      if (correct) correctTagHits[tag] = (correctTagHits[tag] ?? 0) + 1;
      else wrongTagHits[tag] = (wrongTagHits[tag] ?? 0) + 1;
    }
  });
  const percent = totalQuestions > 0 ? (correctAnswers / totalQuestions) * 100 : 0;
  const grade = ihkGradeFromPercent(percent);
  return {
    completedAtMs: Date.now(),
    totalQuestions,
    correctAnswers,
    percent,
    grade,
    gradeLabel: ihkGradeLabel(grade),
    correctTagHits,
    wrongTagHits,
    challengeMeta: run.challengeMeta,
  };
}

async function submitMockExamResultInBackground(run: MockExamState): Promise<void> {
  const totalQuestions = run.questionSet.length;
  const correctAnswers = run.questionSet.reduce((acc, q, idx) => acc + (run.answers[idx] === q.correctIndex ? 1 : 0), 0);
  const percent = totalQuestions > 0 ? (correctAnswers / totalQuestions) * 100 : 0;
  const durationMs = Math.max(0, (run.finishedAtMs ?? Date.now()) - run.startedAtMs);
  await submitMockExamResult({
    examId: "MOCK_EXAM",
    scorePercent: percent,
    totalQuestions,
    correctAnswers,
    durationMs,
  });
}

export interface MockExamSlice {
  mockExam: MockExamState | null;
  mockExamHistory: MockExamHistoryEntry[];
  startMockExam: () => void;
  startMockExamChallenge: (input: {
    ids: string[];
    by: string;
    elapsedMs: number | null;
    percent: number | null;
  }) => void;
  acceptMockExamChallenge: () => void;
  tickMockExamTimer: () => void;
  setMockExamAnswer: (optionIndex: number) => void;
  nextMockExamQuestion: () => void;
  prevMockExamQuestion: () => void;
  jumpMockExamQuestion: (index: number) => void;
  toggleMockExamFlag: () => void;
  submitMockExam: () => void;
  abandonMockExam: () => void;
}

export const createMockExamSlice: StateCreator<AppState, [], [], MockExamSlice> = (set, get) => ({
  mockExam: null,
  mockExamHistory: [],
  startMockExam: () => {
    const questionSet = getMockExamQuestions(30, 40);
    if (questionSet.length === 0) return;
    const durationSec = Math.max(60 * 45, questionSet.length * 150);
    set({
      activeSection: "mockExam",
      mockExam: {
        questionSet,
        answers: Array.from({ length: questionSet.length }, () => null),
        flagged: Array.from({ length: questionSet.length }, () => false),
        questionIndex: 0,
        durationSec,
        timeRemainingSec: durationSec,
        startedAtMs: Date.now(),
        finishedAtMs: null,
        submitted: false,
        challengeMeta: null,
        challengeAccepted: true,
      },
      moreMenuOpen: false,
    });
  },
  startMockExamChallenge: (input) => {
    const ids = input.ids.map((x) => x.trim()).filter(Boolean);
    if (ids.length === 0) return;
    const questionSet: ArenaQuestion[] = getChallengeQuestionSet(ids);
    if (questionSet.length === 0) return;
    const durationSec = Math.max(60 * 30, questionSet.length * 145);
    set({
      activeSection: "mockExam",
      mockExam: {
        questionSet,
        answers: Array.from({ length: questionSet.length }, () => null),
        flagged: Array.from({ length: questionSet.length }, () => false),
        questionIndex: 0,
        durationSec,
        timeRemainingSec: durationSec,
        startedAtMs: Date.now(),
        finishedAtMs: null,
        submitted: false,
        challengeMeta: {
          by: input.by.trim() || "Unknown_Operator",
          elapsedMs: input.elapsedMs,
          percent: input.percent,
        },
        challengeAccepted: false,
      },
      moreMenuOpen: false,
    });
  },
  acceptMockExamChallenge: () => {
    const run = get().mockExam;
    if (!run || run.challengeAccepted) return;
    set({ mockExam: { ...run, challengeAccepted: true } });
  },
  tickMockExamTimer: () => {
    const run = get().mockExam;
    if (!run || run.submitted || !run.challengeAccepted) return;
    if (run.timeRemainingSec <= 1) {
      const finalized: MockExamState = {
        ...run,
        timeRemainingSec: 0,
        submitted: true,
        finishedAtMs: Date.now(),
      };
      const entry = buildMockExamHistoryEntry(finalized);
      set({
        mockExam: finalized,
        mockExamHistory: [entry, ...get().mockExamHistory].slice(0, 32),
      });
      pushTrainingPlanFromRun(finalized);
      void submitMockExamResultInBackground(finalized);
      return;
    }
    set({ mockExam: { ...run, timeRemainingSec: run.timeRemainingSec - 1 } });
  },
  setMockExamAnswer: (optionIndex) => {
    const run = get().mockExam;
    if (!run || run.submitted || !run.challengeAccepted) return;
    if (optionIndex < 0 || optionIndex > 3) return;
    const answers = [...run.answers];
    answers[run.questionIndex] = optionIndex;
    set({ mockExam: { ...run, answers } });
  },
  nextMockExamQuestion: () => {
    const run = get().mockExam;
    if (!run || !run.challengeAccepted) return;
    const maxIdx = run.questionSet.length - 1;
    const idx = Math.min(maxIdx, run.questionIndex + 1);
    if (idx === run.questionIndex) return;
    set({ mockExam: { ...run, questionIndex: idx } });
  },
  prevMockExamQuestion: () => {
    const run = get().mockExam;
    if (!run || !run.challengeAccepted) return;
    const idx = Math.max(0, run.questionIndex - 1);
    if (idx === run.questionIndex) return;
    set({ mockExam: { ...run, questionIndex: idx } });
  },
  jumpMockExamQuestion: (index) => {
    const run = get().mockExam;
    if (!run || !run.challengeAccepted) return;
    const idx = Math.max(0, Math.min(run.questionSet.length - 1, Math.floor(index)));
    if (idx === run.questionIndex) return;
    set({ mockExam: { ...run, questionIndex: idx } });
  },
  toggleMockExamFlag: () => {
    const run = get().mockExam;
    if (!run || run.submitted || !run.challengeAccepted) return;
    const base = run.flagged?.length === run.questionSet.length ? run.flagged : Array.from({ length: run.questionSet.length }, () => false);
    const flagged = [...base];
    flagged[run.questionIndex] = !flagged[run.questionIndex];
    set({ mockExam: { ...run, flagged } });
  },
  submitMockExam: () => {
    const run = get().mockExam;
    if (!run || run.submitted || !run.challengeAccepted) return;
    const finalized: MockExamState = { ...run, submitted: true, finishedAtMs: Date.now() };
    const entry = buildMockExamHistoryEntry(finalized);
    set({
      mockExam: finalized,
      mockExamHistory: [entry, ...get().mockExamHistory].slice(0, 32),
    });
    pushTrainingPlanFromRun(finalized);
    void submitMockExamResultInBackground(finalized);
  },
  abandonMockExam: () =>
    set({
      activeSection: "command",
      mockExam: null,
      moreMenuOpen: false,
    }),
});
