/** XP bis zum nächsten Level — gleicher Start wie Command-HUD bei Level 12 */
export function globalXpToNextForLevel(level: number): number {
  return Math.min(99999, Math.floor(600 + level * 150));
}

/** Kumulatives Lifetime-XP aus abgeschlossenen Level-Balken plus aktueller Balken */
export function computeLifetimeXp(level: number, xpCurrent: number): number {
  const lv = Math.max(0, Math.floor(level));
  let sum = 0;
  for (let l = 0; l < lv; l += 1) {
    sum += globalXpToNextForLevel(l);
  }
  return sum + Math.max(0, Math.floor(xpCurrent));
}
