export function resolveUnlockedLoreIds(totalGlobalXp: number): string[] {
  const xp = Math.max(0, Math.floor(totalGlobalXp));
  return LORE_REGISTRY.filter((row) => xp >= row.xpThreshold)
    .map((row) => row.id)
    .slice();
}

export function findLoreFragmentById(id: string): LoreFragment | null {
  const row = LORE_REGISTRY.find((item) => item.id === id);
  return row ?? null;
}
