import { motion } from "framer-motion";
import { cn } from "../../../../lib/cn";
import { UNIVERSE_THEME_FALLBACK } from "../../../../styles/themes/universeThemes";

const STEPS: { id: string; label: string; tag: string }[] = [
  { id: "theory", label: "Theorie", tag: "Briefing" },
  { id: "snippets", label: "Snippets", tag: "Intel" },
  { id: "tasks", label: "Aufgaben", tag: "Field Ops" },
  { id: "free", label: "Bonus", tag: "Sandbox" },
];

type TutorialMissionRailProps = {
  /** 0 Theorie 1 Snippets 2 Aufgaben 3 Bonus */
  activeStepIndex: number;
  /** One short line what to do next no trailing punctuation */
  objectiveLine: string;
  reducedMotion: boolean;
};

export function TutorialMissionRail({ activeStepIndex, objectiveLine, reducedMotion }: TutorialMissionRailProps) {
  const active = Math.min(STEPS.length - 1, Math.max(0, activeStepIndex));
  const primary = `var(--universe-primary, ${UNIVERSE_THEME_FALLBACK.primary})`;
  const accent = `var(--universe-accent, ${UNIVERSE_THEME_FALLBACK.accent})`;

  return (
    <div
      className="academy-tutorial-rail rounded-xl border border-solid bg-gradient-to-b from-slate-950/95 to-slate-950/80 px-3 py-3 backdrop-blur-md sm:px-4"
      style={{
        borderColor: `color-mix(in srgb, ${primary} 22%, transparent)`,
        boxShadow: `0 0 40px color-mix(in srgb, ${primary} 9%, transparent)`,
      }}
    >
      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between gap-2">
          <p
            className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em]"
            style={{ color: `color-mix(in srgb, ${primary} 78%, white)` }}
          >
            Tutorial uplink
          </p>
          <span
            className="rounded border border-solid px-2 py-0.5 font-mono text-[8px] font-semibold uppercase tracking-[0.16em]"
            style={{
              borderColor: `color-mix(in srgb, ${accent} 42%, transparent)`,
              backgroundColor: `color-mix(in srgb, ${accent} 14%, rgb(15 23 42))`,
              color: `color-mix(in srgb, ${accent} 72%, white)`,
            }}
          >
            Handgefuehrt
          </span>
        </div>
        <ol className="flex list-none items-stretch gap-1 sm:gap-1.5" aria-label="Tutorialphasen">
          {STEPS.map((step, index) => {
            const done = index < active;
            const current = index === active;
            const stepSurface =
              current
                ? {
                    borderColor: `color-mix(in srgb, ${primary} 58%, transparent)`,
                    backgroundColor: `color-mix(in srgb, ${primary} 16%, rgb(15 23 42))`,
                    boxShadow: `inset 0 0 22px color-mix(in srgb, ${primary} 14%, transparent)`,
                  }
                : done
                  ? {
                      borderColor: `color-mix(in srgb, ${accent} 38%, transparent)`,
                      backgroundColor: `color-mix(in srgb, ${accent} 11%, rgb(15 23 42))`,
                    }
                  : {};

            return (
              <li key={step.id} className="relative min-w-0 flex-1">
                <div
                  className={cn(
                    "flex h-full flex-col rounded-lg border border-solid px-1.5 py-2 text-center transition-colors sm:px-2 sm:py-2.5",
                    !current && !done ? "border-white/[0.08] bg-slate-950/40 opacity-55" : "",
                    reducedMotion ? "" : "duration-200",
                  )}
                  style={current || done ? stepSurface : undefined}
                >
                  {current && !reducedMotion ? (
                    <motion.span
                      layoutId="tutorial-rail-pulse"
                      className="pointer-events-none absolute inset-0 rounded-lg border border-solid"
                      style={{ borderColor: `color-mix(in srgb, ${primary} 36%, transparent)` }}
                      initial={{ opacity: 0.35 }}
                      animate={{ opacity: [0.35, 0.72, 0.35] }}
                      transition={{ duration: 2.4, repeat: Number.POSITIVE_INFINITY, ease: "easeInOut" }}
                    />
                  ) : null}
                  <span
                    className="relative z-[1] font-mono text-[8px] font-semibold uppercase tracking-[0.14em] sm:text-[9px]"
                    style={
                      current
                        ? { color: `color-mix(in srgb, ${primary} 82%, white)` }
                        : done
                          ? { color: `color-mix(in srgb, ${accent} 68%, white)` }
                          : undefined
                    }
                  >
                    {step.tag}
                  </span>
                  <span
                    className={cn(
                      "relative z-[1] mt-0.5 truncate text-[10px] font-semibold tracking-tight sm:text-[11px]",
                      !current && !done ? "text-slate-500" : "",
                    )}
                    style={
                      current
                        ? { color: `color-mix(in srgb, ${primary} 92%, white)` }
                        : done
                          ? { color: `color-mix(in srgb, ${accent} 78%, white)` }
                          : undefined
                    }
                  >
                    {done ? `${step.label} OK` : step.label}
                  </span>
                </div>
              </li>
            );
          })}
        </ol>
        <p className="text-center font-mono text-[10px] leading-relaxed tracking-[0.06em] text-slate-300/95 sm:text-[11px]">
          {objectiveLine}
        </p>
        {active < STEPS.length - 1 ? (
          <p className="text-center font-mono text-[9px] uppercase tracking-[0.18em] text-slate-500">Naechste Phasen folgen automatisch</p>
        ) : null}
      </div>
    </div>
  );
}
