import { motion, useReducedMotion } from "framer-motion";
import { EXAMS } from "../../data/exams";
import { MAX_EQUIPPED_PERKS, PERKS } from "../../data/perks";
import type { PerkId } from "../../data/perks";
import { IconArrowLeft, IconCrosshair, IconPlay } from "../icons/ThinLineIcons";
import { cn } from "../../lib/cn";
import { itemRevealHeavy, springHeavy, staggerContainer } from "../../motion/variants";
import { accentStyles } from "../../types/accent";
import { useAppStore } from "../../store/useAppStore";

function formatDuration(min: number): string {
  return `${min} Min Dauer`;
}

function formatPass(rate: number): string {
  return `${rate}% Bestehen`;
}

const dockTap = { scale: 0.94 as const, y: 3 as const };

export function LoadoutScreen() {
  const prefersReduced = useReducedMotion();
  const selectedExamId = useAppStore((s) => s.selectedExamId);
  const setSelectedExamId = useAppStore((s) => s.setSelectedExamId);
  const selectedPerkIds = useAppStore((s) => s.selectedPerkIds);
  const togglePerk = useAppStore((s) => s.togglePerk);
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  const startArena = useAppStore((s) => s.startArena);

  const canDeploy = selectedPerkIds.length <= MAX_EQUIPPED_PERKS;

  return (
    <div className="relative mx-auto w-full max-w-[1240px] space-y-10">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <motion.button
          type="button"
          whileTap={dockTap}
          transition={springHeavy}
          onClick={() => setActiveSection("command")}
          className="inline-flex items-center gap-2 border border-white/[0.1] bg-surface-muted/40 px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-foreground-muted hover-breathe hover:border-white/[0.14] hover:text-foreground"
        >
          <IconArrowLeft className="size-4" />
          Zurück zum Hub
        </motion.button>
        <div className="flex items-center gap-2 font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
          <IconCrosshair className="size-4" />
          Loadout / Prüfungs-Select
        </div>
      </div>

      <motion.div
        variants={staggerContainer}
        initial="initial"
        animate="animate"
        className="space-y-4"
      >
        <motion.div variants={itemRevealHeavy}>
          <p className="font-mono text-[11px] font-medium uppercase tracking-[0.32em] text-foreground-muted">
            Wähle deine Prüfung
          </p>
          <h2 className="headline-cinema mt-2 text-3xl font-semibold sm:text-4xl">Character Select</h2>
          <p className="mt-2 max-w-2xl font-sans text-sm leading-relaxed text-foreground-muted sm:text-base">
            Jede Prüfung bringt andere Timer und Quoten · pick deinen Boss und rüste Perks für den Lauf
          </p>
        </motion.div>

        <motion.div variants={itemRevealHeavy} className="grid grid-cols-1 gap-5 md:grid-cols-3">
          {EXAMS.map((exam) => {
            const active = selectedExamId === exam.id;
            const styles = accentStyles[exam.accent];
            return (
              <motion.button
                key={exam.id}
                type="button"
                layout
                onClick={() => setSelectedExamId(exam.id)}
                whileHover={prefersReduced ? undefined : { y: -4 }}
                whileTap={dockTap}
                transition={springHeavy}
                className={cn(
                  "group relative overflow-hidden border bg-surface/90 p-6 text-left hover-breathe",
                  active
                    ? "border-signal/40 bg-signal/[0.06]"
                    : "border-white/[0.1] hover:border-white/[0.14]",
                )}
              >
                <div
                  className={cn(
                    "pointer-events-none absolute inset-0 opacity-0 transition-opacity duration-700 group-hover:opacity-100",
                    "bg-gradient-to-br",
                    styles.gradient,
                  )}
                />
                <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.12] mix-blend-overlay" />
                <div className="relative space-y-4">
                  <div className="flex items-center justify-between gap-2">
                    <span
                      className={cn(
                        "font-sans text-2xl font-semibold uppercase tracking-[-0.04em]",
                        active ? "text-foreground" : "text-foreground-muted",
                      )}
                    >
                      {exam.title}
                    </span>
                    {active ? (
                      <span className="border border-signal/35 bg-signal/[0.08] px-2 py-0.5 font-mono text-[9px] uppercase tracking-wider text-signal">
                        Equipped
                      </span>
                    ) : null}
                  </div>
                  <p className="font-sans text-xs leading-relaxed text-foreground-muted">{exam.tagline}</p>
                  <div className="flex flex-wrap gap-2">
                    <span className="border border-white/[0.1] px-3 py-1 font-mono text-[10px] font-medium uppercase tracking-wide text-foreground-muted">
                      {formatDuration(exam.durationMin)}
                    </span>
                    <span className="border border-white/[0.1] px-3 py-1 font-mono text-[10px] font-medium uppercase tracking-wide text-foreground-muted">
                      {formatPass(exam.passRatePercent)}
                    </span>
                  </div>
                </div>
              </motion.button>
            );
          })}
        </motion.div>

        <motion.div
          variants={itemRevealHeavy}
          className="relative overflow-hidden border border-white/[0.1] bg-surface-muted/40 p-6 backdrop-blur-xl"
        >
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.14]" />
          <div className="relative space-y-4">
            <div className="flex flex-wrap items-end justify-between gap-3">
              <div>
                <p className="font-mono text-[11px] font-medium uppercase tracking-[0.28em] text-foreground-muted">
                  Taktische Perks
                </p>
                <h3 className="headline-cinema mt-1 text-xl font-semibold">
                  Ausrüsten ({selectedPerkIds.length}/{MAX_EQUIPPED_PERKS})
                </h3>
              </div>
              <p className="max-w-xs font-sans text-xs leading-relaxed text-foreground-muted">
                Max zwei Slots · tippe zum Equippen vor dem Start
              </p>
            </div>
            <div className="flex flex-wrap gap-3">
              {PERKS.map((perk) => {
                const on = selectedPerkIds.includes(perk.id);
                const full = !on && selectedPerkIds.length >= MAX_EQUIPPED_PERKS;
                return (
                  <motion.button
                    key={perk.id}
                    type="button"
                    whileHover={full ? undefined : { scale: 1.02 }}
                    whileTap={full ? undefined : dockTap}
                    transition={springHeavy}
                    disabled={full}
                    onClick={() => togglePerk(perk.id as PerkId)}
                    className={cn(
                      "min-w-[140px] flex-1 border px-4 py-3 text-left transition-colors duration-700",
                      on
                        ? "border-signal/40 bg-signal/[0.08]"
                        : "border-white/[0.1] bg-transparent hover-breathe hover:border-white/[0.16]",
                      full && !on && "cursor-not-allowed opacity-40",
                    )}
                  >
                    <p className="font-mono text-sm font-semibold uppercase tracking-wide text-foreground">
                      {perk.title}
                    </p>
                    <p className="mt-1 font-sans text-[11px] leading-snug text-foreground-muted">{perk.blurb}</p>
                  </motion.button>
                );
              })}
            </div>
          </div>
        </motion.div>

        <motion.div variants={itemRevealHeavy} className="flex justify-center pt-2">
          <motion.button
            type="button"
            disabled={!canDeploy}
            onClick={() => startArena()}
            whileHover={canDeploy && !prefersReduced ? { scale: 1.02 } : undefined}
            whileTap={canDeploy ? dockTap : undefined}
            transition={springHeavy}
            className={cn(
              "inline-flex items-center gap-3 border border-signal/40 bg-signal/[0.1] px-10 py-4 font-mono text-sm font-semibold uppercase tracking-wide text-signal hover-breathe hover:border-signal/55 hover:bg-signal/[0.14]",
              !canDeploy && "cursor-not-allowed opacity-45",
            )}
          >
            <IconPlay className="size-6" />
            In die Arena
          </motion.button>
        </motion.div>
      </motion.div>
    </div>
  );
}
