import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useReactToPrint } from "react-to-print";
import { AchievementCabinet } from "../achievements/AchievementCabinet";
import { AudioVisualizerBars } from "../audio/AudioVisualizerBars";
import { PwaInstallButton } from "./PwaInstallButton";
import { RigCalibrationPanel } from "./RigCalibrationPanel";
import { ArtifactPedestal } from "./ArtifactPedestal";
import { SeasonLegacyBadge } from "./SeasonLegacyBadge";
import {
  IconGem,
  IconHexagon,
  IconLayers,
  IconPrinter,
  IconSparkles,
  IconTree,
} from "../icons/ThinLineIcons";
import { CODESNAP_LOGO_PATH } from "../../lib/brandAssets";
import { realmConqueredHexCount, sm2BucketsByTag } from "../../lib/dossierStats";
import { computeLifetimeXp } from "../../lib/xpCurve";
import { ihkGradeFromPercent } from "../../lib/mockExamGrading";
import { getNextRankMilestone, getPrestigeRankByLifetimeXp, getRankArtifact } from "../../lib/rankEngine";
import { sortSeasonArtifacts, type LegacyFactionFilter, type LegacySortMode } from "../../lib/sortSeasonArtifacts";
import { springHeavy } from "../../motion/variants";
import { cn } from "../../lib/cn";
import { useFeedback } from "../../hooks/useFeedback";
import { useAppStore } from "../../store/useAppStore";

const PRINT_CLASS = "codesnap-print-dossier";

function TagSm2Bar({ tag, cyan, yellow, magenta }: { tag: string; cyan: number; yellow: number; magenta: number }) {
  const total = cyan + yellow + magenta || 1;
  const pc = (n: number) => `${(n / total) * 100}%`;
  return (
    <div className="space-y-3 border-b border-white/[0.1] pb-6 last:border-0 last:pb-0">
      <div className="flex items-center justify-between gap-3">
        <span className="font-mono text-[11px] font-medium uppercase tracking-[0.2em] text-foreground dossier-print-title">
          {tag}
        </span>
        <span className="font-mono text-[10px] text-foreground-muted dossier-print-muted">
          {cyan}/{yellow}/{magenta} Slots
        </span>
      </div>
      <div className="flex h-2 w-full overflow-hidden border border-white/[0.1] bg-void/80 dossier-print-bar-track">
        <motion.div layout className="h-full bg-white/35 dossier-print-seg-cyan" style={{ width: pc(cyan) }} title="Stabil" />
        <motion.div layout className="h-full bg-white/18 dossier-print-seg-yellow" style={{ width: pc(yellow) }} title="Aktiv" />
        <motion.div layout className="h-full bg-signal/50 dossier-print-seg-magenta" style={{ width: pc(magenta) }} title="Neu" />
      </div>
      <div className="flex gap-5 font-mono text-[9px] uppercase tracking-wider text-foreground-muted dossier-print-muted">
        <span className="text-foreground/70">Stabil</span>
        <span className="text-titan">Aktiv</span>
        <span className="text-signal">Neu</span>
      </div>
    </div>
  );
}

function TrophyBadge({
  icon: Icon,
  label,
  value,
}: {
  icon: typeof IconGem;
  label: string;
  value: string;
}) {
  return (
    <div className="flex flex-col items-center gap-2 border border-white/[0.1] bg-void/40 px-4 py-4 dossier-trophy hover-breathe hover:border-white/[0.14]">
      <Icon className="size-6 text-foreground-muted" />
      <span className="font-mono text-lg font-semibold tabular-nums text-foreground dossier-print-value">{value}</span>
      <span className="text-center font-mono text-[10px] font-medium uppercase tracking-wide text-foreground-muted dossier-print-muted">
        {label}
      </span>
    </div>
  );
}

export function OperatorDossierView() {
  const feedback = useFeedback();
  const progress = useAppStore((s) => s.flashcardProgress);
  const flashcardTotalReviews = useAppStore((s) => s.flashcardTotalReviews);
  const gems = useAppStore((s) => s.gems);
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const globalXpToNext = useAppStore((s) => s.globalXpToNext);
  const realmTiles = useAppStore((s) => s.realmTiles);
  const unlockedNodes = useAppStore((s) => s.unlockedNodes);
  const progressUser = useAppStore((s) => s.progress);
  const authUser = useAppStore((s) => s.authUser);
  const operatorHandle = useAppStore((s) => s.operatorHandle);
  const cloudUplinkBusy = useAppStore((s) => s.cloudUplinkBusy);
  const cloudLastError = useAppStore((s) => s.cloudLastError);
  const unlockedAchievementIds = useAppStore((s) => s.unlockedAchievementIds);
  const seasonLegacyArtifacts = useAppStore((s) => s.seasonLegacyArtifacts);
  const mockExamHistory = useAppStore((s) => s.mockExamHistory);
  const ghostModeEnabled = useAppStore((s) => s.ghostModeEnabled);
  const setGhostModeEnabled = useAppStore((s) => s.setGhostModeEnabled);
  const [handleDraft, setHandleDraft] = useState("");
  const [handleBanner, setHandleBanner] = useState<null | { kind: "ok" | "err"; text: string }>(null);
  const [ghostBusy, setGhostBusy] = useState(false);
  const [ghostBanner, setGhostBanner] = useState<null | { kind: "ok" | "err"; text: string }>(null);
  const [artifactOpen, setArtifactOpen] = useState(false);
  const [exportBusy, setExportBusy] = useState(false);
  const [legacySortMode, setLegacySortMode] = useState<LegacySortMode>("NEWEST");
  const [legacyFactionFilter, setLegacyFactionFilter] = useState<LegacyFactionFilter>("ALL");
  const [bossRaidTitle, setBossRaidTitle] = useState<string | null>(null);
  const exportRef = useRef<HTMLDivElement>(null);
  const legacyOrderSigRef = useRef<string>("");
  const legacyReadyRef = useRef(false);
  const rotateX = useMotionValue(0);
  const rotateY = useMotionValue(0);
  const springRotateX = useSpring(rotateX, { mass: 1.2, damping: 35 });
  const springRotateY = useSpring(rotateY, { mass: 1.2, damping: 35 });
  const assetTransform = useTransform(
    [springRotateX, springRotateY],
    ([x, y]) => `rotateX(${x}deg) rotateY(${y}deg)`,
  );

  const bucketsByTag = useMemo(() => sm2BucketsByTag(progress), [progress]);
  const hexCount = useMemo(() => realmConqueredHexCount(realmTiles), [realmTiles]);
  const tagsSorted = useMemo(() => Object.keys(bucketsByTag).sort(), [bucketsByTag]);

  const stripPrintClass = useCallback(() => {
    document.documentElement.classList.remove(PRINT_CLASS);
    setExportBusy(false);
  }, []);

  useEffect(() => {
    window.addEventListener("afterprint", stripPrintClass);
    return () => window.removeEventListener("afterprint", stripPrintClass);
  }, [stripPrintClass]);

  const doPrint = useReactToPrint({
    contentRef: exportRef,
    documentTitle: "codesnap-operator-dossier",
    onBeforePrint: async () => {
      document.documentElement.classList.add(PRINT_CLASS);
    },
    onAfterPrint: () => {
      stripPrintClass();
    },
  });

  const handlePrint = useCallback(async () => {
    setExportBusy(true);
    await new Promise<void>((resolve) => window.setTimeout(resolve, 620));
    await doPrint();
  }, [doPrint]);

  const xpLabel = `${globalXP}`;
  const displayHandle = operatorHandle || progressUser.displayName || "Unknown_Operator";
  const rankArtifact = getRankArtifact(userLevel);
  const nextMilestone = getNextRankMilestone(userLevel);
  const prestigeTitle = getPrestigeRankByLifetimeXp(computeLifetimeXp(userLevel, globalXP)).title;

  const mockExamStats = useMemo(() => {
    const total = mockExamHistory.length;
    if (total === 0) {
      return {
        exams: 0,
        avgPercent: 0,
        avgGrade: 6,
        strongestTags: [] as Array<[string, number]>,
      };
    }
    const avgPercent = mockExamHistory.reduce((acc, row) => acc + row.percent, 0) / total;
    const avgGrade = ihkGradeFromPercent(avgPercent);
    const tagHits = new Map<string, number>();
    for (const row of mockExamHistory) {
      for (const [tag, hits] of Object.entries(row.correctTagHits)) {
        tagHits.set(tag, (tagHits.get(tag) ?? 0) + hits);
      }
    }
    const strongestTags = [...tagHits.entries()].sort((a, b) => b[1] - a[1]).slice(0, 8);
    return { exams: total, avgPercent, avgGrade, strongestTags };
  }, [mockExamHistory]);
  const recentMockExams = useMemo(() => mockExamHistory.slice(0, 6), [mockExamHistory]);
  const visibleSeasonArtifacts = useMemo(
    () => sortSeasonArtifacts(seasonLegacyArtifacts, legacySortMode, legacyFactionFilter),
    [seasonLegacyArtifacts, legacySortMode, legacyFactionFilter],
  );
  const visibleLegacySig = useMemo(
    () => visibleSeasonArtifacts.map((a) => `${a.seasonKey}#${a.rank}`).join("|"),
    [visibleSeasonArtifacts],
  );

  useEffect(() => {
    setHandleDraft(displayHandle);
  }, [displayHandle]);

  const saveHandle = useCallback(async () => {
    if (!authUser) {
      setHandleBanner({ kind: "err", text: "Melde dich im Uplink an um den Handle zu speichern" });
      return;
    }
    const res = await import("../../lib/syncController").then((m) => m.setOperatorHandle(handleDraft));
    if (!res.ok) {
      setHandleBanner({ kind: "err", text: res.error ?? cloudLastError ?? "Handle konnte nicht gespeichert werden" });
      return;
    }
    setHandleBanner({ kind: "ok", text: `Handle gespeichert als ${res.handle}` });
  }, [authUser, cloudLastError, handleDraft]);

  const toggleGhostMode = useCallback(async () => {
    if (ghostBusy) return;
    const next = !ghostModeEnabled;
    setGhostBusy(true);
    setGhostBanner(null);
    setGhostModeEnabled(next);
    const res = await import("../../lib/syncController").then((m) => m.setOperatorGhostMode(next));
    if (!res.ok) {
      setGhostModeEnabled(!next);
      setGhostBanner({ kind: "err", text: res.error ?? "Ghost Mode konnte nicht gespeichert werden" });
      setGhostBusy(false);
      return;
    }
    setGhostBanner({ kind: "ok", text: next ? "Ghost Mode aktiv Stream maskiert" : "Ghost Mode aus Stream sichtbar" });
    setGhostBusy(false);
  }, [ghostBusy, ghostModeEnabled, setGhostModeEnabled]);

  useEffect(() => {
    feedback.dossierSubBassHum();
  }, [feedback]);

  useEffect(() => {
    if (!authUser?.id) {
      setBossRaidTitle(null);
      return;
    }
    let cancelled = false;
    void import("../../lib/syncController")
      .then((m) => m.fetchBossRaidTitleForUser(authUser.id))
      .then((title) => {
        if (!cancelled) setBossRaidTitle(title);
      })
      .catch(() => {
        if (!cancelled) setBossRaidTitle(null);
      });
    return () => {
      cancelled = true;
    };
  }, [authUser?.id]);

  useEffect(() => {
    if (!legacyReadyRef.current) {
      legacyReadyRef.current = true;
      legacyOrderSigRef.current = visibleLegacySig;
      return;
    }
    if (visibleLegacySig !== legacyOrderSigRef.current) {
      feedback.flip();
      legacyOrderSigRef.current = visibleLegacySig;
    }
  }, [feedback, visibleLegacySig]);

  const onArtifactMove = useCallback(
    (event: React.PointerEvent<HTMLButtonElement>) => {
      const rect = event.currentTarget.getBoundingClientRect();
      const px = (event.clientX - rect.left) / rect.width - 0.5;
      const py = (event.clientY - rect.top) / rect.height - 0.5;
      rotateX.set(py * -10);
      rotateY.set(px * 10);
    },
    [rotateX, rotateY],
  );

  const resetArtifactTilt = useCallback(() => {
    rotateX.set(0);
    rotateY.set(0);
  }, [rotateX, rotateY]);

  return (
    <div ref={exportRef} className="operator-dossier relative -mx-4 space-y-12 pb-20 sm:-mx-6">
      <img
        src={CODESNAP_LOGO_PATH}
        alt=""
        width={512}
        height={512}
        decoding="async"
        draggable={false}
        className="dossier-brand-watermark pointer-events-none absolute right-6 top-8 z-10 h-24 w-24 object-contain opacity-[0.08] select-none sm:h-28 sm:w-28 print:h-36 print:w-36"
      />

      <header className="dossier-hero relative overflow-hidden border border-white/[0.1] bg-surface/40 p-8 sm:p-10">
        <span
          className="pointer-events-none absolute -left-2 top-1/2 z-0 -translate-y-1/2 select-none font-sans text-[clamp(10rem,36vw,22rem)] font-bold tabular-nums leading-none text-white/[0.05]"
          aria-hidden
        >
          {userLevel}
        </span>
        <span
          className="pointer-events-none absolute bottom-0 right-0 z-0 max-w-[90%] translate-y-1/4 select-none truncate text-right font-sans text-[clamp(6rem,22vw,14rem)] font-bold tabular-nums leading-none text-white/[0.05]"
          aria-hidden
        >
          {xpLabel}
        </span>

        <div className="relative z-10 flex flex-wrap items-end gap-8">
          <motion.button
            type="button"
            data-print-hide
            whileHover={{ scale: 1.05 }}
            onPointerMove={onArtifactMove}
            onPointerLeave={resetArtifactTilt}
            onClick={() => {
              feedback.artifactClick();
              setArtifactOpen((v) => !v);
            }}
            style={{
              transformStyle: "preserve-3d",
              transform: assetTransform,
            }}
            transition={springHeavy}
            className="group relative flex aspect-square w-[5.5rem] shrink-0 items-center justify-center [perspective:1200px] print:border-zinc-300"
          >
            <ArtifactPedestal artifact={rankArtifact} tiltX={springRotateX} tiltY={springRotateY} variant="hero" className="print:border-zinc-300" />
          </motion.button>
          <div className="min-w-0 flex-1 space-y-3">
            <p className="font-mono text-[10px] font-medium uppercase tracking-[0.35em] text-foreground-muted dossier-print-muted">
              CodeSnap operator file
            </p>
            <h1 className="headline-cinema max-w-[20ch] text-4xl font-semibold sm:text-6xl dossier-print-title">
              {displayHandle}
            </h1>
            <p className="max-w-xl font-sans text-sm leading-relaxed text-foreground-muted dossier-print-muted">
              Vollständiges Lernprofil inklusive SM-2 Matrix und Kampagnen-Trophäen · exportierbar für Ausbilder
            </p>
            <div className="max-w-xl space-y-2" data-print-hide>
              <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
                Operator Handle
              </p>
              <div className="flex flex-wrap items-end gap-3 border-b border-titan/55 pb-2">
                <input
                  type="text"
                  value={handleDraft}
                  onChange={(e) => setHandleDraft(e.target.value)}
                  placeholder="Unknown_Operator"
                  maxLength={24}
                  className="min-w-[220px] flex-1 bg-transparent font-mono text-sm text-foreground outline-none placeholder:text-foreground-muted/60"
                />
                <motion.button
                  type="button"
                  whileTap={{ scale: 0.95, y: 2 }}
                  transition={springHeavy}
                  disabled={cloudUplinkBusy}
                  onClick={() => void saveHandle()}
                  className="border border-white/[0.1] bg-transparent px-3 py-1.5 font-mono text-[10px] font-semibold uppercase tracking-[0.18em] text-foreground-muted hover-breathe hover:border-white/[0.14] hover:text-foreground disabled:opacity-50"
                >
                  Handle speichern
                </motion.button>
              </div>
              {handleBanner ? (
                <p className={handleBanner.kind === "ok" ? "font-mono text-[10px] text-foreground-muted" : "font-mono text-[10px] text-signal"}>
                  {handleBanner.text}
                </p>
              ) : null}
              <div className="mt-2 border border-white/[0.1] bg-black/25 px-3 py-2">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
                    Ghost Mode
                  </p>
                  <motion.button
                    type="button"
                    whileTap={{ scale: 0.96, y: 1 }}
                    disabled={ghostBusy}
                    onClick={() => void toggleGhostMode()}
                    className={cn(
                      "border px-2.5 py-1 font-mono text-[9px] font-semibold uppercase tracking-[0.16em]",
                      ghostModeEnabled
                        ? "border-cyan-300/45 bg-cyan-500/12 text-cyan-100"
                        : "border-white/[0.12] bg-transparent text-foreground-muted",
                    )}
                  >
                    {ghostBusy ? "Syncing" : ghostModeEnabled ? "Hidden" : "Visible"}
                  </motion.button>
                </div>
                <p className="mt-1 font-mono text-[10px] uppercase tracking-[0.1em] text-foreground-muted">
                  Eigene Social Pulse Events bleiben außerhalb des globalen Streams
                </p>
                {ghostBanner ? (
                  <p className={cn("mt-1 font-mono text-[10px]", ghostBanner.kind === "ok" ? "text-foreground-muted" : "text-signal")}>
                    {ghostBanner.text}
                  </p>
                ) : null}
              </div>
            </div>
            <div className="flex flex-wrap gap-2 pt-1 font-mono text-[11px] text-foreground-muted dossier-print-muted">
              <span className="border border-white/[0.1] bg-void/50 px-3 py-1 dossier-print-chip">LV {userLevel}</span>
              <span className="border border-white/[0.1] bg-void/50 px-3 py-1 dossier-print-chip">{rankArtifact.tier.replaceAll("_", " ")}</span>
              {bossRaidTitle ? (
                <span className="border border-amber-300/40 bg-amber-500/[0.14] px-3 py-1 text-amber-100 dossier-print-chip">
                  {bossRaidTitle}
                </span>
              ) : null}
              <span className="border border-white/[0.1] bg-void/50 px-3 py-1 dossier-print-chip">
                XP {globalXP}/{globalXpToNext}
              </span>
              <span className="border border-white/[0.1] bg-void/50 px-3 py-1 text-signal dossier-print-chip">G {gems}</span>
            </div>
            {artifactOpen ? (
              <div className="max-w-xl border border-white/[0.1] bg-void/40 px-4 py-3">
                <p className={cn("font-mono text-[10px] uppercase tracking-[0.22em]", rankArtifact.accentClass)}>
                  Rang Artefakt
                </p>
                <p className="mt-2 font-sans text-sm text-foreground">
                  {rankArtifact.tier.replaceAll("_", " ")}
                </p>
                <p className="mt-1 font-mono text-[10px] uppercase tracking-[0.18em] text-foreground-muted">
                  {nextMilestone
                    ? `Nächster Rang ${nextMilestone.nextTier.replaceAll("_", " ")} ab Level ${nextMilestone.nextLevel}`
                    : "Maximaler Rang erreicht"}
                </p>
              </div>
            ) : null}
          </div>
          <motion.button
            type="button"
            data-print-hide
            whileTap={{ scale: 0.97, y: 2 }}
            transition={springHeavy}
            onClick={() => void handlePrint()}
            disabled={exportBusy}
            className="inline-flex items-center gap-2 border border-white/[0.12] bg-void/50 px-4 py-2.5 font-mono text-[11px] font-semibold uppercase tracking-wide text-foreground hover-breathe hover:border-white/[0.18] print:hidden"
          >
            <IconPrinter className="size-4" />
            {exportBusy ? "Generating Neural Print" : "Export Operator Dossier"}
          </motion.button>
        </div>
      </header>

      <RigCalibrationPanel />

      <section className="dossier-section space-y-6 border border-white/[0.1] bg-surface/35 p-6 sm:p-8">
        <div>
          <h2 className="headline-cinema text-2xl font-semibold dossier-print-title">SM-2 Matrix</h2>
          <p className="mt-2 max-w-prose font-sans text-xs leading-relaxed text-foreground-muted dossier-print-muted">
            Segmentierte Balken pro Themengebiet · Lesbarkeit vor Effekt
          </p>
        </div>
        <div className="grid gap-0">
          {tagsSorted.map((tag) => {
            const b = bucketsByTag[tag];
            return <TagSm2Bar key={tag} tag={tag} cyan={b.cyan} yellow={b.yellow} magenta={b.magenta} />;
          })}
        </div>
      </section>

      <section className="dossier-section space-y-6 border border-white/[0.1] bg-surface/35 p-6 sm:p-8">
        <AchievementCabinet unlockedIds={unlockedAchievementIds} />
      </section>

      <section className="dossier-section space-y-6 border border-amber-300/24 bg-gradient-to-br from-amber-500/[0.06] via-surface/35 to-slate-300/[0.04] p-6 sm:p-8">
        <div className="space-y-2">
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-amber-100/85 dossier-print-muted">
            Legacy Achievements
          </p>
          <h2 className="headline-cinema text-2xl font-semibold dossier-print-title">Season Relikte</h2>
          <p className="font-sans text-xs leading-relaxed text-foreground-muted dossier-print-muted">
            Hall Of Fame Signaturen aus vergangenen Kampagnen
          </p>
        </div>
        {seasonLegacyArtifacts.length === 0 ? (
          <div className="border border-white/[0.1] bg-black/30 px-4 py-5">
            <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
              Noch keine Season Artefakte geborgen
            </p>
            <p className="mt-1 font-sans text-xs text-foreground-muted">
              Hol dir einen Top Platz im nächsten Season Cataclysm
            </p>
          </div>
        ) : (
          <>
            <div className="flex flex-wrap items-center gap-2 border border-white/[0.1] bg-black/25 px-2 py-2">
              <span className="px-2 font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
                Sort
              </span>
              {([
                ["NEWEST", "Neueste"],
                ["TOP_RANK", "Top Rank"],
                ["FACTION", "Fraktion"],
              ] as const).map(([id, label]) => (
                <motion.button
                  key={id}
                  type="button"
                  whileTap={{ scale: 0.96, y: 1 }}
                  transition={springHeavy}
                  onPointerEnter={() => feedback.hoverTick()}
                  onClick={() => setLegacySortMode(id)}
                  className={cn(
                    "border px-2.5 py-1 font-mono text-[9px] font-semibold uppercase tracking-[0.18em]",
                    legacySortMode === id
                      ? "border-amber-300/45 bg-amber-500/15 text-amber-100"
                      : "border-white/[0.12] bg-transparent text-foreground-muted hover:border-white/[0.18] hover:text-foreground",
                  )}
                >
                  {label}
                </motion.button>
              ))}
              <span className="ml-1 px-2 font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
                Sieger
              </span>
              {([
                ["ALL", "Alle"],
                ["FISI", "FISI"],
                ["FIAE", "FIAE"],
              ] as const).map(([id, label]) => (
                <motion.button
                  key={id}
                  type="button"
                  whileTap={{ scale: 0.96, y: 1 }}
                  transition={springHeavy}
                  onPointerEnter={() => feedback.hoverTick()}
                  onClick={() => setLegacyFactionFilter(id)}
                  className={cn(
                    "border px-2.5 py-1 font-mono text-[9px] font-semibold uppercase tracking-[0.18em]",
                    legacyFactionFilter === id
                      ? id === "FISI"
                        ? "border-signal/50 bg-signal/[0.14] text-signal"
                        : id === "FIAE"
                          ? "border-fuchsia-400/45 bg-fuchsia-500/12 text-fuchsia-200"
                          : "border-white/[0.2] bg-white/[0.08] text-foreground"
                      : "border-white/[0.12] bg-transparent text-foreground-muted hover:border-white/[0.18] hover:text-foreground",
                  )}
                >
                  {label}
                </motion.button>
              ))}
            </div>
            {visibleSeasonArtifacts.length === 0 ? (
              <div className="border border-white/[0.1] bg-black/25 px-4 py-4">
                <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
                  Kein Relikt für diesen Filter
                </p>
              </div>
            ) : (
              <motion.div
                layout
                transition={springHeavy}
                className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4"
              >
                {visibleSeasonArtifacts.map((artifact) => (
                  <SeasonLegacyBadge key={`${artifact.seasonKey}-${artifact.rank}`} artifact={artifact} />
                ))}
              </motion.div>
            )}
          </>
        )}
      </section>

      <section className="dossier-section space-y-6 border border-emerald-300/28 bg-gradient-to-r from-emerald-500/[0.08] via-surface/40 to-cyan-500/[0.06] p-6 sm:p-8">
        <div className="space-y-2">
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-foreground-muted dossier-print-muted">
            Nexus Certification
          </p>
          <h2 className="headline-cinema text-2xl font-semibold dossier-print-title">Operator Zertifikat</h2>
          <p className="font-sans text-xs leading-relaxed text-foreground-muted dossier-print-muted">
            Offizieller Leistungsnachweis für Ausbilder und Projektprüfung
          </p>
        </div>
        <div className="dossier-cert-panel grid gap-3 border border-white/[0.12] bg-black/25 p-4 font-mono text-[11px] uppercase tracking-[0.18em] text-foreground sm:grid-cols-2">
          <p>Operator {displayHandle}</p>
          <p>Rang {prestigeTitle}</p>
          <p>Mock Exams {mockExamStats.exams}</p>
          <p>
            Notendurchschnitt {mockExamStats.avgGrade} · {mockExamStats.avgPercent.toFixed(1)}%
          </p>
        </div>
        <div className="space-y-2 border border-white/[0.1] bg-void/25 p-4 font-mono text-[10px] uppercase tracking-[0.16em] text-foreground-muted">
          <p className="dossier-print-title text-foreground">Letzte Mock Exam Ergebnisse</p>
          {recentMockExams.length === 0 ? (
            <p>Noch keine Prüfungsversuche gespeichert</p>
          ) : (
            recentMockExams.map((row, idx) => (
              <p key={`${row.completedAtMs}-${idx}`}>
                Versuch {idx + 1} · Note {row.grade} · {row.percent.toFixed(1)}% · {row.correctAnswers}/{row.totalQuestions}
              </p>
            ))
          )}
        </div>
      </section>

      <section className="dossier-section space-y-6 border border-white/[0.1] bg-surface/35 p-6 sm:p-8">
        <h2 className="headline-cinema text-2xl font-semibold dossier-print-title">Skill Matrix</h2>
        <p className="font-sans text-xs text-foreground-muted dossier-print-muted">
          Tags aus korrekt gelösten Mock Exam Fragen
        </p>
        {mockExamStats.strongestTags.length === 0 ? (
          <p className="font-mono text-xs uppercase tracking-[0.18em] text-foreground-muted">Noch keine Mock Exam Daten</p>
        ) : (
          <div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-3">
            {mockExamStats.strongestTags.map(([tag, hits]) => (
              <div
                key={tag}
                className="dossier-skill-chip border border-white/[0.1] bg-void/35 px-3 py-2 font-mono text-[11px] uppercase tracking-[0.16em] text-foreground"
              >
                {tag} · {hits} Treffer
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="dossier-section space-y-6 border border-white/[0.1] bg-surface/35 p-6 sm:p-8">
        <h2 className="headline-cinema text-2xl font-semibold dossier-print-title">Trophy Room</h2>
        <p className="font-sans text-xs text-foreground-muted dossier-print-muted">
          Harte Stats · offline erarbeitet
        </p>
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
          <TrophyBadge icon={IconGem} label="Gems" value={String(gems)} />
          <TrophyBadge icon={IconSparkles} label="Level" value={String(userLevel)} />
          <TrophyBadge icon={IconHexagon} label="Realm Felder" value={String(hexCount)} />
          <TrophyBadge icon={IconLayers} label="Kartenreviews" value={String(flashcardTotalReviews)} />
          <TrophyBadge icon={IconTree} label="Skill-Knoten" value={String(unlockedNodes.length)} />
        </div>
      </section>

      <section
        data-print-hide
        className="grid gap-8 border border-white/[0.1] bg-void/30 p-6 sm:grid-cols-2 sm:p-8"
      >
        <div>
          <p className="mb-2 font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
            Signal
          </p>
          <AudioVisualizerBars compact />
        </div>
        <div className="flex flex-col justify-end">
          <PwaInstallButton />
        </div>
      </section>
    </div>
  );
}
