import { AnimatePresence, motion } from "framer-motion";
import { UNIVERSE_THEME_FALLBACK } from "../../../../styles/themes/universeThemes";

type TutorialXpFloatProps = {
  amount: number;
  nonce: number;
  reducedMotion: boolean;
};

export function TutorialXpFloat({ amount, nonce, reducedMotion }: TutorialXpFloatProps) {
  const primary = `var(--universe-primary, ${UNIVERSE_THEME_FALLBACK.primary})`;

  return (
    <div className="pointer-events-none fixed bottom-[5.75rem] left-1/2 z-[55] flex -translate-x-1/2 justify-center" aria-hidden>
      <AnimatePresence mode="wait">
        <motion.span
          key={nonce}
          initial={reducedMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: 10, scale: 0.94 }}
          animate={reducedMotion ? { opacity: 1, y: 0 } : { opacity: 1, y: -42, scale: 1 }}
          exit={reducedMotion ? { opacity: 0 } : { opacity: 0, y: -64 }}
          transition={{ duration: reducedMotion ? 0.06 : 0.75, ease: "easeOut" }}
          className="font-mono text-sm font-bold tabular-nums tracking-wide"
          style={{
            color: `color-mix(in srgb, ${primary} 88%, white)`,
            textShadow: `0 0 18px color-mix(in srgb, ${primary} 55%, transparent), 0 0 36px color-mix(in srgb, ${primary} 28%, transparent)`,
          }}
        >
          +{amount} XP
        </motion.span>
      </AnimatePresence>
    </div>
  );
}
