import { motion, useReducedMotion } from "framer-motion";
import { useEffect } from "react";
import { useRegisterSW } from "virtual:pwa-register/react";
import { springHeavy } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

const PATCH_NOTES = ["Optimizing Uplink", "Securing Vault", "Refining Signal Matrix"] as const;

/** Phase 54.1 — kritischer Patch-Hinweis für SW-Updates */
export function SystemPatchOverlay() {
  const prefersReduced = useReducedMotion();
  const setSwNeedRefresh = useAppStore((s) => s.setSwNeedRefresh);
  const swNeedRefresh = useAppStore((s) => s.swNeedRefresh);
  const { needRefresh, updateServiceWorker } = useRegisterSW({ immediate: true });
  const ready = needRefresh[0];

  useEffect(() => {
    setSwNeedRefresh(ready);
  }, [ready, setSwNeedRefresh]);

  if (!swNeedRefresh) return null;

  return (
    <div className="pointer-events-none fixed inset-0 z-[600] flex items-start justify-center px-4 pt-20 sm:pt-24">
      <motion.div
        initial={{ opacity: 0, y: -10, scale: 0.98 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={prefersReduced ? { duration: 0.14 } : springHeavy}
        className="pointer-events-auto relative w-full max-w-2xl border border-emerald-300/45 bg-black/78 p-5 shadow-[0_0_34px_rgb(16_185_129_/0.22),inset_0_0_24px_rgb(16_185_129_/0.2)] backdrop-blur-md sm:p-6"
      >
        <motion.div
          aria-hidden
          className="absolute inset-0 border border-emerald-300/30"
          animate={
            prefersReduced
              ? { opacity: 0.55 }
              : { opacity: [0.42, 0.92, 0.42], boxShadow: ["0 0 18px rgb(16 185 129 / 0.16)", "0 0 36px rgb(16 185 129 / 0.3)", "0 0 18px rgb(16 185 129 / 0.16)"] }
          }
          transition={prefersReduced ? { duration: 0 } : { duration: 1.7, repeat: Infinity, ease: "easeInOut" }}
        />
        <p className="relative z-10 font-mono text-[10px] font-black uppercase tracking-[0.28em] text-emerald-200">
          NEW SYSTEM PATCH DETECTED
        </p>
        <ul className="relative z-10 mt-4 space-y-2 border-t border-emerald-300/25 pt-4 font-mono text-[11px] uppercase tracking-[0.18em] text-emerald-100/90">
          {PATCH_NOTES.map((note) => (
            <li key={note} className="flex items-center gap-2">
              <span className="text-emerald-300">■</span>
              <span>{note}</span>
            </li>
          ))}
        </ul>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => void updateServiceWorker(true)}
          className="relative z-10 mt-5 inline-flex items-center border border-emerald-300/45 bg-emerald-500/[0.14] px-5 py-2.5 font-mono text-xs font-bold uppercase tracking-[0.2em] text-emerald-100 hover-breathe hover:bg-emerald-500/[0.2]"
        >
          APPLY PATCH
        </motion.button>
      </motion.div>
    </div>
  );
}
