import type { StateCreator } from "zustand";
import { canUnlockNode } from "../../data/skillTree";
import { INITIAL_PSEUDO_UNLOCKED, PSEUDO_LEVELS } from "../../data/pseudoLevels";
import { INITIAL_SQL_UNLOCKED, SQL_MISSIONS } from "../../data/sqlMissions";
import { INITIAL_SUPPORT_INBOX_IDS, SUPPORT_TICKET_POOL } from "../../data/supportTickets";
import { axialNeighbors, realmHexCoordinates, tileKey } from "../../lib/hexLayout";
import { REALM_BUILD_COSTS, type RealmBuildKind, type RealmTileState } from "../../types/realmQuest";
import type { RealmFactionId } from "../../types/faction";
import type { AppState } from "../useAppStore";

const DEFAULT_UNLOCKED_NODES = ["nexus-root"] as const;

function createInitialRealmTiles(): Record<string, RealmTileState> {
  const tiles: Record<string, RealmTileState> = {};
  for (const { q, r } of realmHexCoordinates()) {
    tiles[tileKey(q, r)] = {
      structure: q === 0 && r === 0 ? "main" : "empty",
    };
  }
  return tiles;
}

export interface RealmSlice {
  unlockedNodes: string[];
  tryUnlockSkillNode: (nodeId: string) => void;
  selectedFaction: RealmFactionId | null;
  setSelectedFaction: (id: RealmFactionId | null) => void;
  nexusView: AppState["nexusView"];
  setNexusView: (v: AppState["nexusView"]) => void;
  openNexusArcade: () => void;
  openNexusTree: () => void;
  enterRealmFaction: () => void;
  enterRealmBoard: () => void;
  sqlUnlockedLevels: string[];
  completeSqlMission: (missionId: string) => void;
  enterSqlAdventure: () => void;
  enterSqlSandbox: () => void;
  pseudoUnlockedLevels: string[];
  completePseudoLevel: (levelId: string) => void;
  enterPseudoTrainer: () => void;
  supportInboxIds: string[];
  resolvedTickets: string[];
  enqueueSupportTicket: () => void;
  resolveSupportTicket: (ticketId: string) => void;
  enterItSupport: () => void;
  realmGold: number;
  realmDiamonds: number;
  realmKnowledge: number;
  realmTiles: Record<string, RealmTileState>;
  realmBuildSelection: { q: number; r: number } | null;
  tryOpenRealmBuildMenu: (q: number, r: number) => void;
  closeRealmBuildMenu: () => void;
  buildStructure: (kind: RealmBuildKind) => void;
  realmTutorialStep: number | null;
  realmTutorialComplete: boolean;
  advanceRealmTutorial: () => void;
  skipRealmTutorial: () => void;
}

export const createRealmSlice: StateCreator<AppState, [], [], RealmSlice> = (set, get) => ({
  unlockedNodes: [...DEFAULT_UNLOCKED_NODES],
  tryUnlockSkillNode: (nodeId) => {
    const unlocked = get().unlockedNodes;
    if (!canUnlockNode(nodeId, unlocked)) return;
    if (unlocked.includes(nodeId)) return;
    set({ unlockedNodes: [...unlocked, nodeId] });
  },
  selectedFaction: null,
  setSelectedFaction: (id) => set({ selectedFaction: id }),
  nexusView: "hub",
  setNexusView: (v) => set({ nexusView: v }),
  openNexusArcade: () => set({ activeSection: "nexus", nexusView: "arcade", moreMenuOpen: false }),
  openNexusTree: () => set({ activeSection: "nexus", nexusView: "tree", moreMenuOpen: false }),
  enterRealmFaction: () => set({ nexusView: "faction", moreMenuOpen: false }),
  sqlUnlockedLevels: [...INITIAL_SQL_UNLOCKED],
  completeSqlMission: (missionId) => {
    const idx = SQL_MISSIONS.findIndex((m) => m.id === missionId);
    if (idx < 0 || idx >= SQL_MISSIONS.length - 1) return;
    const nextId = SQL_MISSIONS[idx + 1].id;
    const cur = get().sqlUnlockedLevels;
    if (cur.includes(nextId)) return;
    set({ sqlUnlockedLevels: [...cur, nextId] });
    get().awardGlobalXp(45);
    get().registerDailyGrindActivity("sql_checkpoint", 1);
  },
  enterSqlAdventure: () => set({ activeSection: "nexus", nexusView: "sqlMissions", moreMenuOpen: false }),
  enterSqlSandbox: () => set({ nexusView: "sqlSandbox", moreMenuOpen: false }),
  pseudoUnlockedLevels: [...INITIAL_PSEUDO_UNLOCKED],
  completePseudoLevel: (levelId) => {
    const idx = PSEUDO_LEVELS.findIndex((l) => l.id === levelId);
    if (idx < 0 || idx >= PSEUDO_LEVELS.length - 1) return;
    const nextId = PSEUDO_LEVELS[idx + 1].id;
    const cur = get().pseudoUnlockedLevels;
    if (cur.includes(nextId)) return;
    set({ pseudoUnlockedLevels: [...cur, nextId] });
    get().awardGlobalXp(35);
  },
  enterPseudoTrainer: () => set({ activeSection: "nexus", nexusView: "pseudoTrainer", moreMenuOpen: false }),
  supportInboxIds: [...INITIAL_SUPPORT_INBOX_IDS],
  resolvedTickets: [],
  enqueueSupportTicket: () => {
    const inbox = get().supportInboxIds;
    const resolved = get().resolvedTickets;
    const next = SUPPORT_TICKET_POOL.find((t) => !inbox.includes(t.id) && !resolved.includes(t.id));
    if (!next || inbox.includes(next.id)) return;
    set({ supportInboxIds: [...inbox, next.id] });
  },
  resolveSupportTicket: (ticketId) => {
    const inbox = get().supportInboxIds.filter((id) => id !== ticketId);
    const resolved = get().resolvedTickets.includes(ticketId)
      ? get().resolvedTickets
      : [...get().resolvedTickets, ticketId];
    set({ supportInboxIds: inbox, resolvedTickets: resolved });
    get().enqueueSupportTicket();
    get().awardGlobalXp(28);
    get().tryUnlockAchievements();
  },
  enterItSupport: () => set({ activeSection: "nexus", nexusView: "itSupport", moreMenuOpen: false }),
  enterRealmBoard: () => {
    if (!get().selectedFaction) return;
    if (get().realmTutorialComplete) {
      set({ nexusView: "realm", realmBuildSelection: null });
    } else {
      set({ nexusView: "realm", realmBuildSelection: null, realmTutorialStep: 0 });
    }
  },
  realmGold: 120,
  realmDiamonds: 3,
  realmKnowledge: 2,
  realmTiles: createInitialRealmTiles(),
  realmBuildSelection: null,
  tryOpenRealmBuildMenu: (q, r) => {
    const k = tileKey(q, r);
    const tiles = get().realmTiles;
    const tile = tiles[k];
    if (!tile || tile.structure !== "empty") {
      set({ realmBuildSelection: null });
      return;
    }
    const hasNeighbor = axialNeighbors(q, r).some((n) => {
      const t = tiles[tileKey(n.q, n.r)];
      return t !== undefined && t.structure !== "empty";
    });
    if (!hasNeighbor) {
      set({ realmBuildSelection: null });
      return;
    }
    set({ realmBuildSelection: { q, r } });
  },
  closeRealmBuildMenu: () => set({ realmBuildSelection: null }),
  buildStructure: (kind) => {
    const sel = get().realmBuildSelection;
    if (!sel) return;
    const k = tileKey(sel.q, sel.r);
    const tiles = { ...get().realmTiles };
    const tile = tiles[k];
    if (!tile || tile.structure !== "empty") return;
    const cost = REALM_BUILD_COSTS[kind].gold;
    if (get().realmGold < cost) return;
    const okNeighbor = axialNeighbors(sel.q, sel.r).some((n) => {
      const t = tiles[tileKey(n.q, n.r)];
      return t !== undefined && t.structure !== "empty";
    });
    if (!okNeighbor) return;
    const structure = kind === "goldmine" ? "goldmine" : "barracks";
    tiles[k] = { structure };
    const gold = get().realmGold - cost;
    let knowledge = get().realmKnowledge;
    let diamonds = get().realmDiamonds;
    if (kind === "goldmine") knowledge += 8;
    if (kind === "barracks") {
      knowledge += 4;
      diamonds += 1;
    }
    set({
      realmTiles: tiles,
      realmGold: gold,
      realmKnowledge: knowledge,
      realmDiamonds: diamonds,
      realmBuildSelection: null,
    });
  },
  realmTutorialStep: null,
  realmTutorialComplete: false,
  advanceRealmTutorial: () => {
    const step = get().realmTutorialStep;
    if (step === null) return;
    if (step >= 2) {
      set({ realmTutorialStep: null, realmTutorialComplete: true });
      return;
    }
    set({ realmTutorialStep: step + 1 });
  },
  skipRealmTutorial: () => set({ realmTutorialStep: null, realmTutorialComplete: true }),
});
