export type CSharpConcept = "event binding" | "state mutation" | "style variable update";

export type CSharpActionContract = {
  transitionId: string;
  handlerName: string;
  cssVariable: string;
  cssValue: string;
  concepts: CSharpConcept[];
};

export type CSharpSimulationResult = {
  triggered: boolean;
  transitionId: string;
  handlerName: string;
  cssVariables: Record<string, string>;
  summary: string;
};

export type CSharpInventoryState = {
  items: string[];
  listHtml: string;
};

export type ShieldIntegrityResult = {
  shieldValue: number;
  critical: boolean;
  cssVariables: Record<string, string>;
};

const MAX_CONCEPTS = 3;

function makeContract(transitionId: string): CSharpActionContract {
  return {
    transitionId,
    handlerName: `On${transitionId.replace(/[^a-z0-9]/gi, "").replace(/^./, (m) => m.toUpperCase())}Click`,
    cssVariable: `--${transitionId}-glow`,
    cssValue: "0 0 26px rgba(56,189,248,0.85)",
    concepts: ["event binding", "state mutation", "style variable update"],
  };
}

export function buildCSharpActionContracts(transitionIds: string[]): CSharpActionContract[] {
  return transitionIds.map((id) => makeContract(id));
}

export function validateNoOverwhelmConcepts(contract: CSharpActionContract): boolean {
  return contract.concepts.length <= MAX_CONCEPTS;
}

export function simulateCSharpClickEvent(input: {
  transitionId: string;
  contracts: CSharpActionContract[];
  existingCssVariables?: Record<string, string>;
}): CSharpSimulationResult {
  const contract = input.contracts.find((entry) => entry.transitionId === input.transitionId);
  if (!contract) {
    return {
      triggered: false,
      transitionId: input.transitionId,
      handlerName: "None",
      cssVariables: input.existingCssVariables ?? {},
      summary: "No CSharp handler mapped for transition",
    };
  }
  const cssVariables = {
    ...(input.existingCssVariables ?? {}),
    [contract.cssVariable]: contract.cssValue,
  };
  return {
    triggered: true,
    transitionId: contract.transitionId,
    handlerName: contract.handlerName,
    cssVariables,
    summary: `CSharp handler ${contract.handlerName} updated ${contract.cssVariable}`,
  };
}

export function clampShieldValue(value: number): number {
  return Math.max(0, Math.min(100, Math.round(value)));
}

export function renderCSharpListToHtml(items: string[]): string {
  const rows = items.map((item) => `  <li>${item}</li>`).join("\n");
  return `<ul id="kyber-inventory">\n${rows}\n</ul>`;
}

export function addInventoryItem(input: { items: string[]; item: string }): CSharpInventoryState {
  const clean = input.item.trim();
  const nextItems = clean.length > 0 ? [...input.items, clean] : [...input.items];
  return {
    items: nextItems,
    listHtml: renderCSharpListToHtml(nextItems),
  };
}

export function applyShieldIntegrityListener(input: {
  shieldValue: number;
  existingCssVariables?: Record<string, string>;
  criticalThreshold?: number;
}): ShieldIntegrityResult {
  const threshold = input.criticalThreshold ?? 20;
  const shieldValue = clampShieldValue(input.shieldValue);
  const critical = shieldValue < threshold;
  const cssVariables: Record<string, string> = {
    ...(input.existingCssVariables ?? {}),
    "--shield-integrity-color": critical ? "#ef4444" : "#22d3ee",
    "--shield-alert-glow": critical ? "0 0 24px rgba(239,68,68,0.88)" : "0 0 0 rgba(34,211,238,0)",
  };
  return {
    shieldValue,
    critical,
    cssVariables,
  };
}
