import { motion, useReducedMotion } from "framer-motion";
import { useMemo } from "react";
import { buildDailyMissionsForDay, localCalendarYmd, type DailyMissionDef } from "../../lib/dailyGrindMissions";
import { itemReveal, springHeavy, staggerContainer } from "../../motion/variants";
import type { DailyGrindState } from "../../store/useAppStore";
import { useAppStore } from "../../store/useAppStore";
import { cn } from "../../lib/cn";

function progressForMission(dg: DailyGrindState, m: DailyMissionDef): number {
  if (m.kind === "arena_win") return dg.arenaWinsToday;
  if (m.kind === "flashcard_reviews") return dg.flashReviewsToday;
  return dg.sqlCheckpointToday;
}

export function DailyGrindPanel() {
  const prefersReduced = useReducedMotion();
  const careerPath = useAppStore((s) => s.careerPath);
  const dg = useAppStore((s) => s.dailyGrind);

  const missions = useMemo(
    () => buildDailyMissionsForDay(localCalendarYmd(), careerPath),
    [careerPath],
  );

  const doneCount = missions.filter((m) => progressForMission(dg, m) >= m.target).length;

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className="relative overflow-hidden rounded-2xl border border-white/[0.1] bg-black/25 p-5 ring-1 ring-toxic/15 sm:p-6"
    >
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_20%_0%,rgb(57_255_20_/_0.08),transparent_55%)]" />
      <div className="relative space-y-4">
        <motion.div variants={itemReveal} className="flex flex-wrap items-end justify-between gap-3">
          <div>
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-toxic/90">
              Phase 37 · Daily Grind
            </p>
            <h2 className="mt-1 font-display text-lg font-bold uppercase tracking-wide text-foreground sm:text-xl">
              Tagesmissionen
            </h2>
            <p className="mt-1 max-w-xl font-sans text-xs text-foreground-muted">
              Pfad {careerPath ?? "FISI/FIAE Mix"} · volle Runde = Streak Push für die Klasse
            </p>
          </div>
          <div className="rounded-xl border border-toxic/30 bg-toxic/10 px-3 py-2 text-right">
            <p className="font-mono text-[9px] uppercase tracking-widest text-foreground-muted">Heute</p>
            <p className="font-display text-2xl font-black tabular-nums text-toxic">
              {doneCount}/{missions.length}
            </p>
          </div>
        </motion.div>

        <ul className="space-y-3">
          {missions.map((m) => {
            const cur = progressForMission(dg, m);
            const done = cur >= m.target;
            const pct = Math.min(1, m.target > 0 ? cur / m.target : 0);
            return (
              <motion.li
                key={m.id}
                variants={itemReveal}
                className={cn(
                  "relative overflow-hidden rounded-xl border px-4 py-3",
                  done ? "border-toxic/40 bg-toxic/[0.07]" : "border-white/[0.08] bg-white/[0.02]",
                )}
              >
                {!prefersReduced && done ? (
                  <motion.div
                    className="pointer-events-none absolute inset-0 opacity-40"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: [0.15, 0.35, 0.15] }}
                    transition={{ duration: 2.4, repeat: Infinity, ease: "easeInOut" }}
                    style={{
                      background:
                        "radial-gradient(120% 80% at 50% 50%, rgb(57 255 20 / 0.25), transparent 70%)",
                    }}
                  />
                ) : null}
                <div className="relative flex flex-wrap items-start justify-between gap-3">
                  <div className="min-w-0 flex-1 space-y-1">
                    <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
                      {m.kind === "arena_win" ? "Arena" : m.kind === "flashcard_reviews" ? "Matrix" : "SQL"}
                    </p>
                    <p className="font-sans text-sm font-semibold text-foreground">{m.title}</p>
                    <p className="font-sans text-xs text-foreground-muted">{m.subtitle}</p>
                  </div>
                  <span
                    className={cn(
                      "shrink-0 rounded-lg border px-2.5 py-1 font-mono text-[11px] font-bold tabular-nums",
                      done ? "border-toxic/50 text-toxic" : "border-white/10 text-foreground-muted",
                    )}
                  >
                    {Math.min(cur, m.target)}/{m.target}
                  </span>
                </div>
                <div className="relative mt-3 h-1 overflow-hidden rounded-full bg-white/[0.06]">
                  <motion.div
                    className="h-full rounded-full bg-gradient-to-r from-toxic/80 to-cyber-cyan/90"
                    initial={false}
                    animate={{ width: `${pct * 100}%` }}
                    transition={springHeavy}
                  />
                </div>
              </motion.li>
            );
          })}
        </ul>
      </div>
    </motion.div>
  );
}
