import type { KnowledgeCard } from "./vaultKnowledgeHub";
import { useAcademyStore } from "../store/academyStore";
import { useAppStore } from "../store/useAppStore";

/** Routes Vault hub cards into SqlAcademyShell Helpdesk or Karten */
export function executeVaultKnowledgeJump(card: KnowledgeCard): void {
  const jump = card.jump;
  if (jump.kind === "sql_academy") {
    useAcademyStore.getState().setSqlAcademyDeepLinkIntent({
      nonce: Date.now(),
      universeId: jump.universeId,
      chapterId: jump.chapterId,
      focus: jump.focus,
    });
    const app = useAppStore.getState();
    app.setSelectedUniverseId(jump.universeId);
    app.setActiveChapterId(jump.chapterId);
    app.enterSqlAdventure();
    return;
  }
  if (jump.kind === "helpdesk") {
    useAcademyStore.getState().clearSqlAcademyDeepLinkIntent();
    useAppStore.getState().enterItSupport();
    return;
  }
  useAcademyStore.getState().clearSqlAcademyDeepLinkIntent();
  useAppStore.getState().enterFlashcards();
}
