import { useEffect } from "react";
import { motion, useReducedMotion } from "framer-motion";
import type { SqlUniverseId } from "../../../../data/universes";
import { UNIVERSE_THEMES } from "../../../../styles/themes/universeThemes";

type FloatingGainsProps = {
  open: boolean;
  amount: number;
  universeId: SqlUniverseId;
  successLabel?: string;
  onDone: () => void;
};

export function FloatingGains({ open, amount, universeId, successLabel = "Success", onDone }: FloatingGainsProps) {
  const reduceMotion = useReducedMotion();
  const theme = UNIVERSE_THEMES[universeId];

  useEffect(() => {
    if (!open) return;
    const timer = window.setTimeout(onDone, reduceMotion ? 520 : 560);
    return () => window.clearTimeout(timer);
  }, [open, onDone, reduceMotion]);

  if (!open) return null;

  if (reduceMotion) {
    return (
      <div className="pointer-events-none absolute -top-7 right-0 rounded-md border border-emerald-300/65 bg-emerald-950/90 px-2 py-1 text-[10px] font-semibold uppercase tracking-[0.14em] text-emerald-200">
        {successLabel}
      </div>
    );
  }

  return (
    <motion.div
      className="pointer-events-none absolute -top-2 right-1 z-10 rounded-md px-2 py-1 text-[11px] font-semibold uppercase tracking-[0.14em]"
      style={{
        color: theme.accent,
        textShadow: `0 0 10px ${theme.accent}`,
      }}
      initial={{ opacity: 0, y: 0, scale: 0.92 }}
      animate={{ opacity: [0, 1, 1, 0], y: -34, scale: [0.92, 1, 1] }}
      transition={{ duration: 0.56, ease: "easeOut" }}
    >
      {theme.icon} +{amount} XP
    </motion.div>
  );
}
