import { useEffect, useRef, useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
import { useTranslation } from "../../../../i18n/useTranslation";
import { LeagueBadge } from "./LeagueBadge";
import { SpeedrunTracker } from "./SpeedrunTracker";
import { EfficiencyHeatMap } from "./EfficiencyHeatMap";

type MasteryDashboardProps = {
  trackLabel: string;
  masteryPercent: number;
  solvedUnits: number;
  totalUnits: number;
  currentLevel: number;
  currentTitle: string;
  totalXP: number;
  dailyStreak: number;
  totalProteinQueried: number;
  workoutsMastered: number;
  trainingDaysSimulated: number;
  persistenceHealthy: boolean;
  chapterAttempts: number;
  chapterPersonalBestMs: number | null;
  chapterCurrentRunMs: number;
  heatMapSegments: Array<{ id: string; label: string; currentMs: number; pbMs: number; globalAvgMs: number }>;
  chapterRunActive: boolean;
  leagueTier: "Bronze" | "Silver" | "Gold" | "Platinum" | "Diamond" | "Master";
  eternalLegendUnlocked: boolean;
  onResetGains: () => void;
  onOpenCertificate: () => void;
};

export function MasteryDashboard({
  trackLabel,
  masteryPercent,
  solvedUnits,
  totalUnits,
  currentLevel,
  currentTitle,
  totalXP,
  dailyStreak,
  totalProteinQueried,
  workoutsMastered,
  trainingDaysSimulated,
  persistenceHealthy,
  chapterAttempts,
  chapterPersonalBestMs,
  chapterCurrentRunMs,
  heatMapSegments,
  chapterRunActive,
  leagueTier,
  eternalLegendUnlocked,
  onResetGains,
  onOpenCertificate,
}: MasteryDashboardProps) {
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [thumpTick, setThumpTick] = useState(0);
  const resetButtonRef = useRef<HTMLButtonElement | null>(null);
  const confirmButtonRef = useRef<HTMLButtonElement | null>(null);
  const previousXpRef = useRef(totalXP);
  const reduceMotion = useReducedMotion();
  const t = useTranslation();

  useEffect(() => {
    if (!confirmOpen) return;
    confirmButtonRef.current?.focus();
  }, [confirmOpen]);

  useEffect(() => {
    if (totalXP > previousXpRef.current) {
      setThumpTick((v) => v + 1);
    }
    previousXpRef.current = totalXP;
  }, [totalXP]);

  function closeModal() {
    setConfirmOpen(false);
    resetButtonRef.current?.focus();
  }

  const levelFromXp = Math.max(1, Math.floor(Math.sqrt(Math.max(0, totalXP) / 120)) + 1);
  const currentLevelFloor = 120 * (levelFromXp - 1) * (levelFromXp - 1);
  const nextLevelFloor = 120 * levelFromXp * levelFromXp;
  const levelRange = Math.max(1, nextLevelFloor - currentLevelFloor);
  const levelProgress = Math.min(100, Math.max(0, Math.round(((totalXP - currentLevelFloor) / levelRange) * 100)));
  const xpToNext = Math.max(0, nextLevelFloor - totalXP);
  const bestLabel =
    chapterPersonalBestMs === null
      ? t.general.noRunYet
      : `${Math.floor(chapterPersonalBestMs / 1000)}s`;

  return (
    <>
      <div className="mt-4 rounded-lg border border-emerald-400/35 bg-emerald-950/15 p-3">
        <p className="text-[10px] uppercase tracking-[0.16em] text-emerald-300">{trackLabel}</p>
        <div className="mt-1 flex items-center gap-2">
          <p className="text-sm font-semibold text-emerald-100">{masteryPercent}%</p>
          <LeagueBadge league={leagueTier} />
          <span className={`h-2.5 w-2.5 rounded-full ${persistenceHealthy ? "animate-pulse bg-emerald-300" : "bg-orange-300"}`} />
          <span className={`text-[10px] uppercase tracking-[0.14em] ${persistenceHealthy ? "text-emerald-200" : "text-orange-200"}`}>
            {persistenceHealthy ? t.ui.progressSecured : t.ui.syncPending}
          </span>
        </div>
        <p className="mt-1 text-xs text-emerald-200/90">
          {t.ui.gains} {solvedUnits}/{totalUnits}
        </p>
        <p className="mt-1 text-xs text-cyan-200/90">{t.general.level} {currentLevel} XP {totalXP}</p>
        <p className="mt-1 text-xs text-cyan-200/90">{t.general.rank} {currentTitle}</p>
        <p className="mt-1 text-xs text-cyan-200/90">{t.ui.dailyStreak} {dailyStreak}</p>
        <p className="mt-1 text-xs text-fuchsia-200/90">{t.ui.personalBest} {bestLabel}</p>
        <p className="mt-1 text-xs text-fuchsia-200/90">
          {t.general.attempts} {chapterAttempts} {chapterRunActive ? t.general.chapterRunActive : ""}
        </p>
        {eternalLegendUnlocked ? (
          <div className="mt-3 rounded-md border border-fuchsia-300/45 bg-slate-950/80 p-2.5">
            <motion.div
              className="relative overflow-hidden rounded-md border border-cyan-300/45 bg-slate-900/70 px-3 py-2"
              initial={false}
              animate={
                reduceMotion
                  ? { opacity: 1 }
                  : {
                      boxShadow: [
                        "0 0 0px rgba(69,243,255,0.3)",
                        "0 0 16px rgba(255,43,214,0.45)",
                        "0 0 22px rgba(109,255,180,0.42)",
                        "0 0 0px rgba(69,243,255,0.3)",
                      ],
                    }
              }
              transition={reduceMotion ? { duration: 0 } : { duration: 3.2, repeat: Infinity, ease: "easeInOut" }}
            >
              <motion.div
                className="pointer-events-none absolute inset-0 bg-[conic-gradient(from_0deg,rgba(69,243,255,0.26),rgba(255,43,214,0.24),rgba(109,255,180,0.24),rgba(69,243,255,0.26))]"
                initial={false}
                animate={reduceMotion ? { opacity: 0.45 } : { rotate: 360 }}
                transition={reduceMotion ? { duration: 0 } : { duration: 7, repeat: Infinity, ease: "linear" }}
              />
              <div className="relative">
                <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-200">Grand Master End State</p>
                <p className="mt-1 text-xs font-semibold text-fuchsia-100">Eternal Legend</p>
                <p className="mt-1 text-[11px] text-emerald-100">All three universes at full mastery</p>
              </div>
            </motion.div>
          </div>
        ) : null}
        <div className="mt-3 rounded-md border border-cyan-400/25 bg-slate-950/65 p-2">
          <div className="mb-1 flex items-center justify-between text-[10px] uppercase tracking-[0.14em] text-cyan-200">
            <span>{t.ui.xpToNextLevel}</span>
            <span>{xpToNext} {t.ui.xpLeft}</span>
          </div>
          <div className="h-2.5 w-full overflow-hidden rounded-full border border-cyan-300/35 bg-slate-900/70">
            <motion.div
              key={thumpTick}
              className="h-full rounded-full transition-[width] duration-500 ease-out"
              style={{
                width: `${levelProgress}%`,
                background: "linear-gradient(90deg, var(--academy-primary, #45f3ff), var(--academy-accent, #7dffcf))",
                boxShadow: "0 0 10px color-mix(in srgb, var(--academy-primary, #45f3ff) 70%, transparent)",
              }}
              initial={reduceMotion ? false : { scaleY: 1, scaleX: 1 }}
              animate={reduceMotion ? { scaleY: 1, scaleX: 1 } : { scaleY: [1, 1.22, 1], scaleX: [1, 1.015, 1] }}
              transition={reduceMotion ? { duration: 0 } : { duration: 0.38, ease: "easeOut" }}
            />
          </div>
          <p className="mt-1 text-[10px] uppercase tracking-[0.14em] text-cyan-200">
            {t.general.level} {levelFromXp} {t.general.progress} {levelProgress}%
          </p>
        </div>
        <SpeedrunTracker currentRunMs={chapterCurrentRunMs} personalBestMs={chapterPersonalBestMs} />
        <EfficiencyHeatMap segments={heatMapSegments} />
        <div className="mt-3 grid grid-cols-1 gap-2 text-[11px] sm:grid-cols-3">
          <div className="rounded-md border border-cyan-400/25 bg-slate-900/65 px-2 py-1.5 text-cyan-100">
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">{t.ui.totalProteinQueried}</p>
            <p className="mt-1 font-semibold">{totalProteinQueried}</p>
          </div>
          <div className="rounded-md border border-cyan-400/25 bg-slate-900/65 px-2 py-1.5 text-cyan-100">
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">{t.ui.workoutsMastered}</p>
            <p className="mt-1 font-semibold">{workoutsMastered}</p>
          </div>
          <div className="rounded-md border border-cyan-400/25 bg-slate-900/65 px-2 py-1.5 text-cyan-100">
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">{t.ui.trainingDaysSimulated}</p>
            <p className="mt-1 font-semibold">{trainingDaysSimulated}</p>
          </div>
        </div>
        <div className="mt-3 flex flex-wrap gap-2">
          <button
            type="button"
            className="rounded-md border border-cyan-300/55 bg-cyan-950/35 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-cyan-100"
            onClick={onOpenCertificate}
          >
            {t.ui.certificate}
          </button>
          <button
            ref={resetButtonRef}
            type="button"
            className="rounded-md border border-orange-300/45 bg-orange-950/25 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-orange-200"
            onClick={() => setConfirmOpen(true)}
          >
            {t.ui.resetGains}
          </button>
        </div>
      </div>

      {confirmOpen ? (
        <div
          className="fixed inset-0 z-[565] flex items-center justify-center bg-black/70 p-4"
          role="dialog"
          aria-modal="true"
          aria-label={t.ui.resetDialogAria}
          onKeyDown={(event) => {
            if (event.key === "Escape") closeModal();
          }}
        >
          <div className="w-full max-w-md rounded-xl border border-orange-300/40 bg-slate-950/95 p-5">
            <p className="text-sm font-semibold text-orange-200">{t.ui.resetDialogTitle}</p>
            <p className="mt-2 text-xs text-slate-300">{t.ui.resetDialogBody}</p>
            <div className="mt-4 flex flex-wrap gap-2">
              <button
                ref={confirmButtonRef}
                type="button"
                className="rounded-md border border-orange-300/55 bg-orange-950/30 px-3 py-1.5 text-xs font-semibold uppercase tracking-[0.14em] text-orange-200"
                onClick={() => {
                  onResetGains();
                  closeModal();
                }}
              >
                {t.ui.confirmReset}
              </button>
              <button
                type="button"
                className="rounded-md border border-slate-500/60 bg-slate-900/70 px-3 py-1.5 text-xs font-semibold uppercase tracking-[0.14em] text-slate-200"
                onClick={closeModal}
              >
                {t.ui.cancel}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </>
  );
}
