const STORAGE_KEY = "codesnap-academy-progress-v1";

export type ChapterProgress = {
  solvedTaskIds: string[];
  masteredQuizIds: string[];
  /** Highest inclusive learning-flow step index the user may open in the stepper */
  learningFlowMaxIndex: number;
  learningFlowCursorIndex: number;
  learningFlowAcknowledged: boolean;
  learningFlowLessonComplete: boolean;
  /** Snippet and preview study strip finished user may enter guided tasks */
  materialPhaseComplete: boolean;
  guidedTaskCursorIndex: number;
  guidedTaskMaxUnlockedIndex: number;
  /** User finished sequential task lane and sees repeat plus tools */
  guidedTaskLaneComplete: boolean;
};

const LEARNING_FLOW_UI_DEFAULTS = {
  learningFlowMaxIndex: 0,
  learningFlowCursorIndex: 0,
  learningFlowAcknowledged: false,
  learningFlowLessonComplete: false,
  materialPhaseComplete: false,
  guidedTaskCursorIndex: 0,
  guidedTaskMaxUnlockedIndex: 0,
  guidedTaskLaneComplete: false,
} as const;

export function normalizeChapterProgress(chapter: Partial<ChapterProgress> | undefined): ChapterProgress {
  if (!chapter) {
    return { solvedTaskIds: [], masteredQuizIds: [], ...LEARNING_FLOW_UI_DEFAULTS };
  }
  return {
    solvedTaskIds: chapter.solvedTaskIds ?? [],
    masteredQuizIds: chapter.masteredQuizIds ?? [],
    learningFlowMaxIndex: chapter.learningFlowMaxIndex ?? 0,
    learningFlowCursorIndex: chapter.learningFlowCursorIndex ?? 0,
    learningFlowAcknowledged: chapter.learningFlowAcknowledged ?? false,
    learningFlowLessonComplete: chapter.learningFlowLessonComplete ?? false,
    materialPhaseComplete: chapter.materialPhaseComplete ?? false,
    guidedTaskCursorIndex: chapter.guidedTaskCursorIndex ?? 0,
    guidedTaskMaxUnlockedIndex: chapter.guidedTaskMaxUnlockedIndex ?? 0,
    guidedTaskLaneComplete: chapter.guidedTaskLaneComplete ?? false,
  };
}

