function levelFromXP(xp: number): number {
  return Math.max(1, Math.floor(Math.sqrt(Math.max(0, xp) / 120)) + 1);
}

export function getUniverseTitle(level: number, universeId: SqlUniverseId, locale: AcademyLocale = DEFAULT_ACADEMY_LOCALE): string {
  const rankStep = Math.min(5, Math.floor((Math.max(1, level) - 1) / 2));
  const lore = academyLoreTitles[locale];
  return lore[universeId][rankStep] ?? lore[universeId][0];
}

function ymdNow(): string {
  const now = new Date();
  const y = now.getFullYear();
  const m = String(now.getMonth() + 1).padStart(2, "0");
  const d = String(now.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function yesterdayYmd(input: string): string {
  const dt = new Date(`${input}T00:00:00`);
  dt.setDate(dt.getDate() - 1);
  const y = dt.getFullYear();
  const m = String(dt.getMonth() + 1).padStart(2, "0");
  const d = String(dt.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

