function resolveLeagueTier(score: number): LeagueTier {
  if (score >= 95) return "Master";
  if (score >= 86) return "Diamond";
  if (score >= 72) return "Platinum";
  if (score >= 56) return "Gold";
  if (score >= 38) return "Silver";
  return "Bronze";
}

