import { motion, useReducedMotion } from "framer-motion";
import { useTranslation } from "../../../../i18n/useTranslation";

type LevelUpOverlayProps = {
  open: boolean;
  icon: string;
  level: number;
  title: string;
  onClose: () => void;
};

export function LevelUpOverlay({ open, icon, level, title, onClose }: LevelUpOverlayProps) {
  const reduceMotion = useReducedMotion();
  const t = useTranslation();
  if (!open) return null;

  return (
    <div className="fixed inset-0 z-[590] flex items-center justify-center bg-slate-950/70 px-4">
      <motion.section
        initial={reduceMotion ? false : { opacity: 0, y: 16, scale: 0.98 }}
        animate={reduceMotion ? { opacity: 1 } : { opacity: 1, y: 0, scale: 1 }}
        transition={reduceMotion ? { duration: 0 } : { duration: 0.42, ease: "easeOut" }}
        className="w-full max-w-lg rounded-xl border border-cyan-300/45 bg-slate-950/95 p-6 text-center shadow-[0_0_30px_rgb(69_243_255_/_0.2)]"
      >
        <p className="text-[11px] uppercase tracking-[0.16em] text-cyan-300">{t.ui.levelUp}</p>
        <h3 className="mt-2 text-2xl font-bold text-cyan-100" style={{ textShadow: "0 0 14px var(--academy-primary, #45f3ff)" }}>
          {icon} {title}
        </h3>
        <p className="mt-2 text-sm text-cyan-200">{t.ui.youReachedLevel} {t.general.level} {level}</p>
        <button
          type="button"
          onClick={onClose}
          className="mt-5 rounded-md border border-cyan-300/60 bg-cyan-950/40 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-cyan-100"
        >
          {t.general.continueTraining}
        </button>
      </motion.section>
    </div>
  );
}
