import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useMemo } from "react";
import { cn } from "../../lib/cn";
import { springFactionWar } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

export function FactionWarBar() {
  const prefersReduced = useReducedMotion();
  const fisiXp = useAppStore((s) => s.factionFisiXp);
  const fiaeXp = useAppStore((s) => s.factionFiaeXp);
  const syncStatus = useAppStore((s) => s.syncStatus);

  const { fisiPct, fiaePct, total, fisiLead, fiaeLead } = useMemo(() => {
    const f = Math.max(0, fisiXp);
    const a = Math.max(0, fiaeXp);
    const t = f + a;
    if (t <= 0) return { fisiPct: 50, fiaePct: 50, total: 0, fisiLead: false, fiaeLead: false };
    const fp = (f / t) * 100;
    return {
      fisiPct: fp,
      fiaePct: 100 - fp,
      total: t,
      fisiLead: f > a,
      fiaeLead: a > f,
    };
  }, [fisiXp, fiaeXp]);

  const liveLabel =
    syncStatus === "offline" ? "Letzter Cache · Uplink down" : "Realtime Uplink aktiv";

  return (
    <div className="relative overflow-hidden border border-white/[0.1] bg-black/55 px-4 py-4 sm:px-5">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.07]" aria-hidden />
      <div className="relative mb-3 flex flex-wrap items-end justify-between gap-2">
        <div>
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-foreground-muted">
            Global Faction War
          </p>
          <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">{liveLabel}</p>
        </div>
        <div className="flex gap-4 font-mono text-[10px] uppercase tracking-[0.16em]">
          <span className="text-signal">FISI {fisiXp}</span>
          <span className="text-fuchsia-400">FIAE {fiaeXp}</span>
        </div>
      </div>

      <div
        className={cn(
          "relative h-12 overflow-hidden border border-white/[0.12] bg-black/70",
          !prefersReduced && "faction-war-glitch",
        )}
      >
        <div className="absolute inset-0 scanlines opacity-[0.35]" aria-hidden />
        <div className="relative h-full w-full">
          <motion.div
            layout
            className="absolute left-0 top-0 h-full border-r border-white/[0.08]"
            style={{
              width: `${fisiPct}%`,
              background: "linear-gradient(180deg, rgb(34 211 238 / 0.42), rgb(34 211 238 / 0.14))",
              boxShadow: fisiLead ? "inset 0 0 34px rgb(34 211 238 / 0.45)" : "none",
            }}
            transition={springFactionWar}
          />
          <motion.div
            layout
            className="absolute right-0 top-0 h-full"
            style={{
              width: `${fiaePct}%`,
              background: "linear-gradient(180deg, rgb(232 121 249 / 0.52), rgb(192 38 211 / 0.2))",
              boxShadow: fiaeLead ? "inset 0 0 34px rgb(217 70 239 / 0.48)" : "none",
            }}
            transition={springFactionWar}
          />
        </div>

        <AnimatePresence>
          {!prefersReduced && fisiLead ? (
            <motion.div
              key="fisi-scan"
              className="pointer-events-none absolute inset-y-0 left-0 w-1/3 bg-gradient-to-r from-transparent via-cyan-200/25 to-transparent mix-blend-screen"
              initial={{ x: "-40%", opacity: 0 }}
              animate={{ x: ["-40%", "140%"], opacity: [0, 0.55, 0] }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.6, repeat: Infinity, repeatDelay: 0.8, ease: "linear" }}
            />
          ) : null}
          {!prefersReduced && fiaeLead ? (
            <motion.div
              key="fiae-scan"
              className="pointer-events-none absolute inset-y-0 right-0 w-1/3 bg-gradient-to-l from-transparent via-fuchsia-200/22 to-transparent mix-blend-screen"
              initial={{ x: "40%", opacity: 0 }}
              animate={{ x: ["40%", "-140%"], opacity: [0, 0.5, 0] }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.6, repeat: Infinity, repeatDelay: 0.8, ease: "linear" }}
            />
          ) : null}
        </AnimatePresence>
      </div>

      <div className="relative mt-2 flex justify-between font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
        <span className="text-signal">{fisiPct.toFixed(1)}% Druck</span>
        <span className="tabular-nums">Pool {total}</span>
        <span className="text-fuchsia-400">{fiaePct.toFixed(1)}% Druck</span>
      </div>
    </div>
  );
}
