import { motion } from "framer-motion";
import { useCallback, useEffect, useMemo, useState, type CSSProperties } from "react";
import { buildChallengeSlug } from "../../lib/challengeSlug";
import {
  aggregateExamDomains,
  computeIhkReadinessPercent,
  domainStatsToRadarMetrics,
  inferRepairTargetFromBucket,
  inferRepairTargetFromTag,
  type ExamRadarBucket,
  type ExamRepairTarget,
} from "../../lib/mockExamAnalysis";
import { ihkGradeFromPercent, ihkGradeLabel } from "../../lib/mockExamGrading";
import { cn } from "../../lib/cn";
import { springHeavy } from "../../motion/variants";
import { UNIVERSE_THEME_FALLBACK, UNIVERSE_THEMES } from "../../styles/themes/universeThemes";
import { useAppStore } from "../../store/useAppStore";
import { MockExamResultRadar } from "./MockExamResultRadar";

function fmtClock(totalSec: number): string {
  const s = Math.max(0, Math.floor(totalSec));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${String(m).padStart(2, "0")}:${String(r).padStart(2, "0")}`;
}

function stressRatio(run: { durationSec: number; timeRemainingSec: number }): number {
  if (run.durationSec <= 0) return 0;
  return Math.max(0, Math.min(1, 1 - run.timeRemainingSec / run.durationSec));
}

function timerVisuals(stress: number): { ring: string; text: string; bar: string } {
  if (stress < 0.34) {
    return {
      ring: "border-cyber-cyan/45 shadow-[0_0_28px_rgb(34_211_238_/_0.22)]",
      text: "text-cyber-cyan",
      bar: "from-cyber-cyan/80 to-cyan-300/90",
    };
  }
  if (stress < 0.67) {
    return {
      ring: "border-amber-400/50 shadow-[0_0_26px_rgb(251_191_36_/_0.2)]",
      text: "text-amber-200",
      bar: "from-amber-400/85 to-amber-200/90",
    };
  }
  return {
    ring: "border-signal/55 shadow-[0_0_30px_rgb(248_113_113_/_0.28)]",
    text: "text-signal",
    bar: "from-signal/90 to-rose-400/85",
  };
}

function ExamQuestionMatrix({
  total,
  currentIdx,
  answers,
  flagged,
  onJump,
}: {
  total: number;
  currentIdx: number;
  answers: Array<number | null>;
  flagged: boolean[];
  onJump: (i: number) => void;
}) {
  const cols = total <= 24 ? 8 : total <= 36 ? 9 : 10;
  return (
    <div className="space-y-3">
      <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-zinc-500">Fragenmatrix</p>
      <div
        className="grid gap-1.5"
        style={{ gridTemplateColumns: `repeat(${cols}, minmax(0, 1fr))` }}
      >
        {Array.from({ length: total }).map((_, i) => {
          const answered = answers[i] !== null;
          const mark = Boolean(flagged[i]);
          const active = i === currentIdx;
          return (
            <button
              key={`matrix-${i}`}
              type="button"
              onClick={() => onJump(i)}
              title={`Frage ${i + 1}`}
              className={cn(
                "relative flex aspect-square min-h-[2rem] items-center justify-center rounded-md border font-mono text-[10px] font-bold tabular-nums transition-colors",
                active ? "ring-2 ring-offset-2 ring-offset-[#050608]" : "",
                answered
                  ? "border-emerald-400/45 bg-emerald-500/[0.14] text-emerald-100"
                  : mark
                    ? "border-amber-400/55 bg-amber-500/[0.12] text-amber-100"
                    : "border-white/[0.08] bg-black/35 text-zinc-500 hover:border-white/[0.16] hover:text-zinc-300",
                active && answered ? "ring-emerald-300/80" : active ? "ring-cyber-cyan/70" : "",
              )}
            >
              {i + 1}
              {mark && !answered ? (
                <span className="absolute right-0.5 top-0.5 size-1.5 rounded-full bg-amber-400 shadow-[0_0_6px_rgb(251_191_36_/_0.9)]" aria-hidden />
              ) : null}
            </button>
          );
        })}
      </div>
      <div className="flex flex-wrap gap-x-4 gap-y-1 font-mono text-[9px] uppercase tracking-[0.18em] text-zinc-500">
        <span className="inline-flex items-center gap-1.5">
          <span className="size-2 rounded-sm border border-cyber-cyan/50 bg-black/40" aria-hidden />
          Aktiv
        </span>
        <span className="inline-flex items-center gap-1.5">
          <span className="size-2 rounded-sm border border-emerald-400/45 bg-emerald-500/20" aria-hidden />
          Beantwortet
        </span>
        <span className="inline-flex items-center gap-1.5">
          <span className="size-2 rounded-sm border border-amber-400/55 bg-amber-500/15" aria-hidden />
          Markiert
        </span>
        <span className="inline-flex items-center gap-1.5">
          <span className="size-2 rounded-sm border border-white/10 bg-black/35" aria-hidden />
          Offen
        </span>
      </div>
    </div>
  );
}

export function MockExamView() {
  const run = useAppStore((s) => s.mockExam);
  const setAnswer = useAppStore((s) => s.setMockExamAnswer);
  const next = useAppStore((s) => s.nextMockExamQuestion);
  const prev = useAppStore((s) => s.prevMockExamQuestion);
  const jump = useAppStore((s) => s.jumpMockExamQuestion);
  const tick = useAppStore((s) => s.tickMockExamTimer);
  const submit = useAppStore((s) => s.submitMockExam);
  const abandon = useAppStore((s) => s.abandonMockExam);
  const acceptChallenge = useAppStore((s) => s.acceptMockExamChallenge);
  const toggleFlag = useAppStore((s) => s.toggleMockExamFlag);
  const operatorHandle = useAppStore((s) => s.operatorHandle);
  const selectedExamId = useAppStore((s) => s.selectedExamId);
  const [shareState, setShareState] = useState<null | "ok" | "err">(null);

  useEffect(() => {
    if (!run || run.submitted || !run.challengeAccepted) return;
    const id = window.setInterval(() => tick(), 1000);
    return () => window.clearInterval(id);
  }, [run, tick]);

  useEffect(() => {
    if (!run || run.submitted || !run.challengeAccepted) return;
    const onBeforeUnload = (event: BeforeUnloadEvent) => {
      event.preventDefault();
      event.returnValue = "";
    };
    window.addEventListener("beforeunload", onBeforeUnload);
    return () => window.removeEventListener("beforeunload", onBeforeUnload);
  }, [run]);

  const result = useMemo(() => {
    if (!run) {
      return { correct: 0, percent: 0, grade: ihkGradeFromPercent(0), weakTags: [] as Array<[string, number]> };
    }
    let correct = 0;
    const wrongTags = new Map<string, number>();
    run.questionSet.forEach((q, i) => {
      const a = run.answers[i];
      if (a === q.correctIndex) {
        correct += 1;
        return;
      }
      for (const t of q.tags) wrongTags.set(t, (wrongTags.get(t) ?? 0) + 1);
    });
    const total = run.questionSet.length;
    const percent = total > 0 ? (correct / total) * 100 : 0;
    const grade = ihkGradeFromPercent(percent);
    const weakTags = [...wrongTags.entries()]
      .sort((a, b) => b[1] - a[1])
      .slice(0, 6);
    return { correct, percent, grade, weakTags };
  }, [run]);

  const elapsedMs = useMemo(
    () => (run ? Math.max(0, ((run.submitted ? run.finishedAtMs : Date.now()) ?? Date.now()) - run.startedAtMs) : 0),
    [run],
  );

  const challengeCompare = useMemo(() => {
    if (!run) return null;
    const meta = run.challengeMeta;
    if (!meta || meta.elapsedMs == null || meta.elapsedMs <= 0) return null;
    const delta = meta.elapsedMs - elapsedMs;
    const pct = Math.abs((delta / meta.elapsedMs) * 100);
    return {
      faster: delta > 0,
      pct,
      by: meta.by,
      scoreDelta: result.percent - (meta.percent ?? result.percent),
    };
  }, [elapsedMs, result.percent, run]);

  const postAnalysis = useMemo(() => {
    if (!run?.submitted) return null;
    const stats = aggregateExamDomains(run.questionSet, run.answers);
    const radar = domainStatsToRadarMetrics(stats);
    const readiness = computeIhkReadinessPercent({
      overallPercent: result.percent,
      grade: result.grade,
      stats,
    });
    const gapBuckets = [...new Set(radar.filter((m) => m.value < 72).map((m) => m.id as ExamRadarBucket))];
    return { stats, radar, readiness, gapBuckets };
  }, [run, result.percent, result.grade]);

  const selectedUniverseId = useAppStore((s) => s.selectedUniverseId);
  const enterSqlAdventure = useAppStore((s) => s.enterSqlAdventure);
  const enterItSupport = useAppStore((s) => s.enterItSupport);
  const enterFlashcards = useAppStore((s) => s.enterFlashcards);
  const enterDataVault = useAppStore((s) => s.enterDataVault);

  const openRepair = useCallback(
    (target: ExamRepairTarget) => {
      if (target === "sql_academy") enterSqlAdventure();
      else if (target === "helpdesk") enterItSupport();
      else if (target === "flashcards") enterFlashcards();
      else enterDataVault();
    },
    [enterDataVault, enterFlashcards, enterItSupport, enterSqlAdventure],
  );

  const repairCtaLabel: Record<ExamRepairTarget, string> = {
    sql_academy: "SQL Academy öffnen",
    helpdesk: "Helpdesk Lab öffnen",
    flashcards: "Karten Stack öffnen",
    vault: "Wissens Hub öffnen",
  };

  if (!run) {
    return (
      <div className="rounded-2xl border border-white/[0.08] bg-[#060708]/95 px-6 py-12 text-center font-mono text-xs uppercase tracking-[0.22em] text-zinc-500">
        Keine aktive Prüfung
      </div>
    );
  }

  const total = run.questionSet.length;
  const idx = Math.max(0, Math.min(total - 1, run.questionIndex));
  const question = run.questionSet[idx];
  if (!question || total === 0) {
    return (
      <div className="rounded-2xl border border-white/[0.08] bg-[#060708]/95 px-6 py-12 text-center font-mono text-xs uppercase tracking-[0.22em] text-zinc-500">
        Fragepool nicht verfügbar
      </div>
    );
  }
  const answeredCount = run.answers.filter((x) => x !== null).length;
  const progressPercent = total > 0 ? (answeredCount / total) * 100 : 0;
  const flagged = run.flagged?.length === total ? run.flagged : Array.from({ length: total }, () => false);
  const isFlagged = Boolean(flagged[idx]);

  if (!run.challengeAccepted) {
    return (
      <div className="mx-auto max-w-lg space-y-5 rounded-2xl border border-emerald-400/35 bg-emerald-500/[0.06] p-6 shadow-[inset_0_0_32px_rgb(16_185_129_/_0.12)] sm:p-8">
        <p className="font-mono text-[10px] font-black uppercase tracking-[0.32em] text-emerald-200/95">Challenge empfangen</p>
        <div className="space-y-2 rounded-xl border border-emerald-300/30 bg-black/35 p-4 font-mono text-xs uppercase tracking-[0.18em] text-zinc-200">
          <p>Herausforderer {run.challengeMeta?.by ?? "Unknown_Operator"}</p>
          <p>Fragenset {total} Items</p>
          {run.challengeMeta?.percent != null ? <p>Zielwert {run.challengeMeta.percent.toFixed(1)}%</p> : null}
        </div>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => acceptChallenge()}
          className="w-full rounded-xl border border-emerald-300/45 bg-emerald-500/[0.14] px-5 py-3 font-mono text-xs font-black uppercase tracking-[0.22em] text-emerald-100 hover:border-emerald-200/60"
        >
          Challenge starten
        </motion.button>
      </div>
    );
  }

  if (run.submitted) {
    const universeTheme = UNIVERSE_THEMES[selectedUniverseId] ?? UNIVERSE_THEME_FALLBACK;
    const examThemeStyle = {
      "--universe-primary": universeTheme.primary,
      "--universe-accent": universeTheme.accent,
    } as CSSProperties;

    return (
      <div
        className="mx-auto max-w-5xl space-y-6 rounded-2xl border border-white/[0.08] bg-[#050608] p-5 sm:p-8"
        style={examThemeStyle}
      >
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-zinc-500">Auswertung</p>

        <div className="grid gap-6 lg:grid-cols-2 lg:items-start">
          <div className="space-y-4">
            <div
              className="rounded-2xl border px-5 py-6 ring-1"
              style={{
                borderColor: "color-mix(in srgb, var(--universe-primary) 38%, transparent)",
                backgroundColor: "color-mix(in srgb, var(--universe-primary) 10%, rgb(9 9 11))",
                boxShadow: "0 0 0 1px color-mix(in srgb, var(--universe-primary) 18%, transparent)",
              }}
            >
              <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.26em] text-zinc-500">IHK Readiness</p>
              <p
                className="mt-2 font-display text-5xl font-black tabular-nums tracking-tight sm:text-6xl"
                style={{ color: "var(--universe-primary)" }}
              >
                {postAnalysis?.readiness ?? 0}%
              </p>
              <p className="mt-2 max-w-md font-sans text-xs leading-relaxed text-zinc-400">
                Geschätzte Bestehensnähe aus Domänenbilanz und Note ohne rechtliche Gewähr
              </p>
            </div>
            <div className="rounded-xl border border-emerald-400/35 bg-emerald-500/[0.08] px-4 py-3 font-mono text-sm uppercase tracking-[0.16em] text-emerald-100">
              Note {result.grade} · {ihkGradeLabel(result.grade)} · {result.percent.toFixed(1)}%
            </div>
            <div className="grid gap-3 rounded-xl border border-white/[0.08] p-4 font-mono text-[11px] uppercase tracking-[0.16em] text-zinc-400 sm:grid-cols-3">
              <p>Fragen {total}</p>
              <p>Richtig {result.correct}</p>
              <p>Falsch {Math.max(0, total - result.correct)}</p>
            </div>
            {postAnalysis ? (
              <div className="space-y-2 rounded-xl border border-white/[0.08] bg-black/35 p-4">
                <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">Domänen Balken</p>
                <div className="space-y-2">
                  {postAnalysis.radar.map((m) => (
                    <div key={m.id} className="space-y-1">
                      <div className="flex justify-between font-mono text-[10px] uppercase tracking-[0.14em] text-zinc-400">
                        <span>{m.label}</span>
                        <span className="tabular-nums text-zinc-300">{m.value}%</span>
                      </div>
                      <div className="h-2 overflow-hidden rounded-full border border-white/[0.08] bg-black/50">
                        <div
                          className="h-full rounded-full transition-all"
                          style={{
                            width: `${m.value}%`,
                            background: `linear-gradient(90deg, color-mix(in srgb, var(--universe-primary) 85%, transparent), color-mix(in srgb, var(--universe-accent) 80%, transparent))`,
                          }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ) : null}
          </div>

          {postAnalysis ? (
            <MockExamResultRadar
              metrics={postAnalysis.radar.map((m) => ({ id: m.id, label: m.label, value: m.value }))}
              style={examThemeStyle}
            />
          ) : null}
        </div>

        {postAnalysis && postAnalysis.gapBuckets.length > 0 ? (
          <div className="rounded-xl border border-amber-400/30 bg-amber-500/[0.06] p-4">
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.22em] text-amber-100/90">Lücken Fokus</p>
            <p className="mt-1 font-sans text-xs text-amber-50/85">Unter 72% Trefferquote hier nachziehen</p>
            <div className="mt-3 flex flex-wrap gap-2">
              {postAnalysis.gapBuckets.map((bucket) => {
                const target = inferRepairTargetFromBucket(bucket);
                return (
                  <motion.button
                    key={bucket}
                    type="button"
                    whileTap={{ scale: 0.97 }}
                    transition={springHeavy}
                    onClick={() => openRepair(target)}
                    className="rounded-lg border border-amber-400/45 bg-black/30 px-3 py-2 font-mono text-[10px] font-semibold uppercase tracking-[0.16em] text-amber-50 hover:border-amber-300/65"
                  >
                    {repairCtaLabel[target]}
                  </motion.button>
                );
              })}
            </div>
          </div>
        ) : null}

        {challengeCompare ? (
          <div className="rounded-xl border border-emerald-400/35 bg-emerald-500/[0.07] p-4 font-mono text-xs uppercase tracking-[0.16em] text-emerald-100">
            {challengeCompare.faster
              ? `Du warst ${challengeCompare.pct.toFixed(1)}% schneller als ${challengeCompare.by}`
              : `Du warst ${challengeCompare.pct.toFixed(1)}% langsamer als ${challengeCompare.by}`}
            <br />
            Score Delta {challengeCompare.scoreDelta >= 0 ? "+" : ""}
            {challengeCompare.scoreDelta.toFixed(1)}%
          </div>
        ) : null}

        <div className="rounded-xl border border-white/[0.08] bg-black/40 p-4">
          <p className="font-mono text-[10px] uppercase tracking-[0.22em] text-zinc-500">Fehlerquellen und Nachschärfen</p>
          {result.weakTags.length === 0 ? (
            <p className="mt-3 font-mono text-xs uppercase tracking-[0.16em] text-emerald-200/90">Keine offensichtliche Schwachstelle erkannt</p>
          ) : (
            <ul className="mt-3 space-y-3">
              {result.weakTags.map(([tag, count]) => {
                const target = inferRepairTargetFromTag(tag);
                return (
                  <li
                    key={tag}
                    className="flex flex-col gap-2 rounded-lg border border-white/[0.06] bg-black/30 px-3 py-2 sm:flex-row sm:items-center sm:justify-between"
                  >
                    <span className="font-mono text-xs uppercase tracking-[0.14em] text-zinc-300">
                      {tag} · {count} Fehler
                    </span>
                    <motion.button
                      type="button"
                      whileTap={{ scale: 0.97 }}
                      transition={springHeavy}
                      onClick={() => openRepair(target)}
                      className="shrink-0 rounded-md border border-white/[0.12] px-3 py-1.5 font-mono text-[10px] font-semibold uppercase tracking-[0.16em] text-zinc-200 hover:border-[color-mix(in_srgb,var(--universe-primary)_45%,transparent)] hover:text-[var(--universe-primary)]"
                    >
                      {repairCtaLabel[target]}
                    </motion.button>
                  </li>
                );
              })}
            </ul>
          )}
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <motion.button
            type="button"
            whileTap={{ scale: 0.95, y: 2 }}
            transition={springHeavy}
            onClick={async () => {
              const slug = buildChallengeSlug({
                ids: run.questionSet.map((q) => q.id),
                by: operatorHandle ?? "Unknown_Operator",
                elapsedMs,
                percent: result.percent,
              });
              const url = `${window.location.origin}${window.location.pathname}?challenge=${encodeURIComponent(slug)}`;
              try {
                await navigator.clipboard.writeText(url);
                setShareState("ok");
              } catch {
                setShareState("err");
              }
            }}
            className="rounded-xl border border-emerald-400/45 bg-emerald-500/[0.12] px-5 py-2.5 font-mono text-xs font-black uppercase tracking-[0.2em] text-emerald-100 hover:border-emerald-300/55"
          >
            Challenge Link kopieren
          </motion.button>
          {shareState === "ok" ? (
            <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-emerald-200">Challenge Link kopiert</span>
          ) : shareState === "err" ? (
            <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-signal">Clipboard Zugriff blockiert</span>
          ) : null}
        </div>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => abandon()}
          className="w-full rounded-xl border border-white/[0.12] bg-white/[0.05] px-5 py-2.5 font-mono text-xs font-semibold uppercase tracking-[0.18em] text-zinc-200 hover:border-white/[0.2]"
        >
          Zurück zum Hub
        </motion.button>
      </div>
    );
  }

  const stress = stressRatio(run);
  const timer = timerVisuals(stress);

  return (
    <div className="flex min-h-[min(100dvh,100vh)] flex-col bg-[#050608]">
      <div className="sticky top-0 z-20 border-b border-white/[0.06] bg-[#050608]/95 px-3 py-3 backdrop-blur-md sm:px-5">
        <div className="mx-auto flex max-w-[min(100%,1680px)] flex-wrap items-center justify-between gap-3">
          <div className="flex min-w-0 flex-wrap items-center gap-3">
            <span className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-zinc-500">
              IHK Probezeit · {selectedExamId}
            </span>
            <div className="h-4 w-px bg-white/10" aria-hidden />
            <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
              Frage {idx + 1} / {total}
            </span>
            <div className="hidden h-1.5 min-w-[6rem] flex-1 overflow-hidden rounded-full border border-white/[0.08] bg-black/50 sm:block sm:max-w-[10rem]">
              <div
                className={cn("h-full rounded-full bg-gradient-to-r transition-[width] duration-500", timer.bar)}
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <div
              className={cn(
                "flex items-center gap-2 rounded-xl border bg-black/50 px-3 py-2 tabular-nums transition-shadow",
                timer.ring,
              )}
            >
              <span className="font-mono text-[9px] uppercase tracking-[0.24em] text-zinc-500">Restzeit</span>
              <span className={cn("font-mono text-lg font-bold tracking-tight sm:text-xl", timer.text)}>{fmtClock(run.timeRemainingSec)}</span>
            </div>
            <motion.button
              type="button"
              whileTap={{ scale: 0.96 }}
              transition={springHeavy}
              onClick={() => abandon()}
              className="rounded-lg border border-white/[0.12] px-3 py-2 font-mono text-[10px] font-semibold uppercase tracking-[0.2em] text-zinc-400 hover:border-white/[0.2] hover:text-zinc-200"
            >
              Abbrechen
            </motion.button>
            <motion.button
              type="button"
              whileTap={{ scale: 0.96 }}
              transition={springHeavy}
              onClick={() => submit()}
              className="rounded-lg border border-signal/50 bg-signal/[0.12] px-3 py-2 font-mono text-[10px] font-bold uppercase tracking-[0.2em] text-signal hover:border-signal/70"
            >
              Prüfung beenden
            </motion.button>
          </div>
        </div>
      </div>

      <div className="mx-auto flex w-full max-w-[min(100%,1680px)] flex-1 flex-col gap-6 px-3 py-5 lg:flex-row lg:gap-8 lg:px-5 lg:py-6">
        <div className="min-w-0 flex-1 space-y-5">
          <div className="rounded-2xl border border-white/[0.07] bg-black/30 p-4 sm:p-6">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <p className="font-mono text-[10px] uppercase tracking-[0.22em] text-zinc-500">
                {question.type === "sql_challenge" ? "SQL Challenge" : "Multiple Choice"}
              </p>
              <motion.button
                type="button"
                whileTap={{ scale: 0.97 }}
                transition={springHeavy}
                onClick={() => toggleFlag()}
                className={cn(
                  "rounded-lg border px-3 py-1.5 font-mono text-[10px] font-semibold uppercase tracking-[0.18em] transition-colors",
                  isFlagged
                    ? "border-amber-400/55 bg-amber-500/[0.15] text-amber-100"
                    : "border-white/[0.1] text-zinc-500 hover:border-amber-400/35 hover:text-amber-100/90",
                )}
              >
                {isFlagged ? "Markierung lösen" : "Zur Prüfung markieren"}
              </motion.button>
            </div>
            <h2 className="mt-3 font-serif text-xl font-semibold leading-snug text-zinc-50 sm:text-2xl">{question.prompt}</h2>
          </div>

          <div className="space-y-2">
            {question.options.map((opt, optionIndex) => {
              const selected = run.answers[idx] === optionIndex;
              return (
                <button
                  key={`${question.id}-${optionIndex}`}
                  type="button"
                  onClick={() => setAnswer(optionIndex)}
                  className={cn(
                    "w-full rounded-xl border px-4 py-3.5 text-left font-sans text-sm transition-colors",
                    selected
                      ? "border-emerald-400/45 bg-emerald-500/[0.1] text-zinc-50"
                      : "border-white/[0.08] bg-black/25 text-zinc-200 hover:border-white/[0.14]",
                  )}
                >
                  <span className="font-mono text-[10px] uppercase tracking-[0.16em] text-zinc-500">Option {optionIndex + 1}</span>
                  <p className="mt-1 leading-relaxed">{opt}</p>
                </button>
              );
            })}
          </div>

          <div className="flex flex-wrap items-center gap-2 border-t border-white/[0.06] pt-4">
            <motion.button
              type="button"
              whileTap={{ scale: 0.95, y: 2 }}
              transition={springHeavy}
              onClick={() => prev()}
              className="rounded-lg border border-white/[0.1] px-4 py-2 font-mono text-[11px] font-semibold uppercase tracking-[0.16em] text-zinc-400 hover:border-white/[0.18] hover:text-zinc-100"
            >
              Zurück
            </motion.button>
            <motion.button
              type="button"
              whileTap={{ scale: 0.95, y: 2 }}
              transition={springHeavy}
              onClick={() => next()}
              className="rounded-lg border border-white/[0.1] px-4 py-2 font-mono text-[11px] font-semibold uppercase tracking-[0.16em] text-zinc-400 hover:border-white/[0.18] hover:text-zinc-100"
            >
              Weiter
            </motion.button>
            <p className="ml-auto font-mono text-[10px] uppercase tracking-[0.18em] text-zinc-500">
              Beantwortet {answeredCount}/{total}
            </p>
          </div>
        </div>

        <aside className="shrink-0 rounded-2xl border border-white/[0.07] bg-black/25 p-4 lg:w-[min(100%,320px)] lg:self-start">
          <ExamQuestionMatrix total={total} currentIdx={idx} answers={run.answers} flagged={flagged} onJump={jump} />
        </aside>
      </div>
    </div>
  );
}
