import type { RealtimeChannel } from "@supabase/supabase-js";
import { getSupabase } from "../supabase";
import type { NexusActivityEventPayload } from "../../types/nexusActivity";

type SyndicateHandlers = {
  onActivity: (payload: NexusActivityEventPayload) => void;
  onFactionTotals: (snapshot: { fisiXp: number; fiaeXp: number }) => void;
};

let activityChannel: RealtimeChannel | null = null;
let factionChannel: RealtimeChannel | null = null;
let activeHandlers: SyndicateHandlers | null = null;

export function startSyndicateRealtimeBridge(handlers: SyndicateHandlers): void {
  activeHandlers = handlers;
  const sb = getSupabase();
  if (!sb) return;
  if (activityChannel || factionChannel) return;

  activityChannel = sb
    .channel("codesnap-syndicate-activity")
    .on("broadcast", { event: "nexus_activity" }, (packet) => {
      const payload = sanitizeActivityPayload(packet.payload);
      if (!payload) return;
      activeHandlers?.onActivity(payload);
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT") {
        safeStop();
      }
    });

  factionChannel = sb
    .channel("codesnap-syndicate-faction")
    .on(
      "postgres_changes",
      { event: "*", schema: "public", table: "faction_xp_war_totals_live" },
      async () => {
        const snapshot = await fetchFactionTotals();
        activeHandlers?.onFactionTotals(snapshot);
      },
    )
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT") {
        safeStop();
      }
    });
}

export function stopSyndicateRealtimeBridge(): void {
  safeStop();
}

export async function fetchFactionTotals(): Promise<{ fisiXp: number; fiaeXp: number }> {
  const sb = getSupabase();
  if (!sb) return { fisiXp: 0, fiaeXp: 0 };
  const { data } = await sb.from("faction_xp_war_totals_live").select("fisi_total_xp,fiae_total_xp").maybeSingle();
  return {
    fisiXp: Math.max(0, Math.floor(Number(data?.fisi_total_xp ?? 0))),
    fiaeXp: Math.max(0, Math.floor(Number(data?.fiae_total_xp ?? 0))),
  };
}

function safeStop(): void {
  const sb = getSupabase();
  const closingActivity = activityChannel;
  const closingFaction = factionChannel;
  activityChannel = null;
  factionChannel = null;
  activeHandlers = null;
  if (!sb) return;
  if (closingActivity) {
    void sb.removeChannel(closingActivity);
  }
  if (closingFaction) {
    void sb.removeChannel(closingFaction);
  }
}

function sanitizeActivityPayload(payload: unknown): NexusActivityEventPayload | null {
  if (!payload || typeof payload !== "object") return null;
  const event = payload as NexusActivityEventPayload;
  if (typeof event.kind !== "string" || typeof event.label !== "string") return null;
  return {
    kind: event.kind,
    label: event.label,
    userId: typeof event.userId === "string" ? event.userId : undefined,
    handle: typeof event.handle === "string" ? event.handle : undefined,
    routeHint: event.routeHint === "public_dossier" ? "public_dossier" : undefined,
    meta: event.meta && typeof event.meta === "object" ? event.meta : undefined,
  };
}
