import { motion } from "framer-motion";
import { useCallback } from "react";
import { IconTerminal } from "../icons/ThinLineIcons";
import { SQL_MISSIONS } from "../../data/sqlMissions";
import { cn } from "../../lib/cn";
import { itemReveal, sqlMissionStagger, staggerContainer } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";
import { SqlMissionCard } from "./SqlMissionCard";
import { SqlAcademyShell } from "../realm/academy/SqlAcademyShell";

export function SqlMissionList() {
  const sqlUnlockedLevels = useAppStore((s) => s.sqlUnlockedLevels);
  const completeSqlMission = useAppStore((s) => s.completeSqlMission);
  const enterSqlSandbox = useAppStore((s) => s.enterSqlSandbox);

  const onCheckpoint = useCallback(
    (id: string) => {
      completeSqlMission(id);
    },
    [completeSqlMission],
  );

  return (
    <div className="space-y-6">
      <motion.div
        variants={staggerContainer}
        initial="initial"
        animate="animate"
        className="space-y-3"
      >
        <motion.div variants={itemReveal} className="space-y-2">
          <p className="font-sans text-[11px] font-semibold uppercase tracking-[0.28em] text-magenta">
            Datenbank-Insel
          </p>
          <h2 className="font-display text-3xl font-bold uppercase tracking-wide text-foreground sm:text-4xl">
            SQL Adventure
          </h2>
          <p className="max-w-2xl font-sans text-sm text-foreground-muted sm:text-base">
            Missionen mit Neon-Locks — scroll leicht, alles bleibt butterweich im DOM
          </p>
        </motion.div>
        <motion.div variants={itemReveal}>
          <motion.button
            type="button"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={() => enterSqlSandbox()}
            className={cn(
              "inline-flex w-full items-center justify-center gap-2 rounded-2xl border border-toxic/40 bg-toxic/10 py-3 font-display text-sm font-bold uppercase tracking-wide text-toxic ring-1 ring-white/10 sm:w-auto sm:px-8",
            )}
          >
            <IconTerminal className="size-5 shrink-0 text-toxic" aria-hidden />
            Freie SQL-Konsole
          </motion.button>
        </motion.div>
      </motion.div>

      <div
        className={cn(
          "max-h-[min(70vh,540px)] overflow-y-auto overflow-x-hidden rounded-2xl border border-border-glass bg-surface/30 p-3 sm:p-4",
          "overscroll-y-contain touch-pan-y [scrollbar-gutter:stable]",
        )}
        style={{ contain: "layout paint" }}
      >
        <motion.div
          variants={sqlMissionStagger}
          initial="initial"
          animate="animate"
          className="flex flex-col gap-4 pb-2"
        >
          {SQL_MISSIONS.map((mission) => (
            <SqlMissionCard
              key={mission.id}
              mission={mission}
              unlocked={sqlUnlockedLevels.includes(mission.id)}
              onCheckpoint={onCheckpoint}
            />
          ))}
        </motion.div>
      </div>

      <SqlAcademyShell />
    </div>
  );
}
