import type { ExamId } from "./exams";
import type { CareerPath } from "../store/useAppStore";

export type QuestionDifficulty = "easy" | "medium" | "hard";
export type QuestionType = "multiple_choice" | "sql_challenge";
export type QuestionModule =
  | "networking"
  | "security"
  | "operating_systems"
  | "hardware"
  | "programming"
  | "databases"
  | "testing"
  | "architecture"
  | "process"
  | "wiso";

export type MultipleChoicePayload = {
  options: [string, string, string, string];
  correctIndex: 0 | 1 | 2 | 3;
  rationales?: [string?, string?, string?, string?];
};

export type SqlChallengePayload = {
  prompt: string;
  starterSql?: string;
  options: [string, string, string, string];
  correctIndex: 0 | 1 | 2 | 3;
  expectedAnswer?: string;
  hints?: string[];
};

export type QuestionBankEntry = {
  id: string;
  slug: string;
  examId: ExamId;
  careerPaths: CareerPath[];
  module: QuestionModule;
  type: QuestionType;
  prompt: string;
  /** Phase 48 — Kurzbegründung nach Antwort (Cloud-Bank / Ammo-Drop) */
  explanation?: string;
  /** Phase 63 — optional statischer Funk-Hinweis (Arena Neural-Link) */
  hint?: string;
  difficulty: QuestionDifficulty;
  tags: string[];
  source?: string;
  imagePath?: string;
  /** Absolute URL oder data-URI (Phase 46), Vorrang vor imagePath wenn gesetzt */
  imageUrl?: string;
  /** Formatierter Referenzcode unter dem Prompt (Phase 46) */
  codeSnippet?: string;
  version: number;
  isPublished: boolean;
  payload: MultipleChoicePayload | SqlChallengePayload;
};

export type MasterQuestionSeed = QuestionBankEntry[];

export function isExamId(value: unknown): value is ExamId {
  return value === "AP1" || value === "AP2" || value === "WISO";
}

function isQuestionDifficulty(value: unknown): value is QuestionDifficulty {
  return value === "easy" || value === "medium" || value === "hard";
}

function isQuestionModule(value: unknown): value is QuestionModule {
  return (
    value === "networking" ||
    value === "security" ||
    value === "operating_systems" ||
    value === "hardware" ||
    value === "programming" ||
    value === "databases" ||
    value === "testing" ||
    value === "architecture" ||
    value === "process" ||
    value === "wiso"
  );
}

function isQuestionType(value: unknown): value is QuestionType {
  return value === "multiple_choice" || value === "sql_challenge";
}

function isCareerPaths(value: unknown): value is CareerPath[] {
  return (
    Array.isArray(value) &&
    value.length > 0 &&
    value.every((entry) => entry === "FISI" || entry === "FIAE")
  );
}

function isOptions(value: unknown): value is [string, string, string, string] {
  return (
    Array.isArray(value) &&
    value.length === 4 &&
    value.every((entry) => typeof entry === "string" && entry.trim().length > 0)
  );
}

function isRationales(value: unknown): value is [string?, string?, string?, string?] {
  return (
    Array.isArray(value) &&
    value.length === 4 &&
    value.every((entry) => entry === undefined || typeof entry === "string")
  );
}

export function isQuestionBankEntry(value: unknown): value is QuestionBankEntry {
  if (!value || typeof value !== "object") return false;
  const row = value as Record<string, unknown>;
  if (
    typeof row.id !== "string" ||
    typeof row.slug !== "string" ||
    !isExamId(row.examId) ||
    !isCareerPaths(row.careerPaths) ||
    !isQuestionModule(row.module) ||
    !isQuestionType(row.type) ||
    typeof row.prompt !== "string" ||
    !isQuestionDifficulty(row.difficulty) ||
    !Array.isArray(row.tags) ||
    !row.tags.every((entry) => typeof entry === "string") ||
    (row.source !== undefined && typeof row.source !== "string") ||
    (row.imagePath !== undefined && typeof row.imagePath !== "string") ||
    (row.imageUrl !== undefined && typeof row.imageUrl !== "string") ||
    (row.codeSnippet !== undefined && typeof row.codeSnippet !== "string") ||
    (row.hint !== undefined && typeof row.hint !== "string") ||
    typeof row.version !== "number" ||
    typeof row.isPublished !== "boolean" ||
    !row.payload ||
    typeof row.payload !== "object"
  ) {
    return false;
  }

  const payload = row.payload as Record<string, unknown>;
  if (!isOptions(payload.options)) return false;
  if (![0, 1, 2, 3].includes(payload.correctIndex as number)) return false;
  if (row.type === "multiple_choice") {
    return payload.rationales === undefined || isRationales(payload.rationales);
  }
  return (
    typeof payload.prompt === "string" &&
    (payload.starterSql === undefined || typeof payload.starterSql === "string") &&
    (payload.expectedAnswer === undefined || typeof payload.expectedAnswer === "string") &&
    (payload.hints === undefined ||
      (Array.isArray(payload.hints) && payload.hints.every((entry) => typeof entry === "string")))
  );
}
