import type { SqlChapter } from "../../../data/sqlAcademyContent";

type ChapterNavProps = {
  chapters: SqlChapter[];
  activeChapterId: string;
  onSelect: (chapterId: string) => void;
  resolveProgressTone: (chapter: SqlChapter) => "none" | "partial" | "full";
};

export function ChapterNav({ chapters, activeChapterId, onSelect, resolveProgressTone }: ChapterNavProps) {
  return (
    <div className="top-nav">
      {chapters.map((chapter) => {
        const tone = resolveProgressTone(chapter);
        return (
          <button
            key={chapter.id}
            type="button"
            className={`top-nav-btn ${chapter.id === activeChapterId ? "active" : ""}`}
            onClick={() => onSelect(chapter.id)}
          >
            <span>{String(chapter.order).padStart(2, "0")}</span>
            <span
              aria-hidden
              className={`ml-2 inline-block h-2 w-2 rounded-full ${
                tone === "full" ? "bg-emerald-300" : tone === "partial" ? "bg-cyan-300" : "bg-slate-600"
              }`}
            />
          </button>
        );
      })}
    </div>
  );
}
