import type { LearningFlowBlock } from "../../../../data/sqlAcademyContent";
import { cn } from "../../../../lib/cn";

type LearningFocusCardProps = {
  block: LearningFlowBlock;
  /** Optional IHK context line without trailing punctuation */
  examContextLine?: string;
};

export function LearningFocusCard({ block, examContextLine }: LearningFocusCardProps) {
  const isCodeLike =
    block.type === "mini_example" || block.type === "solution" || block.type === "exercise";

  return (
    <article
      className="mx-auto w-full max-w-2xl rounded-2xl border border-cyan-500/25 bg-slate-950/75 p-6 shadow-[0_0_40px_rgba(6,182,212,0.08)] ring-1 ring-white/[0.04] sm:p-8"
      aria-labelledby="academy-focus-title"
    >
      <p className="font-mono text-[10px] uppercase tracking-[0.28em] text-cyan-300/90">Aktueller Baustein</p>
      {examContextLine ? (
        <p className="mt-2 inline-block rounded border border-amber-400/30 bg-amber-950/30 px-2 py-0.5 font-mono text-[9px] uppercase tracking-[0.18em] text-amber-100">
          {examContextLine}
        </p>
      ) : null}
      <h2 id="academy-focus-title" className="mt-4 font-display text-2xl font-semibold tracking-tight text-slate-50 sm:text-3xl">
        {block.title}
      </h2>
      <div className="mt-5">
        {isCodeLike ? (
          <pre
            className={cn(
              "overflow-x-auto rounded-lg border border-cyan-500/20 bg-slate-900/90 p-4 font-mono text-sm leading-relaxed text-cyan-50/95",
            )}
          >
            <code>{block.content}</code>
          </pre>
        ) : (
          <p className="text-base leading-relaxed text-slate-200 sm:text-lg">{block.content}</p>
        )}
      </div>
    </article>
  );
}
