const LORE_PREFIX: Record<SqlUniverseId, string> = {
  bodybuilding: "Gym Ops",
  star_wars: "Jedi Ops",
  anime: "Dojo Ops",
  nutrition: "Meal Ops",
  cs_tactical: "Tactical Ops",
  warzone: "Field Ops",
  wow: "Guild Ops",
};

export function buildJobAssignments(universeId: SqlUniverseId): JobAssignment[] {
  const prefix = LORE_PREFIX[universeId] ?? "Ops";
  return BASE_ASSIGNMENTS.map((assignment, index) => ({
    ...assignment,
    id: `${universeId}-${assignment.id}`,
    title: `${prefix} ${index + 1} ${assignment.title}`,
  }));
}
