export type SyndicateTechBuffVector = {
  xpMultiplier: number;
  timeBonusSec: number;
  dropRateBonus: number;
};

export function resolveSyndicateTechBuffs(unlockedNodeIds: string[]): SyndicateTechBuffVector {
  let xpMultiplier = 1;
  let timeBonusSec = 0;
  let dropRateBonus = 0;
  const unlocked = new Set(unlockedNodeIds);
  for (const node of SYNDICATE_TECH_NODES) {
    if (!unlocked.has(node.id)) continue;
    if (typeof node.effects.xpMultiplier === "number") xpMultiplier *= node.effects.xpMultiplier;
    if (typeof node.effects.timeBonusSec === "number") timeBonusSec += node.effects.timeBonusSec;
    if (typeof node.effects.dropRateBonus === "number") dropRateBonus += node.effects.dropRateBonus;
  }
  return {
    xpMultiplier: Math.max(1, Number(xpMultiplier.toFixed(4))),
    timeBonusSec: Math.max(0, Math.floor(timeBonusSec)),
    dropRateBonus: Math.max(0, Number(dropRateBonus.toFixed(4))),
  };
}
