import { motion, useReducedMotion } from "framer-motion";
import type { CSSProperties } from "react";
import { useEffect, useMemo, useState } from "react";
import {
  DEFAULT_TERMINAL_THEME_ID,
  getTerminalThemeById,
  isTerminalThemeUnlocked,
  prestigeRankIndexFromLifetimeXp,
  resolveScanlineAlpha,
  TERMINAL_THEMES,
  type TerminalThemeDefinition,
  type TerminalThemeId,
} from "../../data/terminalThemes";
import { computeLifetimeXp } from "../../lib/xpCurve";
import { PRESTIGE_RANKS } from "../../lib/rankEngine";
import { springHeavy } from "../../motion/variants";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

function prestigeGateLabel(minRankIndex: number): string {
  const row = PRESTIGE_RANKS[Math.min(PRESTIGE_RANKS.length - 1, Math.max(0, minRankIndex))];
  return row?.title ?? "System Trainee";
}

export function RigCalibrationPanel() {
  const reduceMotion = useReducedMotion();
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const rigTerminalThemeId = useAppStore((s) => s.rigTerminalThemeId);
  const rigScanlineDial = useAppStore((s) => s.rigScanlineDial);
  const setRigTerminalThemeId = useAppStore((s) => s.setRigTerminalThemeId);
  const setRigScanlineDial = useAppStore((s) => s.setRigScanlineDial);

  const lifetimeXp = useMemo(() => computeLifetimeXp(userLevel, globalXP), [userLevel, globalXP]);
  const prestigeRankIndex = useMemo(() => prestigeRankIndexFromLifetimeXp(lifetimeXp), [lifetimeXp]);

  const [previewId, setPreviewId] = useState<TerminalThemeId>(rigTerminalThemeId);
  const previewTheme = useMemo(
    () => getTerminalThemeById(previewId) ?? getTerminalThemeById(DEFAULT_TERMINAL_THEME_ID)!,
    [previewId],
  );
  const previewScanline = resolveScanlineAlpha(previewTheme, rigScanlineDial, prestigeRankIndex);

  useEffect(() => {
    setPreviewId(rigTerminalThemeId);
  }, [rigTerminalThemeId]);

  return (
    <section
      data-print-hide
      className="dossier-section space-y-6 border border-white/[0.12] bg-[#060606]/80 p-6 sm:p-8"
    >
      <div className="space-y-2">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-foreground-muted">
          Rig Calibration
        </p>
        <h2 className="headline-cinema text-2xl font-semibold">Terminal Rig</h2>
        <p className="max-w-prose font-sans text-xs leading-relaxed text-foreground-muted">
          Kalibrierfeld für Phosphor Akzent und Scanline — Presets koppeln an Prestige Lifetime XP
        </p>
      </div>

      <div className="grid gap-8 lg:grid-cols-[minmax(0,1fr)_280px] lg:items-start">
        <div className="space-y-4">
          <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.26em] text-foreground-muted">
            Hardware Vorschau
          </p>
          <motion.div
            layout
            className="relative mx-auto w-full max-w-md overflow-hidden border border-white/[0.18] bg-black/80 p-[10px] shadow-[inset_0_0_0_1px_rgb(255_255_255_/_0.06),0_0_42px_rgb(0_0_0_/_0.55)]"
            transition={springHeavy}
          >
            <div
              className="pointer-events-none absolute left-2 top-2 size-2 rounded-full border border-white/25 bg-white/[0.04]"
              aria-hidden
            />
            <div
              className="pointer-events-none absolute right-2 top-2 size-2 rounded-full border border-white/25 bg-white/[0.04]"
              aria-hidden
            />
            <div
              className="pointer-events-none absolute bottom-2 left-2 size-2 rounded-full border border-white/25 bg-white/[0.04]"
              aria-hidden
            />
            <div
              className="pointer-events-none absolute bottom-2 right-2 size-2 rounded-full border border-white/25 bg-white/[0.04]"
              aria-hidden
            />
            <div className="relative aspect-[16/10] overflow-hidden border border-white/[0.1] bg-[#030303]">
              <div
                className="pointer-events-none absolute inset-0 scanlines opacity-75"
                style={
                  {
                    ["--rig-scanline-alpha" as string]: previewScanline,
                  } as CSSProperties
                }
              />
              <div
                className="pointer-events-none absolute inset-0 mix-blend-soft-light opacity-90"
                style={{
                  background: `radial-gradient(ellipse 70% 58% at 50% 48%, ${previewTheme.phosphorCenter}, transparent 60%)`,
                }}
              />
              <div className="relative flex h-full flex-col justify-end p-4 font-mono text-[11px] leading-relaxed">
                <p className="uppercase tracking-[0.28em] text-foreground-muted">Testraster</p>
                <p className="mt-2 text-sm font-semibold tracking-tight" style={{ color: previewTheme.signalHex }}>
                  SIGNAL OK · CH {previewScanline.toFixed(2)}
                </p>
                <p className="mt-1 text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
                  Referenzpass für Dock und Signal UI
                </p>
              </div>
            </div>
          </motion.div>
        </div>

        <div className="space-y-5">
          <div className="space-y-2">
            <label className="block font-mono text-[9px] font-semibold uppercase tracking-[0.24em] text-foreground-muted">
              Scanline Verstärkung
            </label>
            <input
              type="range"
              min={0}
              max={100}
              value={rigScanlineDial}
              onChange={(e) => setRigScanlineDial(Number(e.target.value))}
              className="h-1.5 w-full cursor-pointer appearance-none rounded-full bg-white/[0.08] accent-[var(--color-signal)]"
            />
            <p className="font-mono text-[9px] tabular-nums text-foreground-muted">
              Dial {rigScanlineDial} · effektiv {previewScanline.toFixed(3)}
            </p>
          </div>
          <p className="font-mono text-[9px] uppercase tracking-[0.18em] text-foreground-muted">
            Prestige {PRESTIGE_RANKS[prestigeRankIndex]?.title ?? "—"}
          </p>
        </div>
      </div>

      <div className="space-y-3">
        <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.26em] text-foreground-muted">
          Preset Matrix
        </p>
        <div className="grid gap-3 sm:grid-cols-2">
          {TERMINAL_THEMES.map((theme: TerminalThemeDefinition) => {
            const unlocked = isTerminalThemeUnlocked(theme, prestigeRankIndex);
            const active = rigTerminalThemeId === theme.id;
            const previewing = previewId === theme.id;
            return (
              <motion.button
                key={theme.id}
                type="button"
                layout
                whileTap={reduceMotion ? undefined : { scale: 0.98 }}
                transition={springHeavy}
                onClick={() => {
                  setPreviewId(theme.id);
                  if (unlocked) setRigTerminalThemeId(theme.id);
                }}
                className={cn(
                  "relative overflow-hidden border px-4 py-3 text-left transition-colors",
                  unlocked ? "border-white/[0.14] bg-white/[0.03] hover:border-white/[0.22]" : "border-white/[0.08] bg-black/40 opacity-70",
                  (active || previewing) && unlocked && "border-[var(--color-signal)]/50 ring-1 ring-[var(--color-signal)]/25",
                )}
              >
                <div
                  className="pointer-events-none absolute inset-0 opacity-[0.14]"
                  style={{
                    background: `linear-gradient(120deg, transparent 0%, ${theme.phosphorCenter} 48%, transparent 72%)`,
                  }}
                />
                <p className="relative font-mono text-[11px] font-semibold uppercase tracking-[0.16em] text-foreground">
                  {theme.displayName}
                </p>
                {!unlocked ? (
                  <p className="relative mt-2 font-mono text-[9px] uppercase tracking-[0.14em] text-foreground-muted">
                    Gesperrt bis {prestigeGateLabel(theme.minPrestigeRankIndex)}
                  </p>
                ) : (
                  <p className="relative mt-2 font-mono text-[9px] uppercase tracking-[0.14em] text-foreground-muted">
                    {active ? "Aktiv im Stack" : "Tippen zum Übernehmen"}
                  </p>
                )}
              </motion.button>
            );
          })}
        </div>
      </div>
    </section>
  );
}
