import { motion, useReducedMotion } from "framer-motion";

const pulse = {
  initial: { opacity: 0.72 },
  animate: { opacity: [0.72, 0.9, 0.72] },
  transition: { duration: 4.2, repeat: Infinity, ease: "easeInOut" as const },
};

export function DBSFlow() {
  const reduce = !!useReducedMotion();

  return (
    <motion.svg
      viewBox="0 0 640 220"
      className="academy-diagram"
      role="img"
      aria-label="Aktenschrank Bibliothekar SQL Fluss"
      {...(reduce
        ? { initial: { opacity: 0.9 }, animate: { opacity: 0.9 } }
        : pulse)}
    >
      <defs>
        <linearGradient id="dbsFrame" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#00E5FF" stopOpacity="0.72" />
          <stop offset="100%" stopColor="#FF2BD6" stopOpacity="0.72" />
        </linearGradient>
        <linearGradient id="dbsBeam" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor="#00E5FF" />
          <stop offset="100%" stopColor="#FF2BD6" />
        </linearGradient>
      </defs>

      <rect x="12" y="14" width="616" height="192" rx="18" fill="#060D19" stroke="url(#dbsFrame)" strokeOpacity="0.65" />

      <g>
        <rect x="38" y="46" width="172" height="124" rx="14" fill="#08192A" stroke="#00E5FF" strokeOpacity="0.7" />
        <text x="124" y="84" textAnchor="middle" className="diagram-title">DB</text>
        <text x="124" y="104" textAnchor="middle" className="diagram-sub">Aktenschrank</text>
        <text x="124" y="124" textAnchor="middle" className="diagram-sub">nahrungsmittel</text>
        <text x="124" y="142" textAnchor="middle" className="diagram-sub">uebungen</text>
      </g>

      <g>
        <rect x="234" y="46" width="172" height="124" rx="14" fill="#1A0822" stroke="#FF2BD6" strokeOpacity="0.72" />
        <text x="320" y="84" textAnchor="middle" className="diagram-title">DBMS</text>
        <text x="320" y="104" textAnchor="middle" className="diagram-sub">Bibliothekar</text>
        <text x="320" y="124" textAnchor="middle" className="diagram-sub">nimmt SQL an</text>
        <text x="320" y="142" textAnchor="middle" className="diagram-sub">liefert Ergebnis</text>
      </g>

      <g>
        <rect x="430" y="46" width="172" height="124" rx="14" fill="#091A22" stroke="#00E5FF" strokeOpacity="0.7" />
        <text x="516" y="84" textAnchor="middle" className="diagram-title">DBS</text>
        <text x="516" y="104" textAnchor="middle" className="diagram-sub">Ganzes Team</text>
        <text x="516" y="124" textAnchor="middle" className="diagram-sub">Aktenschrank</text>
        <text x="516" y="142" textAnchor="middle" className="diagram-sub">plus Bibliothekar</text>
      </g>

      <motion.line
        x1="210"
        y1="108"
        x2="234"
        y2="108"
        stroke="url(#dbsBeam)"
        strokeWidth="4"
        initial={reduce ? { pathLength: 1 } : { pathLength: 0 }}
        animate={{ pathLength: 1 }}
        transition={reduce ? { duration: 0 } : { duration: 1.2 }}
      />
      <motion.line
        x1="406"
        y1="108"
        x2="430"
        y2="108"
        stroke="url(#dbsBeam)"
        strokeWidth="4"
        initial={reduce ? { pathLength: 1 } : { pathLength: 0 }}
        animate={{ pathLength: 1 }}
        transition={reduce ? { duration: 0 } : { duration: 1.25, delay: 0.32 }}
      />

      {reduce ? null : (
        <motion.rect
          x="24"
          y="20"
          width="592"
          height="10"
          fill="#00E5FF"
          fillOpacity="0.07"
          animate={{ x: [24, 34, 24] }}
          transition={{ duration: 6, repeat: Infinity, ease: "easeInOut" }}
        />
      )}
    </motion.svg>
  );
}
