import type { CSSProperties } from "react";
import { cn } from "../../../../lib/cn";
import { UNIVERSE_THEME_FALLBACK } from "../../../../styles/themes/universeThemes";

export type GuidedTaskStepItem = {
  id: string;
  letter: string;
};

type GuidedTaskStepperProps = {
  tasks: readonly GuidedTaskStepItem[];
  maxUnlockedIndex: number;
  cursorIndex: number;
  onSelectStep: (index: number) => void;
  reducedMotion: boolean;
};

export function GuidedTaskStepper({
  tasks,
  maxUnlockedIndex,
  cursorIndex,
  onSelectStep,
  reducedMotion,
}: GuidedTaskStepperProps) {
  const primary = `var(--universe-primary, ${UNIVERSE_THEME_FALLBACK.primary})`;
  const accent = `var(--universe-accent, ${UNIVERSE_THEME_FALLBACK.accent})`;

  if (tasks.length === 0) return null;

  return (
    <nav
      aria-label="Aufgabenfolge"
      className="academy-guided-task-stepper border-b border-solid bg-slate-950/80 px-2 py-2 sm:px-4"
      style={{
        borderBottomColor: `color-mix(in srgb, ${primary} 22%, transparent)`,
        boxShadow: `0 8px 28px color-mix(in srgb, ${primary} 6%, transparent)`,
      }}
    >
      <ol className="mx-auto flex max-w-4xl list-none flex-wrap items-center justify-center gap-1 sm:gap-2">
        {tasks.map((task, index) => {
          const unlocked = index <= maxUnlockedIndex;
          const active = index === cursorIndex;
          const done = index < cursorIndex;
          const unlockedFuture = unlocked && !active && !done;

          const buttonStyle: CSSProperties | undefined = active
            ? {
                borderColor: `color-mix(in srgb, ${primary} 58%, transparent)`,
                backgroundColor: `color-mix(in srgb, ${primary} 18%, rgb(15 23 42))`,
                color: `color-mix(in srgb, ${primary} 92%, white)`,
                boxShadow: `0 0 18px color-mix(in srgb, ${primary} 22%, transparent), inset 0 0 14px color-mix(in srgb, ${primary} 10%, transparent)`,
              }
            : done
              ? {
                  borderColor: `color-mix(in srgb, ${accent} 48%, transparent)`,
                  backgroundColor: `color-mix(in srgb, ${accent} 12%, rgb(15 23 42))`,
                  color: `color-mix(in srgb, ${accent} 82%, white)`,
                  boxShadow: `0 0 12px color-mix(in srgb, ${accent} 14%, transparent)`,
                }
              : unlockedFuture
                ? {
                    borderColor: "color-mix(in srgb, rgb(255 255 255) 12%, transparent)",
                    backgroundColor: "color-mix(in srgb, rgb(15 23 42) 92%, transparent)",
                    color: "rgb(226 232 240)",
                  }
                : {
                    borderColor: "color-mix(in srgb, rgb(255 255 255) 6%, transparent)",
                    backgroundColor: "color-mix(in srgb, rgb(2 6 23) 88%, transparent)",
                    color: "rgb(71 85 105)",
                  };

          return (
            <li key={task.id} className="flex min-w-0 items-center">
              {index > 0 ? (
                <span
                  className="mx-0.5 hidden h-px w-2 shrink-0 sm:inline sm:w-3"
                  aria-hidden
                  style={{
                    backgroundColor: done
                      ? `color-mix(in srgb, ${accent} 35%, transparent)`
                      : `color-mix(in srgb, ${primary} 22%, transparent)`,
                  }}
                />
              ) : null}
              <button
                type="button"
                disabled={!unlocked}
                onClick={() => {
                  if (unlocked) onSelectStep(index);
                }}
                style={buttonStyle}
                className={cn(
                  "rounded-md border border-solid px-2 py-1 text-[10px] font-semibold uppercase tracking-[0.12em] transition-colors sm:px-2.5",
                  unlockedFuture ? "academy-guided-step-unlocked" : "",
                  !unlocked ? "cursor-not-allowed" : "",
                  reducedMotion ? "" : "duration-200",
                )}
              >
                <span className="sr-only">
                  Aufgabe {task.letter} {active ? "aktuell" : unlocked ? "wählbar" : "gesperrt"}
                </span>
                <span aria-hidden>{task.letter}</span>
              </button>
            </li>
          );
        })}
      </ol>
    </nav>
  );
}
