import { AnimatePresence, motion } from "framer-motion";
import { useEffect, useState } from "react";
import { SQL_UNIVERSE_ORDER, type SqlUniverseId } from "../../../data/universes";
import { getUniverseSeed } from "../../../data/factories/sqlContentFactory";
import { cn } from "../../../lib/cn";

const ACCENT_BUTTON: Record<SqlUniverseId, string> = {
  bodybuilding: "border-slate-300 hover:border-cyan-500",
  star_wars: "border-slate-300 hover:border-sky-500",
  nutrition: "border-slate-300 hover:border-emerald-500",
  cs_tactical: "border-slate-300 hover:border-lime-500",
  anime: "border-slate-300 hover:border-fuchsia-500",
  warzone: "border-slate-300 hover:border-amber-500",
  wow: "border-slate-300 hover:border-blue-500",
};

export function UniverseSelector({
  selectedUniverseId,
  onSelect,
}: {
  selectedUniverseId: SqlUniverseId;
  onSelect: (universeId: SqlUniverseId) => void;
}) {
  const [glitchId, setGlitchId] = useState<SqlUniverseId | null>(null);

  useEffect(() => {
    if (!glitchId) return;
    const timeout = window.setTimeout(() => setGlitchId(null), 260);
    return () => window.clearTimeout(timeout);
  }, [glitchId]);

  return (
    <div className="relative mt-3 grid gap-2">
      <AnimatePresence>
        {glitchId ? (
          <motion.div
            key={glitchId}
            initial={{ opacity: 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            className="pointer-events-none absolute inset-0 border border-sky-300 bg-sky-100/60"
          />
        ) : null}
      </AnimatePresence>
      {SQL_UNIVERSE_ORDER.map((universeId) => {
        const isActive = selectedUniverseId === universeId;
        const universe = getUniverseSeed(universeId);
        return (
          <motion.button
            key={universeId}
            type="button"
            onClick={() => {
              setGlitchId(universeId);
              onSelect(universeId);
            }}
            whileTap={{ scale: 0.98 }}
            className={cn(
              "relative overflow-hidden border px-2 py-2 text-left font-mono text-[10px] uppercase tracking-[0.15em] transition",
              ACCENT_BUTTON[universeId],
              isActive ? "bg-sky-100 text-sky-700 shadow-[0_0_0_1px_rgba(14,165,233,0.35)]" : "bg-white text-slate-700",
            )}
          >
            <span className="pointer-events-none absolute inset-0 bg-[linear-gradient(to_bottom,rgba(15,23,42,0.04)_1px,transparent_1px)] bg-[size:100%_6px]" />
            {universe.universeName}
          </motion.button>
        );
      })}
    </div>
  );
}
