import { motion, useReducedMotion } from "framer-motion";
import { useCallback, useEffect, useState } from "react";
import type { QuestionModule } from "../../data/questionSchema";
import { useAdminTelemetry } from "../../hooks/useAdminTelemetry";
import { cn } from "../../lib/cn";
import { getAudioRuntimeHealth } from "../../lib/webAudioUi";
import { QuestionForgeView } from "./QuestionForgeView";
import {
  broadcastSystemAnnouncement,
  armLaunchInitEvent,
  emergencyStopGlobalEvents,
  finalizeCurrentSeason,
  getRealtimeIntegritySnapshot,
  setManualRaidDropRateScale,
  triggerManualNeuralOverdrive,
} from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";

const BG = "#0a0304";
const OVERDRIVE_MODULES: Array<{ id: QuestionModule; label: string }> = [
  { id: "networking", label: "Netzwerk" },
  { id: "security", label: "Security" },
  { id: "operating_systems", label: "Betriebssysteme" },
  { id: "hardware", label: "Hardware" },
  { id: "programming", label: "Programmierung" },
  { id: "databases", label: "Datenbanken" },
  { id: "testing", label: "Testing" },
  { id: "architecture", label: "Architektur" },
  { id: "process", label: "Prozess" },
  { id: "wiso", label: "Wirtschaft" },
];

export function AdminControlView() {
  const prefersReduced = !!useReducedMotion();
  const isAdmin = useAppStore((s) => s.isAdmin);
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  const { loading, activeOperators, ingestPerMinute, serverLoadPct, painPoints, factionFisiXp, factionFiaeXp, refresh } =
    useAdminTelemetry();
  const [broadcastDraft, setBroadcastDraft] = useState("");
  const [broadcastStatus, setBroadcastStatus] = useState<"idle" | "ok" | "err">("idle");
  const [broadcastMsg, setBroadcastMsg] = useState("");
  const [seasonLabelDraft, setSeasonLabelDraft] = useState("");
  const [seasonFinalizeBusy, setSeasonFinalizeBusy] = useState(false);
  const [seasonFinalizeMsg, setSeasonFinalizeMsg] = useState("");
  const [seasonFinalizeStatus, setSeasonFinalizeStatus] = useState<"idle" | "ok" | "err">("idle");
  const syncStatus = useAppStore((s) => s.syncStatus);
  const swNeedRefresh = useAppStore((s) => s.swNeedRefresh);
  const feedbackEnabled = useAppStore((s) => s.feedbackEnabled);
  const raidDropRateScale = useAppStore((s) => s.raidDropRateScale);
  const [integrityTick, setIntegrityTick] = useState(0);
  const [dropScaleDraft, setDropScaleDraft] = useState(Math.round(raidDropRateScale * 100));
  const [directiveBusy, setDirectiveBusy] = useState(false);
  const [directiveMsg, setDirectiveMsg] = useState("");
  const [directiveStatus, setDirectiveStatus] = useState<"idle" | "ok" | "err">("idle");
  const [launchBusy, setLaunchBusy] = useState(false);

  const totalFactionXp = Math.max(1, factionFisiXp + factionFiaeXp);
  const fisiPct = (factionFisiXp / totalFactionXp) * 100;
  const fiaePct = (factionFiaeXp / totalFactionXp) * 100;
  const leader =
    factionFisiXp > factionFiaeXp ? "FISI" : factionFiaeXp > factionFisiXp ? "FIAE" : "TIE";
  const rt = getRealtimeIntegritySnapshot();
  const audio = getAudioRuntimeHealth();
  const integrityRows = [
    {
      id: "sync",
      label: "Supabase Sync",
      ok: syncStatus !== "offline",
      detail: syncStatus === "offline" ? "offline" : syncStatus,
    },
    {
      id: "pulse",
      label: "Realtime Pulse",
      ok: rt.pulse === "subscribed" && rt.faction === "subscribed",
      detail: `pulse ${rt.pulse} · faction ${rt.faction}`,
    },
    {
      id: "audio",
      label: "Audio Context",
      ok:
        !feedbackEnabled ||
        ((audio.contextState === "running" || audio.contextState === "suspended") && audio.masterReady),
      detail: feedbackEnabled
        ? `${audio.contextState} · ambient ${audio.ambientActive ? "on" : "off"}`
        : "master off",
    },
    {
      id: "sw",
      label: "Service Worker",
      ok: !swNeedRefresh,
      detail: swNeedRefresh ? "update pending" : "cache healthy",
    },
  ] as const;
  const launchReady = integrityRows.every((r) => r.ok);

  useEffect(() => {
    setDropScaleDraft(Math.round(raidDropRateScale * 100));
  }, [raidDropRateScale]);

  const onBroadcast = useCallback(async () => {
    setBroadcastStatus("idle");
    setBroadcastMsg("");
    const res = await broadcastSystemAnnouncement(broadcastDraft);
    if (res.ok) {
      setBroadcastDraft("");
      setBroadcastStatus("ok");
      setBroadcastMsg("Broadcast akzeptiert — Realtime verteilt");
    } else {
      setBroadcastStatus("err");
      setBroadcastMsg(res.error ?? "Broadcast abgelehnt");
    }
  }, [broadcastDraft]);

  const onFinalizeSeason = useCallback(async () => {
    if (seasonFinalizeBusy) return;
    setSeasonFinalizeBusy(true);
    setSeasonFinalizeStatus("idle");
    setSeasonFinalizeMsg("");
    const res = await finalizeCurrentSeason(seasonLabelDraft);
    if (!res.ok || !res.data) {
      setSeasonFinalizeStatus("err");
      setSeasonFinalizeMsg(res.error ?? "Season Freeze wurde abgelehnt");
      setSeasonFinalizeBusy(false);
      return;
    }
    setSeasonFinalizeStatus("ok");
    setSeasonFinalizeMsg(
      `Archiviert ${res.data.seasonKey} Sieger ${res.data.winnerFaction} FISI ${res.data.fisiTotalXp} FIAE ${res.data.fiaeTotalXp}`,
    );
    setSeasonLabelDraft("");
    await refresh();
    setSeasonFinalizeBusy(false);
  }, [refresh, seasonFinalizeBusy, seasonLabelDraft]);

  const onManualOverdrive = useCallback(async (module: QuestionModule) => {
    if (directiveBusy) return;
    setDirectiveBusy(true);
    setDirectiveStatus("idle");
    setDirectiveMsg("");
    const res = await triggerManualNeuralOverdrive(module);
    if (!res.ok) {
      setDirectiveStatus("err");
      setDirectiveMsg(res.error ?? "Directive abgelehnt");
      setDirectiveBusy(false);
      return;
    }
    setDirectiveStatus("ok");
    setDirectiveMsg(`Admin Directive Overdrive ${module.toUpperCase()} aktiv`);
    setDirectiveBusy(false);
  }, [directiveBusy]);

  const onApplyDropScale = useCallback(async () => {
    if (directiveBusy) return;
    setDirectiveBusy(true);
    setDirectiveStatus("idle");
    setDirectiveMsg("");
    const scale = Math.max(0, Math.min(300, Math.floor(dropScaleDraft))) / 100;
    const res = await setManualRaidDropRateScale(scale);
    if (!res.ok) {
      setDirectiveStatus("err");
      setDirectiveMsg(res.error ?? "Drop Rate Directive abgelehnt");
      setDirectiveBusy(false);
      return;
    }
    setDirectiveStatus("ok");
    setDirectiveMsg(`Admin Directive Drop Rate ${Math.round(scale * 100)} PCT`);
    setDirectiveBusy(false);
  }, [directiveBusy, dropScaleDraft]);

  const onEmergencyStop = useCallback(async () => {
    if (directiveBusy) return;
    setDirectiveBusy(true);
    setDirectiveStatus("idle");
    setDirectiveMsg("");
    const res = await emergencyStopGlobalEvents();
    if (!res.ok) {
      setDirectiveStatus("err");
      setDirectiveMsg(res.error ?? "Emergency Stop abgelehnt");
      setDirectiveBusy(false);
      return;
    }
    setDirectiveStatus("ok");
    setDirectiveMsg("Admin Directive All Stop ausgeführt");
    setDirectiveBusy(false);
  }, [directiveBusy]);

  const onLaunchInit = useCallback(async () => {
    if (launchBusy) return;
    setLaunchBusy(true);
    setDirectiveStatus("idle");
    setDirectiveMsg("");
    const res = await armLaunchInitEvent({
      xpMultiplier: 1.25,
      durationHours: 24,
      message: "WELCOME TO THE NEXUS",
    });
    if (!res.ok) {
      setDirectiveStatus("err");
      setDirectiveMsg(res.error ?? "Launch Init blockiert");
      setLaunchBusy(false);
      return;
    }
    setDirectiveStatus("ok");
    setDirectiveMsg("LAUNCH INIT LIVE XP BOOST 24H");
    setLaunchBusy(false);
  }, [launchBusy]);

  useEffect(() => {
    const id = window.setInterval(() => setIntegrityTick((x) => x + 1), 2200);
    return () => window.clearInterval(id);
  }, []);

  if (!isAdmin) {
    return null;
  }

  return (
    <section
      className="relative overflow-x-hidden border border-red-900/45 px-3 py-4 sm:px-4 sm:py-5"
      style={{ backgroundColor: BG }}
    >
      <div className="pointer-events-none absolute inset-0 opacity-[0.07] hud-grid" aria-hidden />
      <motion.div
        initial={prefersReduced ? false : { opacity: 0, y: 4 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: prefersReduced ? 0 : 0.22, ease: [0.16, 1, 0.3, 1] }}
        className="relative space-y-4 font-mono text-red-100/90"
      >
        <header className="flex flex-wrap items-end justify-between gap-2 border-b border-red-900/50 pb-2">
          <div>
            <p className="text-[9px] font-bold uppercase tracking-[0.32em] text-red-500">CRITICAL · Overseer</p>
            <h1 className="text-lg font-bold uppercase tracking-tight text-red-200 sm:text-xl">Kohorten-Lage</h1>
          </div>
          <button
            type="button"
            onClick={() => void refresh()}
            className="border border-red-800/50 bg-red-950/30 px-2 py-1 text-[8px] font-bold uppercase tracking-[0.16em] text-red-300/90 hover:bg-red-950/50"
          >
            Refresh
          </button>
        </header>

        <div key={integrityTick} className="grid gap-2 lg:grid-cols-5">
          <div className="border border-red-900/55 bg-red-950/20 p-2 ring-1 ring-red-950/40">
            <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-red-400/90">Global Active Operators</p>
            <p className="mt-1 text-2xl font-bold tabular-nums text-red-100">{loading ? "—" : activeOperators}</p>
            <p className="mt-0.5 text-[7px] uppercase leading-tight tracking-[0.1em] text-red-500/75">
              auth.users last_sign_in_at innerhalb 15 min
            </p>
          </div>

          <div className="border border-fuchsia-900/55 bg-fuchsia-950/20 p-2 ring-1 ring-fuchsia-950/40">
            <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-fuchsia-300/92">Server Load Sim</p>
            <p className="mt-1 text-2xl font-bold tabular-nums text-fuchsia-100">{loading ? "—" : `${serverLoadPct.toFixed(1)}%`}</p>
            <div className="mt-1 h-1.5 w-full overflow-hidden border border-fuchsia-950/60">
              <div className="h-full bg-fuchsia-400/75" style={{ width: `${Math.max(0, Math.min(100, serverLoadPct))}%` }} />
            </div>
            <p className="mt-1 text-[7px] uppercase tracking-[0.1em] text-fuchsia-300/75">Ingest per min {loading ? "—" : ingestPerMinute}</p>
          </div>

          <div className="border border-red-900/55 bg-red-950/20 p-2 ring-1 ring-red-950/40">
            <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-red-400/90">Faction War Status</p>
            <div className="mt-1 flex h-2 w-full overflow-hidden border border-red-950/60">
              <div className="h-full bg-red-700/80" style={{ width: `${fisiPct}%` }} title="FISI" />
              <div className="h-full bg-rose-400/50" style={{ width: `${fiaePct}%` }} title="FIAE" />
            </div>
            <div className="mt-1 flex flex-wrap justify-between gap-1 text-[8px] tabular-nums text-red-200/95">
              <span>FISI {factionFisiXp}</span>
              <span className="text-red-400">Lead {leader}</span>
              <span>FIAE {factionFiaeXp}</span>
            </div>
          </div>

          <div className="border border-red-900/55 bg-red-950/25 p-2 ring-1 ring-red-800/30">
            <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-red-400/90">Action Center</p>
            <textarea
              value={broadcastDraft}
              onChange={(e) => setBroadcastDraft(e.target.value)}
              rows={2}
              placeholder="SYSWIDE Nachricht"
              className={cn(
                "mt-1 w-full resize-none border border-red-900/50 bg-black/70 px-2 py-1 text-[9px] text-red-100",
                "placeholder:text-red-700/80 focus:border-red-600/60 focus:outline-none",
              )}
            />
            <button
              type="button"
              onClick={() => void onBroadcast()}
              className="mt-1.5 w-full border border-red-600/55 bg-red-900/35 py-1.5 text-[8px] font-bold uppercase tracking-[0.2em] text-red-100 hover:bg-red-800/40"
            >
              BROADCAST EVENT
            </button>
            {broadcastStatus !== "idle" ? (
              <p
                className={cn(
                  "mt-1 text-[7px] font-semibold uppercase tracking-[0.12em]",
                  broadcastStatus === "ok" ? "text-red-300" : "text-red-500",
                )}
              >
                {broadcastMsg}
              </p>
            ) : null}

            <div className="mt-3 border-t border-red-900/50 pt-2">
              <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-red-400/90">
                Season Cataclysm
              </p>
              <input
                value={seasonLabelDraft}
                onChange={(e) => setSeasonLabelDraft(e.target.value)}
                placeholder="Optional Season Label"
                className={cn(
                  "mt-1 w-full border border-red-900/50 bg-black/70 px-2 py-1 text-[9px] text-red-100",
                  "placeholder:text-red-700/80 focus:border-red-600/60 focus:outline-none",
                )}
              />
              <button
                type="button"
                disabled={seasonFinalizeBusy}
                onClick={() => void onFinalizeSeason()}
                className={cn(
                  "mt-1.5 w-full border py-1.5 text-[8px] font-bold uppercase tracking-[0.2em]",
                  seasonFinalizeBusy
                    ? "cursor-wait border-red-950/70 bg-red-950/30 text-red-500/80"
                    : "border-amber-400/55 bg-amber-500/15 text-amber-100 hover:bg-amber-500/25",
                )}
              >
                {seasonFinalizeBusy ? "FINALIZING" : "FINALIZE SEASON"}
              </button>
              {seasonFinalizeStatus !== "idle" ? (
                <p
                  className={cn(
                    "mt-1 text-[7px] font-semibold uppercase tracking-[0.12em]",
                    seasonFinalizeStatus === "ok" ? "text-amber-200" : "text-red-500",
                  )}
                >
                  {seasonFinalizeMsg}
                </p>
              ) : null}
            </div>
          </div>

          <div className="border border-emerald-700/45 bg-emerald-950/20 p-2 ring-1 ring-emerald-950/40">
            <div className="flex items-start justify-between gap-2">
              <p className="text-[8px] font-bold uppercase tracking-[0.22em] text-emerald-300/90">
                System Integrity
              </p>
              <span
                className={cn(
                  "border px-1.5 py-0.5 text-[7px] font-black uppercase tracking-[0.15em]",
                  launchReady
                    ? "border-emerald-300/55 bg-emerald-400/20 text-emerald-100"
                    : "border-amber-300/45 bg-amber-500/15 text-amber-100",
                )}
              >
                {launchReady ? "READY FOR LAUNCH" : "PATCH REQUIRED"}
              </span>
            </div>
            <div className="mt-1.5 space-y-1">
              {integrityRows.map((row) => (
                <div
                  key={row.id}
                  className="flex items-center justify-between gap-2 border border-emerald-950/40 bg-black/30 px-1.5 py-1"
                >
                  <span className="text-[7px] uppercase tracking-[0.14em] text-emerald-200/90">
                    {row.label}
                  </span>
                  <span
                    className={cn(
                      "text-[7px] uppercase tracking-[0.12em]",
                      row.ok ? "text-emerald-200" : "text-amber-200",
                    )}
                  >
                    {row.detail}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <QuestionForgeView />

        <div className="border border-red-800/55 bg-red-950/20 p-3 ring-1 ring-red-900/40">
          <div className="flex flex-wrap items-end justify-between gap-2 border-b border-red-900/50 pb-2">
            <div>
              <p className="text-[8px] font-bold uppercase tracking-[0.24em] text-red-400/90">Tactical Command Center</p>
              <p className="mt-0.5 text-[7px] uppercase tracking-[0.12em] text-red-500/80">Master Override Channel</p>
            </div>
            <span className="border border-red-700/50 bg-red-900/25 px-2 py-1 text-[7px] font-bold uppercase tracking-[0.16em] text-red-200">
              Industrial Switchboard
            </span>
          </div>

          <div className="mt-2">
            <p className="text-[8px] font-bold uppercase tracking-[0.2em] text-red-300/90">Manual Overdrive Trigger</p>
            <div className="mt-1.5 grid gap-1 sm:grid-cols-2 lg:grid-cols-5">
              {OVERDRIVE_MODULES.map((mod) => (
                <button
                  key={mod.id}
                  type="button"
                  disabled={directiveBusy}
                  onClick={() => void onManualOverdrive(mod.id)}
                  className={cn(
                    "border px-2 py-1.5 text-[8px] font-bold uppercase tracking-[0.14em]",
                    directiveBusy
                      ? "cursor-wait border-red-950/65 bg-red-950/25 text-red-500/80"
                      : "border-cyan-300/45 bg-cyan-500/12 text-cyan-100 hover:bg-cyan-500/20",
                  )}
                >
                  Ignite {mod.label}
                </button>
              ))}
            </div>
          </div>

          <div className="mt-3 border-t border-red-900/50 pt-2">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <p className="text-[8px] font-bold uppercase tracking-[0.2em] text-red-300/90">Drop Rate Control</p>
              <span className="text-[8px] font-bold uppercase tracking-[0.14em] text-red-200">{dropScaleDraft} PCT</span>
            </div>
            <input
              type="range"
              min={0}
              max={300}
              value={dropScaleDraft}
              onChange={(e) => setDropScaleDraft(Number(e.target.value))}
              className="mt-1 w-full accent-red-400"
            />
            <button
              type="button"
              disabled={directiveBusy}
              onClick={() => void onApplyDropScale()}
              className={cn(
                "mt-1.5 w-full border py-1.5 text-[8px] font-bold uppercase tracking-[0.18em]",
                directiveBusy
                  ? "cursor-wait border-red-950/65 bg-red-950/25 text-red-500/80"
                  : "border-amber-300/55 bg-amber-500/18 text-amber-100 hover:bg-amber-500/28",
              )}
            >
              Apply Drop Directive
            </button>
          </div>

          <div className="mt-3 border-t border-red-900/50 pt-2">
            <button
              type="button"
              disabled={launchBusy}
              onClick={() => void onLaunchInit()}
              className={cn(
                "mb-2 w-full border py-1.5 text-[8px] font-black uppercase tracking-[0.22em]",
                launchBusy
                  ? "cursor-wait border-fuchsia-950/65 bg-fuchsia-950/25 text-fuchsia-500/80"
                  : "border-fuchsia-300/60 bg-fuchsia-500/20 text-fuchsia-100 hover:bg-fuchsia-500/30",
              )}
            >
              {launchBusy ? "ARMING LAUNCH" : "LAUNCH INIT 24H XP BOOST"}
            </button>
            <button
              type="button"
              disabled={directiveBusy}
              onClick={() => void onEmergencyStop()}
              className={cn(
                "w-full border py-2 text-[8px] font-black uppercase tracking-[0.24em]",
                "shadow-[0_0_20px_rgb(239_68_68/0.35),inset_0_0_16px_rgb(185_28_28/0.35)]",
                directiveBusy
                  ? "cursor-wait border-red-950/65 bg-red-950/25 text-red-500/80"
                  : "animate-pulse border-red-300/60 bg-red-600/30 text-red-50 hover:bg-red-600/40",
              )}
            >
              ALL STOP
            </button>
          </div>
          {directiveStatus !== "idle" ? (
            <p
              className={cn(
                "mt-2 text-[7px] font-semibold uppercase tracking-[0.12em]",
                directiveStatus === "ok" ? "text-red-200" : "text-red-500",
              )}
            >
              {directiveMsg}
            </p>
          ) : null}
        </div>

        <div className="border border-red-900/50 bg-black/40 p-2">
          <div className="flex flex-wrap items-baseline justify-between gap-2 border-b border-red-950/50 pb-1">
            <p className="text-[8px] font-bold uppercase tracking-[0.24em] text-red-400">Most Failed Questions</p>
            <p className="text-[7px] uppercase tracking-[0.12em] text-red-600/90">Top aus get_top_question_misses</p>
          </div>
          {loading ? (
            <p className="py-2 text-[9px] text-red-600">Sync läuft</p>
          ) : painPoints.length === 0 ? (
            <p className="py-2 text-[9px] text-red-600">Keine Miss-Samples</p>
          ) : (
            <div className="max-h-[220px] overflow-auto pt-1 question-scrollbar">
              <table className="w-full border-collapse text-left text-[8px] uppercase tracking-[0.08em] text-red-200/95">
                <thead>
                  <tr className="border-b border-red-950/60 text-[7px] text-red-500">
                    <th className="py-0.5 pr-1 font-semibold">#</th>
                    <th className="py-0.5 pr-1 font-semibold">Slug</th>
                    <th className="py-0.5 text-right font-semibold">Miss</th>
                  </tr>
                </thead>
                <tbody>
                  {painPoints.map((row, i) => (
                    <tr
                      key={row.question_id}
                      title={row.prompt.trim() || row.slug}
                      className={cn(
                        "border-b border-red-950/35",
                        i === 0 && "bg-red-950/35",
                        i === 1 && "bg-red-950/20",
                        i === 2 && "bg-red-950/12",
                      )}
                    >
                      <td className="py-0.5 pr-1 tabular-nums text-red-400">{String(i + 1).padStart(2, "0")}</td>
                      <td className="max-w-[1px] truncate py-0.5 pr-1 font-medium text-red-100">{row.slug}</td>
                      <td className="py-0.5 text-right tabular-nums font-bold text-red-300">{row.miss_count}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        <button
          type="button"
          onClick={() => setActiveSection("command")}
          className="text-[8px] font-bold uppercase tracking-[0.18em] text-red-600/90 underline-offset-2 hover:text-red-300 hover:underline"
        >
          Schließen — Command Deck
        </button>
      </motion.div>
    </section>
  );
}
