import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useState } from "react";
import { cn } from "../../lib/cn";
import { acceptDuelChallenge, issueDuelChallenge, startMirrorDuel } from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";
import { formatNexusActivityLine } from "../../types/nexusActivity";

export function ActivityStream() {
  const prefersReduced = !!useReducedMotion();
  const entries = useAppStore((s) => s.nexusActivity);
  const openPublicDossier = useAppStore((s) => s.openPublicDossier);
  const duelInbox = useAppStore((s) => s.duelInbox);
  const selfUserId = useAppStore((s) => s.authUser?.id ?? null);
  const isAdmin = useAppStore((s) => s.isAdmin);
  const bossGhostArmed = useAppStore((s) => s.bossGhostArmed);
  const setBossGhostArmed = useAppStore((s) => s.setBossGhostArmed);
  const [duelBusyId, setDuelBusyId] = useState<string | null>(null);

  return (
    <section className="relative overflow-hidden border border-white/[0.1] bg-black/55">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" aria-hidden />
      <header className="relative flex items-center justify-between border-b border-white/[0.08] px-4 py-2 sm:px-5">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-foreground-muted">
          Social Pulse
        </p>
        <div className="flex items-center gap-1.5">
          <button
            type="button"
            disabled={duelBusyId === "mirror-boss"}
            onClick={() => {
              setDuelBusyId("mirror-boss");
              void startMirrorDuel("global_boss").finally(() => setDuelBusyId(null));
            }}
            className="border border-fuchsia-300/45 bg-fuchsia-500/[0.2] px-2 py-1 font-mono text-[8px] font-bold uppercase tracking-[0.14em] text-fuchsia-100 hover:bg-fuchsia-500/[0.3]"
          >
            {duelBusyId === "mirror-boss" ? "Sync" : "Mirror Boss"}
          </button>
          <button
            type="button"
            disabled={duelBusyId === "mirror-weekly"}
            onClick={() => {
              setDuelBusyId("mirror-weekly");
              void startMirrorDuel("weekly_top").finally(() => setDuelBusyId(null));
            }}
            className="border border-cyan-300/30 bg-cyan-500/[0.12] px-2 py-1 font-mono text-[8px] font-bold uppercase tracking-[0.14em] text-cyan-100 hover:bg-cyan-500/[0.2]"
          >
            {duelBusyId === "mirror-weekly" ? "Sync" : "Mirror Week"}
          </button>
          <button
            type="button"
            disabled={duelBusyId === "mirror-personal"}
            onClick={() => {
              setDuelBusyId("mirror-personal");
              void startMirrorDuel("personal_best").finally(() => setDuelBusyId(null));
            }}
            className="border border-violet-300/30 bg-violet-500/[0.12] px-2 py-1 font-mono text-[8px] font-bold uppercase tracking-[0.14em] text-violet-100 hover:bg-violet-500/[0.2]"
          >
            {duelBusyId === "mirror-personal" ? "Sync" : "Mirror Self"}
          </button>
          {isAdmin ? (
            <button
              type="button"
              onClick={() => setBossGhostArmed(!bossGhostArmed)}
              className={cn(
                "border px-2 py-1 font-mono text-[8px] font-bold uppercase tracking-[0.14em]",
                bossGhostArmed
                  ? "border-violet-300/55 bg-violet-500/[0.28] text-violet-100"
                  : "border-violet-300/35 bg-violet-500/[0.12] text-violet-200/90",
              )}
            >
              {bossGhostArmed ? "Boss Armed" : "Arm Boss Run"}
            </button>
          ) : null}
        </div>
      </header>
      <div className="relative max-h-72 overflow-y-auto px-2 py-2 question-scrollbar sm:px-3">
        {duelInbox.length > 0 ? (
          <div className="mb-2 space-y-1">
            {duelInbox.map((duel) => (
              <div key={duel.duelId} className="border border-amber-300/35 bg-amber-500/[0.08] px-2 py-1.5">
                <p className="font-mono text-[9px] uppercase tracking-[0.12em] text-amber-100">
                  Duel request {duel.fromHandle} {duel.examId} stake {duel.stakeAmount} {duel.stakeKind}
                </p>
                <button
                  type="button"
                  disabled={duelBusyId === duel.duelId}
                  onClick={() => {
                    setDuelBusyId(duel.duelId);
                    void acceptDuelChallenge(duel.duelId).finally(() => setDuelBusyId(null));
                  }}
                  className="mt-1 border border-amber-300/45 bg-amber-500/20 px-2 py-1 font-mono text-[9px] font-bold uppercase tracking-[0.14em] text-amber-100 hover:bg-amber-500/30"
                >
                  {duelBusyId === duel.duelId ? "Linking" : "Accept Duel"}
                </button>
              </div>
            ))}
          </div>
        ) : null}
        <AnimatePresence initial={false}>
          {entries.length === 0 ? (
            <motion.div
              key="idle"
              initial={prefersReduced ? false : { opacity: 0, y: -6 }}
              animate={{ opacity: 1, y: 0 }}
              className="border border-white/[0.08] bg-black/30 px-3 py-2 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground-muted"
            >
              Stream idle waiting for uplink packets
            </motion.div>
          ) : (
            entries.map((entry) => {
              const clickable = entry.routeHint === "public_dossier" && !!entry.userId;
              const isBossGhost = entry.kind === "GLOBAL_BOSS_GHOST";
              const isOutbreak =
                entry.kind === "SYSTEM_INFECTED" || entry.kind === "NEURAL_PURGE" || entry.kind === "SYSTEM_CURED";
              const isSyndicate = entry.kind === "SYNDICATE_FOUNDED" || entry.kind === "SYNDICATE_ASCENSION";
              const isSector = entry.kind === "SECTOR_CAPTURED";
              const isCouncil = entry.kind === "COUNCIL_PROPOSAL" || entry.kind === "COUNCIL_DECREE";
              const isSingularity = entry.kind === "NEXUS_SINGULARITY";
              const isLaunch = entry.kind === "LAUNCH_INIT";
              return (
                <motion.div
                  key={entry.id}
                  initial={prefersReduced ? false : { opacity: 0, y: -12 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={prefersReduced ? undefined : { opacity: 0, y: 6 }}
                  transition={{ duration: prefersReduced ? 0 : 0.18, ease: [0.22, 1, 0.36, 1] }}
                  className={cn(
                    "mb-1.5 w-full border px-3 py-2 text-left font-mono text-[10px] uppercase tracking-[0.13em]",
                    isBossGhost
                      ? "border-violet-300/55 bg-violet-500/[0.2] text-violet-100 hover:bg-violet-500/[0.32]"
                      : isLaunch
                      ? "border-cyan-200/60 bg-cyan-400/[0.22] text-cyan-50 hover:bg-cyan-400/[0.32]"
                      : isSingularity
                      ? "border-fuchsia-300/58 bg-fuchsia-500/[0.2] text-fuchsia-100 hover:bg-fuchsia-500/[0.3]"
                      : isCouncil
                      ? "border-amber-300/55 bg-amber-500/[0.18] text-amber-100 hover:bg-amber-500/[0.28]"
                      : isSector
                      ? "border-sky-300/55 bg-sky-500/[0.18] text-sky-100 hover:bg-sky-500/[0.28]"
                      : isSyndicate
                      ? "border-lime-300/55 bg-lime-500/[0.16] text-lime-100 hover:bg-lime-500/[0.26]"
                      : isOutbreak
                      ? "border-emerald-300/55 bg-emerald-500/[0.16] text-emerald-100 hover:bg-emerald-500/[0.24]"
                      : clickable
                      ? "border-cyan-300/28 bg-cyan-500/[0.06] text-cyan-100 hover:bg-cyan-500/[0.11]"
                      : "border-white/[0.08] bg-black/30 text-foreground/85",
                  )}
                >
                  <button
                    type="button"
                    disabled={!clickable}
                    onClick={() => {
                      if (!clickable || !entry.userId) return;
                      openPublicDossier(entry.userId, entry.handle ?? null);
                    }}
                    className="block w-full text-left"
                  >
                    <span className="block truncate">{formatNexusActivityLine(entry)}</span>
                  </button>
                  {entry.userId && entry.userId !== selfUserId ? (
                    <button
                      type="button"
                      disabled={duelBusyId === entry.id}
                      onClick={() => {
                        setDuelBusyId(entry.id);
                        void issueDuelChallenge(entry.userId ?? "", entry.handle ?? "Unknown_Operator").finally(() =>
                          setDuelBusyId(null),
                        );
                      }}
                      className="mt-1 border border-fuchsia-300/38 bg-fuchsia-500/[0.16] px-2 py-1 font-mono text-[9px] font-bold uppercase tracking-[0.12em] text-fuchsia-100 hover:bg-fuchsia-500/[0.26]"
                    >
                      {duelBusyId === entry.id ? "Arming" : "Challenge"}
                    </button>
                  ) : null}
                </motion.div>
              );
            })
          )}
        </AnimatePresence>
      </div>
    </section>
  );
}
