import type { StateCreator } from "zustand";
import type { AppState, AppSection, DockSectionId } from "../useAppStore";

export interface NavigationSlice {
  activeSection: AppSection;
  setActiveSection: (id: AppSection) => void;
  dockHoveredId: DockSectionId | null;
  setDockHoveredId: (id: DockSectionId | null) => void;
  moreMenuOpen: boolean;
  openMoreMenu: () => void;
  closeMoreMenu: () => void;
  enterFlashcards: () => void;
  leaveFlashcards: () => void;
  enterDataVault: () => void;
  enterCloudUplink: () => void;
}

export const createNavigationSlice: StateCreator<AppState, [], [], NavigationSlice> = (set, get) => ({
  activeSection: "command",
  setActiveSection: (id) => {
    if (id === "adminCmd" && !get().isAdmin) {
      set({ activeSection: "command", moreMenuOpen: false });
      return;
    }
    const prev = get().activeSection;
    if (prev === "mockExam" && id !== "mockExam") {
      const run = get().mockExam;
      if (run && !run.submitted) {
        set({ activeSection: "mockExam", moreMenuOpen: false });
        return;
      }
    }
    if ((prev === "arena" || prev === "loadout") && id !== "arena" && id !== "loadout" && id !== "publicDossier") {
      set({
        activeSection: id,
        arenaRun: null,
        arenaFeedback: null,
        moreMenuOpen: false,
        ...(id === "nexus" ? { nexusView: "hub" as const } : {}),
      });
      return;
    }
    if (id === "nexus") {
      set({ activeSection: "nexus", nexusView: "hub", moreMenuOpen: false });
      return;
    }
    set({
      activeSection: id,
      moreMenuOpen: false,
      ...(prev === "mockExam" && id !== "mockExam" ? { mockExam: null } : {}),
      ...(id !== "publicDossier"
        ? {
            selectedPublicOperatorId: null,
            selectedPublicOperatorHandle: null,
            publicDossierBusy: false,
            publicDossierOnline: false,
            publicDossierData: null,
          }
        : {}),
    });
  },
  dockHoveredId: null,
  setDockHoveredId: (id) => set({ dockHoveredId: id }),
  moreMenuOpen: false,
  openMoreMenu: () => set({ moreMenuOpen: true }),
  closeMoreMenu: () => set({ moreMenuOpen: false }),
  enterFlashcards: () => set({ activeSection: "flashcards", moreMenuOpen: false }),
  leaveFlashcards: () => set({ activeSection: "command", moreMenuOpen: false }),
  enterDataVault: () => set({ activeSection: "vault", moreMenuOpen: false }),
  enterCloudUplink: () => set({ activeSection: "cloud", moreMenuOpen: false }),
});
