import { AnimatePresence, motion } from "framer-motion";
import { useEffect, useState } from "react";
import { UNIVERSE_THEME_FALLBACK } from "../../../../styles/themes/universeThemes";

type AcademyCheckpointToastProps = {
  /** Increment to trigger a new toast */
  pulse: number;
  reducedMotion: boolean;
};

export function AcademyCheckpointToast({ pulse, reducedMotion }: AcademyCheckpointToastProps) {
  const [activeKey, setActiveKey] = useState(0);
  const primary = `var(--universe-primary, ${UNIVERSE_THEME_FALLBACK.primary})`;
  const accent = `var(--universe-accent, ${UNIVERSE_THEME_FALLBACK.accent})`;

  useEffect(() => {
    if (pulse <= 0) return;
    setActiveKey(pulse);
    const timer = window.setTimeout(() => setActiveKey(0), 2600);
    return () => window.clearTimeout(timer);
  }, [pulse]);

  return (
    <div className="pointer-events-none fixed right-4 top-[max(5rem,env(safe-area-inset-top))] z-[60] max-w-[min(20rem,calc(100vw-2rem))]" aria-live="polite">
      <AnimatePresence mode="wait">
        {activeKey > 0 ? (
          <motion.div
            key={`checkpoint-${activeKey}`}
            role="status"
            initial={reducedMotion ? { opacity: 1, x: 0 } : { opacity: 0, x: 28 }}
            animate={reducedMotion ? { opacity: 1, x: 0 } : { opacity: 1, x: 0 }}
            exit={reducedMotion ? { opacity: 0 } : { opacity: 0, x: 16 }}
            transition={{ duration: reducedMotion ? 0.08 : 0.32, ease: "easeOut" }}
            className="rounded-lg border border-solid bg-slate-950/92 px-4 py-3 backdrop-blur-md"
            style={{
              borderColor: `color-mix(in srgb, ${primary} 52%, transparent)`,
              boxShadow: `0 0 28px color-mix(in srgb, ${primary} 34%, transparent), inset 0 1px 0 color-mix(in srgb, ${accent} 24%, transparent)`,
            }}
          >
            <p
              className="font-display text-base font-semibold tracking-tight"
              style={{
                color: `color-mix(in srgb, ${primary} 88%, white)`,
                textShadow: `0 0 14px color-mix(in srgb, ${primary} 42%, transparent)`,
              }}
            >
              Checkpoint gesichert
            </p>
            <p
              className="mt-1 font-mono text-[10px] uppercase tracking-[0.14em]"
              style={{ color: `color-mix(in srgb, ${accent} 72%, white)` }}
            >
              Sync mit Tutorial Rail
            </p>
          </motion.div>
        ) : null}
      </AnimatePresence>
    </div>
  );
}
