import type { ArenaQuestion } from "./questionContent";
import type { IhkGrade } from "./mockExamGrading";

export type ExamRadarBucket = "sql" | "netz" | "wiso" | "it_core";

export type ExamDomainStat = {
  correct: number;
  total: number;
};

export type ExamRepairTarget = "sql_academy" | "helpdesk" | "flashcards" | "vault";

const BUCKETS: ExamRadarBucket[] = ["sql", "netz", "wiso", "it_core"];

const RADAR_LABEL: Record<ExamRadarBucket, string> = {
  sql: "SQL",
  netz: "Netzwerk",
  wiso: "WISO",
  it_core: "IT Kern",
};

const TAG_NETZ = new Set(
  "http https tcp ip dns udp vpn lan vlan routing switch firewall rest api uri url smtp pop imap snmp".split(/\s+/),
);
const TAG_SQL = new Set("sql select join index transaction view trigger constraint nosql".split(/\s+/));
const TAG_WISO = new Set("wiso legal contract gdpr agb urheber datenschutz projekt wirtschaft".split(/\s+/));

export function mapQuestionToRadarBucket(question: Pick<ArenaQuestion, "module" | "tags">): ExamRadarBucket {
  const mod = question.module;
  if (mod === "databases") return "sql";
  if (mod === "wiso") return "wiso";
  if (mod === "networking" || mod === "security" || mod === "hardware" || mod === "operating_systems") return "netz";
  for (const t of question.tags) {
    const k = t.toLowerCase();
    if (TAG_SQL.has(k)) return "sql";
    if (TAG_NETZ.has(k)) return "netz";
    if (TAG_WISO.has(k)) return "wiso";
  }
  if (mod === "programming" || mod === "testing" || mod === "architecture" || mod === "process") return "it_core";
  return "it_core";
}

export function aggregateExamDomains(
  questions: readonly Pick<ArenaQuestion, "module" | "tags" | "correctIndex">[],
  answers: readonly (number | null)[],
): Record<ExamRadarBucket, ExamDomainStat> {
  const base: Record<ExamRadarBucket, ExamDomainStat> = {
    sql: { correct: 0, total: 0 },
    netz: { correct: 0, total: 0 },
    wiso: { correct: 0, total: 0 },
    it_core: { correct: 0, total: 0 },
  };
  questions.forEach((q, i) => {
    const bucket = mapQuestionToRadarBucket(q);
    const row = base[bucket];
    row.total += 1;
    if (answers[i] === q.correctIndex) row.correct += 1;
  });
  return base;
}

export function domainStatsToRadarMetrics(stats: Record<ExamRadarBucket, ExamDomainStat>): Array<{ id: ExamRadarBucket; label: string; value: number }> {
  return BUCKETS.map((id) => {
    const s = stats[id];
    const value = s.total <= 0 ? 100 : Math.round((s.correct / s.total) * 100);
    return { id, label: RADAR_LABEL[id], value };
  });
}

export function computeIhkReadinessPercent(input: {
  overallPercent: number;
  grade: IhkGrade;
  stats: Record<ExamRadarBucket, ExamDomainStat>;
}): number {
  const { overallPercent, grade, stats } = input;
  const domainPercents = BUCKETS.map((id) => {
    const s = stats[id];
    return s.total <= 0 ? 100 : (s.correct / s.total) * 100;
  });
  const minDomain = Math.min(...domainPercents);
  const blended = overallPercent * 0.62 + minDomain * 0.38;
  const gradeDrag = grade > 3 ? (grade - 3) * 6.5 : 0;
  return Math.max(0, Math.min(100, Math.round(blended - gradeDrag)));
}

export function inferRepairTargetFromTag(tag: string): ExamRepairTarget {
  const k = tag.toLowerCase();
  if (TAG_SQL.has(k) || k.includes("sql")) return "sql_academy";
  if (TAG_NETZ.has(k) || k.includes("net")) return "helpdesk";
  if (TAG_WISO.has(k) || k.includes("wiso")) return "flashcards";
  return "vault";
}

export function inferRepairTargetFromBucket(bucket: ExamRadarBucket): ExamRepairTarget {
  if (bucket === "sql") return "sql_academy";
  if (bucket === "netz") return "helpdesk";
  if (bucket === "wiso") return "flashcards";
  return "vault";
}
