import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import type { HallAncientRow } from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";

export function HallOfAncients() {
  const prefersReduced = !!useReducedMotion();
  const [busy, setBusy] = useState(false);
  const [rows, setRows] = useState<HallAncientRow[]>([]);
  const [singularityBusy, setSingularityBusy] = useState(false);
  const [errorLine, setErrorLine] = useState<string | null>(null);
  const userLevel = useAppStore((s) => s.userLevel);
  const legacyPoints = useAppStore((s) => s.legacyPoints);
  const legacyTranscendCount = useAppStore((s) => s.legacyTranscendCount);
  const legacyXpBoostMultiplier = useAppStore((s) => s.legacyXpBoostMultiplier);
  const openPublicDossier = useAppStore((s) => s.openPublicDossier);
  const canTranscend = userLevel >= 30 && !singularityBusy;

  const refresh = () => {
    setBusy(true);
    setErrorLine(null);
    void import("../../lib/syncController")
      .then((m) => m.fetchHallOfAncients(26))
      .then((next) => setRows(next))
      .catch(() => setErrorLine("Archiv uplink blockiert"))
      .finally(() => setBusy(false));
  };

  useEffect(() => {
    refresh();
  }, []);

  return (
    <section className="relative overflow-hidden rounded-3xl border border-amber-300/38 bg-gradient-to-br from-slate-900 via-zinc-900 to-amber-900/[0.16] p-6 ring-1 ring-amber-200/24">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.16]" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex flex-wrap items-end justify-between gap-2">
          <div className="space-y-1">
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-amber-100/92">
              Hall Of Ancients
            </p>
            <h3 className="font-display text-2xl font-bold uppercase tracking-wide text-amber-50">
              Monument Registry
            </h3>
          </div>
          <button
            type="button"
            onClick={refresh}
            className="border border-amber-300/35 bg-amber-500/[0.16] px-2.5 py-1 font-mono text-[9px] uppercase tracking-[0.16em] text-amber-100 hover:bg-amber-500/[0.24]"
          >
            Refresh
          </button>
        </div>

        <div className="grid gap-2 md:grid-cols-3">
          <div className="border border-amber-200/24 bg-black/35 p-3">
            <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/86">Legacy Points</p>
            <p className="mt-1 font-mono text-xl font-black text-amber-50">{legacyPoints}</p>
          </div>
          <div className="border border-amber-200/24 bg-black/35 p-3">
            <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/86">Transcend Count</p>
            <p className="mt-1 font-mono text-xl font-black text-amber-50">{legacyTranscendCount}</p>
          </div>
          <div className="border border-amber-200/24 bg-black/35 p-3">
            <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/86">Permanent XP Boost</p>
            <p className="mt-1 font-mono text-xl font-black text-amber-50">x{legacyXpBoostMultiplier.toFixed(2)}</p>
          </div>
        </div>

        <div className="border border-amber-300/30 bg-black/40 p-3">
          <div className="flex flex-wrap items-center justify-between gap-2">
            <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-amber-100/88">
              Nexus Singularity Protocol
            </p>
            <button
              type="button"
              disabled={!canTranscend}
              onClick={() => {
                setSingularityBusy(true);
                setErrorLine(null);
                void import("../../lib/syncController")
                  .then((m) => m.triggerNexusSingularity())
                  .then((res) => {
                    if (!res.ok) {
                      setErrorLine(res.error ?? "Singularity blockiert");
                      return;
                    }
                    refresh();
                  })
                  .finally(() => setSingularityBusy(false));
              }}
              className="border border-amber-200/45 bg-amber-500/[0.18] px-3 py-1.5 font-mono text-[8px] font-black uppercase tracking-[0.2em] text-amber-100 hover:bg-amber-500/[0.3] disabled:opacity-45"
            >
              {singularityBusy ? "Transcending" : "Initiate Singularity"}
            </button>
          </div>
          <p className="mt-1 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/76">
            Erfordert Level 30 oder höher danach beginnt der Legacy Reset mit permanentem Bonus
          </p>
        </div>

        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-amber-100/80">Ruhmeshalle synchronisiert</p>
        ) : rows.length === 0 ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-amber-100/80">Noch kein Ancient gelistet</p>
        ) : (
          <div className="grid gap-2">
            {rows.map((row, idx) => (
              <motion.button
                key={`${row.userId}-${row.achievedAt}-${idx}`}
                type="button"
                initial={prefersReduced ? false : { opacity: 0, y: 6 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: prefersReduced ? 0 : 0.2, delay: prefersReduced ? 0 : idx * 0.02 }}
                onClick={() => openPublicDossier(row.userId, row.handle)}
                className="grid grid-cols-[auto_1fr_auto] items-center gap-3 border border-amber-200/24 bg-black/35 px-3 py-2 text-left hover:border-amber-200/40"
              >
                <span className="border border-amber-200/35 bg-amber-500/[0.14] px-2 py-1 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100">
                  {row.seasonTag}
                </span>
                <div className="space-y-0.5">
                  <p className="truncate font-mono text-[9px] uppercase tracking-[0.14em] text-amber-50">{row.handle}</p>
                  <p className="font-mono text-[8px] uppercase tracking-[0.12em] text-amber-100/82">
                    Legacy +{row.legacyPointsAwarded} Total {row.legacyPointsTotal}
                  </p>
                </div>
                <span className="font-mono text-[8px] uppercase tracking-[0.12em] text-amber-100/70">
                  {new Date(row.achievedAt).toLocaleDateString("de-DE")}
                </span>
              </motion.button>
            ))}
          </div>
        )}

        {errorLine ? <p className="font-mono text-[9px] uppercase tracking-[0.14em] text-rose-200">{errorLine}</p> : null}
      </div>
    </section>
  );
}
