import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect } from "react";
import { useAppStore } from "../../store/useAppStore";

export function SingularitySequence() {
  const prefersReduced = !!useReducedMotion();
  const sequence = useAppStore((s) => s.singularitySequence);
  const finish = useAppStore((s) => s.finishSingularitySequence);

  useEffect(() => {
    if (!sequence.active) return;
    const timeout = window.setTimeout(() => finish(), prefersReduced ? 1400 : 5200);
    return () => window.clearTimeout(timeout);
  }, [finish, prefersReduced, sequence.active]);

  return (
    <AnimatePresence>
      {sequence.active ? (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[120] grid place-items-center bg-black/94"
        >
          <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.1]" aria-hidden />
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.28]" aria-hidden />

          <motion.div
            className="relative grid place-items-center"
            initial={prefersReduced ? false : { scale: 0.85, opacity: 0.2 }}
            animate={
              prefersReduced
                ? { scale: 1, opacity: 1 }
                : {
                    scale: [0.85, 1.25, 0.22, 1.08, 1],
                    opacity: [0.22, 1, 0.18, 1, 1],
                    rotate: [0, 22, -18, 8, 0],
                    filter: ["hue-rotate(0deg)", "hue-rotate(72deg)", "hue-rotate(-36deg)", "hue-rotate(0deg)"],
                  }
            }
            transition={{ duration: prefersReduced ? 0.2 : 4.6, ease: "easeInOut", times: [0, 0.22, 0.45, 0.75, 1] }}
          >
            <motion.div
              className="absolute size-[46vh] rounded-full border border-cyan-300/45"
              animate={prefersReduced ? { opacity: 0.65 } : { scale: [0.7, 1.5, 0.18, 1.1], opacity: [0.2, 1, 0.15, 0.82] }}
              transition={{ duration: prefersReduced ? 0.2 : 4.2, ease: "easeInOut" }}
            />
            <motion.div
              className="absolute size-[32vh] rounded-full border border-fuchsia-300/45"
              animate={prefersReduced ? { opacity: 0.65 } : { scale: [1.1, 0.28, 1.35, 1], opacity: [0.3, 1, 0.28, 0.86] }}
              transition={{ duration: prefersReduced ? 0.2 : 4.2, ease: "easeInOut" }}
            />
            <motion.div
              className="size-[16vh] rounded-full bg-gradient-to-br from-cyan-300/50 via-fuchsia-300/55 to-amber-200/45 shadow-[0_0_90px_rgb(56_189_248/0.65)]"
              animate={prefersReduced ? { scale: 1 } : { scale: [1, 1.9, 0.16, 1.24, 1], opacity: [0.4, 1, 0.16, 1, 0.92] }}
              transition={{ duration: prefersReduced ? 0.2 : 4.8, ease: "easeInOut" }}
            />
          </motion.div>

          <motion.div
            className="relative mt-10 space-y-2 text-center font-mono uppercase"
            initial={prefersReduced ? false : { opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: prefersReduced ? 0 : 0.5, duration: prefersReduced ? 0 : 0.3 }}
          >
            <p className="text-[12px] font-black tracking-[0.35em] text-cyan-100">NEXUS SINGULARITY</p>
            <p className="text-[10px] tracking-[0.22em] text-fuchsia-100">
              Season {sequence.seasonTag} Legacy +{sequence.gainedLegacyPoints}
            </p>
            <p className="text-[9px] tracking-[0.18em] text-amber-100/88">VOID CORE COLLAPSE REBIRTH COMPLETE</p>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
