import { useMemo, useState } from "react";
import { useEffect } from "react";
import type { SqlQuizBlock } from "../../../../data/sqlAcademyContent";
import type { SqlUniverseId } from "../../../../data/universes";
import { useTranslation } from "../../../../i18n/useTranslation";
import { useAcademyStore } from "../../../../store/academyStore";
import { FloatingGains } from "../effects/FloatingGains";

type QuizHostProps = {
  quiz: SqlQuizBlock;
  chapterId: string;
  universeId: SqlUniverseId;
};

export function QuizHost({ quiz, chapterId, universeId }: QuizHostProps) {
  const [selected, setSelected] = useState<string[]>([]);
  const [checked, setChecked] = useState(false);
  const [showGain, setShowGain] = useState(false);
  const markQuizMastered = useAcademyStore((s) => s.markQuizMastered);
  const mastered = useAcademyStore((s) => s.isQuizMastered({ universeId, chapterId, quizId: quiz.id }));
  const lastXpGain = useAcademyStore((s) => s.lastXpGain);
  const t = useTranslation();

  const expected = useMemo(() => [...quiz.correctOptionIds].sort().join("|"), [quiz.correctOptionIds]);
  const selectedKey = useMemo(() => [...selected].sort().join("|"), [selected]);
  const isCorrect = checked && expected === selectedKey;

  function toggleOption(optionId: string) {
    setChecked(false);
    setSelected((prev) => (prev.includes(optionId) ? prev.filter((id) => id !== optionId) : [...prev, optionId]));
  }

  function handleCheck() {
    setChecked(true);
    if (expected === selectedKey) {
      markQuizMastered({ universeId, chapterId, quizId: quiz.id });
    }
  }

  useEffect(() => {
    if (!lastXpGain) return;
    if (lastXpGain.entityType !== "quiz") return;
    if (lastXpGain.universeId !== universeId) return;
    if (lastXpGain.chapterId !== chapterId) return;
    if (lastXpGain.entityId !== quiz.id) return;
    setShowGain(true);
  }, [lastXpGain, universeId, chapterId, quiz.id]);

  if (mastered) {
    return (
      <section className="rounded-xl border border-emerald-400/45 bg-slate-950/75 p-5">
        <h4 className="text-sm font-semibold leading-6 text-emerald-200">{quiz.question}</h4>
        <div className="mt-4 inline-flex items-center rounded-md border border-emerald-300/50 bg-emerald-950/35 px-3 py-1 text-xs font-semibold uppercase tracking-[0.14em] text-emerald-200">
          {t.ui.mastered}
        </div>
        <p className="mt-3 text-xs text-emerald-300">{t.feedback.quizMasteredHint}</p>
      </section>
    );
  }

  return (
    <section className="rounded-xl border border-cyan-500/35 bg-slate-950/75 p-5">
      <h4 className="text-sm font-semibold leading-6 text-cyan-100">{quiz.question}</h4>
      <fieldset className="mt-4 space-y-2">
        <legend className="sr-only">{t.ui.quizOptionsLegend}</legend>
        {quiz.options.map((option) => {
          const active = selected.includes(option.id);
          return (
            <label
              key={option.id}
              className={`flex cursor-pointer items-center gap-3 rounded-lg border px-3 py-2 text-sm transition ${
                active ? "border-cyan-300 bg-cyan-950/35 text-cyan-100" : "border-slate-700 bg-slate-900/70 text-slate-200"
              }`}
            >
              <input
                type="checkbox"
                className="h-4 w-4 accent-cyan-400"
                checked={active}
                onChange={() => toggleOption(option.id)}
              />
              <span>{option.label}</span>
            </label>
          );
        })}
      </fieldset>
      <div className="relative mt-4 flex items-center gap-3">
        <FloatingGains open={showGain} amount={24} universeId={universeId} onDone={() => setShowGain(false)} />
        <button
          type="button"
          className="rounded-md border border-cyan-400/60 bg-cyan-950/40 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-cyan-100 hover:border-cyan-300"
          onClick={handleCheck}
          disabled={selected.length === 0}
        >
          {t.ui.check}
        </button>
        {checked ? (
          <p className={`text-xs font-semibold ${isCorrect ? "text-emerald-300" : "text-orange-300"}`}>
            {isCorrect ? quiz.successMessage : quiz.hintMessage}
          </p>
        ) : null}
      </div>
    </section>
  );
}
