import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useRef } from "react";
import { GameCard } from "../cards/GameCard";
import { HeroHUD } from "../dashboard/HeroHUD";
import { ActivityStream } from "../dashboard/ActivityStream";
import { MatrixHeatmap } from "../dashboard/MatrixHeatmap";
import { SingularitySequence } from "../dashboard/SingularitySequence";
import { WorldSectorMap } from "../dashboard/WorldSectorMap";
import { VoidCore } from "../dashboard/VoidCore";
import { TrainingNextStepsPanel } from "../dashboard/TrainingNextStepsPanel";
import { ArenaView } from "../exam/ArenaView";
import { LoadoutScreen } from "../exam/LoadoutScreen";
import { MockExamView } from "../exam/MockExamView";
import { FlashcardStudyView } from "../flashcards/FlashcardStudyView";
import { CloudAuthView } from "../cloud/CloudAuthView";
import { DataVaultView } from "../vault/DataVaultView";
import { NexusShell } from "../nexus/NexusShell";
import { AdminControlView } from "../admin/AdminControlView";
import { AdminGateLockout } from "../admin/AdminGateLockout";
import { OperatorDossierView } from "../profile/OperatorDossierView";
import { PublicDossierView } from "../profile/PublicDossierView";
import { TelemetryMatrixView } from "../stats/TelemetryMatrixView";
import { cn } from "../../lib/cn";
import {
  cinematicBandDeep,
  cinematicBandMid,
  cinematicBandShallow,
  cinematicStaggerRoot,
  nexusEpicEnter,
  nexusEpicEnterReduced,
  pageTransition,
  pageTransitionReduced,
  springFactionWar,
} from "../../motion/variants";
import {
  useAppStore,
  type AppSection,
  type DockSectionId,
} from "../../store/useAppStore";

function isDockSection(id: AppSection): id is DockSectionId {
  return id === "command" || id === "nexus" || id === "stats" || id === "profile";
}

function sectionTitle(id: DockSectionId): string {
  switch (id) {
    case "command":
      return "Command Deck";
    case "nexus":
      return "The Nexus";
    case "stats":
      return "Performance Telemetry";
    case "profile":
      return "Operator Dossier";
    default:
      return "";
  }
}

function sectionBody(id: DockSectionId): string {
  switch (id) {
    case "command":
      return "Dein Hub für heute · Streaks, XP und nächste Moves";
    case "nexus":
      return "Warp zwischen Skill-Map und Arcade-Runs ohne Ladebildschirm";
    case "stats":
      return "Heatmaps und Laufzeiten folgen · die Arena ist schon live";
    case "profile":
      return "Avatar, Badges und Security folgen · jetzt zählen Vibes und Struktur";
    default:
      return "";
  }
}

export function MainContent() {
  const activeSection = useAppStore((s) => s.activeSection);
  const mockExam = useAppStore((s) => s.mockExam);
  const examFocusShell =
    activeSection === "mockExam" && mockExam !== null && mockExam.challengeAccepted && !mockExam.submitted;
  const isAdmin = useAppStore((s) => s.isAdmin);
  const arenaExamId = useAppStore((s) =>
    s.activeSection === "arena" ? s.arenaRun?.examId : undefined,
  );
  const openLoadout = useAppStore((s) => s.openLoadout);
  const startMockExam = useAppStore((s) => s.startMockExam);
  const openNexusArcade = useAppStore((s) => s.openNexusArcade);
  const enterSqlAdventure = useAppStore((s) => s.enterSqlAdventure);
  const enterPseudoTrainer = useAppStore((s) => s.enterPseudoTrainer);
  const enterItSupport = useAppStore((s) => s.enterItSupport);
  const prefersReduced = useReducedMotion();
  const factionWarPulseKey = useAppStore((s) => s.factionWarPulseKey);

  const prevSectionRef = useRef<AppSection>(activeSection);
  const fromArenaToNexus =
    prevSectionRef.current === "arena" && activeSection === "nexus";
  prevSectionRef.current = activeSection;

  const variants = prefersReduced
    ? fromArenaToNexus
      ? nexusEpicEnterReduced
      : pageTransitionReduced
    : fromArenaToNexus
      ? nexusEpicEnter
      : pageTransition;

  const transitionKey =
    activeSection === "arena"
      ? `arena-${arenaExamId ?? "pending"}`
      : activeSection === "nexus"
        ? "nexus"
        : activeSection === "flashcards"
          ? "flashcards"
          : activeSection === "mockExam"
            ? "mock-exam"
          : activeSection === "vault"
            ? "vault"
            : activeSection === "cloud"
              ? "cloud"
              : activeSection === "adminCmd"
                ? "admin-cmd"
                : activeSection === "stats"
                  ? "stats"
                  : activeSection;

  return (
    <div
      className={cn(
        "relative mx-auto w-full",
        examFocusShell
          ? "max-w-[min(100%,1920px)] px-2 pb-24 pt-2 sm:px-4 sm:pb-28 sm:pt-3"
          : "max-w-6xl px-4 pb-32 pt-6 sm:px-6 sm:pb-36 sm:pt-8",
      )}
    >
      <AnimatePresence>
        {!prefersReduced && factionWarPulseKey ? (
          <motion.div
            key={factionWarPulseKey}
            aria-hidden
            className="pointer-events-none absolute inset-0 z-[4] rounded-[1.75rem] bg-gradient-to-br from-signal/25 via-fuchsia-500/15 to-transparent mix-blend-screen ring-1 ring-fuchsia-400/30"
            initial={{ opacity: 0, scale: 0.99 }}
            animate={{ opacity: [0, 0.52, 0.14, 0], scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{
              opacity: { duration: 1.05, times: [0, 0.35, 0.72, 1], ease: "easeOut" },
              scale: springFactionWar,
            }}
          />
        ) : null}
      </AnimatePresence>
      <AnimatePresence mode="sync" initial={false}>
        <motion.div
          key={transitionKey}
          variants={variants}
          initial="initial"
          animate="animate"
          exit="exit"
          className="space-y-8"
        >
          {activeSection === "loadout" ? (
            <LoadoutScreen />
          ) : activeSection === "arena" ? (
            <ArenaView />
          ) : activeSection === "mockExam" ? (
            <MockExamView />
          ) : activeSection === "command" ? (
            <motion.div
              variants={cinematicStaggerRoot}
              initial="initial"
              animate="animate"
              className="space-y-10"
            >
              <motion.div variants={cinematicBandDeep}>
                <HeroHUD />
              </motion.div>
              <motion.div variants={cinematicBandShallow} className="mx-auto w-full max-w-3xl space-y-6">
                <TrainingNextStepsPanel />
                <VoidCore />
              </motion.div>
              <motion.div variants={cinematicBandShallow}>
                <ActivityStream />
              </motion.div>
              <motion.div variants={cinematicBandShallow}>
                <MatrixHeatmap />
              </motion.div>
              <motion.div variants={cinematicBandShallow}>
                <WorldSectorMap />
              </motion.div>
              <motion.div variants={cinematicBandMid} className="space-y-6">
                <div className="flex flex-wrap items-end justify-between gap-4">
                  <div className="space-y-2">
                    <p className="font-mono text-[10px] font-medium uppercase tracking-[0.32em] text-foreground-muted">
                      Featured Runs
                    </p>
                    <h2 className="headline-cinema text-3xl font-semibold sm:text-5xl">Game Cards</h2>
                  </div>
                  <span className="border border-white/[0.1] bg-white/[0.03] px-3 py-1.5 font-mono text-[10px] uppercase tracking-wide text-foreground-muted hover-breathe">
                    Live build
                  </span>
                </div>
                <motion.div
                  variants={cinematicBandShallow}
                  className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-3"
                >
                  <GameCard
                    title="Die Arena"
                    subtitle="Boss-Fight gegen die Prüfung · komplett offline simuliert"
                    accent="cyan"
                    badge="IHK"
                    onSelect={openLoadout}
                  />
                  <GameCard
                    title="Mock Exam Protocol"
                    subtitle="30 bis 40 Fragen im offiziellen Fokusmodus · Auswertung erst am Ende"
                    accent="toxic"
                    badge="MX"
                    onSelect={startMockExam}
                  />
                  <GameCard
                    title="RealmQuest"
                    subtitle="Branching Quests mit Faction-Buffs und Story-Beats"
                    accent="cyan"
                    badge="RPG"
                    onSelect={openNexusArcade}
                  />
                  <GameCard
                    title="SQL Adventure"
                    subtitle="Joins, Indizes und Transaktionen als Dungeon-Crawl"
                    accent="magenta"
                    badge="SQL"
                    onSelect={enterSqlAdventure}
                  />
                  <GameCard
                    title="Pseudocode Trainer"
                    subtitle="Strukturierte Logik in einer Hacker-IDE · komplett offline"
                    accent="toxic"
                    badge="PSD"
                    onSelect={enterPseudoTrainer}
                  />
                  <GameCard
                    title="IT-Support Simulator"
                    subtitle="Tickets, Prioritäten und IHK-Fragen im Helpdesk-Flow"
                    accent="cyan"
                    badge="IT"
                    onSelect={enterItSupport}
                  />
                </motion.div>
              </motion.div>
            </motion.div>
          ) : activeSection === "nexus" ? (
            <NexusShell />
          ) : activeSection === "flashcards" ? (
            <FlashcardStudyView />
          ) : activeSection === "vault" ? (
            <DataVaultView />
          ) : activeSection === "cloud" ? (
            <CloudAuthView />
          ) : activeSection === "adminCmd" ? (
            isAdmin ? <AdminControlView /> : <AdminGateLockout />
          ) : activeSection === "publicDossier" ? (
            <PublicDossierView />
          ) : activeSection === "profile" ? (
            <OperatorDossierView />
          ) : activeSection === "stats" ? (
            <TelemetryMatrixView />
          ) : isDockSection(activeSection) ? (
            <section
              className={cn(
                "relative overflow-hidden rounded-3xl border border-white/[0.1] bg-surface/90 p-8",
              )}
            >
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.14]" />
              <div className="relative space-y-5">
                <p className="font-mono text-[10px] font-medium uppercase tracking-[0.32em] text-foreground-muted">
                  {activeSection}
                </p>
                <h2 className="headline-cinema text-3xl font-semibold sm:text-5xl">
                  {sectionTitle(activeSection)}
                </h2>
                <p className="max-w-2xl font-sans text-base leading-relaxed tracking-[-0.01em] text-foreground-muted">
                  {sectionBody(activeSection)}
                </p>
              </div>
            </section>
          ) : null}
        </motion.div>
      </AnimatePresence>
      <SingularitySequence />
    </div>
  );
}
