import type { SeasonLegacyArtifact } from "../store/useAppStore";

export type LegacySortMode = "NEWEST" | "TOP_RANK" | "FACTION";
export type LegacyFactionFilter = "ALL" | "FISI" | "FIAE";

/**
 * Phase 67 — deterministische Sortierung für Legacy-Badges
 */
export function sortSeasonArtifacts(
  input: SeasonLegacyArtifact[],
  sortMode: LegacySortMode,
  factionFilter: LegacyFactionFilter,
): SeasonLegacyArtifact[] {
  const filtered =
    factionFilter === "ALL"
      ? input
      : input.filter((row) => row.winnerFaction === factionFilter);

  const out = [...filtered];
  out.sort((a, b) => {
    if (sortMode === "TOP_RANK") {
      if (a.rank !== b.rank) return a.rank - b.rank;
      return a.closedAt < b.closedAt ? 1 : -1;
    }
    if (sortMode === "FACTION") {
      const aW = a.winnerFaction === "FISI" ? 0 : a.winnerFaction === "FIAE" ? 1 : 2;
      const bW = b.winnerFaction === "FISI" ? 0 : b.winnerFaction === "FIAE" ? 1 : 2;
      if (aW !== bW) return aW - bW;
      if (a.rank !== b.rank) return a.rank - b.rank;
      return a.closedAt < b.closedAt ? 1 : -1;
    }
    return a.closedAt < b.closedAt ? 1 : -1;
  });
  return out;
}
