import type { LearningFlowBlock } from "../../../../data/sqlAcademyContent";
import { cn } from "../../../../lib/cn";

const STEP_LABELS: Record<LearningFlowBlock["type"], string> = {
  learning_goal: "Ziel",
  core_statement: "Kern",
  explanation: "Erklärung",
  mini_example: "Beispiel",
  exercise: "Aufgabe",
  solution: "Lösung",
  summary: "Fazit",
};

type LearningFlowStepperProps = {
  blocks: readonly LearningFlowBlock[];
  maxUnlockedIndex: number;
  cursorIndex: number;
  onSelectStep: (index: number) => void;
  reducedMotion: boolean;
};

export function LearningFlowStepper({
  blocks,
  maxUnlockedIndex,
  cursorIndex,
  onSelectStep,
  reducedMotion,
}: LearningFlowStepperProps) {
  if (blocks.length === 0) return null;

  return (
    <nav
      aria-label="Lernschritte"
      className="border-b border-cyan-500/20 bg-slate-950/80 px-2 py-2 sm:px-4"
    >
      <ol className="mx-auto flex max-w-4xl list-none flex-wrap items-center justify-center gap-1 sm:gap-2">
        {blocks.map((block, index) => {
          const unlocked = index <= maxUnlockedIndex;
          const active = index === cursorIndex;
          const label = STEP_LABELS[block.type] ?? `Schritt ${index + 1}`;
          return (
            <li key={`${block.type}-${index}`} className="flex min-w-0 items-center">
              {index > 0 ? (
                <span
                  className="mx-0.5 hidden h-px w-2 shrink-0 bg-cyan-500/25 sm:inline sm:w-3"
                  aria-hidden
                />
              ) : null}
              <button
                type="button"
                disabled={!unlocked}
                onClick={() => {
                  if (unlocked) onSelectStep(index);
                }}
                className={cn(
                  "rounded-md border px-1.5 py-1 text-[9px] font-semibold uppercase tracking-[0.08em] transition-colors sm:px-2 sm:text-[10px] sm:tracking-[0.12em]",
                  active
                    ? "border-cyan-400/60 bg-cyan-950/50 text-cyan-50"
                    : unlocked
                      ? "border-white/12 bg-slate-900/60 text-slate-200 hover:border-cyan-400/35 hover:text-cyan-100"
                      : "cursor-not-allowed border-white/[0.06] bg-slate-950/40 text-slate-600",
                  reducedMotion ? "" : "duration-200",
                )}
              >
                <span className="sr-only">
                  {label} {active ? "aktuell" : unlocked ? "wählbar" : "gesperrt"}
                </span>
                <span aria-hidden className="truncate">
                  {label}
                </span>
              </button>
            </li>
          );
        })}
      </ol>
    </nav>
  );
}
