import { motion, useReducedMotion } from "framer-motion";
import {
  SKILL_TREE_EDGES,
  SKILL_TREE_NODES,
  canUnlockNode,
  getNode,
} from "../../data/skillTree";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

export function TechTreeMap() {
  const prefersReduced = useReducedMotion();
  const unlockedNodes = useAppStore((s) => s.unlockedNodes);
  const tryUnlockSkillNode = useAppStore((s) => s.tryUnlockSkillNode);

  return (
    <div className="relative w-full overflow-hidden rounded-3xl border border-border-glass bg-surface/90 p-4 ring-1 ring-white/10 sm:p-6">
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20 mix-blend-overlay" />
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-15" />
      <p className="relative mb-4 font-sans text-[11px] font-semibold uppercase tracking-[0.28em] text-cyber-cyan">
        Der Fahrplan · Skill-Tree
      </p>
      <div className="relative mx-auto aspect-[100/54] w-full max-w-4xl">
        <svg
          className="absolute inset-0 h-full w-full text-transparent"
          viewBox="0 0 100 54"
          preserveAspectRatio="xMidYMid meet"
          aria-hidden
        >
          {SKILL_TREE_EDGES.map((edge, i) => {
            const a = getNode(edge.from);
            const b = getNode(edge.to);
            if (!a || !b) return null;
            const lit =
              unlockedNodes.includes(edge.from) && unlockedNodes.includes(edge.to);
            const d = `M ${a.x} ${a.y} L ${b.x} ${b.y}`;
            return (
              <motion.path
                key={`${edge.from}-${edge.to}`}
                d={d}
                fill="none"
                vectorEffect="non-scaling-stroke"
                strokeWidth={lit ? 0.55 : 0.32}
                stroke={lit ? "rgb(0 245 255 / 0.65)" : "rgb(55 58 68 / 0.85)"}
                strokeLinecap="round"
                initial={prefersReduced ? false : { pathLength: 0, opacity: 0.35 }}
                animate={{ pathLength: 1, opacity: 1 }}
                transition={{
                  pathLength: { duration: 1.05, delay: i * 0.06, ease: [0.16, 1, 0.3, 1] },
                  opacity: { duration: 0.35, delay: i * 0.04 },
                }}
              />
            );
          })}
        </svg>

        {SKILL_TREE_NODES.map((node) => {
          const unlocked = unlockedNodes.includes(node.id);
          const unlockable = canUnlockNode(node.id, unlockedNodes);
          return (
            <motion.button
              key={node.id}
              type="button"
              style={{
                left: `${node.x}%`,
                top: `${(node.y / 54) * 100}%`,
                transform: "translate(-50%, -50%)",
              }}
              className={cn(
                "absolute z-10 flex min-w-[4.5rem] max-w-[7rem] flex-col items-center gap-1 rounded-full border px-2 py-2 text-center font-sans text-[9px] font-bold uppercase leading-tight tracking-wide transition sm:min-w-[5.5rem] sm:px-3 sm:text-[10px]",
                unlocked &&
                  "border-cyber-cyan/60 bg-cyber-cyan/15 text-cyber-cyan ring-1 ring-white/10",
                !unlocked && "border-zinc-700/80 bg-zinc-950/90 text-zinc-500",
                unlockable &&
                  !unlocked &&
                  "ring-2 ring-magenta/40 hover:border-magenta/50 hover:text-magenta",
              )}
              whileHover={unlockable || unlocked ? { scale: 1.06 } : { scale: 1.02 }}
              whileTap={{ scale: 0.94 }}
              onClick={() => tryUnlockSkillNode(node.id)}
            >
              <span
                className={cn(
                  "size-2 rounded-full",
                  unlocked ? "border border-white/15 bg-cyber-cyan ring-1 ring-white/10" : "bg-zinc-600",
                )}
              />
              {node.label}
            </motion.button>
          );
        })}
      </div>
      <p className="relative mt-4 font-sans text-xs text-foreground-muted">
        Tippe freigeschaltbare Knoten — gesperrte werden aktiv sobald alle Parents leuchten
      </p>
    </div>
  );
}
