export type SynthesisRecipeType = "static" | "probabilistic";

export interface SynthesisMaterialRequirement {
  itemId: string;
  amount: number;
}

export interface SynthesisOutputItem {
  itemId: string;
  amount: number;
}

interface SynthesisRecipeBase {
  id: string;
  name: string;
  type: SynthesisRecipeType;
  input: SynthesisMaterialRequirement[];
  output: SynthesisOutputItem;
}

export interface StaticSynthesisRecipe extends SynthesisRecipeBase {
  type: "static";
  successRate: 1;
}

export interface ProbabilisticSynthesisRecipe extends SynthesisRecipeBase {
  type: "probabilistic";
  successRate: number;
}

export type SynthesisRecipe = StaticSynthesisRecipe | ProbabilisticSynthesisRecipe;

function req(itemId: string, amount: number): SynthesisMaterialRequirement {
  return { itemId, amount };
}

function out(itemId: string, amount = 1): SynthesisOutputItem {
  return { itemId, amount };
}

