type InfoCardTone = "info" | "tip" | "warning";

type InfoCardProps = {
  tone: InfoCardTone;
  title: string;
  children: string;
};

function TipIcon() {
  return (
    <svg viewBox="0 0 24 24" className="h-4 w-4" fill="none" aria-hidden="true">
      <path d="M12 3L21 8V16L12 21L3 16V8L12 3Z" stroke="currentColor" strokeWidth="1.5" />
      <path d="M12 8V13" stroke="currentColor" strokeWidth="1.5" />
      <circle cx="12" cy="16.5" r="1" fill="currentColor" />
    </svg>
  );
}

function WarningIcon() {
  return (
    <svg viewBox="0 0 24 24" className="h-4 w-4" fill="none" aria-hidden="true">
      <path d="M12 3L22 21H2L12 3Z" stroke="currentColor" strokeWidth="1.5" />
      <path d="M12 9V14" stroke="currentColor" strokeWidth="1.5" />
      <circle cx="12" cy="17.5" r="1" fill="currentColor" />
    </svg>
  );
}

function InfoIcon() {
  return (
    <svg viewBox="0 0 24 24" className="h-4 w-4" fill="none" aria-hidden="true">
      <circle cx="12" cy="12" r="9" stroke="currentColor" strokeWidth="1.5" />
      <path d="M12 10V16" stroke="currentColor" strokeWidth="1.5" />
      <circle cx="12" cy="7.5" r="1" fill="currentColor" />
    </svg>
  );
}

export function InfoCard({ tone, title, children }: InfoCardProps) {
  const isTip = tone === "tip";
  const isInfo = tone === "info";
  const toneClass = isInfo
    ? "border-sky-500/40 border-l-4 border-l-sky-300"
    : isTip
      ? "border-cyan-500/40 border-l-4 border-l-cyan-300"
      : "border-orange-500/40 border-l-4 border-l-orange-400";
  const textClass = isInfo ? "text-sky-200" : isTip ? "text-cyan-200" : "text-orange-200";

  return (
    <aside className={`rounded-xl border bg-slate-950/70 p-4 ${toneClass}`}>
      <div className={`mb-2 flex items-center gap-2 ${textClass}`}>
        {isInfo ? <InfoIcon /> : isTip ? <TipIcon /> : <WarningIcon />}
        <p className="text-xs font-semibold uppercase tracking-[0.15em]">{title}</p>
      </div>
      <p className="text-sm leading-6 text-slate-200">{children}</p>
    </aside>
  );
}
