/**
 * Phase 63 — statische Oracle-Registry (Arena Neural-Link)
 * Keys: question `id` (Bank/Seed) oder `slug`; Werte ohne Satzschlusszeichen
 */

const ORACLE_BY_QUESTION_ID: Record<string, string> = {
  "ap1-fiae-rest-001":
    "[Registry · REST] · Der Server vergisst dich zwischen zwei Pulsen · nur die Ressource bleibt im Licht",
  "fallback-q1":
    "[Registry · API] · Stateless heißt nicht leer · heißt kein Gedächtnis zwischen den Requests",
  "fallback-q2":
    "[Registry · SQL] · Lesen brennt kein Loch · schreiben schon",
  "fallback-q3":
    "[Registry · git] · Marker sind Landminen zwischen zwei Wahrheiten",
};

const ORACLE_BY_SLUG: Record<string, string> = {
  "rest-ressourcen-prinzip":
    "[Slug-Leak · REST] · URIs sind Koordinaten · nicht Dekoration",
};

export function getQuestionOracleHint(questionId: string, slug?: string): string | undefined {
  const id = questionId.trim();
  if (id && ORACLE_BY_QUESTION_ID[id]) return ORACLE_BY_QUESTION_ID[id];
  const s = slug?.trim();
  if (s && ORACLE_BY_SLUG[s]) return ORACLE_BY_SLUG[s];
  return undefined;
}
