type AcademyPrimaryActionBarProps = {
  primaryLabel: string;
  primaryDisabled: boolean;
  onPrimary: () => void;
  showBack: boolean;
  onBack: () => void;
  reducedMotion: boolean;
  /** Announced when primary label changes */
  liveRegionText: string;
  /** Optional tutorial hint above buttons no trailing punctuation */
  contextLine?: string;
};

export function AcademyPrimaryActionBar({
  primaryLabel,
  primaryDisabled,
  onPrimary,
  showBack,
  onBack,
  reducedMotion,
  liveRegionText,
  contextLine,
}: AcademyPrimaryActionBarProps) {
  return (
    <div
      className="fixed bottom-0 left-0 right-0 z-40 border-t border-cyan-500/25 bg-slate-950/95 pb-[max(0.75rem,env(safe-area-inset-bottom))] pt-3 backdrop-blur-md"
      style={{ transition: reducedMotion ? undefined : "border-color 0.2s ease" }}
    >
      <div className="sr-only" aria-live="polite">
        {liveRegionText}
      </div>
      {contextLine ? (
        <p className="mx-auto mb-2 max-w-lg px-4 text-center font-mono text-[10px] leading-snug uppercase tracking-[0.14em] text-cyan-200/85">
          {contextLine}
        </p>
      ) : null}
      <div className="mx-auto flex max-w-2xl items-center justify-between gap-3 px-4">
        <button
          type="button"
          className="min-w-[4.5rem] rounded-lg border border-white/15 bg-slate-900/70 px-3 py-2.5 text-[11px] font-semibold uppercase tracking-[0.12em] text-slate-200 disabled:cursor-not-allowed disabled:opacity-35"
          onClick={onBack}
          disabled={!showBack}
        >
          Zurück
        </button>
        <button
          type="button"
          className="min-h-[48px] flex-1 rounded-xl border border-cyan-400/50 bg-gradient-to-r from-cyan-600/90 to-cyan-500/80 px-4 py-3 text-sm font-semibold uppercase tracking-[0.14em] text-slate-950 shadow-[0_0_24px_rgba(34,211,238,0.25)] disabled:cursor-not-allowed disabled:opacity-40"
          onClick={onPrimary}
          disabled={primaryDisabled}
        >
          {primaryLabel}
        </button>
      </div>
    </div>
  );
}
