import { DAILY_FLASHCARDS } from "../data/dailyFlashcards";
import { endOfTodayTimestamp } from "./sm2";
import type { FlashcardProgressEntry } from "./sm2";

export interface Sm2TagBuckets {
  cyan: number;
  yellow: number;
  magenta: number;
}

/** Pro Themengebiet (tag): Anteile für Cyan / Gelb / Magenta-Balken */
export function sm2BucketsByTag(
  progress: Record<string, FlashcardProgressEntry>,
): Record<string, Sm2TagBuckets> {
  const lim = endOfTodayTimestamp();
  const out: Record<string, Sm2TagBuckets> = {};

  const tags = new Set(DAILY_FLASHCARDS.map((c) => c.tag));
  for (const tag of tags) {
    out[tag] = { cyan: 0, yellow: 0, magenta: 0 };
  }

  for (const card of DAILY_FLASHCARDS) {
    const p = progress[card.id];
    const b = out[card.tag];
    if (!b) continue;

    if (!p || p.repetitions <= 0) {
      b.magenta += 1;
      continue;
    }
    const due = p.nextReviewDate <= lim;
    if (p.repetitions >= 2 && !due) {
      b.cyan += 1;
    } else {
      b.yellow += 1;
    }
  }

  return out;
}

export function realmConqueredHexCount(tiles: Record<string, { structure: string }>): number {
  return Object.values(tiles).filter((t) => t.structure !== "empty").length;
}
