import type { StateCreator } from "zustand";
import type { ResolvedGlobalLiveEvent } from "../../lib/globalEventEngine";
import { fetchGlobalEventSnapshot, subscribeGlobalEventUpdates } from "../../lib/services/eventService";
import type { SyndicateTechNodeId } from "../../data/techTreeNodes";
import type { AppState, LaunchPulseState, OverdriveEventModifier } from "../useAppStore";

export interface EventSlice {
  serverTimeOffsetMs: number;
  globalLiveEvent: ResolvedGlobalLiveEvent | null;
  refreshGlobalLiveEvent: () => Promise<void>;
  launchPulse: LaunchPulseState;
  setLaunchPulse: (next: LaunchPulseState) => void;
  systemPulse: AppState["systemPulse"];
  pushSystemPulseEvent: AppState["pushSystemPulseEvent"];
  clearSystemPulse: () => void;
  activeEventModifier: OverdriveEventModifier | null;
  setActiveEventModifier: (next: OverdriveEventModifier | null) => void;
  raidDropRateScale: number;
  setRaidDropRateScale: (next: number) => void;
  raidArtifacts: AppState["raidArtifacts"];
  maybeDropRaidArtifact: AppState["maybeDropRaidArtifact"];
  globalLore: AppState["globalLore"];
  setGlobalLore: AppState["setGlobalLore"];
  globalFrictionAvg: number;
  setGlobalFrictionAvg: (next: number) => void;
  neuralOutbreak: AppState["neuralOutbreak"];
  setNeuralOutbreak: AppState["setNeuralOutbreak"];
  claimedOutbreakRewardIds: string[];
  claimOutbreakReward: (outbreakId: string) => void;
  syndicateRuntimeBuffs: AppState["syndicateRuntimeBuffs"];
  setSyndicateRuntimeBuffs: AppState["setSyndicateRuntimeBuffs"];
  councilRuntime: AppState["councilRuntime"];
  setCouncilRuntime: AppState["setCouncilRuntime"];
  singularitySequence: AppState["singularitySequence"];
  startSingularitySequence: AppState["startSingularitySequence"];
  finishSingularitySequence: () => void;
  refreshEventRuntime: () => Promise<void>;
}

let __eventsRealtimeUnsub: null | (() => void) = null;

export const createEventSlice: StateCreator<AppState, [], [], EventSlice> = (set, get) => ({
  serverTimeOffsetMs: 0,
  globalLiveEvent: null,
  refreshGlobalLiveEvent: async () => {
    const snap = await fetchGlobalEventSnapshot();
    const prevId = get().globalLiveEvent?.id ?? null;
    set({ serverTimeOffsetMs: snap.serverTimeOffsetMs, globalLiveEvent: snap.globalLiveEvent });
    if (snap.globalLiveEvent != null && snap.globalLiveEvent.id !== prevId) {
      get().pushSystemPulseEvent({ kind: "GLOBAL_LIVE_EVENT", headline: snap.globalLiveEvent.pulseLine });
    }
  },
  launchPulse: {
    active: false,
    xpMultiplier: 1,
    startsAtMs: 0,
    endsAtMs: 0,
    message: "WELCOME TO THE NEXUS",
  },
  setLaunchPulse: (next) =>
    set({
      launchPulse: {
        active: !!next.active,
        xpMultiplier: Math.max(1, Math.min(2, Number.isFinite(next.xpMultiplier) ? next.xpMultiplier : 1)),
        startsAtMs: Math.max(0, Math.floor(next.startsAtMs)),
        endsAtMs: Math.max(0, Math.floor(next.endsAtMs)),
        message: String(next.message || "WELCOME TO THE NEXUS"),
      },
    }),
  systemPulse: [],
  pushSystemPulseEvent: (event) =>
    set((s) => {
      const id = `pulse-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
      const full = { ...event, id, ts: Date.now() };
      return { systemPulse: [full, ...s.systemPulse].slice(0, 10) };
    }),
  clearSystemPulse: () => set({ systemPulse: [] }),
  activeEventModifier: null,
  setActiveEventModifier: (next) => set({ activeEventModifier: next }),
  raidDropRateScale: 1,
  setRaidDropRateScale: (next) =>
    set({ raidDropRateScale: Math.max(0, Math.min(3, Number.isFinite(next) ? next : 1)) }),
  raidArtifacts: [],
  maybeDropRaidArtifact: (module) => {
    const s = get();
    const raid = s.activeEventModifier;
    if (!raid || !module || raid.targetModule !== module) return null;
    const now = Date.now() + s.serverTimeOffsetMs;
    if (now >= raid.endsAtMs) {
      set({ activeEventModifier: null });
      return null;
    }
    const councilDropScale = s.councilRuntime.active ? 1 + Math.max(0, s.councilRuntime.dropScaleDelta) : 1;
    const scalar = Math.max(
      0,
      Math.min(4, s.raidDropRateScale * (1 + s.syndicateRuntimeBuffs.dropRateBonus) * councilDropScale),
    );
    const pLegend = Math.min(0.5, 0.02 * scalar);
    const pRare = Math.min(0.92, 0.11 * scalar);
    const roll = Math.random();
    const rarity = roll < pLegend ? "legendary" : roll < pRare ? "rare" : null;
    if (!rarity) return null;
    const artifact = {
      id: `raid-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      label: rarity === "legendary" ? `Overdrive Core ${module.toUpperCase()}` : `Raid Fragment ${module.toUpperCase()}`,
      rarity,
      module,
      eventId: raid.id,
      receivedAt: new Date().toISOString(),
    } as const;
    set({ raidArtifacts: [artifact, ...s.raidArtifacts].slice(0, 24) });
    get().pushSystemPulseEvent({
      kind: "SYSTEM_ANNOUNCEMENT",
      message: `RAID ARTIFACT ${artifact.label}`,
    });
    return artifact;
  },
  globalLore: { totalGlobalXp: 0, unlockedLoreIds: [] },
  setGlobalLore: (next) =>
    set({
      globalLore: {
        totalGlobalXp: Math.max(0, Math.floor(next.totalGlobalXp)),
        unlockedLoreIds: Array.from(new Set(next.unlockedLoreIds.filter((x) => typeof x === "string"))),
      },
    }),
  globalFrictionAvg: 0,
  setGlobalFrictionAvg: (next) =>
    set({ globalFrictionAvg: Math.max(0, Math.min(1, Number.isFinite(next) ? next : 0)) }),
  neuralOutbreak: {
    infected: false,
    outbreakId: null,
    module: null,
    progress: 0,
    target: 0,
    hotZoneBossId: null,
  },
  setNeuralOutbreak: (next) =>
    set({
      neuralOutbreak: {
        infected: !!next.infected,
        outbreakId: next.outbreakId ? String(next.outbreakId) : null,
        module: next.module ?? null,
        progress: Math.max(0, Math.floor(next.progress)),
        target: Math.max(0, Math.floor(next.target)),
        hotZoneBossId: next.hotZoneBossId ? String(next.hotZoneBossId) : null,
      },
    }),
  claimedOutbreakRewardIds: [],
  claimOutbreakReward: (outbreakId) =>
    set((s) => {
      if (!outbreakId || s.claimedOutbreakRewardIds.includes(outbreakId)) return {};
      return { claimedOutbreakRewardIds: [...s.claimedOutbreakRewardIds, outbreakId].slice(-24) };
    }),
  syndicateRuntimeBuffs: {
    syndicateId: null,
    role: null,
    unlockedNodeIds: [],
    xpMultiplier: 1,
    timeBonusSec: 0,
    dropRateBonus: 0,
  },
  councilRuntime: {
    active: false,
    proposalId: null,
    targetModule: null,
    xpBoostMultiplier: 1,
    dropScaleDelta: 0,
    label: "",
    expiresAt: null,
  },
  setSyndicateRuntimeBuffs: (next) =>
    set({
      syndicateRuntimeBuffs: {
        syndicateId: next.syndicateId ? String(next.syndicateId) : null,
        role:
          next.role === "founder" || next.role === "officer" || next.role === "member"
            ? next.role
            : null,
        unlockedNodeIds: Array.from(
          new Set(next.unlockedNodeIds.filter((id): id is SyndicateTechNodeId => typeof id === "string")),
        ),
        xpMultiplier: Math.max(1, Number.isFinite(next.xpMultiplier) ? next.xpMultiplier : 1),
        timeBonusSec: Math.max(0, Math.floor(Number(next.timeBonusSec ?? 0))),
        dropRateBonus: Math.max(0, Number.isFinite(next.dropRateBonus) ? next.dropRateBonus : 0),
      },
    }),
  setCouncilRuntime: (next) =>
    set({
      councilRuntime: {
        active: !!next.active,
        proposalId: next.proposalId ? String(next.proposalId) : null,
        targetModule: next.targetModule ?? null,
        xpBoostMultiplier: Math.max(1, Number.isFinite(next.xpBoostMultiplier) ? next.xpBoostMultiplier : 1),
        dropScaleDelta: Number.isFinite(next.dropScaleDelta) ? next.dropScaleDelta : 0,
        label: typeof next.label === "string" ? next.label : "",
        expiresAt: next.expiresAt ? String(next.expiresAt) : null,
      },
    }),
  singularitySequence: {
    active: false,
    seasonTag: "",
    gainedLegacyPoints: 0,
  },
  startSingularitySequence: (payload) =>
    set({
      singularitySequence: {
        active: true,
        seasonTag: String(payload.seasonTag || "SEASON_NULL"),
        gainedLegacyPoints: Math.max(0, Math.floor(payload.gainedLegacyPoints)),
      },
    }),
  finishSingularitySequence: () =>
    set({
      singularitySequence: {
        active: false,
        seasonTag: "",
        gainedLegacyPoints: 0,
      },
    }),
  refreshEventRuntime: async () => {
    await get().refreshGlobalLiveEvent();
    if (!__eventsRealtimeUnsub) {
      __eventsRealtimeUnsub = subscribeGlobalEventUpdates(() => {
        void get().refreshGlobalLiveEvent();
      });
    }
  },
});
