import { useCallback, useMemo, type CSSProperties } from "react";
import { motion } from "framer-motion";
import { UNIVERSE_THEMES, UNIVERSE_THEME_FALLBACK } from "../../styles/themes/universeThemes";
import { useAppStore } from "../../store/useAppStore";
import { useAcademyStore } from "../../store/academyStore";
import type { ExamRepairTarget } from "../../lib/mockExamAnalysis";
import type { TrainingPlanTaskV1 } from "../../lib/mockExamTrainingPlan";

const REPAIR_CTA: Record<ExamRepairTarget, string> = {
  sql_academy: "SQL Academy öffnen",
  helpdesk: "Helpdesk Lab öffnen",
  flashcards: "Karten Stack öffnen",
  vault: "Wissens Hub öffnen",
};

export function TrainingNextStepsPanel() {
  const trainingPlan = useAcademyStore((s) => s.trainingPlan);
  const selectedUniverseId = useAppStore((s) => s.selectedUniverseId);
  const enterSqlAdventure = useAppStore((s) => s.enterSqlAdventure);
  const enterItSupport = useAppStore((s) => s.enterItSupport);
  const enterFlashcards = useAppStore((s) => s.enterFlashcards);
  const enterDataVault = useAppStore((s) => s.enterDataVault);

  const theme = UNIVERSE_THEMES[selectedUniverseId] ?? UNIVERSE_THEME_FALLBACK;

  const openRepair = useCallback(
    (target: ExamRepairTarget) => {
      if (target === "sql_academy") enterSqlAdventure();
      else if (target === "helpdesk") enterItSupport();
      else if (target === "flashcards") enterFlashcards();
      else enterDataVault();
    },
    [enterDataVault, enterFlashcards, enterItSupport, enterSqlAdventure],
  );

  const primary = trainingPlan?.tasks[0];
  const rest = trainingPlan?.tasks.slice(1) ?? [];

  const cssVars = useMemo(
    () =>
      ({
        "--universe-primary": theme.primary,
        "--universe-accent": theme.accent,
      }) as CSSProperties,
    [theme.accent, theme.primary],
  );

  if (!trainingPlan || trainingPlan.tasks.length === 0) return null;

  return (
    <motion.section
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-2xl border border-white/[0.08] bg-[#060708]/90 p-5 shadow-[0_0_0_1px_rgb(255_255_255/0.03)]"
      style={cssVars}
    >
      <div className="flex flex-wrap items-start justify-between gap-3 border-b border-white/[0.06] pb-4">
        <div className="space-y-1">
          <p className="font-mono text-[10px] font-medium uppercase tracking-[0.32em] text-foreground-muted">Next Steps</p>
          <h2 className="text-lg font-semibold tracking-tight text-zinc-100">Trainings Roadmap</h2>
          <p className="max-w-xl text-xs text-zinc-500">Aus deiner letzten Mock Prüfung · max drei Fokus Aufgaben</p>
        </div>
      </div>

      <div className="mt-4 space-y-3">
        {primary ? <PrimaryTaskRow task={primary} onOpen={() => openRepair(primary.repairTarget)} ctaLabel={REPAIR_CTA[primary.repairTarget]} /> : null}
        {rest.map((task) => (
          <SecondaryTaskRow key={`${task.rank}-${task.source}-${task.questionId ?? task.domainBucket ?? task.title}`} task={task} onOpen={() => openRepair(task.repairTarget)} />
        ))}
      </div>
    </motion.section>
  );
}

function PrimaryTaskRow({ task, onOpen, ctaLabel }: { task: TrainingPlanTaskV1; onOpen: () => void; ctaLabel: string }) {
  return (
    <div className="flex flex-col gap-3 rounded-xl border border-[color-mix(in_srgb,var(--universe-primary)_35%,transparent)] bg-[color-mix(in_srgb,var(--universe-primary)_08%,transparent)] p-4 sm:flex-row sm:items-center sm:justify-between">
      <div className="min-w-0 space-y-2">
        <div className="flex flex-wrap items-center gap-2">
          <span
            className="rounded-full px-2 py-0.5 font-mono text-[9px] font-semibold uppercase tracking-[0.2em] text-[#050608]"
            style={{ background: "var(--universe-primary)" }}
          >
            Recommended
          </span>
          <span className="font-mono text-[10px] uppercase tracking-[0.24em] text-zinc-500">Priorität {task.rank}</span>
        </div>
        <p className="text-sm font-semibold text-zinc-100">{task.title}</p>
        <p className="line-clamp-2 text-xs text-zinc-400">{task.subtitle}</p>
      </div>
      <button
        type="button"
        onClick={onOpen}
        className="shrink-0 rounded-lg px-4 py-2.5 font-mono text-[10px] font-semibold uppercase tracking-[0.2em] text-[#050608] transition hover:opacity-90"
        style={{ background: "var(--universe-primary)" }}
      >
        {ctaLabel}
      </button>
    </div>
  );
}

function SecondaryTaskRow({ task, onOpen }: { task: TrainingPlanTaskV1; onOpen: () => void }) {
  return (
    <div className="flex flex-col gap-2 rounded-lg border border-white/[0.06] bg-white/[0.02] p-3 sm:flex-row sm:items-center sm:justify-between">
      <div className="min-w-0 space-y-1">
        <div className="flex items-center gap-2">
          <span className="font-mono text-[10px] uppercase tracking-[0.24em] text-zinc-500">Priorität {task.rank}</span>
        </div>
        <p className="text-sm font-medium text-zinc-200">{task.title}</p>
        <p className="line-clamp-2 text-xs text-zinc-500">{task.subtitle}</p>
      </div>
      <button
        type="button"
        onClick={onOpen}
        className="shrink-0 self-start rounded-md border border-[color-mix(in_srgb,var(--universe-primary)_45%,transparent)] px-3 py-2 font-mono text-[9px] font-semibold uppercase tracking-[0.18em] text-[color-mix(in_srgb,var(--universe-primary)_95%,white)] transition hover:bg-[color-mix(in_srgb,var(--universe-primary)_12%,transparent)] sm:self-center"
      >
        {REPAIR_CTA[task.repairTarget]}
      </button>
    </div>
  );
}
