type SyncHeartbeatStatus = "idle" | "syncing" | "synced" | "retrying" | "error";

type GlobalSyncPayload = {
  snapshot: unknown;
};

type SyncResult = {
  ok: boolean;
  status: SyncHeartbeatStatus;
  attempts: number;
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => window.setTimeout(resolve, ms));
}

export async function pushGlobalProgressWithBackoff(
  payload: GlobalSyncPayload,
  onStatus?: (status: SyncHeartbeatStatus) => void,
): Promise<SyncResult> {
  const maxAttempts = 4;
  let attempt = 0;
  onStatus?.("syncing");

  while (attempt < maxAttempts) {
    attempt += 1;
    try {
      const response = await fetch("/api/academy/sync-global-progress", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (response.ok) {
        onStatus?.("synced");
        return { ok: true, status: "synced", attempts: attempt };
      }
      if (response.status === 408 || response.status >= 500) {
        onStatus?.("retrying");
        if (attempt < maxAttempts) {
          await sleep(300 * 2 ** (attempt - 1));
          continue;
        }
      }
      onStatus?.("error");
      return { ok: false, status: "error", attempts: attempt };
    } catch {
      onStatus?.("retrying");
      if (attempt < maxAttempts) {
        await sleep(300 * 2 ** (attempt - 1));
        continue;
      }
      onStatus?.("error");
      return { ok: false, status: "error", attempts: attempt };
    }
  }

  onStatus?.("error");
  return { ok: false, status: "error", attempts: maxAttempts };
}
