import { useEffect } from "react";
import confetti from "canvas-confetti";
import { motion, useReducedMotion } from "framer-motion";

type MasteryCelebrationProps = {
  active: boolean;
  onDone: () => void;
};

export function MasteryCelebration({ active, onDone }: MasteryCelebrationProps) {
  const reduce = !!useReducedMotion();

  useEffect(() => {
    if (!active) return;
    if (!reduce) {
      confetti({
        particleCount: 120,
        spread: 88,
        startVelocity: 42,
        colors: ["#00E5FF", "#FF2BD6", "#6DFFB4"],
      });
    }
    const timer = window.setTimeout(onDone, reduce ? 1200 : 2200);
    return () => {
      window.clearTimeout(timer);
      confetti.reset();
    };
  }, [active, reduce, onDone]);

  if (!active) return null;

  return (
    <motion.div
      className="pointer-events-none fixed inset-x-4 top-6 z-[570] mx-auto max-w-xl rounded-lg border border-emerald-300/55 bg-emerald-950/45 px-4 py-3 text-center"
      initial={{ opacity: 0, y: -12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0 }}
      transition={{ duration: reduce ? 0 : 0.28 }}
    >
      <p className="text-sm font-semibold text-emerald-200">Mastery 100 erreicht Neue Gains gesichert</p>
    </motion.div>
  );
}
