import { motion, useReducedMotion } from "framer-motion";

export function FilterLogic() {
  const reduce = !!useReducedMotion();

  return (
    <motion.svg
      viewBox="0 0 640 220"
      className="academy-diagram"
      role="img"
      aria-label="Filter Logik mit WHERE Tuersteher"
      initial={{ opacity: 0.82 }}
      animate={reduce ? { opacity: 0.9 } : { opacity: [0.76, 0.9, 0.76] }}
      transition={reduce ? { duration: 0 } : { duration: 4.4, repeat: Infinity, ease: "easeInOut" }}
    >
      <defs>
        <linearGradient id="filterBeam" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor="#00E5FF" />
          <stop offset="100%" stopColor="#FF2BD6" />
        </linearGradient>
      </defs>

      <rect x="14" y="16" width="612" height="188" rx="16" fill="#060D19" stroke="#00E5FF" strokeOpacity="0.56" />

      <rect x="44" y="54" width="176" height="110" rx="12" fill="#071A2A" stroke="#00E5FF" strokeOpacity="0.68" />
      <text x="132" y="90" textAnchor="middle" className="diagram-title">Tabelle</text>
      <text x="132" y="110" textAnchor="middle" className="diagram-sub">nahrungsmittel</text>
      <text x="132" y="130" textAnchor="middle" className="diagram-sub">alle Zeilen</text>

      <rect x="246" y="44" width="148" height="132" rx="12" fill="#1C0A23" stroke="#FF2BD6" strokeOpacity="0.7" />
      <text x="320" y="80" textAnchor="middle" className="diagram-title">WHERE</text>
      <text x="320" y="100" textAnchor="middle" className="diagram-sub">Tuersteher</text>
      <text x="320" y="120" textAnchor="middle" className="diagram-sub">makro_fokus</text>
      <text x="320" y="140" textAnchor="middle" className="diagram-sub">gleich Protein</text>

      <rect x="420" y="54" width="176" height="110" rx="12" fill="#0A1A24" stroke="#00E5FF" strokeOpacity="0.68" />
      <text x="508" y="90" textAnchor="middle" className="diagram-title">Ergebnis</text>
      <text x="508" y="110" textAnchor="middle" className="diagram-sub">nur passende</text>
      <text x="508" y="130" textAnchor="middle" className="diagram-sub">Zeilen</text>

      <motion.line
        x1="220"
        y1="110"
        x2="246"
        y2="110"
        stroke="url(#filterBeam)"
        strokeWidth="4"
        initial={reduce ? { pathLength: 1 } : { pathLength: 0 }}
        animate={{ pathLength: 1 }}
        transition={reduce ? { duration: 0 } : { duration: 1.2, repeat: Infinity, repeatDelay: 0.45 }}
      />
      <motion.line
        x1="394"
        y1="110"
        x2="420"
        y2="110"
        stroke="url(#filterBeam)"
        strokeWidth="4"
        initial={reduce ? { pathLength: 1 } : { pathLength: 0 }}
        animate={{ pathLength: 1 }}
        transition={reduce ? { duration: 0 } : { duration: 1.2, repeat: Infinity, repeatDelay: 0.45, delay: 0.28 }}
      />

      {reduce ? null : (
        <motion.rect
          x="252"
          y="154"
          width="136"
          height="10"
          fill="#FF2BD6"
          fillOpacity="0.14"
          animate={{ y: [154, 158, 154] }}
          transition={{ duration: 3.1, repeat: Infinity, ease: "easeInOut" }}
        />
      )}
    </motion.svg>
  );
}
