import { motion } from "framer-motion";
import { IconLock } from "../icons/ThinLineIcons";
import { memo } from "react";
import type { SqlMission } from "../../data/sqlMissions";
import { cn } from "../../lib/cn";
import { sqlMissionCardReveal } from "../../motion/variants";
import { SqlDifficultyBadge } from "./SqlDifficultyBadge";

export interface SqlMissionCardProps {
  mission: SqlMission;
  unlocked: boolean;
  onCheckpoint: (id: string) => void;
}

export const SqlMissionCard = memo(function SqlMissionCard({
  mission,
  unlocked,
  onCheckpoint,
}: SqlMissionCardProps) {
  return (
    <motion.article
      variants={sqlMissionCardReveal}
      className={cn(
        "relative flex flex-col gap-3 rounded-2xl border p-4 backdrop-blur-xl sm:p-5",
        "transform-gpu transition-[transform,border-color,background-color] duration-200",
        unlocked
          ? "border-cyber-cyan/45 bg-surface-muted/55 ring-1 ring-white/10 hover:border-emerald-400/50 hover:bg-white/[0.04]"
          : "cursor-not-allowed border-border-glass bg-zinc-950/80 opacity-55 grayscale",
      )}
      style={{ contentVisibility: "auto" as const }}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-15" />
      <div className="relative flex flex-wrap items-start justify-between gap-2">
        <div className="space-y-1">
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
            {mission.island}
          </p>
          <h3
            className={cn(
              "font-display text-lg font-bold uppercase tracking-wide sm:text-xl",
              unlocked ? "text-foreground" : "text-zinc-500",
            )}
          >
            {mission.title}
          </h3>
        </div>
        <div className="flex items-center gap-2">
          <SqlDifficultyBadge difficulty={mission.difficulty} />
          {!unlocked ? (
            <IconLock className="size-5 shrink-0 text-zinc-500" aria-hidden />
          ) : null}
        </div>
      </div>
      <p
        className={cn(
          "relative font-sans text-sm leading-relaxed",
          unlocked ? "text-foreground-muted" : "text-zinc-600",
        )}
      >
        {mission.blurb}
      </p>
      {unlocked ? (
        <div className="relative flex justify-end">
          <button
            type="button"
            onClick={() => onCheckpoint(mission.id)}
            className="rounded-full border border-emerald-400/35 bg-emerald-500/10 px-3 py-1.5 font-mono text-[10px] font-semibold uppercase tracking-wide text-emerald-300 ring-1 ring-white/10 transition hover:bg-emerald-500/20"
          >
            Checkpoint
          </button>
        </div>
      ) : null}
    </motion.article>
  );
});
