import { motion } from "framer-motion";
import { useEffect, useState } from "react";
import { useAppStore } from "../../store/useAppStore";

export function DevToolbox() {
  const isDev = import.meta.env.DEV;

  const seedDevMaterials = useAppStore((s) => s.seedDevMaterials);
  const resetCraftingInventory = useAppStore((s) => s.resetCraftingInventory);
  const getCraftableRecipes = useAppStore((s) => s.getCraftableRecipes);
  const [open, setOpen] = useState(false);
  const [flashMode, setFlashMode] = useState<"none" | "inject" | "reset">("none");

  useEffect(() => {
    if (flashMode === "none") return;
    const timeout = window.setTimeout(() => setFlashMode("none"), 520);
    return () => window.clearTimeout(timeout);
  }, [flashMode]);

  if (!isDev) return null;

  return (
    <div className="pointer-events-none fixed right-4 top-4 z-[80] flex flex-col items-end gap-2">
      <button
        type="button"
        onClick={() => setOpen((value) => !value)}
        className="pointer-events-auto rounded-md border border-cyan/40 bg-black/80 px-3 py-1.5 font-mono text-[11px] uppercase tracking-[0.16em] text-cyan shadow-[0_0_18px_rgba(0,255,255,0.2)]"
      >
        {open ? "Hide Dev Toolbox" : "Show Dev Toolbox"}
      </button>

      {open ? (
        <motion.div
          initial={{ opacity: 0, y: -10, scale: 0.98 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          className={`pointer-events-auto w-[290px] rounded-xl border bg-black/90 p-3 ${
            flashMode === "inject"
              ? "border-cyan shadow-[0_0_26px_rgba(0,255,255,0.45)]"
              : flashMode === "reset"
                ? "border-orange-400 shadow-[0_0_26px_rgba(251,146,60,0.5)]"
                : "border-cyan/40"
          }`}
        >
          <p className="font-sans text-[11px] font-semibold uppercase tracking-[0.28em] text-cyan">Developer Toolbox</p>
          <p className="mt-1 font-sans text-xs text-foreground-muted">
            Craftable recipes {getCraftableRecipes().length}/3
          </p>
          <button
            type="button"
            onClick={() => {
              seedDevMaterials();
              setFlashMode("inject");
            }}
            className="mt-3 w-full rounded-md border border-cyan/50 bg-cyan/20 px-3 py-2 font-mono text-xs uppercase tracking-[0.14em] text-cyan transition hover:bg-cyan/30"
          >
            Inject Crafting Materials
          </button>
          <button
            type="button"
            onClick={() => {
              resetCraftingInventory();
              setFlashMode("reset");
            }}
            className="mt-2 w-full rounded-md border border-orange-400/50 bg-orange-500/20 px-3 py-2 font-mono text-xs uppercase tracking-[0.14em] text-orange-300 transition hover:bg-orange-500/30"
          >
            Reset Inventory
          </button>
        </motion.div>
      ) : null}
    </div>
  );
}
