import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { computeLifetimeXp } from "../../lib/xpCurve";
import { getPrestigePaletteArtifact, getPrestigeRankByLifetimeXp } from "../../lib/rankEngine";
import { heroBackdrop, itemReveal, staggerContainer } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";
import { cn } from "../../lib/cn";
import { useFeedback } from "../../hooks/useFeedback";
import { DailyGrindPanel } from "./DailyGrindPanel";
import { FactionWarBar } from "./FactionWarBar";
import { ProfileGlassPanel } from "./ProfileGlassPanel";
import { SystemReadinessChip } from "./SystemReadinessChip";
import { SystemPulseTicker } from "./SystemPulseTicker";
import type { ActiveFactionBounty } from "../../lib/syncController";

export function HeroHUD() {
  const feedback = useFeedback();
  const progress = useAppStore((s) => s.progress);
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const globalXpToNext = useAppStore((s) => s.globalXpToNext);
  const dailyStreak = useAppStore((s) => s.dailyGrind.streakDays);
  const activeEventModifier = useAppStore((s) => s.activeEventModifier);
  const launchPulse = useAppStore((s) => s.launchPulse);
  const serverTimeOffsetMs = useAppStore((s) => s.serverTimeOffsetMs);
  const neuralOutbreak = useAppStore((s) => s.neuralOutbreak);
  const prefersReduced = useReducedMotion();
  const [rolloutTapCount, setRolloutTapCount] = useState(0);
  const [showRolloutEgg, setShowRolloutEgg] = useState(false);
  const [overdriveTick, setOverdriveTick] = useState(0);
  const [hotZones, setHotZones] = useState<ActiveFactionBounty[]>([]);

  const rolloutEnabledToday = useMemo(() => {
    const now = new Date();
    const ymd = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
    const configured = (import.meta.env.VITE_ROLLOUT_DAY as string | undefined)?.trim() || "2026-04-22";
    return ymd === configured;
  }, []);
  const rolloutDismissed = useMemo(() => {
    try {
      if (typeof localStorage === "undefined") return false;
      return localStorage.getItem("codesnap-rollout-egg-seen") === "1";
    } catch {
      return false;
    }
  }, []);
  const rolloutSecretEnabled = rolloutEnabledToday && !rolloutDismissed;

  const hudProgress = {
    ...progress,
    level: userLevel,
    xpCurrent: globalXP,
    xpToNext: globalXpToNext,
    streakDays: dailyStreak,
  };

  const lifetimeXp = computeLifetimeXp(userLevel, globalXP);
  const prestigeRank = getPrestigeRankByLifetimeXp(lifetimeXp);
  const prestigeArtifact = getPrestigePaletteArtifact(lifetimeXp);

  useEffect(() => {
    if (!rolloutSecretEnabled || showRolloutEgg || rolloutTapCount < 5) return;
    setShowRolloutEgg(true);
    feedback.flip();
    try {
      if (typeof localStorage !== "undefined") localStorage.setItem("codesnap-rollout-egg-seen", "1");
    } catch {
      /* no-op */
    }
  }, [feedback, rolloutSecretEnabled, rolloutTapCount, showRolloutEgg]);

  useEffect(() => {
    if (!activeEventModifier && !launchPulse.active) return;
    const id = window.setInterval(() => setOverdriveTick((x) => x + 1), 1000);
    return () => window.clearInterval(id);
  }, [activeEventModifier, launchPulse.active]);

  const overdriveRemainSec = activeEventModifier
    ? Math.max(0, Math.ceil((activeEventModifier.endsAtMs - (Date.now() + serverTimeOffsetMs)) / 1000))
    : 0;
  void overdriveTick;
  const overdriveMin = String(Math.floor(overdriveRemainSec / 60)).padStart(2, "0");
  const overdriveSec = String(overdriveRemainSec % 60).padStart(2, "0");
  const launchRemainSec = launchPulse.active
    ? Math.max(0, Math.ceil((launchPulse.endsAtMs - (Date.now() + serverTimeOffsetMs)) / 1000))
    : 0;
  const launchHours = String(Math.floor(launchRemainSec / 3600)).padStart(2, "0");
  const launchMinutes = String(Math.floor((launchRemainSec % 3600) / 60)).padStart(2, "0");
  const launchSeconds = String(launchRemainSec % 60).padStart(2, "0");
  const purgePercent = neuralOutbreak.infected
    ? Math.max(0, Math.min(100, Math.round((neuralOutbreak.progress / Math.max(1, neuralOutbreak.target)) * 100)))
    : 0;

  useEffect(() => {
    let alive = true;
    const pull = () =>
      import("../../lib/syncController")
        .then((m) => m.fetchActiveFactionBounties())
        .then((rows) => {
          if (!alive) return;
          setHotZones(rows.filter((row) => row.isHotZone));
        })
        .catch(() => {
          if (!alive) return;
          setHotZones([]);
        });
    void pull();
    const id = window.setInterval(() => {
      void pull();
    }, 45_000);
    return () => {
      alive = false;
      window.clearInterval(id);
    };
  }, []);

  return (
    <section
      className={cn(
        "relative isolate overflow-hidden rounded-3xl border border-white/[0.1]",
        "bg-surface/75",
      )}
    >
      <motion.div
        variants={prefersReduced ? undefined : heroBackdrop}
        initial="initial"
        animate="animate"
        className="pointer-events-none absolute -inset-24 opacity-[0.04] hud-grid"
        aria-hidden
      />
      <motion.div
        variants={prefersReduced ? undefined : heroBackdrop}
        initial="initial"
        animate="animate"
        className="pointer-events-none absolute -left-32 -top-32 size-[420px] rounded-full bg-gradient-to-br from-white/[0.07] to-transparent blur-3xl"
        aria-hidden
      />
      <motion.div
        variants={prefersReduced ? undefined : heroBackdrop}
        initial="initial"
        animate="animate"
        className="pointer-events-none absolute -bottom-40 -right-24 size-[380px] rounded-full bg-gradient-to-tl from-signal/[0.06] to-transparent blur-3xl"
        aria-hidden
      />
      <div className="pointer-events-none absolute inset-0 noise-overlay mix-blend-overlay opacity-30" />

      <div className="relative p-6 sm:p-8">
        {rolloutSecretEnabled ? (
          <button
            type="button"
            aria-label="Launch Glyph"
            onClick={() => setRolloutTapCount((n) => n + 1)}
            className="absolute right-2 top-2 z-20 size-4 opacity-0"
          />
        ) : null}
        <motion.div
          variants={staggerContainer}
          initial="initial"
          animate="animate"
          className="space-y-8"
        >
          <motion.div variants={itemReveal} className="flex flex-wrap items-end justify-between gap-4">
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <span className="size-1.5 rounded-full bg-signal" />
                <span className="font-mono text-[10px] font-medium uppercase tracking-[0.35em] text-foreground-muted">
                  Command Channel
                </span>
              </div>
              <h1 className="headline-cinema max-w-[18ch] text-4xl font-semibold sm:text-6xl">
                Willkommen{" "}
                <span className="text-signal">{progress.displayName}</span>
              </h1>
              <p className="max-w-prose font-sans text-sm leading-relaxed tracking-[-0.01em] text-foreground-muted sm:text-base">
                Dein Lernpfad ist live · wähle ein Modul, halte den Streak und push den Level mit dem
                gleichen Druck wie ein Release-Build
              </p>
            </div>
            <div className="hidden items-center gap-2 border border-white/[0.1] bg-white/[0.03] px-4 py-2 font-mono text-[11px] text-foreground-muted sm:flex">
              <span className="opacity-70">HUD</span>
              <span className="text-foreground/30">|</span>
              <span>v0.1.0-alpha</span>
            </div>
            <div className="hidden sm:block">
              <SystemReadinessChip />
            </div>
          </motion.div>

          <motion.div variants={itemReveal} className="relative">
            <FactionWarBar />
          </motion.div>
          <motion.div variants={itemReveal} className="relative">
            <SystemPulseTicker />
          </motion.div>
          {activeEventModifier && overdriveRemainSec > 0 ? (
            <motion.div
              variants={itemReveal}
              initial={prefersReduced ? false : { opacity: 0.5, y: -4 }}
              animate={
                prefersReduced
                  ? { opacity: 1, y: 0 }
                  : { opacity: [0.55, 1, 0.62, 1], y: [0, -1, 0], filter: ["hue-rotate(0deg)", "hue-rotate(12deg)", "hue-rotate(0deg)"] }
              }
              transition={prefersReduced ? { duration: 0 } : { duration: 0.9, repeat: Infinity, ease: "linear" }}
              className="relative overflow-hidden border border-orange-300/45 bg-gradient-to-r from-orange-500/22 via-amber-400/18 to-cyan-400/18 px-4 py-3 shadow-[0_0_22px_rgb(251_146_60/0.28),inset_0_0_16px_rgb(251_146_60/0.18)]"
            >
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.2]" aria-hidden />
              <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.26em] text-orange-100">
                NEURAL OVERDRIVE ACTIVE
              </p>
              <p className="relative mt-1 font-mono text-[10px] uppercase tracking-[0.2em] text-orange-100/92">
                Ziel Modul {activeEventModifier.targetModule} XP Mult {activeEventModifier.xpMultiplier.toFixed(2)} Zeit {overdriveMin}:{overdriveSec}
              </p>
            </motion.div>
          ) : null}
          {launchPulse.active && launchRemainSec > 0 ? (
            <motion.div
              variants={itemReveal}
              initial={prefersReduced ? false : { opacity: 0.55, y: -4 }}
              animate={
                prefersReduced
                  ? { opacity: 1, y: 0 }
                  : { opacity: [0.6, 1, 0.66, 1], y: [0, -1, 0], filter: ["hue-rotate(0deg)", "hue-rotate(18deg)", "hue-rotate(0deg)"] }
              }
              transition={prefersReduced ? { duration: 0 } : { duration: 0.8, repeat: Infinity, ease: "linear" }}
              className="relative overflow-hidden border border-cyan-200/60 bg-gradient-to-r from-cyan-500/25 via-sky-400/18 to-fuchsia-400/12 px-4 py-3 shadow-[0_0_22px_rgb(34_211_238/0.28),inset_0_0_16px_rgb(34_211_238/0.18)]"
            >
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.2]" aria-hidden />
              <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.26em] text-cyan-50">
                LAUNCH INIT ACTIVE
              </p>
              <p className="relative mt-1 font-mono text-[10px] uppercase tracking-[0.2em] text-cyan-100/92">
                Welcome to the Nexus XP Mult {launchPulse.xpMultiplier.toFixed(2)} Zeit {launchHours}:{launchMinutes}:{launchSeconds}
              </p>
            </motion.div>
          ) : null}
          {hotZones.length > 0 ? (
            <motion.div
              variants={itemReveal}
              initial={prefersReduced ? false : { opacity: 0.55, y: -6 }}
              animate={
                prefersReduced
                  ? { opacity: 1, y: 0 }
                  : { opacity: [0.58, 1, 0.66, 1], x: [0, -2, 2, 0], filter: ["hue-rotate(0deg)", "hue-rotate(-14deg)", "hue-rotate(0deg)"] }
              }
              transition={prefersReduced ? { duration: 0 } : { duration: 0.65, repeat: Infinity, ease: "linear" }}
              className="relative overflow-hidden border border-red-300/55 bg-gradient-to-r from-red-600/[0.28] via-fuchsia-600/[0.18] to-black/60 px-4 py-3 shadow-[0_0_24px_rgb(239_68_68/0.35)]"
            >
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.34]" aria-hidden />
              <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.26em] text-red-100">
                HOT ZONE ACTIVE
              </p>
              <p className="relative mt-1 font-mono text-[10px] uppercase tracking-[0.18em] text-red-100/92">
                Contracts {hotZones.length} Kritische Bounties mit Eskalation
              </p>
            </motion.div>
          ) : null}
          {neuralOutbreak.infected ? (
            <motion.div variants={itemReveal} className="relative overflow-hidden border border-emerald-300/55 bg-gradient-to-r from-emerald-500/[0.2] via-cyan-500/[0.15] to-black/70 px-4 py-3 shadow-[0_0_24px_rgb(16_185_129/0.24)]">
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.24]" aria-hidden />
              <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.26em] text-emerald-100">
                NEURAL PURGE
              </p>
              <p className="relative mt-1 font-mono text-[10px] uppercase tracking-[0.18em] text-emerald-100/92">
                Modul {neuralOutbreak.module ?? "process"} Fortschritt {neuralOutbreak.progress}/{Math.max(1, neuralOutbreak.target)}
              </p>
              <div className="relative mt-2 h-2 overflow-hidden border border-emerald-200/30 bg-black/50">
                <motion.div
                  className="h-full bg-gradient-to-r from-emerald-300 via-cyan-300 to-emerald-200"
                  animate={{ width: `${purgePercent}%` }}
                  transition={{ duration: prefersReduced ? 0 : 0.35, ease: "easeOut" }}
                />
              </div>
            </motion.div>
          ) : null}
          <motion.div variants={itemReveal} className="relative">
            <ProfileGlassPanel
              progress={hudProgress}
              prestigeTitle={prestigeRank.title}
              prestigeArtifact={prestigeArtifact}
            />

          </motion.div>
          <motion.div variants={itemReveal} className="relative">
            <DailyGrindPanel />
          </motion.div>
          {showRolloutEgg ? (
            <motion.div
              variants={itemReveal}
              className="border border-emerald-300/45 bg-emerald-500/[0.08] px-4 py-3 font-mono text-[11px] font-bold uppercase tracking-[0.24em] text-emerald-100 shadow-[inset_0_0_20px_rgb(16_185_129_/0.2),0_0_20px_rgb(16_185_129_/0.12)]"
            >
              READY FOR LAUNCH
            </motion.div>
          ) : null}
        </motion.div>
      </div>
    </section>
  );
}
