import { InsightRadar } from "./InsightRadar";

type ProfileDashboardProps = {
  globalXP: number;
  globalLevel: number;
  globalSolvedUnits: number;
  globalCareerCompleted: number;
  cloudSnapshotText: string;
  radarMetrics: Array<{ label: string; value: number }>;
  performanceHistory: number[];
  primaryColor: string;
  accentColor: string;
  onManualSync: () => void;
};

export function ProfileDashboard({
  globalXP,
  globalLevel,
  globalSolvedUnits,
  globalCareerCompleted,
  cloudSnapshotText,
  radarMetrics,
  performanceHistory,
  primaryColor,
  accentColor,
  onManualSync,
}: ProfileDashboardProps) {
  return (
    <section className="rounded-xl border border-cyan-400/35 bg-slate-950/75 p-6 shadow-[0_0_26px_rgb(0_229_255_/_0.14)]">
      <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-300">Profile Dashboard</p>
      <h3 className="mt-2 text-xl font-semibold text-cyan-100">Developer Career Profile</h3>
      <div className="mt-3 grid grid-cols-1 gap-2 text-[11px] sm:grid-cols-4">
        <div className="rounded-md border border-cyan-300/30 bg-slate-900/60 px-3 py-2">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Global XP</p>
          <p className="mt-1 font-semibold text-cyan-100">{globalXP}</p>
        </div>
        <div className="rounded-md border border-cyan-300/30 bg-slate-900/60 px-3 py-2">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Global Level</p>
          <p className="mt-1 font-semibold text-cyan-100">{globalLevel}</p>
        </div>
        <div className="rounded-md border border-cyan-300/30 bg-slate-900/60 px-3 py-2">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Solved Units</p>
          <p className="mt-1 font-semibold text-cyan-100">{globalSolvedUnits}</p>
        </div>
        <div className="rounded-md border border-cyan-300/30 bg-slate-900/60 px-3 py-2">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Career Tickets</p>
          <p className="mt-1 font-semibold text-cyan-100">{globalCareerCompleted}</p>
        </div>
      </div>
      <div className="mt-4 rounded-lg border border-cyan-300/30 bg-slate-950/80 p-3">
        <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Cloud Snapshot</p>
        <pre className="mt-2 max-h-48 overflow-auto whitespace-pre-wrap text-[10px] text-cyan-100">{cloudSnapshotText}</pre>
      </div>
      <div className="mt-4">
        <InsightRadar metrics={radarMetrics} performanceHistory={performanceHistory} primaryColor={primaryColor} accentColor={accentColor} />
      </div>
      <button
        type="button"
        className="mt-4 rounded-md border border-emerald-300/55 bg-emerald-950/30 px-4 py-2 text-[10px] font-semibold uppercase tracking-[0.14em] text-emerald-100"
        onClick={onManualSync}
      >
        Manual Cloud Sync
      </button>
    </section>
  );
}
