export const ACHIEVEMENT_IDS = [
  "first_response",
  "s_tier_specialist",
  "infinite_grind",
  "season_alpha_champion",
  "season_alpha_vanguard",
  "season_alpha_legend",
  "season_alpha_faction_victor",
] as const;

export type AchievementId = (typeof ACHIEVEMENT_IDS)[number];

export type AchievementTier = "signal" | "toxic" | "cyan";

export type AchievementDef = {
  id: AchievementId;
  title: string;
  /** Tooltip / title-Attribut ohne Satzendpunkt */
  requirement: string;
  tier: AchievementTier;
};

export const ACHIEVEMENTS: Record<AchievementId, AchievementDef> = {
  first_response: {
    id: "first_response",
    title: "First Response",
    requirement: "Schließe dein erstes Support-Ticket oder Helpdesk-Diagnostik erfolgreich ab",
    tier: "cyan",
  },
  s_tier_specialist: {
    id: "s_tier_specialist",
    title: "S-Tier Specialist",
    requirement: "Erreiche einen Arena-Bestwert von mindestens 2000 Punkten",
    tier: "signal",
  },
  infinite_grind: {
    id: "infinite_grind",
    title: "Infinite Grind",
    requirement: "Halte eine Daily-Streak von mindestens 7 abgeschlossenen Tagen",
    tier: "toxic",
  },
  season_alpha_champion: {
    id: "season_alpha_champion",
    title: "Season 1 Alpha Champion",
    requirement: "Belege Platz 1 beim Saisonabschluss Alpha",
    tier: "signal",
  },
  season_alpha_vanguard: {
    id: "season_alpha_vanguard",
    title: "Season 1 Vanguard",
    requirement: "Belege Platz 2 beim Saisonabschluss Alpha",
    tier: "cyan",
  },
  season_alpha_legend: {
    id: "season_alpha_legend",
    title: "Season 1 Legend",
    requirement: "Belege Platz 3 beim Saisonabschluss Alpha",
    tier: "toxic",
  },
  season_alpha_faction_victor: {
    id: "season_alpha_faction_victor",
    title: "Season 1 Faction Victor",
    requirement: "Gehöre zur Siegerfraktion beim Saisonabschluss Alpha",
    tier: "signal",
  },
};

export const ACHIEVEMENT_LIST: AchievementDef[] = ACHIEVEMENT_IDS.map((id) => ACHIEVEMENTS[id]);

const ID_SET = new Set<string>(ACHIEVEMENT_IDS);

export function isAchievementId(v: string): v is AchievementId {
  return ID_SET.has(v);
}

export function sanitizeAchievementIds(raw: unknown, max = 32): AchievementId[] {
  if (!Array.isArray(raw) || raw.length > max) return [];
  const out: AchievementId[] = [];
  for (const x of raw) {
    if (typeof x === "string" && isAchievementId(x) && !out.includes(x)) out.push(x);
  }
  return out;
}

export function achievementTierClasses(tier: AchievementTier): { frame: string; glow: string; icon: string } {
  if (tier === "signal") {
    return {
      frame: "border-signal/45 bg-signal/[0.08]",
      glow: "shadow-[inset_0_0_14px_rgb(179_24_38_/0.35)]",
      icon: "text-signal",
    };
  }
  if (tier === "toxic") {
    return {
      frame: "border-emerald-500/40 bg-emerald-950/30",
      glow: "shadow-[inset_0_0_14px_rgb(16_185_129_/0.28)]",
      icon: "text-emerald-300",
    };
  }
  return {
    frame: "border-cyan-500/40 bg-cyan-950/25",
    glow: "shadow-[inset_0_0_14px_rgb(6_182_212_/0.32)]",
    icon: "text-cyan-200",
  };
}
